INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 71, 24, 'My tongue will also talk about your righteousness all day long, for they are disappointed, and they are confounded, who want to harm me.'),
  ('Psalms', 72, 1, 'By Solomon. God, give the king your justice; your righteousness to the royal son.'),
  ('Psalms', 72, 2, 'He will judge your people with righteousness, and your poor with justice.'),
  ('Psalms', 72, 3, 'The mountains shall bring prosperity to the people. The hills bring the fruit of righteousness.'),
  ('Psalms', 72, 4, 'He will judge the poor of the people. He will save the children of the needy, and will break the oppressor in pieces.'),
  ('Psalms', 72, 5, 'They shall fear you while the sun endures; and as long as the moon, throughout all generations.'),
  ('Psalms', 72, 6, 'He will come down like rain on the mown grass, as showers that water the earth.'),
  ('Psalms', 72, 7, 'In his days, the righteous shall flourish, and abundance of peace, until the moon is no more.'),
  ('Psalms', 72, 8, 'He shall have dominion also from sea to sea, from the River to the ends of the earth.'),
  ('Psalms', 72, 9, 'Those who dwell in the wilderness shall bow before him. His enemies shall lick the dust.'),
  ('Psalms', 72, 10, 'The kings of Tarshish and of the islands will bring tribute. The kings of Sheba and Seba shall offer gifts.'),
  ('Psalms', 72, 11, 'Yes, all kings shall fall down before him. All nations shall serve him.'),
  ('Psalms', 72, 12, 'For he will deliver the needy when he cries; the poor, who has no helper.'),
  ('Psalms', 72, 13, 'He will have pity on the poor and needy. He will save the souls of the needy.'),
  ('Psalms', 72, 14, 'He will redeem their soul from oppression and violence. Their blood will be precious in his sight.'),
  ('Psalms', 72, 15, 'He will live; and Sheba’s gold will be given to him. Men will pray for him continually. They will bless him all day long.'),
  ('Psalms', 72, 16, 'Abundance of grain shall be throughout the land. Its fruit sways like Lebanon. Let it flourish, thriving like the grass of the field.'),
  ('Psalms', 72, 17, 'His name endures forever. His name continues as long as the sun. Men shall be blessed by him. All nations will call him blessed.'),
  ('Psalms', 72, 18, 'Praise be to the LORD God, the God of Israel, who alone does marvelous deeds.'),
  ('Psalms', 72, 19, 'Blessed be his glorious name forever! Let the whole earth be filled with his glory! Amen and amen.'),
  ('Psalms', 72, 20, 'This ends the prayers by David, the son of Jesse.'),
  ('Psalms', 73, 1, 'A Psalm by Asaph. Surely God is good to Israel, to those who are pure in heart.'),
  ('Psalms', 73, 2, 'But as for me, my feet were almost gone. My steps had nearly slipped.'),
  ('Psalms', 73, 3, 'For I was envious of the arrogant, when I saw the prosperity of the wicked.'),
  ('Psalms', 73, 4, 'For there are no struggles in their death, but their strength is firm.'),
  ('Psalms', 73, 5, 'They are free from burdens of men, neither are they plagued like other men.'),
  ('Psalms', 73, 6, 'Therefore pride is like a chain around their neck. Violence covers them like a garment.'),
  ('Psalms', 73, 7, 'Their eyes bulge with fat. Their minds pass the limits of conceit.'),
  ('Psalms', 73, 8, 'They scoff and speak with malice. In arrogance, they threaten oppression.'),
  ('Psalms', 73, 9, 'They have set their mouth in the heavens. Their tongue walks through the earth.'),
  ('Psalms', 73, 10, 'Therefore their people return to them, and they drink up waters of abundance.'),
  ('Psalms', 73, 11, 'They say, “How does God know? Is there knowledge in the Most High?”'),
  ('Psalms', 73, 12, 'Behold, these are the wicked. Being always at ease, they increase in riches.'),
  ('Psalms', 73, 13, 'Surely I have cleansed my heart in vain, and washed my hands in innocence,'),
  ('Psalms', 73, 14, 'For all day long I have been plagued, and punished every morning.'),
  ('Psalms', 73, 15, 'If I had said, “I will speak thus”, behold, I would have betrayed the generation of your children.'),
  ('Psalms', 73, 16, 'When I tried to understand this, it was too painful for me—'),
  ('Psalms', 73, 17, 'until I entered God’s sanctuary, and considered their latter end.'),
  ('Psalms', 73, 18, 'Surely you set them in slippery places. You throw them down to destruction.'),
  ('Psalms', 73, 19, 'How they are suddenly destroyed! They are completely swept away with terrors.'),
  ('Psalms', 73, 20, 'As a dream when one wakes up, so, Lord, when you awake, you will despise their fantasies.'),
  ('Psalms', 73, 21, 'For my soul was grieved. I was embittered in my heart.'),
  ('Psalms', 73, 22, 'I was so senseless and ignorant. I was a brute beast before you.'),
  ('Psalms', 73, 23, 'Nevertheless, I am continually with you. You have held my right hand.'),
  ('Psalms', 73, 24, 'You will guide me with your counsel, and afterward receive me to glory.'),
  ('Psalms', 73, 25, 'Whom do I have in heaven? There is no one on earth whom I desire besides you.'),
  ('Psalms', 73, 26, 'My flesh and my heart fails, but God is the strength of my heart and my portion forever.'),
  ('Psalms', 73, 27, 'For, behold, those who are far from you shall perish. You have destroyed all those who are unfaithful to you.'),
  ('Psalms', 73, 28, 'But it is good for me to come close to God. I have made the Lord GOD my refuge, that I may tell of all your works.'),
  ('Psalms', 74, 1, 'A contemplation by Asaph. God, why have you rejected us forever? Why does your anger smolder against the sheep of your pasture?'),
  ('Psalms', 74, 2, 'Remember your congregation, which you purchased of old, which you have redeemed to be the tribe of your inheritance: Mount Zion, in which you have lived.'),
  ('Psalms', 74, 3, 'Lift up your feet to the perpetual ruins, all the evil that the enemy has done in the sanctuary.'),
  ('Psalms', 74, 4, 'Your adversaries have roared in the middle of your assembly. They have set up their standards as signs.'),
  ('Psalms', 74, 5, 'They behaved like men wielding axes, cutting through a thicket of trees.'),
  ('Psalms', 74, 6, 'Now they break all its carved work down with hatchet and hammers.'),
  ('Psalms', 74, 7, 'They have burned your sanctuary to the ground. They have profaned the dwelling place of your Name.'),
  ('Psalms', 74, 8, 'They said in their heart, “We will crush them completely.” They have burned up all the places in the land where God was worshiped.'),
  ('Psalms', 74, 9, 'We see no miraculous signs. There is no longer any prophet, neither is there among us anyone who knows how long.'),
  ('Psalms', 74, 10, 'How long, God, shall the adversary reproach? Shall the enemy blaspheme your name forever?'),
  ('Psalms', 74, 11, 'Why do you draw back your hand, even your right hand? Take it from your chest and consume them!'),
  ('Psalms', 74, 12, 'Yet God is my King of old, working salvation throughout the earth.'),
  ('Psalms', 74, 13, 'You divided the sea by your strength. You broke the heads of the sea monsters in the waters.'),
  ('Psalms', 74, 14, 'You broke the heads of Leviathan in pieces. You gave him as food to people and desert creatures.'),
  ('Psalms', 74, 15, 'You opened up spring and stream. You dried up mighty rivers.'),
  ('Psalms', 74, 16, 'The day is yours, the night is also yours. You have prepared the light and the sun.'),
  ('Psalms', 74, 17, 'You have set all the boundaries of the earth. You have made summer and winter.'),
  ('Psalms', 74, 18, 'Remember this, that the enemy has mocked you, LORD. Foolish people have blasphemed your name.'),
  ('Psalms', 74, 19, 'Don’t deliver the soul of your dove to wild beasts. Don’t forget the life of your poor forever.'),
  ('Psalms', 74, 20, 'Honor your covenant, for haunts of violence fill the dark places of the earth.'),
  ('Psalms', 74, 21, 'Don’t let the oppressed return ashamed. Let the poor and needy praise your name.'),
  ('Psalms', 74, 22, 'Arise, God! Plead your own cause. Remember how the foolish man mocks you all day.'),
  ('Psalms', 74, 23, 'Don’t forget the voice of your adversaries. The tumult of those who rise up against you ascends continually.'),
  ('Psalms', 75, 1, 'For the Chief Musician. To the tune of “Do Not Destroy.” A Psalm by Asaph. A song. We give thanks to you, God. We give thanks, for your Name is near. Men tell about your wondrous works.'),
  ('Psalms', 75, 2, 'When I choose the appointed time, I will judge blamelessly.'),
  ('Psalms', 75, 3, 'The earth and all its inhabitants quake. I firmly hold its pillars. Selah.'),
  ('Psalms', 75, 4, 'I said to the arrogant, “Don’t boast!” I said to the wicked, “Don’t lift up the horn.'),
  ('Psalms', 75, 5, 'Don’t lift up your horn on high. Don’t speak with a stiff neck.”'),
  ('Psalms', 75, 6, 'For neither from the east, nor from the west, nor yet from the south, comes exaltation.'),
  ('Psalms', 75, 7, 'But God is the judge. He puts down one, and lifts up another.'),
  ('Psalms', 75, 8, 'For in the LORD’s hand there is a cup, full of foaming wine mixed with spices. He pours it out. Indeed the wicked of the earth drink and drink it to its very dregs.'),
  ('Psalms', 75, 9, 'But I will declare this forever: I will sing praises to the God of Jacob.'),
  ('Psalms', 75, 10, 'I will cut off all the horns of the wicked, but the horns of the righteous shall be lifted up.'),
  ('Psalms', 76, 1, 'For the Chief Musician. On stringed instruments. A Psalm by Asaph. A song. In Judah, God is known. His name is great in Israel.'),
  ('Psalms', 76, 2, 'His tabernacle is also in Salem. His dwelling place in Zion.'),
  ('Psalms', 76, 3, 'There he broke the flaming arrows of the bow, the shield, and the sword, and the weapons of war. Selah.'),
  ('Psalms', 76, 4, 'Glorious are you, and excellent, more than mountains of game.'),
  ('Psalms', 76, 5, 'Valiant men lie plundered, they have slept their last sleep. None of the men of war can lift their hands.'),
  ('Psalms', 76, 6, 'At your rebuke, God of Jacob, both chariot and horse are cast into a dead sleep.'),
  ('Psalms', 76, 7, 'You, even you, are to be feared. Who can stand in your sight when you are angry?'),
  ('Psalms', 76, 8, 'You pronounced judgment from heaven. The earth feared, and was silent,'),
  ('Psalms', 76, 9, 'when God arose to judgment, to save all the afflicted ones of the earth. Selah.'),
  ('Psalms', 76, 10, 'Surely the wrath of man praises you. The survivors of your wrath are restrained.'),
  ('Psalms', 76, 11, 'Make vows to the LORD your God, and fulfill them! Let all of his neighbors bring presents to him who is to be feared.'),
  ('Psalms', 76, 12, 'He will cut off the spirit of princes. He is feared by the kings of the earth.'),
  ('Psalms', 77, 1, 'For the Chief Musician. To Jeduthun. A Psalm by Asaph. My cry goes to God! Indeed, I cry to God for help, and for him to listen to me.'),
  ('Psalms', 77, 2, 'In the day of my trouble I sought the Lord. My hand was stretched out in the night, and didn’t get tired. My soul refused to be comforted.'),
  ('Psalms', 77, 3, 'I remember God, and I groan. I complain, and my spirit is overwhelmed. Selah.'),
  ('Psalms', 77, 4, 'You hold my eyelids open. I am so troubled that I can’t speak.'),
  ('Psalms', 77, 5, 'I have considered the days of old, the years of ancient times.'),
  ('Psalms', 77, 6, 'I remember my song in the night. I consider in my own heart; my spirit diligently inquires:');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 77, 7, '“Will the Lord reject us forever? Will he be favorable no more?'),
  ('Psalms', 77, 8, 'Has his loving kindness vanished forever? Does his promise fail for generations?'),
  ('Psalms', 77, 9, 'Has God forgotten to be gracious? Has he, in anger, withheld his compassion?” Selah.'),
  ('Psalms', 77, 10, 'Then I thought, “I will appeal to this: the years of the right hand of the Most High.”'),
  ('Psalms', 77, 11, 'I will remember the LORD’s deeds; for I will remember your wonders of old.'),
  ('Psalms', 77, 12, 'I will also meditate on all your work, and consider your doings.'),
  ('Psalms', 77, 13, 'Your way, God, is in the sanctuary. What god is great like God?'),
  ('Psalms', 77, 14, 'You are the God who does wonders. You have made your strength known among the peoples.'),
  ('Psalms', 77, 15, 'You have redeemed your people with your arm, the sons of Jacob and Joseph. Selah.'),
  ('Psalms', 77, 16, 'The waters saw you, God. The waters saw you, and they writhed. The depths also convulsed.'),
  ('Psalms', 77, 17, 'The clouds poured out water. The skies resounded with thunder. Your arrows also flashed around.'),
  ('Psalms', 77, 18, 'The voice of your thunder was in the whirlwind. The lightnings lit up the world. The earth trembled and shook.'),
  ('Psalms', 77, 19, 'Your way was through the sea, your paths through the great waters. Your footsteps were not known.'),
  ('Psalms', 77, 20, 'You led your people like a flock, by the hand of Moses and Aaron.'),
  ('Psalms', 78, 1, 'A contemplation by Asaph. Hear my teaching, my people. Turn your ears to the words of my mouth.'),
  ('Psalms', 78, 2, 'I will open my mouth in a parable. I will utter dark sayings of old,'),
  ('Psalms', 78, 3, 'which we have heard and known, and our fathers have told us.'),
  ('Psalms', 78, 4, 'We will not hide them from their children, telling to the generation to come the praises of the LORD, his strength, and his wondrous deeds that he has done.'),
  ('Psalms', 78, 5, 'For he established a covenant in Jacob, and appointed a teaching in Israel, which he commanded our fathers, that they should make them known to their children;'),
  ('Psalms', 78, 6, 'that the generation to come might know, even the children who should be born; who should arise and tell their children,'),
  ('Psalms', 78, 7, 'that they might set their hope in God, and not forget God’s deeds, but keep his commandments,'),
  ('Psalms', 78, 8, 'and might not be as their fathers— a stubborn and rebellious generation, a generation that didn’t make their hearts loyal, whose spirit was not steadfast with God.'),
  ('Psalms', 78, 9, 'The children of Ephraim, being armed and carrying bows, turned back in the day of battle.'),
  ('Psalms', 78, 10, 'They didn’t keep God’s covenant, and refused to walk in his law.'),
  ('Psalms', 78, 11, 'They forgot his doings, his wondrous deeds that he had shown them.'),
  ('Psalms', 78, 12, 'He did marvelous things in the sight of their fathers, in the land of Egypt, in the field of Zoan.'),
  ('Psalms', 78, 13, 'He split the sea, and caused them to pass through. He made the waters stand as a heap.'),
  ('Psalms', 78, 14, 'In the daytime he also led them with a cloud, and all night with a light of fire.'),
  ('Psalms', 78, 15, 'He split rocks in the wilderness, and gave them drink abundantly as out of the depths.'),
  ('Psalms', 78, 16, 'He brought streams also out of the rock, and caused waters to run down like rivers.'),
  ('Psalms', 78, 17, 'Yet they still went on to sin against him, to rebel against the Most High in the desert.'),
  ('Psalms', 78, 18, 'They tempted God in their heart by asking food according to their desire.'),
  ('Psalms', 78, 19, 'Yes, they spoke against God. They said, “Can God prepare a table in the wilderness?'),
  ('Psalms', 78, 20, 'Behold, he struck the rock, so that waters gushed out, and streams overflowed. Can he give bread also? Will he provide meat for his people?”'),
  ('Psalms', 78, 21, 'Therefore the LORD heard, and was angry. A fire was kindled against Jacob, anger also went up against Israel,'),
  ('Psalms', 78, 22, 'because they didn’t believe in God, and didn’t trust in his salvation.'),
  ('Psalms', 78, 23, 'Yet he commanded the skies above, and opened the doors of heaven.'),
  ('Psalms', 78, 24, 'He rained down manna on them to eat, and gave them food from the sky.'),
  ('Psalms', 78, 25, 'Man ate the bread of angels. He sent them food to the full.'),
  ('Psalms', 78, 26, 'He caused the east wind to blow in the sky. By his power he guided the south wind.'),
  ('Psalms', 78, 27, 'He also rained meat on them as the dust, winged birds as the sand of the seas.'),
  ('Psalms', 78, 28, 'He let them fall in the middle of their camp, around their habitations.'),
  ('Psalms', 78, 29, 'So they ate, and were well filled. He gave them their own desire.'),
  ('Psalms', 78, 30, 'They didn’t turn from their cravings. Their food was yet in their mouths,'),
  ('Psalms', 78, 31, 'when the anger of God went up against them, killed some of their strongest, and struck down the young men of Israel.'),
  ('Psalms', 78, 32, 'For all this they still sinned, and didn’t believe in his wondrous works.'),
  ('Psalms', 78, 33, 'Therefore he consumed their days in vanity, and their years in terror.'),
  ('Psalms', 78, 34, 'When he killed them, then they inquired after him. They returned and sought God earnestly.'),
  ('Psalms', 78, 35, 'They remembered that God was their rock, the Most High God, their redeemer.'),
  ('Psalms', 78, 36, 'But they flattered him with their mouth, and lied to him with their tongue.'),
  ('Psalms', 78, 37, 'For their heart was not right with him, neither were they faithful in his covenant.'),
  ('Psalms', 78, 38, 'But he, being merciful, forgave iniquity, and didn’t destroy them. Yes, many times he turned his anger away, and didn’t stir up all his wrath.'),
  ('Psalms', 78, 39, 'He remembered that they were but flesh, a wind that passes away, and doesn’t come again.'),
  ('Psalms', 78, 40, 'How often they rebelled against him in the wilderness, and grieved him in the desert!'),
  ('Psalms', 78, 41, 'They turned again and tempted God, and provoked the Holy One of Israel.'),
  ('Psalms', 78, 42, 'They didn’t remember his hand, nor the day when he redeemed them from the adversary;'),
  ('Psalms', 78, 43, 'how he set his signs in Egypt, his wonders in the field of Zoan,'),
  ('Psalms', 78, 44, 'he turned their rivers into blood, and their streams, so that they could not drink.'),
  ('Psalms', 78, 45, 'He sent among them swarms of flies, which devoured them; and frogs, which destroyed them.'),
  ('Psalms', 78, 46, 'He also gave their increase to the caterpillar, and their labor to the locust.'),
  ('Psalms', 78, 47, 'He destroyed their vines with hail, their sycamore fig trees with frost.'),
  ('Psalms', 78, 48, 'He also gave over their livestock to the hail, and their flocks to hot thunderbolts.'),
  ('Psalms', 78, 49, 'He threw on them the fierceness of his anger, wrath, indignation, and trouble, and a band of angels of evil.'),
  ('Psalms', 78, 50, 'He made a path for his anger. He didn’t spare their soul from death, but gave their life over to the pestilence,'),
  ('Psalms', 78, 51, 'and struck all the firstborn in Egypt, the chief of their strength in the tents of Ham.'),
  ('Psalms', 78, 52, 'But he led out his own people like sheep, and guided them in the wilderness like a flock.'),
  ('Psalms', 78, 53, 'He led them safely, so that they weren’t afraid, but the sea overwhelmed their enemies.'),
  ('Psalms', 78, 54, 'He brought them to the border of his sanctuary, to this mountain, which his right hand had taken.'),
  ('Psalms', 78, 55, 'He also drove out the nations before them, allotted them for an inheritance by line, and made the tribes of Israel to dwell in their tents.'),
  ('Psalms', 78, 56, 'Yet they tempted and rebelled against the Most High God, and didn’t keep his testimonies,'),
  ('Psalms', 78, 57, 'but turned back, and dealt treacherously like their fathers. They were twisted like a deceitful bow.'),
  ('Psalms', 78, 58, 'For they provoked him to anger with their high places, and moved him to jealousy with their engraved images.'),
  ('Psalms', 78, 59, 'When God heard this, he was angry, and greatly abhorred Israel,'),
  ('Psalms', 78, 60, 'so that he abandoned the tent of Shiloh, the tent which he placed among men,'),
  ('Psalms', 78, 61, 'and delivered his strength into captivity, his glory into the adversary’s hand.'),
  ('Psalms', 78, 62, 'He also gave his people over to the sword, and was angry with his inheritance.'),
  ('Psalms', 78, 63, 'Fire devoured their young men. Their virgins had no wedding song.'),
  ('Psalms', 78, 64, 'Their priests fell by the sword, and their widows couldn’t weep.'),
  ('Psalms', 78, 65, 'Then the Lord awakened as one out of sleep, like a mighty man who shouts by reason of wine.'),
  ('Psalms', 78, 66, 'He struck his adversaries backward. He put them to a perpetual reproach.'),
  ('Psalms', 78, 67, 'Moreover he rejected the tent of Joseph, and didn’t choose the tribe of Ephraim,'),
  ('Psalms', 78, 68, 'But chose the tribe of Judah, Mount Zion which he loved.'),
  ('Psalms', 78, 69, 'He built his sanctuary like the heights, like the earth which he has established forever.'),
  ('Psalms', 78, 70, 'He also chose David his servant, and took him from the sheepfolds;'),
  ('Psalms', 78, 71, 'from following the ewes that have their young, he brought him to be the shepherd of Jacob, his people, and Israel, his inheritance.'),
  ('Psalms', 78, 72, 'So he was their shepherd according to the integrity of his heart, and guided them by the skillfulness of his hands.'),
  ('Psalms', 79, 1, 'A Psalm by Asaph. God, the nations have come into your inheritance. They have defiled your holy temple. They have laid Jerusalem in heaps.'),
  ('Psalms', 79, 2, 'They have given the dead bodies of your servants to be food for the birds of the sky, the flesh of your saints to the animals of the earth.'),
  ('Psalms', 79, 3, 'They have shed their blood like water around Jerusalem. There was no one to bury them.'),
  ('Psalms', 79, 4, 'We have become a reproach to our neighbors, a scoffing and derision to those who are around us.'),
  ('Psalms', 79, 5, 'How long, LORD? Will you be angry forever? Will your jealousy burn like fire?'),
  ('Psalms', 79, 6, 'Pour out your wrath on the nations that don’t know you, on the kingdoms that don’t call on your name,'),
  ('Psalms', 79, 7, 'for they have devoured Jacob, and destroyed his homeland.'),
  ('Psalms', 79, 8, 'Don’t hold the iniquities of our forefathers against us. Let your tender mercies speedily meet us, for we are in desperate need.'),
  ('Psalms', 79, 9, 'Help us, God of our salvation, for the glory of your name. Deliver us, and forgive our sins, for your name’s sake.'),
  ('Psalms', 79, 10, 'Why should the nations say, “Where is their God?” Let it be known among the nations, before our eyes, that vengeance for your servants’ blood is being poured out.'),
  ('Psalms', 79, 11, 'Let the sighing of the prisoner come before you. According to the greatness of your power, preserve those who are sentenced to death.'),
  ('Psalms', 79, 12, 'Pay back to our neighbors seven times into their bosom their reproach with which they have reproached you, Lord.'),
  ('Psalms', 79, 13, 'So we, your people and sheep of your pasture, will give you thanks forever. We will praise you forever, to all generations.'),
  ('Psalms', 80, 1, 'For the Chief Musician. To the tune of “The Lilies of the Covenant.” A Psalm by Asaph. Hear us, Shepherd of Israel, you who lead Joseph like a flock, you who sit above the cherubim, shine out.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 80, 2, 'Before Ephraim, Benjamin, and Manasseh, stir up your might! Come to save us!'),
  ('Psalms', 80, 3, 'Turn us again, God. Cause your face to shine, and we will be saved.'),
  ('Psalms', 80, 4, 'LORD God of Armies, how long will you be angry against the prayer of your people?'),
  ('Psalms', 80, 5, 'You have fed them with the bread of tears, and given them tears to drink in large measure.'),
  ('Psalms', 80, 6, 'You make us a source of contention to our neighbors. Our enemies laugh among themselves.'),
  ('Psalms', 80, 7, 'Turn us again, God of Armies. Cause your face to shine, and we will be saved.'),
  ('Psalms', 80, 8, 'You brought a vine out of Egypt. You drove out the nations, and planted it.'),
  ('Psalms', 80, 9, 'You cleared the ground for it. It took deep root, and filled the land.'),
  ('Psalms', 80, 10, 'The mountains were covered with its shadow. Its boughs were like God’s cedars.'),
  ('Psalms', 80, 11, 'It sent out its branches to the sea, its shoots to the River.'),
  ('Psalms', 80, 12, 'Why have you broken down its walls, so that all those who pass by the way pluck it?'),
  ('Psalms', 80, 13, 'The boar out of the wood ravages it. The wild animals of the field feed on it.'),
  ('Psalms', 80, 14, 'Turn again, we beg you, God of Armies. Look down from heaven, and see, and visit this vine,'),
  ('Psalms', 80, 15, 'the stock which your right hand planted, the branch that you made strong for yourself.'),
  ('Psalms', 80, 16, 'It’s burned with fire. It’s cut down. They perish at your rebuke.'),
  ('Psalms', 80, 17, 'Let your hand be on the man of your right hand, on the son of man whom you made strong for yourself.'),
  ('Psalms', 80, 18, 'So we will not turn away from you. Revive us, and we will call on your name.'),
  ('Psalms', 80, 19, 'Turn us again, LORD God of Armies. Cause your face to shine, and we will be saved.'),
  ('Psalms', 81, 1, 'For the Chief Musician. On an instrument of Gath. By Asaph. Sing aloud to God, our strength! Make a joyful shout to the God of Jacob!'),
  ('Psalms', 81, 2, 'Raise a song, and bring here the tambourine, the pleasant lyre with the harp.'),
  ('Psalms', 81, 3, 'Blow the trumpet at the New Moon, at the full moon, on our feast day.'),
  ('Psalms', 81, 4, 'For it is a statute for Israel, an ordinance of the God of Jacob.'),
  ('Psalms', 81, 5, 'He appointed it in Joseph for a covenant, when he went out over the land of Egypt, I heard a language that I didn’t know.'),
  ('Psalms', 81, 6, '“I removed his shoulder from the burden. His hands were freed from the basket.'),
  ('Psalms', 81, 7, 'You called in trouble, and I delivered you. I answered you in the secret place of thunder. I tested you at the waters of Meribah.” Selah.'),
  ('Psalms', 81, 8, '“Hear, my people, and I will testify to you, Israel, if you would listen to me!'),
  ('Psalms', 81, 9, 'There shall be no strange god in you, neither shall you worship any foreign god.'),
  ('Psalms', 81, 10, 'I am the LORD, your God, who brought you up out of the land of Egypt. Open your mouth wide, and I will fill it.'),
  ('Psalms', 81, 11, 'But my people didn’t listen to my voice. Israel desired none of me.'),
  ('Psalms', 81, 12, 'So I let them go after the stubbornness of their hearts, that they might walk in their own counsels.'),
  ('Psalms', 81, 13, 'Oh that my people would listen to me, that Israel would walk in my ways!'),
  ('Psalms', 81, 14, 'I would soon subdue their enemies, and turn my hand against their adversaries.'),
  ('Psalms', 81, 15, 'The haters of the LORD would cringe before him, and their punishment would last forever.'),
  ('Psalms', 81, 16, 'But he would have also fed them with the finest of the wheat. I will satisfy you with honey out of the rock.”'),
  ('Psalms', 82, 1, 'A Psalm by Asaph. God presides in the great assembly. He judges among the gods.'),
  ('Psalms', 82, 2, '“How long will you judge unjustly, and show partiality to the wicked?” Selah.'),
  ('Psalms', 82, 3, '“Defend the weak, the poor, and the fatherless. Maintain the rights of the poor and oppressed.'),
  ('Psalms', 82, 4, 'Rescue the weak and needy. Deliver them out of the hand of the wicked.”'),
  ('Psalms', 82, 5, 'They don’t know, neither do they understand. They walk back and forth in darkness. All the foundations of the earth are shaken.'),
  ('Psalms', 82, 6, 'I said, “You are gods, all of you are sons of the Most High.'),
  ('Psalms', 82, 7, 'Nevertheless you shall die like men, and fall like one of the rulers.”'),
  ('Psalms', 82, 8, 'Arise, God, judge the earth, for you inherit all of the nations.'),
  ('Psalms', 83, 1, 'A song. A Psalm by Asaph. God, don’t keep silent. Don’t keep silent, and don’t be still, God.'),
  ('Psalms', 83, 2, 'For, behold, your enemies are stirred up. Those who hate you have lifted up their heads.'),
  ('Psalms', 83, 3, 'They conspire with cunning against your people. They plot against your cherished ones.'),
  ('Psalms', 83, 4, '“Come,” they say, “let’s destroy them as a nation, that the name of Israel may be remembered no more.”'),
  ('Psalms', 83, 5, 'For they have conspired together with one mind. They form an alliance against you.'),
  ('Psalms', 83, 6, 'The tents of Edom and the Ishmaelites; Moab, and the Hagrites;'),
  ('Psalms', 83, 7, 'Gebal, Ammon, and Amalek; Philistia with the inhabitants of Tyre;'),
  ('Psalms', 83, 8, 'Assyria also is joined with them. They have helped the children of Lot. Selah.'),
  ('Psalms', 83, 9, 'Do to them as you did to Midian, as to Sisera, as to Jabin, at the river Kishon;'),
  ('Psalms', 83, 10, 'who perished at Endor, who became as dung for the earth.'),
  ('Psalms', 83, 11, 'Make their nobles like Oreb and Zeeb, yes, all their princes like Zebah and Zalmunna,'),
  ('Psalms', 83, 12, 'who said, “Let’s take possession of God’s pasture lands.”'),
  ('Psalms', 83, 13, 'My God, make them like tumbleweed, like chaff before the wind.'),
  ('Psalms', 83, 14, 'As the fire that burns the forest, as the flame that sets the mountains on fire,'),
  ('Psalms', 83, 15, 'so pursue them with your tempest, and terrify them with your storm.'),
  ('Psalms', 83, 16, 'Fill their faces with confusion, that they may seek your name, LORD.'),
  ('Psalms', 83, 17, 'Let them be disappointed and dismayed forever. Yes, let them be confounded and perish;'),
  ('Psalms', 83, 18, 'that they may know that you alone, whose name is the LORD, are the Most High over all the earth.'),
  ('Psalms', 84, 1, 'For the Chief Musician. On an instrument of Gath. A Psalm by the sons of Korah. How lovely are your dwellings, LORD of Armies!'),
  ('Psalms', 84, 2, 'My soul longs, and even faints for the courts of the LORD. My heart and my flesh cry out for the living God.'),
  ('Psalms', 84, 3, 'Yes, the sparrow has found a home, and the swallow a nest for herself, where she may have her young, near your altars, LORD of Armies, my King, and my God.'),
  ('Psalms', 84, 4, 'Blessed are those who dwell in your house. They are always praising you. Selah.'),
  ('Psalms', 84, 5, 'Blessed are those whose strength is in you, who have set their hearts on a pilgrimage.'),
  ('Psalms', 84, 6, 'Passing through the valley of Weeping, they make it a place of springs. Yes, the autumn rain covers it with blessings.'),
  ('Psalms', 84, 7, 'They go from strength to strength. Every one of them appears before God in Zion.'),
  ('Psalms', 84, 8, 'LORD, God of Armies, hear my prayer. Listen, God of Jacob. Selah.'),
  ('Psalms', 84, 9, 'Behold, God our shield, look at the face of your anointed.'),
  ('Psalms', 84, 10, 'For a day in your courts is better than a thousand. I would rather be a doorkeeper in the house of my God, than to dwell in the tents of wickedness.'),
  ('Psalms', 84, 11, 'For the LORD God is a sun and a shield. The LORD will give grace and glory. He withholds no good thing from those who walk blamelessly.'),
  ('Psalms', 84, 12, 'LORD of Armies, blessed is the man who trusts in you.'),
  ('Psalms', 85, 1, 'For the Chief Musician. A Psalm by the sons of Korah. LORD, you have been favorable to your land. You have restored the fortunes of Jacob.'),
  ('Psalms', 85, 2, 'You have forgiven the iniquity of your people. You have covered all their sin. Selah.'),
  ('Psalms', 85, 3, 'You have taken away all your wrath. You have turned from the fierceness of your anger.'),
  ('Psalms', 85, 4, 'Turn us, God of our salvation, and cause your indignation toward us to cease.'),
  ('Psalms', 85, 5, 'Will you be angry with us forever? Will you draw out your anger to all generations?'),
  ('Psalms', 85, 6, 'Won’t you revive us again, that your people may rejoice in you?'),
  ('Psalms', 85, 7, 'Show us your loving kindness, LORD. Grant us your salvation.'),
  ('Psalms', 85, 8, 'I will hear what God, the LORD, will speak, for he will speak peace to his people, his saints; but let them not turn again to folly.'),
  ('Psalms', 85, 9, 'Surely his salvation is near those who fear him, that glory may dwell in our land.'),
  ('Psalms', 85, 10, 'Mercy and truth meet together. Righteousness and peace have kissed each other.'),
  ('Psalms', 85, 11, 'Truth springs out of the earth. Righteousness has looked down from heaven.'),
  ('Psalms', 85, 12, 'Yes, the LORD will give that which is good. Our land will yield its increase.'),
  ('Psalms', 85, 13, 'Righteousness goes before him, and prepares the way for his steps.'),
  ('Psalms', 86, 1, 'A Prayer by David. Hear, LORD, and answer me, for I am poor and needy.'),
  ('Psalms', 86, 2, 'Preserve my soul, for I am godly. You, my God, save your servant who trusts in you.'),
  ('Psalms', 86, 3, 'Be merciful to me, Lord, for I call to you all day long.'),
  ('Psalms', 86, 4, 'Bring joy to the soul of your servant, for to you, Lord, do I lift up my soul.'),
  ('Psalms', 86, 5, 'For you, Lord, are good, and ready to forgive, abundant in loving kindness to all those who call on you.'),
  ('Psalms', 86, 6, 'Hear, LORD, my prayer. Listen to the voice of my petitions.'),
  ('Psalms', 86, 7, 'In the day of my trouble I will call on you, for you will answer me.'),
  ('Psalms', 86, 8, 'There is no one like you among the gods, Lord, nor any deeds like your deeds.'),
  ('Psalms', 86, 9, 'All nations you have made will come and worship before you, Lord. They shall glorify your name.'),
  ('Psalms', 86, 10, 'For you are great, and do wondrous things. You are God alone.'),
  ('Psalms', 86, 11, 'Teach me your way, LORD. I will walk in your truth. Make my heart undivided to fear your name.'),
  ('Psalms', 86, 12, 'I will praise you, Lord my God, with my whole heart. I will glorify your name forever more.'),
  ('Psalms', 86, 13, 'For your loving kindness is great toward me. You have delivered my soul from the lowest Sheol.'),
  ('Psalms', 86, 14, 'God, the proud have risen up against me. A company of violent men have sought after my soul, and they don’t hold regard for you before them.'),
  ('Psalms', 86, 15, 'But you, Lord, are a merciful and gracious God, slow to anger, and abundant in loving kindness and truth.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 86, 16, 'Turn to me, and have mercy on me! Give your strength to your servant. Save the son of your servant.'),
  ('Psalms', 86, 17, 'Show me a sign of your goodness, that those who hate me may see it, and be shamed, because you, LORD, have helped me, and comforted me.'),
  ('Psalms', 87, 1, 'A Psalm by the sons of Korah; a Song. His foundation is in the holy mountains.'),
  ('Psalms', 87, 2, 'The LORD loves the gates of Zion more than all the dwellings of Jacob.'),
  ('Psalms', 87, 3, 'Glorious things are spoken about you, city of God. Selah.'),
  ('Psalms', 87, 4, 'I will record Rahab and Babylon among those who acknowledge me. Behold, Philistia, Tyre, and also Ethiopia: “This one was born there.”'),
  ('Psalms', 87, 5, 'Yes, of Zion it will be said, “This one and that one was born in her;” the Most High himself will establish her.'),
  ('Psalms', 87, 6, 'The LORD will count, when he writes up the peoples, “This one was born there.” Selah.'),
  ('Psalms', 87, 7, 'Those who sing as well as those who dance say, “All my springs are in you.”'),
  ('Psalms', 88, 1, 'A Song. A Psalm by the sons of Korah. For the Chief Musician. To the tune of “The Suffering of Affliction.” A contemplation by Heman, the Ezrahite. LORD, the God of my salvation, I have cried day and night before you.'),
  ('Psalms', 88, 2, 'Let my prayer enter into your presence. Turn your ear to my cry.'),
  ('Psalms', 88, 3, 'For my soul is full of troubles. My life draws near to Sheol.'),
  ('Psalms', 88, 4, 'I am counted among those who go down into the pit. I am like a man who has no help,'),
  ('Psalms', 88, 5, 'set apart among the dead, like the slain who lie in the grave, whom you remember no more. They are cut off from your hand.'),
  ('Psalms', 88, 6, 'You have laid me in the lowest pit, in the darkest depths.'),
  ('Psalms', 88, 7, 'Your wrath lies heavily on me. You have afflicted me with all your waves. Selah.'),
  ('Psalms', 88, 8, 'You have taken my friends from me. You have made me an abomination to them. I am confined, and I can’t escape.'),
  ('Psalms', 88, 9, 'My eyes are dim from grief. I have called on you daily, LORD. I have spread out my hands to you.'),
  ('Psalms', 88, 10, 'Do you show wonders to the dead? Do the departed spirits rise up and praise you? Selah.'),
  ('Psalms', 88, 11, 'Is your loving kindness declared in the grave? Or your faithfulness in Destruction?'),
  ('Psalms', 88, 12, 'Are your wonders made known in the dark? Or your righteousness in the land of forgetfulness?'),
  ('Psalms', 88, 13, 'But to you, LORD, I have cried. In the morning, my prayer comes before you.'),
  ('Psalms', 88, 14, 'LORD, why do you reject my soul? Why do you hide your face from me?'),
  ('Psalms', 88, 15, 'I am afflicted and ready to die from my youth up. While I suffer your terrors, I am distracted.'),
  ('Psalms', 88, 16, 'Your fierce wrath has gone over me. Your terrors have cut me off.'),
  ('Psalms', 88, 17, 'They came around me like water all day long. They completely engulfed me.'),
  ('Psalms', 88, 18, 'You have put lover and friend far from me, and my friends into darkness.'),
  ('Psalms', 89, 1, 'A contemplation by Ethan, the Ezrahite. I will sing of the loving kindness of the LORD forever. With my mouth, I will make known your faithfulness to all generations.'),
  ('Psalms', 89, 2, 'I indeed declare, “Love stands firm forever. You established the heavens. Your faithfulness is in them.”'),
  ('Psalms', 89, 3, '“I have made a covenant with my chosen one, I have sworn to David, my servant,'),
  ('Psalms', 89, 4, '‘I will establish your offspring forever, and build up your throne to all generations.’” Selah.'),
  ('Psalms', 89, 5, 'The heavens will praise your wonders, LORD, your faithfulness also in the assembly of the holy ones.'),
  ('Psalms', 89, 6, 'For who in the skies can be compared to the LORD? Who among the sons of the heavenly beings is like the LORD,'),
  ('Psalms', 89, 7, 'a very awesome God in the council of the holy ones, to be feared above all those who are around him?'),
  ('Psalms', 89, 8, 'LORD, God of Armies, who is a mighty one, like you? LORD, your faithfulness is around you.'),
  ('Psalms', 89, 9, 'You rule the pride of the sea. When its waves rise up, you calm them.'),
  ('Psalms', 89, 10, 'You have broken Rahab in pieces, like one of the slain. You have scattered your enemies with your mighty arm.'),
  ('Psalms', 89, 11, 'The heavens are yours. The earth also is yours, the world and its fullness. You have founded them.'),
  ('Psalms', 89, 12, 'You have created the north and the south. Tabor and Hermon rejoice in your name.'),
  ('Psalms', 89, 13, 'You have a mighty arm. Your hand is strong, and your right hand is exalted.'),
  ('Psalms', 89, 14, 'Righteousness and justice are the foundation of your throne. Loving kindness and truth go before your face.'),
  ('Psalms', 89, 15, 'Blessed are the people who learn to acclaim you. They walk in the light of your presence, LORD.'),
  ('Psalms', 89, 16, 'In your name they rejoice all day. In your righteousness, they are exalted.'),
  ('Psalms', 89, 17, 'For you are the glory of their strength. In your favor, our horn will be exalted.'),
  ('Psalms', 89, 18, 'For our shield belongs to the LORD, our king to the Holy One of Israel.'),
  ('Psalms', 89, 19, 'Then you spoke in vision to your saints, and said, “I have given strength to the warrior. I have exalted a young man from the people.'),
  ('Psalms', 89, 20, 'I have found David, my servant. I have anointed him with my holy oil,'),
  ('Psalms', 89, 21, 'with whom my hand shall be established. My arm will also strengthen him.'),
  ('Psalms', 89, 22, 'No enemy will tax him. No wicked man will oppress him.'),
  ('Psalms', 89, 23, 'I will beat down his adversaries before him, and strike those who hate him.'),
  ('Psalms', 89, 24, 'But my faithfulness and my loving kindness will be with him. In my name, his horn will be exalted.'),
  ('Psalms', 89, 25, 'I will set his hand also on the sea, and his right hand on the rivers.'),
  ('Psalms', 89, 26, 'He will call to me, ‘You are my Father, my God, and the rock of my salvation!’'),
  ('Psalms', 89, 27, 'I will also appoint him my firstborn, the highest of the kings of the earth.'),
  ('Psalms', 89, 28, 'I will keep my loving kindness for him forever more. My covenant will stand firm with him.'),
  ('Psalms', 89, 29, 'I will also make his offspring endure forever, and his throne as the days of heaven.'),
  ('Psalms', 89, 30, 'If his children forsake my law, and don’t walk in my ordinances;'),
  ('Psalms', 89, 31, 'if they break my statutes, and don’t keep my commandments;'),
  ('Psalms', 89, 32, 'then I will punish their sin with the rod, and their iniquity with stripes.'),
  ('Psalms', 89, 33, 'But I will not completely take my loving kindness from him, nor allow my faithfulness to fail.'),
  ('Psalms', 89, 34, 'I will not break my covenant, nor alter what my lips have uttered.'),
  ('Psalms', 89, 35, 'Once I have sworn by my holiness, I will not lie to David.'),
  ('Psalms', 89, 36, 'His offspring will endure forever, his throne like the sun before me.'),
  ('Psalms', 89, 37, 'It will be established forever like the moon, the faithful witness in the sky.” Selah.'),
  ('Psalms', 89, 38, 'But you have rejected and spurned. You have been angry with your anointed.'),
  ('Psalms', 89, 39, 'You have renounced the covenant of your servant. You have defiled his crown in the dust.'),
  ('Psalms', 89, 40, 'You have broken down all his hedges. You have brought his strongholds to ruin.'),
  ('Psalms', 89, 41, 'All who pass by the way rob him. He has become a reproach to his neighbors.'),
  ('Psalms', 89, 42, 'You have exalted the right hand of his adversaries. You have made all of his enemies rejoice.'),
  ('Psalms', 89, 43, 'Yes, you turn back the edge of his sword, and haven’t supported him in battle.'),
  ('Psalms', 89, 44, 'You have ended his splendor, and thrown his throne down to the ground.'),
  ('Psalms', 89, 45, 'You have shortened the days of his youth. You have covered him with shame. Selah.'),
  ('Psalms', 89, 46, 'How long, LORD? Will you hide yourself forever? Will your wrath burn like fire?'),
  ('Psalms', 89, 47, 'Remember how short my time is, for what vanity you have created all the children of men!'),
  ('Psalms', 89, 48, 'What man is he who shall live and not see death, who shall deliver his soul from the power of Sheol? Selah.'),
  ('Psalms', 89, 49, 'Lord, where are your former loving kindnesses, which you swore to David in your faithfulness?'),
  ('Psalms', 89, 50, 'Remember, Lord, the reproach of your servants, how I bear in my heart the taunts of all the mighty peoples,'),
  ('Psalms', 89, 51, 'With which your enemies have mocked, LORD, with which they have mocked the footsteps of your anointed one.'),
  ('Psalms', 89, 52, 'Blessed be the LORD forever more. Amen, and Amen.'),
  ('Psalms', 90, 1, 'A Prayer by Moses, the man of God. Lord, you have been our dwelling place for all generations.'),
  ('Psalms', 90, 2, 'Before the mountains were born, before you had formed the earth and the world, even from everlasting to everlasting, you are God.'),
  ('Psalms', 90, 3, 'You turn man to destruction, saying, “Return, you children of men.”'),
  ('Psalms', 90, 4, 'For a thousand years in your sight are just like yesterday when it is past, like a watch in the night.'),
  ('Psalms', 90, 5, 'You sweep them away as they sleep. In the morning they sprout like new grass.'),
  ('Psalms', 90, 6, 'In the morning it sprouts and springs up. By evening, it is withered and dry.'),
  ('Psalms', 90, 7, 'For we are consumed in your anger. We are troubled in your wrath.'),
  ('Psalms', 90, 8, 'You have set our iniquities before you, our secret sins in the light of your presence.'),
  ('Psalms', 90, 9, 'For all our days have passed away in your wrath. We bring our years to an end as a sigh.'),
  ('Psalms', 90, 10, 'The days of our years are seventy, or even by reason of strength eighty years; yet their pride is but labor and sorrow, for it passes quickly, and we fly away.'),
  ('Psalms', 90, 11, 'Who knows the power of your anger, your wrath according to the fear that is due to you?'),
  ('Psalms', 90, 12, 'So teach us to count our days, that we may gain a heart of wisdom.'),
  ('Psalms', 90, 13, 'Relent, LORD! How long? Have compassion on your servants!'),
  ('Psalms', 90, 14, 'Satisfy us in the morning with your loving kindness, that we may rejoice and be glad all our days.'),
  ('Psalms', 90, 15, 'Make us glad for as many days as you have afflicted us, for as many years as we have seen evil.'),
  ('Psalms', 90, 16, 'Let your work appear to your servants, your glory to their children.'),
  ('Psalms', 90, 17, 'Let the favor of the Lord our God be on us. Establish the work of our hands for us. Yes, establish the work of our hands.'),
  ('Psalms', 91, 1, 'He who dwells in the secret place of the Most High will rest in the shadow of the Almighty.'),
  ('Psalms', 91, 2, 'I will say of the LORD, “He is my refuge and my fortress; my God, in whom I trust.”'),
  ('Psalms', 91, 3, 'For he will deliver you from the snare of the fowler, and from the deadly pestilence.'),
  ('Psalms', 91, 4, 'He will cover you with his feathers. Under his wings you will take refuge. His faithfulness is your shield and rampart.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 91, 5, 'You shall not be afraid of the terror by night, nor of the arrow that flies by day,'),
  ('Psalms', 91, 6, 'nor of the pestilence that walks in darkness, nor of the destruction that wastes at noonday.'),
  ('Psalms', 91, 7, 'A thousand may fall at your side, and ten thousand at your right hand; but it will not come near you.'),
  ('Psalms', 91, 8, 'You will only look with your eyes, and see the recompense of the wicked.'),
  ('Psalms', 91, 9, 'Because you have made the LORD your refuge, and the Most High your dwelling place,'),
  ('Psalms', 91, 10, 'no evil shall happen to you, neither shall any plague come near your dwelling.'),
  ('Psalms', 91, 11, 'For he will put his angels in charge of you, to guard you in all your ways.'),
  ('Psalms', 91, 12, 'They will bear you up in their hands, so that you won’t dash your foot against a stone.'),
  ('Psalms', 91, 13, 'You will tread on the lion and cobra. You will trample the young lion and the serpent underfoot.'),
  ('Psalms', 91, 14, '“Because he has set his love on me, therefore I will deliver him. I will set him on high, because he has known my name.'),
  ('Psalms', 91, 15, 'He will call on me, and I will answer him. I will be with him in trouble. I will deliver him, and honor him.'),
  ('Psalms', 91, 16, 'I will satisfy him with long life, and show him my salvation.”'),
  ('Psalms', 92, 1, 'A Psalm. A song for the Sabbath day. It is a good thing to give thanks to the LORD, to sing praises to your name, Most High,'),
  ('Psalms', 92, 2, 'to proclaim your loving kindness in the morning, and your faithfulness every night,'),
  ('Psalms', 92, 3, 'with the ten-stringed lute, with the harp, and with the melody of the lyre.'),
  ('Psalms', 92, 4, 'For you, LORD, have made me glad through your work. I will triumph in the works of your hands.'),
  ('Psalms', 92, 5, 'How great are your works, LORD! Your thoughts are very deep.'),
  ('Psalms', 92, 6, 'A senseless man doesn’t know, neither does a fool understand this:'),
  ('Psalms', 92, 7, 'though the wicked spring up as the grass, and all the evildoers flourish, they will be destroyed forever.'),
  ('Psalms', 92, 8, 'But you, LORD, are on high forever more.'),
  ('Psalms', 92, 9, 'For behold, your enemies, LORD, for behold, your enemies shall perish. All the evildoers will be scattered.'),
  ('Psalms', 92, 10, 'But you have exalted my horn like that of the wild ox. I am anointed with fresh oil.'),
  ('Psalms', 92, 11, 'My eye has also seen my enemies. My ears have heard of the wicked enemies who rise up against me.'),
  ('Psalms', 92, 12, 'The righteous shall flourish like the palm tree. He will grow like a cedar in Lebanon.'),
  ('Psalms', 92, 13, 'They are planted in the LORD’s house. They will flourish in our God’s courts.'),
  ('Psalms', 92, 14, 'They will still produce fruit in old age. They will be full of sap and green,'),
  ('Psalms', 92, 15, 'to show that the LORD is upright. He is my rock, and there is no unrighteousness in him.'),
  ('Psalms', 93, 1, 'The LORD reigns! He is clothed with majesty! The LORD is armed with strength. The world also is established. It can’t be moved.'),
  ('Psalms', 93, 2, 'Your throne is established from long ago. You are from everlasting.'),
  ('Psalms', 93, 3, 'The floods have lifted up, LORD, the floods have lifted up their voice. The floods lift up their waves.'),
  ('Psalms', 93, 4, 'Above the voices of many waters, the mighty breakers of the sea, the LORD on high is mighty.'),
  ('Psalms', 93, 5, 'Your statutes stand firm. Holiness adorns your house, LORD, forever more.'),
  ('Psalms', 94, 1, 'LORD, you God to whom vengeance belongs, you God to whom vengeance belongs, shine out.'),
  ('Psalms', 94, 2, 'Rise up, you judge of the earth. Pay back the proud what they deserve.'),
  ('Psalms', 94, 3, 'LORD, how long will the wicked, how long will the wicked triumph?'),
  ('Psalms', 94, 4, 'They pour out arrogant words. All the evildoers boast.'),
  ('Psalms', 94, 5, 'They break your people in pieces, LORD, and afflict your heritage.'),
  ('Psalms', 94, 6, 'They kill the widow and the alien, and murder the fatherless.'),
  ('Psalms', 94, 7, 'They say, “The LORD will not see, neither will Jacob’s God consider.”'),
  ('Psalms', 94, 8, 'Consider, you senseless among the people; you fools, when will you be wise?'),
  ('Psalms', 94, 9, 'He who implanted the ear, won’t he hear? He who formed the eye, won’t he see?'),
  ('Psalms', 94, 10, 'He who disciplines the nations, won’t he punish? He who teaches man knows.'),
  ('Psalms', 94, 11, 'The LORD knows the thoughts of man, that they are futile.'),
  ('Psalms', 94, 12, 'Blessed is the man whom you discipline, LORD, and teach out of your law,'),
  ('Psalms', 94, 13, 'that you may give him rest from the days of adversity, until the pit is dug for the wicked.'),
  ('Psalms', 94, 14, 'For the LORD won’t reject his people, neither will he forsake his inheritance.'),
  ('Psalms', 94, 15, 'For judgment will return to righteousness. All the upright in heart shall follow it.'),
  ('Psalms', 94, 16, 'Who will rise up for me against the wicked? Who will stand up for me against the evildoers?'),
  ('Psalms', 94, 17, 'Unless the LORD had been my help, my soul would have soon lived in silence.'),
  ('Psalms', 94, 18, 'When I said, “My foot is slipping!” Your loving kindness, LORD, held me up.'),
  ('Psalms', 94, 19, 'In the multitude of my thoughts within me, your comforts delight my soul.'),
  ('Psalms', 94, 20, 'Shall the throne of wickedness have fellowship with you, which brings about mischief by statute?'),
  ('Psalms', 94, 21, 'They gather themselves together against the soul of the righteous, and condemn the innocent blood.'),
  ('Psalms', 94, 22, 'But the LORD has been my high tower, my God, the rock of my refuge.'),
  ('Psalms', 94, 23, 'He has brought on them their own iniquity, and will cut them off in their own wickedness. The LORD, our God, will cut them off.'),
  ('Psalms', 95, 1, 'Oh come, let’s sing to the LORD. Let’s shout aloud to the rock of our salvation!'),
  ('Psalms', 95, 2, 'Let’s come before his presence with thanksgiving. Let’s extol him with songs!'),
  ('Psalms', 95, 3, 'For the LORD is a great God, a great King above all gods.'),
  ('Psalms', 95, 4, 'In his hand are the deep places of the earth. The heights of the mountains are also his.'),
  ('Psalms', 95, 5, 'The sea is his, and he made it. His hands formed the dry land.'),
  ('Psalms', 95, 6, 'Oh come, let’s worship and bow down. Let’s kneel before the LORD, our Maker,'),
  ('Psalms', 95, 7, 'for he is our God. We are the people of his pasture, and the sheep in his care. Today, oh that you would hear his voice!'),
  ('Psalms', 95, 8, 'Don’t harden your heart, as at Meribah, as in the day of Massah in the wilderness,'),
  ('Psalms', 95, 9, 'when your fathers tempted me, tested me, and saw my work.'),
  ('Psalms', 95, 10, 'Forty long years I was grieved with that generation, and said, “They are a people who err in their heart. They have not known my ways.”'),
  ('Psalms', 95, 11, 'Therefore I swore in my wrath, “They won’t enter into my rest.”'),
  ('Psalms', 96, 1, 'Sing to the LORD a new song! Sing to the LORD, all the earth.'),
  ('Psalms', 96, 2, 'Sing to the LORD! Bless his name! Proclaim his salvation from day to day!'),
  ('Psalms', 96, 3, 'Declare his glory among the nations, his marvelous works among all the peoples.'),
  ('Psalms', 96, 4, 'For the LORD is great, and greatly to be praised! He is to be feared above all gods.'),
  ('Psalms', 96, 5, 'For all the gods of the peoples are idols, but the LORD made the heavens.'),
  ('Psalms', 96, 6, 'Honor and majesty are before him. Strength and beauty are in his sanctuary.'),
  ('Psalms', 96, 7, 'Ascribe to the LORD, you families of nations, ascribe to the LORD glory and strength.'),
  ('Psalms', 96, 8, 'Ascribe to the LORD the glory due to his name. Bring an offering, and come into his courts.'),
  ('Psalms', 96, 9, 'Worship the LORD in holy array. Tremble before him, all the earth.'),
  ('Psalms', 96, 10, 'Say among the nations, “The LORD reigns.” The world is also established. It can’t be moved. He will judge the peoples with equity.'),
  ('Psalms', 96, 11, 'Let the heavens be glad, and let the earth rejoice. Let the sea roar, and its fullness!'),
  ('Psalms', 96, 12, 'Let the field and all that is in it exult! Then all the trees of the woods shall sing for joy'),
  ('Psalms', 96, 13, 'before the LORD; for he comes, for he comes to judge the earth. He will judge the world with righteousness, the peoples with his truth.'),
  ('Psalms', 97, 1, 'The LORD reigns! Let the earth rejoice! Let the multitude of islands be glad!'),
  ('Psalms', 97, 2, 'Clouds and darkness are around him. Righteousness and justice are the foundation of his throne.'),
  ('Psalms', 97, 3, 'A fire goes before him, and burns up his adversaries on every side.'),
  ('Psalms', 97, 4, 'His lightning lights up the world. The earth sees, and trembles.'),
  ('Psalms', 97, 5, 'The mountains melt like wax at the presence of the LORD, at the presence of the Lord of the whole earth.'),
  ('Psalms', 97, 6, 'The heavens declare his righteousness. All the peoples have seen his glory.'),
  ('Psalms', 97, 7, 'Let all them be shamed who serve engraved images, who boast in their idols. Worship him, all you gods!'),
  ('Psalms', 97, 8, 'Zion heard and was glad. The daughters of Judah rejoiced because of your judgments, LORD.'),
  ('Psalms', 97, 9, 'For you, LORD, are most high above all the earth. You are exalted far above all gods.'),
  ('Psalms', 97, 10, 'You who love the LORD, hate evil! He preserves the souls of his saints. He delivers them out of the hand of the wicked.'),
  ('Psalms', 97, 11, 'Light is sown for the righteous, and gladness for the upright in heart.'),
  ('Psalms', 97, 12, 'Be glad in the LORD, you righteous people! Give thanks to his holy Name.'),
  ('Psalms', 98, 1, 'A Psalm. Sing to the LORD a new song, for he has done marvelous things! His right hand and his holy arm have worked salvation for him.'),
  ('Psalms', 98, 2, 'The LORD has made known his salvation. He has openly shown his righteousness in the sight of the nations.'),
  ('Psalms', 98, 3, 'He has remembered his loving kindness and his faithfulness toward the house of Israel. All the ends of the earth have seen the salvation of our God.'),
  ('Psalms', 98, 4, 'Make a joyful noise to the LORD, all the earth! Burst out and sing for joy, yes, sing praises!'),
  ('Psalms', 98, 5, 'Sing praises to the LORD with the harp, with the harp and the voice of melody.'),
  ('Psalms', 98, 6, 'With trumpets and sound of the ram’s horn, make a joyful noise before the King, the LORD.'),
  ('Psalms', 98, 7, 'Let the sea roar with its fullness; the world, and those who dwell therein.'),
  ('Psalms', 98, 8, 'Let the rivers clap their hands. Let the mountains sing for joy together.'),
  ('Psalms', 98, 9, 'Let them sing before the LORD, for he comes to judge the earth. He will judge the world with righteousness, and the peoples with equity.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 99, 1, 'The LORD reigns! Let the peoples tremble. He sits enthroned among the cherubim. Let the earth be moved.'),
  ('Psalms', 99, 2, 'The LORD is great in Zion. He is high above all the peoples.'),
  ('Psalms', 99, 3, 'Let them praise your great and awesome name. He is Holy!'),
  ('Psalms', 99, 4, 'The King’s strength also loves justice. You establish equity. You execute justice and righteousness in Jacob.'),
  ('Psalms', 99, 5, 'Exalt the LORD our God. Worship at his footstool. He is Holy!'),
  ('Psalms', 99, 6, 'Moses and Aaron were among his priests, Samuel was among those who call on his name. They called on the LORD, and he answered them.'),
  ('Psalms', 99, 7, 'He spoke to them in the pillar of cloud. They kept his testimonies, the statute that he gave them.'),
  ('Psalms', 99, 8, 'You answered them, LORD our God. You are a God who forgave them, although you took vengeance for their doings.'),
  ('Psalms', 99, 9, 'Exalt the LORD, our God. Worship at his holy hill, for the LORD, our God, is holy!'),
  ('Psalms', 100, 1, 'A Psalm of thanksgiving. Shout for joy to the LORD, all you lands!'),
  ('Psalms', 100, 2, 'Serve the LORD with gladness. Come before his presence with singing.'),
  ('Psalms', 100, 3, 'Know that the LORD, he is God. It is he who has made us, and we are his. We are his people, and the sheep of his pasture.'),
  ('Psalms', 100, 4, 'Enter into his gates with thanksgiving, and into his courts with praise. Give thanks to him, and bless his name.'),
  ('Psalms', 100, 5, 'For the LORD is good. His loving kindness endures forever, his faithfulness to all generations.'),
  ('Psalms', 101, 1, 'A Psalm by David. I will sing of loving kindness and justice. To you, LORD, I will sing praises.'),
  ('Psalms', 101, 2, 'I will be careful to live a blameless life. When will you come to me? I will walk within my house with a blameless heart.'),
  ('Psalms', 101, 3, 'I will set no vile thing before my eyes. I hate the deeds of faithless men. They will not cling to me.'),
  ('Psalms', 101, 4, 'A perverse heart will be far from me. I will have nothing to do with evil.'),
  ('Psalms', 101, 5, 'I will silence whoever secretly slanders his neighbor. I won’t tolerate one who is arrogant and conceited.'),
  ('Psalms', 101, 6, 'My eyes will be on the faithful of the land, that they may dwell with me. He who walks in a perfect way, he will serve me.'),
  ('Psalms', 101, 7, 'He who practices deceit won’t dwell within my house. He who speaks falsehood won’t be established before my eyes.'),
  ('Psalms', 101, 8, 'Morning by morning, I will destroy all the wicked of the land, to cut off all the workers of iniquity from the LORD’s city.'),
  ('Psalms', 102, 1, 'A Prayer of the afflicted, when he is overwhelmed and pours out his complaint before the LORD. Hear my prayer, LORD! Let my cry come to you.'),
  ('Psalms', 102, 2, 'Don’t hide your face from me in the day of my distress. Turn your ear to me. Answer me quickly in the day when I call.'),
  ('Psalms', 102, 3, 'For my days consume away like smoke. My bones are burned as a torch.'),
  ('Psalms', 102, 4, 'My heart is blighted like grass, and withered, for I forget to eat my bread.'),
  ('Psalms', 102, 5, 'By reason of the voice of my groaning, my bones stick to my skin.'),
  ('Psalms', 102, 6, 'I am like a pelican of the wilderness. I have become as an owl of the waste places.'),
  ('Psalms', 102, 7, 'I watch, and have become like a sparrow that is alone on the housetop.'),
  ('Psalms', 102, 8, 'My enemies reproach me all day. Those who are mad at me use my name as a curse.'),
  ('Psalms', 102, 9, 'For I have eaten ashes like bread, and mixed my drink with tears,'),
  ('Psalms', 102, 10, 'because of your indignation and your wrath; for you have taken me up and thrown me away.'),
  ('Psalms', 102, 11, 'My days are like a long shadow. I have withered like grass.'),
  ('Psalms', 102, 12, 'But you, LORD, will remain forever; your renown endures to all generations.'),
  ('Psalms', 102, 13, 'You will arise and have mercy on Zion, for it is time to have pity on her. Yes, the set time has come.'),
  ('Psalms', 102, 14, 'For your servants take pleasure in her stones, and have pity on her dust.'),
  ('Psalms', 102, 15, 'So the nations will fear the LORD’s name, all the kings of the earth your glory.'),
  ('Psalms', 102, 16, 'For the LORD has built up Zion. He has appeared in his glory.'),
  ('Psalms', 102, 17, 'He has responded to the prayer of the destitute, and has not despised their prayer.'),
  ('Psalms', 102, 18, 'This will be written for the generation to come. A people which will be created will praise the LORD,'),
  ('Psalms', 102, 19, 'for he has looked down from the height of his sanctuary. From heaven, the LORD saw the earth,'),
  ('Psalms', 102, 20, 'to hear the groans of the prisoner, to free those who are condemned to death,'),
  ('Psalms', 102, 21, 'that men may declare the LORD’s name in Zion, and his praise in Jerusalem,'),
  ('Psalms', 102, 22, 'when the peoples are gathered together, the kingdoms, to serve the LORD.'),
  ('Psalms', 102, 23, 'He weakened my strength along the course. He shortened my days.'),
  ('Psalms', 102, 24, 'I said, “My God, don’t take me away in the middle of my days. Your years are throughout all generations.'),
  ('Psalms', 102, 25, 'Of old, you laid the foundation of the earth. The heavens are the work of your hands.'),
  ('Psalms', 102, 26, 'They will perish, but you will endure. Yes, all of them will wear out like a garment. You will change them like a cloak, and they will be changed.'),
  ('Psalms', 102, 27, 'But you are the same. Your years will have no end.'),
  ('Psalms', 102, 28, 'The children of your servants will continue. Their offspring will be established before you.”'),
  ('Psalms', 103, 1, 'By David. Praise the LORD, my soul! All that is within me, praise his holy name!'),
  ('Psalms', 103, 2, 'Praise the LORD, my soul, and don’t forget all his benefits,'),
  ('Psalms', 103, 3, 'who forgives all your sins, who heals all your diseases,'),
  ('Psalms', 103, 4, 'who redeems your life from destruction, who crowns you with loving kindness and tender mercies,'),
  ('Psalms', 103, 5, 'who satisfies your desire with good things, so that your youth is renewed like the eagle’s.'),
  ('Psalms', 103, 6, 'The LORD executes righteous acts, and justice for all who are oppressed.'),
  ('Psalms', 103, 7, 'He made known his ways to Moses, his deeds to the children of Israel.'),
  ('Psalms', 103, 8, 'The LORD is merciful and gracious, slow to anger, and abundant in loving kindness.'),
  ('Psalms', 103, 9, 'He will not always accuse; neither will he stay angry forever.'),
  ('Psalms', 103, 10, 'He has not dealt with us according to our sins, nor repaid us for our iniquities.'),
  ('Psalms', 103, 11, 'For as the heavens are high above the earth, so great is his loving kindness toward those who fear him.'),
  ('Psalms', 103, 12, 'As far as the east is from the west, so far has he removed our transgressions from us.'),
  ('Psalms', 103, 13, 'Like a father has compassion on his children, so the LORD has compassion on those who fear him.'),
  ('Psalms', 103, 14, 'For he knows how we are made. He remembers that we are dust.'),
  ('Psalms', 103, 15, 'As for man, his days are like grass. As a flower of the field, so he flourishes.'),
  ('Psalms', 103, 16, 'For the wind passes over it, and it is gone. Its place remembers it no more.'),
  ('Psalms', 103, 17, 'But the LORD’s loving kindness is from everlasting to everlasting with those who fear him, his righteousness to children’s children,'),
  ('Psalms', 103, 18, 'to those who keep his covenant, to those who remember to obey his precepts.'),
  ('Psalms', 103, 19, 'The LORD has established his throne in the heavens. His kingdom rules over all.'),
  ('Psalms', 103, 20, 'Praise the LORD, you angels of his, who are mighty in strength, who fulfill his word, obeying the voice of his word.'),
  ('Psalms', 103, 21, 'Praise the LORD, all you armies of his, you servants of his, who do his pleasure.'),
  ('Psalms', 103, 22, 'Praise the LORD, all you works of his, in all places of his dominion. Praise the LORD, my soul!'),
  ('Psalms', 104, 1, 'Bless the LORD, my soul. The LORD, my God, you are very great. You are clothed with honor and majesty.'),
  ('Psalms', 104, 2, 'He covers himself with light as with a garment. He stretches out the heavens like a curtain.'),
  ('Psalms', 104, 3, 'He lays the beams of his rooms in the waters. He makes the clouds his chariot. He walks on the wings of the wind.'),
  ('Psalms', 104, 4, 'He makes his messengers winds, and his servants flames of fire.'),
  ('Psalms', 104, 5, 'He laid the foundations of the earth, that it should not be moved forever.'),
  ('Psalms', 104, 6, 'You covered it with the deep as with a cloak. The waters stood above the mountains.'),
  ('Psalms', 104, 7, 'At your rebuke they fled. At the voice of your thunder they hurried away.'),
  ('Psalms', 104, 8, 'The mountains rose, the valleys sank down, to the place which you had assigned to them.'),
  ('Psalms', 104, 9, 'You have set a boundary that they may not pass over, that they don’t turn again to cover the earth.'),
  ('Psalms', 104, 10, 'He sends springs into the valleys. They run among the mountains.'),
  ('Psalms', 104, 11, 'They give drink to every animal of the field. The wild donkeys quench their thirst.'),
  ('Psalms', 104, 12, 'The birds of the sky nest by them. They sing among the branches.'),
  ('Psalms', 104, 13, 'He waters the mountains from his rooms. The earth is filled with the fruit of your works.'),
  ('Psalms', 104, 14, 'He causes the grass to grow for the livestock, and plants for man to cultivate, that he may produce food out of the earth:'),
  ('Psalms', 104, 15, 'wine that makes the heart of man glad, oil to make his face to shine, and bread that strengthens man’s heart.'),
  ('Psalms', 104, 16, 'The LORD’s trees are well watered, the cedars of Lebanon, which he has planted,'),
  ('Psalms', 104, 17, 'where the birds make their nests. The stork makes its home in the cypress trees.'),
  ('Psalms', 104, 18, 'The high mountains are for the wild goats. The rocks are a refuge for the rock badgers.'),
  ('Psalms', 104, 19, 'He appointed the moon for seasons. The sun knows when to set.'),
  ('Psalms', 104, 20, 'You make darkness, and it is night, in which all the animals of the forest prowl.'),
  ('Psalms', 104, 21, 'The young lions roar after their prey, and seek their food from God.'),
  ('Psalms', 104, 22, 'The sun rises, and they steal away, and lie down in their dens.'),
  ('Psalms', 104, 23, 'Man goes out to his work, to his labor until the evening.'),
  ('Psalms', 104, 24, 'LORD, how many are your works! In wisdom, you have made them all. The earth is full of your riches.'),
  ('Psalms', 104, 25, 'There is the sea, great and wide, in which are innumerable living things, both small and large animals.'),
  ('Psalms', 104, 26, 'There the ships go, and leviathan, whom you formed to play there.'),
  ('Psalms', 104, 27, 'These all wait for you, that you may give them their food in due season.'),
  ('Psalms', 104, 28, 'You give to them; they gather. You open your hand; they are satisfied with good.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 104, 29, 'You hide your face; they are troubled. You take away their breath; they die and return to the dust.'),
  ('Psalms', 104, 30, 'You send out your Spirit and they are created. You renew the face of the ground.'),
  ('Psalms', 104, 31, 'Let the LORD’s glory endure forever. Let the LORD rejoice in his works.'),
  ('Psalms', 104, 32, 'He looks at the earth, and it trembles. He touches the mountains, and they smoke.'),
  ('Psalms', 104, 33, 'I will sing to the LORD as long as I live. I will sing praise to my God while I have any being.'),
  ('Psalms', 104, 34, 'Let my meditation be sweet to him. I will rejoice in the LORD.'),
  ('Psalms', 104, 35, 'Let sinners be consumed out of the earth. Let the wicked be no more. Bless the LORD, my soul. Praise the LORD!'),
  ('Psalms', 105, 1, 'Give thanks to the LORD! Call on his name! Make his doings known among the peoples.'),
  ('Psalms', 105, 2, 'Sing to him, sing praises to him! Tell of all his marvelous works.'),
  ('Psalms', 105, 3, 'Glory in his holy name. Let the heart of those who seek the LORD rejoice.'),
  ('Psalms', 105, 4, 'Seek the LORD and his strength. Seek his face forever more.'),
  ('Psalms', 105, 5, 'Remember his marvelous works that he has done: his wonders, and the judgments of his mouth,'),
  ('Psalms', 105, 6, 'you offspring of Abraham, his servant, you children of Jacob, his chosen ones.'),
  ('Psalms', 105, 7, 'He is the LORD, our God. His judgments are in all the earth.'),
  ('Psalms', 105, 8, 'He has remembered his covenant forever, the word which he commanded to a thousand generations,'),
  ('Psalms', 105, 9, 'the covenant which he made with Abraham, his oath to Isaac,'),
  ('Psalms', 105, 10, 'and confirmed it to Jacob for a statute; to Israel for an everlasting covenant,'),
  ('Psalms', 105, 11, 'saying, “To you I will give the land of Canaan, the lot of your inheritance,”'),
  ('Psalms', 105, 12, 'when they were but a few men in number, yes, very few, and foreigners in it.'),
  ('Psalms', 105, 13, 'They went about from nation to nation, from one kingdom to another people.'),
  ('Psalms', 105, 14, 'He allowed no one to do them wrong. Yes, he reproved kings for their sakes,'),
  ('Psalms', 105, 15, '“Don’t touch my anointed ones! Do my prophets no harm!”'),
  ('Psalms', 105, 16, 'He called for a famine on the land. He destroyed the food supplies.'),
  ('Psalms', 105, 17, 'He sent a man before them. Joseph was sold for a slave.'),
  ('Psalms', 105, 18, 'They bruised his feet with shackles. His neck was locked in irons,'),
  ('Psalms', 105, 19, 'until the time that his word happened, and the LORD’s word proved him true.'),
  ('Psalms', 105, 20, 'The king sent and freed him, even the ruler of peoples, and let him go free.'),
  ('Psalms', 105, 21, 'He made him lord of his house, and ruler of all of his possessions,'),
  ('Psalms', 105, 22, 'to discipline his princes at his pleasure, and to teach his elders wisdom.'),
  ('Psalms', 105, 23, 'Israel also came into Egypt. Jacob lived in the land of Ham.'),
  ('Psalms', 105, 24, 'He increased his people greatly, and made them stronger than their adversaries.'),
  ('Psalms', 105, 25, 'He turned their heart to hate his people, to conspire against his servants.'),
  ('Psalms', 105, 26, 'He sent Moses, his servant, and Aaron, whom he had chosen.'),
  ('Psalms', 105, 27, 'They performed miracles among them, and wonders in the land of Ham.'),
  ('Psalms', 105, 28, 'He sent darkness, and made it dark. They didn’t rebel against his words.'),
  ('Psalms', 105, 29, 'He turned their waters into blood, and killed their fish.'),
  ('Psalms', 105, 30, 'Their land swarmed with frogs, even in the rooms of their kings.'),
  ('Psalms', 105, 31, 'He spoke, and swarms of flies came, and lice in all their borders.'),
  ('Psalms', 105, 32, 'He gave them hail for rain, with lightning in their land.'),
  ('Psalms', 105, 33, 'He struck their vines and also their fig trees, and shattered the trees of their country.'),
  ('Psalms', 105, 34, 'He spoke, and the locusts came with the grasshoppers, without number.'),
  ('Psalms', 105, 35, 'They ate up every plant in their land, and ate up the fruit of their ground.'),
  ('Psalms', 105, 36, 'He struck also all the firstborn in their land, the first fruits of all their manhood.'),
  ('Psalms', 105, 37, 'He brought them out with silver and gold. There was not one feeble person among his tribes.'),
  ('Psalms', 105, 38, 'Egypt was glad when they departed, for the fear of them had fallen on them.'),
  ('Psalms', 105, 39, 'He spread a cloud for a covering, fire to give light in the night.'),
  ('Psalms', 105, 40, 'They asked, and he brought quails, and satisfied them with the bread of the sky.'),
  ('Psalms', 105, 41, 'He opened the rock, and waters gushed out. They ran as a river in the dry places.'),
  ('Psalms', 105, 42, 'For he remembered his holy word, and Abraham, his servant.'),
  ('Psalms', 105, 43, 'He brought his people out with joy, his chosen with singing.'),
  ('Psalms', 105, 44, 'He gave them the lands of the nations. They took the labor of the peoples in possession,'),
  ('Psalms', 105, 45, 'that they might keep his statutes, and observe his laws. Praise the LORD!'),
  ('Psalms', 106, 1, 'Praise the LORD! Give thanks to the LORD, for he is good, for his loving kindness endures forever.'),
  ('Psalms', 106, 2, 'Who can utter the mighty acts of the LORD, or fully declare all his praise?'),
  ('Psalms', 106, 3, 'Blessed are those who keep justice. Blessed is one who does what is right at all times.'),
  ('Psalms', 106, 4, 'Remember me, LORD, with the favor that you show to your people. Visit me with your salvation,'),
  ('Psalms', 106, 5, 'that I may see the prosperity of your chosen, that I may rejoice in the gladness of your nation, that I may glory with your inheritance.'),
  ('Psalms', 106, 6, 'We have sinned with our fathers. We have committed iniquity. We have done wickedly.'),
  ('Psalms', 106, 7, 'Our fathers didn’t understand your wonders in Egypt. They didn’t remember the multitude of your loving kindnesses, but were rebellious at the sea, even at the Red Sea.'),
  ('Psalms', 106, 8, 'Nevertheless he saved them for his name’s sake, that he might make his mighty power known.'),
  ('Psalms', 106, 9, 'He rebuked the Red Sea also, and it was dried up; so he led them through the depths, as through a desert.'),
  ('Psalms', 106, 10, 'He saved them from the hand of him who hated them, and redeemed them from the hand of the enemy.'),
  ('Psalms', 106, 11, 'The waters covered their adversaries. There was not one of them left.'),
  ('Psalms', 106, 12, 'Then they believed his words. They sang his praise.'),
  ('Psalms', 106, 13, 'They soon forgot his works. They didn’t wait for his counsel,'),
  ('Psalms', 106, 14, 'but gave in to craving in the desert, and tested God in the wasteland.'),
  ('Psalms', 106, 15, 'He gave them their request, but sent leanness into their soul.'),
  ('Psalms', 106, 16, 'They envied Moses also in the camp, and Aaron, the LORD’s saint.'),
  ('Psalms', 106, 17, 'The earth opened and swallowed up Dathan, and covered the company of Abiram.'),
  ('Psalms', 106, 18, 'A fire was kindled in their company. The flame burned up the wicked.'),
  ('Psalms', 106, 19, 'They made a calf in Horeb, and worshiped a molten image.'),
  ('Psalms', 106, 20, 'Thus they exchanged their glory for an image of a bull that eats grass.'),
  ('Psalms', 106, 21, 'They forgot God, their Savior, who had done great things in Egypt,'),
  ('Psalms', 106, 22, 'wondrous works in the land of Ham, and awesome things by the Red Sea.'),
  ('Psalms', 106, 23, 'Therefore he said that he would destroy them, had Moses, his chosen, not stood before him in the breach, to turn away his wrath, so that he wouldn’t destroy them.'),
  ('Psalms', 106, 24, 'Yes, they despised the pleasant land. They didn’t believe his word,'),
  ('Psalms', 106, 25, 'but murmured in their tents, and didn’t listen to the LORD’s voice.'),
  ('Psalms', 106, 26, 'Therefore he swore to them that he would overthrow them in the wilderness,'),
  ('Psalms', 106, 27, 'that he would overthrow their offspring among the nations, and scatter them in the lands.'),
  ('Psalms', 106, 28, 'They joined themselves also to Baal Peor, and ate the sacrifices of the dead.'),
  ('Psalms', 106, 29, 'Thus they provoked him to anger with their deeds. The plague broke in on them.'),
  ('Psalms', 106, 30, 'Then Phinehas stood up and executed judgment, so the plague was stopped.'),
  ('Psalms', 106, 31, 'That was credited to him for righteousness, for all generations to come.'),
  ('Psalms', 106, 32, 'They angered him also at the waters of Meribah, so that Moses was troubled for their sakes;'),
  ('Psalms', 106, 33, 'because they were rebellious against his spirit, he spoke rashly with his lips.'),
  ('Psalms', 106, 34, 'They didn’t destroy the peoples, as the LORD commanded them,'),
  ('Psalms', 106, 35, 'but mixed themselves with the nations, and learned their works.'),
  ('Psalms', 106, 36, 'They served their idols, which became a snare to them.'),
  ('Psalms', 106, 37, 'Yes, they sacrificed their sons and their daughters to demons.'),
  ('Psalms', 106, 38, 'They shed innocent blood, even the blood of their sons and of their daughters, whom they sacrificed to the idols of Canaan. The land was polluted with blood.'),
  ('Psalms', 106, 39, 'Thus they were defiled with their works, and prostituted themselves in their deeds.'),
  ('Psalms', 106, 40, 'Therefore the LORD burned with anger against his people. He abhorred his inheritance.'),
  ('Psalms', 106, 41, 'He gave them into the hand of the nations. Those who hated them ruled over them.'),
  ('Psalms', 106, 42, 'Their enemies also oppressed them. They were brought into subjection under their hand.'),
  ('Psalms', 106, 43, 'He rescued them many times, but they were rebellious in their counsel, and were brought low in their iniquity.'),
  ('Psalms', 106, 44, 'Nevertheless he regarded their distress, when he heard their cry.'),
  ('Psalms', 106, 45, 'He remembered for them his covenant, and repented according to the multitude of his loving kindnesses.'),
  ('Psalms', 106, 46, 'He made them also to be pitied by all those who carried them captive.'),
  ('Psalms', 106, 47, 'Save us, LORD, our God, gather us from among the nations, to give thanks to your holy name, to triumph in your praise!'),
  ('Psalms', 106, 48, 'Blessed be the LORD, the God of Israel, from everlasting even to everlasting! Let all the people say, “Amen.” Praise the LORD!');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 107, 1, 'Give thanks to the LORD, for he is good, for his loving kindness endures forever.'),
  ('Psalms', 107, 2, 'Let the redeemed by the LORD say so, whom he has redeemed from the hand of the adversary,'),
  ('Psalms', 107, 3, 'and gathered out of the lands, from the east and from the west, from the north and from the south.'),
  ('Psalms', 107, 4, 'They wandered in the wilderness in a desert way. They found no city to live in.'),
  ('Psalms', 107, 5, 'Hungry and thirsty, their soul fainted in them.'),
  ('Psalms', 107, 6, 'Then they cried to the LORD in their trouble, and he delivered them out of their distresses.'),
  ('Psalms', 107, 7, 'He led them also by a straight way, that they might go to a city to live in.'),
  ('Psalms', 107, 8, 'Let them praise the LORD for his loving kindness, for his wonderful deeds to the children of men!'),
  ('Psalms', 107, 9, 'For he satisfies the longing soul. He fills the hungry soul with good.'),
  ('Psalms', 107, 10, 'Some sat in darkness and in the shadow of death, being bound in affliction and iron,'),
  ('Psalms', 107, 11, 'because they rebelled against the words of God, and condemned the counsel of the Most High.'),
  ('Psalms', 107, 12, 'Therefore he brought down their heart with labor. They fell down, and there was no one to help.'),
  ('Psalms', 107, 13, 'Then they cried to the LORD in their trouble, and he saved them out of their distresses.'),
  ('Psalms', 107, 14, 'He brought them out of darkness and the shadow of death, and broke away their chains.'),
  ('Psalms', 107, 15, 'Let them praise the LORD for his loving kindness, for his wonderful deeds to the children of men!'),
  ('Psalms', 107, 16, 'For he has broken the gates of bronze, and cut through bars of iron.'),
  ('Psalms', 107, 17, 'Fools are afflicted because of their disobedience, and because of their iniquities.'),
  ('Psalms', 107, 18, 'Their soul abhors all kinds of food. They draw near to the gates of death.'),
  ('Psalms', 107, 19, 'Then they cry to the LORD in their trouble, and he saves them out of their distresses.'),
  ('Psalms', 107, 20, 'He sends his word, and heals them, and delivers them from their graves.'),
  ('Psalms', 107, 21, 'Let them praise the LORD for his loving kindness, for his wonderful deeds to the children of men!'),
  ('Psalms', 107, 22, 'Let them offer the sacrifices of thanksgiving, and declare his deeds with singing.'),
  ('Psalms', 107, 23, 'Those who go down to the sea in ships, who do business in great waters,'),
  ('Psalms', 107, 24, 'these see the LORD’s deeds, and his wonders in the deep.'),
  ('Psalms', 107, 25, 'For he commands, and raises the stormy wind, which lifts up its waves.'),
  ('Psalms', 107, 26, 'They mount up to the sky; they go down again to the depths. Their soul melts away because of trouble.'),
  ('Psalms', 107, 27, 'They reel back and forth, and stagger like a drunken man, and are at their wits’ end.'),
  ('Psalms', 107, 28, 'Then they cry to the LORD in their trouble, and he brings them out of their distress.'),
  ('Psalms', 107, 29, 'He makes the storm a calm, so that its waves are still.'),
  ('Psalms', 107, 30, 'Then they are glad because it is calm, so he brings them to their desired haven.'),
  ('Psalms', 107, 31, 'Let them praise the LORD for his loving kindness, for his wonderful deeds for the children of men!'),
  ('Psalms', 107, 32, 'Let them exalt him also in the assembly of the people, and praise him in the seat of the elders.'),
  ('Psalms', 107, 33, 'He turns rivers into a desert, water springs into a thirsty ground,'),
  ('Psalms', 107, 34, 'and a fruitful land into a salt waste, for the wickedness of those who dwell in it.'),
  ('Psalms', 107, 35, 'He turns a desert into a pool of water, and a dry land into water springs.'),
  ('Psalms', 107, 36, 'There he makes the hungry live, that they may prepare a city to live in,'),
  ('Psalms', 107, 37, 'sow fields, plant vineyards, and reap the fruits of increase.'),
  ('Psalms', 107, 38, 'He blesses them also, so that they are multiplied greatly. He doesn’t allow their livestock to decrease.'),
  ('Psalms', 107, 39, 'Again, they are diminished and bowed down through oppression, trouble, and sorrow.'),
  ('Psalms', 107, 40, 'He pours contempt on princes, and causes them to wander in a trackless waste.'),
  ('Psalms', 107, 41, 'Yet he lifts the needy out of their affliction, and increases their families like a flock.'),
  ('Psalms', 107, 42, 'The upright will see it, and be glad. All the wicked will shut their mouths.'),
  ('Psalms', 107, 43, 'Whoever is wise will pay attention to these things. They will consider the loving kindnesses of the LORD.'),
  ('Psalms', 108, 1, 'A Song. A Psalm by David. My heart is steadfast, God. I will sing and I will make music with my soul.'),
  ('Psalms', 108, 2, 'Wake up, harp and lyre! I will wake up the dawn.'),
  ('Psalms', 108, 3, 'I will give thanks to you, LORD, among the nations. I will sing praises to you among the peoples.'),
  ('Psalms', 108, 4, 'For your loving kindness is great above the heavens. Your faithfulness reaches to the skies.'),
  ('Psalms', 108, 5, 'Be exalted, God, above the heavens! Let your glory be over all the earth.'),
  ('Psalms', 108, 6, 'That your beloved may be delivered, save with your right hand, and answer us.'),
  ('Psalms', 108, 7, 'God has spoken from his sanctuary: “In triumph, I will divide Shechem, and measure out the valley of Succoth.'),
  ('Psalms', 108, 8, 'Gilead is mine. Manasseh is mine. Ephraim also is my helmet. Judah is my scepter.'),
  ('Psalms', 108, 9, 'Moab is my wash pot. I will toss my sandal on Edom. I will shout over Philistia.”'),
  ('Psalms', 108, 10, 'Who will bring me into the fortified city? Who will lead me to Edom?'),
  ('Psalms', 108, 11, 'Haven’t you rejected us, God? You don’t go out, God, with our armies.'),
  ('Psalms', 108, 12, 'Give us help against the enemy, for the help of man is vain.'),
  ('Psalms', 108, 13, 'Through God, we will do valiantly, for it is he who will tread down our enemies.'),
  ('Psalms', 109, 1, 'For the Chief Musician. A Psalm by David. God of my praise, don’t remain silent,'),
  ('Psalms', 109, 2, 'for they have opened the mouth of the wicked and the mouth of deceit against me. They have spoken to me with a lying tongue.'),
  ('Psalms', 109, 3, 'They have also surrounded me with words of hatred, and fought against me without a cause.'),
  ('Psalms', 109, 4, 'In return for my love, they are my adversaries; but I am in prayer.'),
  ('Psalms', 109, 5, 'They have rewarded me evil for good, and hatred for my love.'),
  ('Psalms', 109, 6, 'Set a wicked man over him. Let an adversary stand at his right hand.'),
  ('Psalms', 109, 7, 'When he is judged, let him come out guilty. Let his prayer be turned into sin.'),
  ('Psalms', 109, 8, 'Let his days be few. Let another take his office.'),
  ('Psalms', 109, 9, 'Let his children be fatherless, and his wife a widow.'),
  ('Psalms', 109, 10, 'Let his children be wandering beggars. Let them be sought from their ruins.'),
  ('Psalms', 109, 11, 'Let the creditor seize all that he has. Let strangers plunder the fruit of his labor.'),
  ('Psalms', 109, 12, 'Let there be no one to extend kindness to him, neither let there be anyone to have pity on his fatherless children.'),
  ('Psalms', 109, 13, 'Let his posterity be cut off. In the generation following let their name be blotted out.'),
  ('Psalms', 109, 14, 'Let the iniquity of his fathers be remembered by the LORD. Don’t let the sin of his mother be blotted out.'),
  ('Psalms', 109, 15, 'Let them be before the LORD continually, that he may cut off their memory from the earth;'),
  ('Psalms', 109, 16, 'because he didn’t remember to show kindness, but persecuted the poor and needy man, the broken in heart, to kill them.'),
  ('Psalms', 109, 17, 'Yes, he loved cursing, and it came to him. He didn’t delight in blessing, and it was far from him.'),
  ('Psalms', 109, 18, 'He clothed himself also with cursing as with his garment. It came into his inward parts like water, like oil into his bones.'),
  ('Psalms', 109, 19, 'Let it be to him as the clothing with which he covers himself, for the belt that is always around him.'),
  ('Psalms', 109, 20, 'This is the reward of my adversaries from the LORD, of those who speak evil against my soul.'),
  ('Psalms', 109, 21, 'But deal with me, GOD the Lord, for your name’s sake, because your loving kindness is good, deliver me;'),
  ('Psalms', 109, 22, 'for I am poor and needy. My heart is wounded within me.'),
  ('Psalms', 109, 23, 'I fade away like an evening shadow. I am shaken off like a locust.'),
  ('Psalms', 109, 24, 'My knees are weak through fasting. My body is thin and lacks fat.'),
  ('Psalms', 109, 25, 'I have also become a reproach to them. When they see me, they shake their head.'),
  ('Psalms', 109, 26, 'Help me, LORD, my God. Save me according to your loving kindness;'),
  ('Psalms', 109, 27, 'that they may know that this is your hand; that you, LORD, have done it.'),
  ('Psalms', 109, 28, 'They may curse, but you bless. When they arise, they will be shamed, but your servant shall rejoice.'),
  ('Psalms', 109, 29, 'Let my adversaries be clothed with dishonor. Let them cover themselves with their own shame as with a robe.'),
  ('Psalms', 109, 30, 'I will give great thanks to the LORD with my mouth. Yes, I will praise him among the multitude.'),
  ('Psalms', 109, 31, 'For he will stand at the right hand of the needy, to save him from those who judge his soul.'),
  ('Psalms', 110, 1, 'A Psalm by David. The LORD says to my Lord, “Sit at my right hand, until I make your enemies your footstool for your feet.”'),
  ('Psalms', 110, 2, 'The LORD will send out the rod of your strength out of Zion. Rule among your enemies.'),
  ('Psalms', 110, 3, 'Your people offer themselves willingly in the day of your power, in holy array. Out of the womb of the morning, you have the dew of your youth.'),
  ('Psalms', 110, 4, 'The LORD has sworn, and will not change his mind: “You are a priest forever in the order of Melchizedek.”'),
  ('Psalms', 110, 5, 'The Lord is at your right hand. He will crush kings in the day of his wrath.'),
  ('Psalms', 110, 6, 'He will judge among the nations. He will heap up dead bodies. He will crush the ruler of the whole earth.'),
  ('Psalms', 110, 7, 'He will drink of the brook on the way; therefore he will lift up his head.'),
  ('Psalms', 111, 1, 'Praise the LORD! I will give thanks to the LORD with my whole heart, in the council of the upright, and in the congregation.'),
  ('Psalms', 111, 2, 'The LORD’s works are great, pondered by all those who delight in them.'),
  ('Psalms', 111, 3, 'His work is honor and majesty. His righteousness endures forever.'),
  ('Psalms', 111, 4, 'He has caused his wonderful works to be remembered. The LORD is gracious and merciful.'),
  ('Psalms', 111, 5, 'He has given food to those who fear him. He always remembers his covenant.'),
  ('Psalms', 111, 6, 'He has shown his people the power of his works, in giving them the heritage of the nations.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 111, 7, 'The works of his hands are truth and justice. All his precepts are sure.'),
  ('Psalms', 111, 8, 'They are established forever and ever. They are done in truth and uprightness.'),
  ('Psalms', 111, 9, 'He has sent redemption to his people. He has ordained his covenant forever. His name is holy and awesome!'),
  ('Psalms', 111, 10, 'The fear of the LORD is the beginning of wisdom. All those who do his work have a good understanding. His praise endures forever!'),
  ('Psalms', 112, 1, 'Praise the LORD! Blessed is the man who fears the LORD, who delights greatly in his commandments.'),
  ('Psalms', 112, 2, 'His offspring will be mighty in the land. The generation of the upright will be blessed.'),
  ('Psalms', 112, 3, 'Wealth and riches are in his house. His righteousness endures forever.'),
  ('Psalms', 112, 4, 'Light dawns in the darkness for the upright, gracious, merciful, and righteous.'),
  ('Psalms', 112, 5, 'It is well with the man who deals graciously and lends. He will maintain his cause in judgment.'),
  ('Psalms', 112, 6, 'For he will never be shaken. The righteous will be remembered forever.'),
  ('Psalms', 112, 7, 'He will not be afraid of evil news. His heart is steadfast, trusting in the LORD.'),
  ('Psalms', 112, 8, 'His heart is established. He will not be afraid in the end when he sees his adversaries.'),
  ('Psalms', 112, 9, 'He has dispersed, he has given to the poor. His righteousness endures forever. His horn will be exalted with honor.'),
  ('Psalms', 112, 10, 'The wicked will see it, and be grieved. He shall gnash with his teeth, and melt away. The desire of the wicked will perish.'),
  ('Psalms', 113, 1, 'Praise the LORD! Praise, you servants of the LORD, praise the LORD’s name.'),
  ('Psalms', 113, 2, 'Blessed be the LORD’s name, from this time forward and forever more.'),
  ('Psalms', 113, 3, 'From the rising of the sun to its going down, the LORD’s name is to be praised.'),
  ('Psalms', 113, 4, 'The LORD is high above all nations, his glory above the heavens.'),
  ('Psalms', 113, 5, 'Who is like the LORD, our God, who has his seat on high,'),
  ('Psalms', 113, 6, 'who stoops down to see in heaven and in the earth?'),
  ('Psalms', 113, 7, 'He raises up the poor out of the dust, and lifts up the needy from the ash heap,'),
  ('Psalms', 113, 8, 'that he may set him with princes, even with the princes of his people.'),
  ('Psalms', 113, 9, 'He settles the barren woman in her home as a joyful mother of children. Praise the LORD!'),
  ('Psalms', 114, 1, 'When Israel went out of Egypt, the house of Jacob from a people of foreign language,'),
  ('Psalms', 114, 2, 'Judah became his sanctuary, Israel his dominion.'),
  ('Psalms', 114, 3, 'The sea saw it, and fled. The Jordan was driven back.'),
  ('Psalms', 114, 4, 'The mountains skipped like rams, the little hills like lambs.'),
  ('Psalms', 114, 5, 'What was it, you sea, that you fled? You Jordan, that you turned back?'),
  ('Psalms', 114, 6, 'You mountains, that you skipped like rams? You little hills, like lambs?'),
  ('Psalms', 114, 7, 'Tremble, you earth, at the presence of the Lord, at the presence of the God of Jacob,'),
  ('Psalms', 114, 8, 'who turned the rock into a pool of water, the flint into a spring of waters.'),
  ('Psalms', 115, 1, 'Not to us, LORD, not to us, but to your name give glory, for your loving kindness, and for your truth’s sake.'),
  ('Psalms', 115, 2, 'Why should the nations say, “Where is their God, now?”'),
  ('Psalms', 115, 3, 'But our God is in the heavens. He does whatever he pleases.'),
  ('Psalms', 115, 4, 'Their idols are silver and gold, the work of men’s hands.'),
  ('Psalms', 115, 5, 'They have mouths, but they don’t speak. They have eyes, but they don’t see.'),
  ('Psalms', 115, 6, 'They have ears, but they don’t hear. They have noses, but they don’t smell.'),
  ('Psalms', 115, 7, 'They have hands, but they don’t feel. They have feet, but they don’t walk, neither do they speak through their throat.'),
  ('Psalms', 115, 8, 'Those who make them will be like them; yes, everyone who trusts in them.'),
  ('Psalms', 115, 9, 'Israel, trust in the LORD! He is their help and their shield.'),
  ('Psalms', 115, 10, 'House of Aaron, trust in the LORD! He is their help and their shield.'),
  ('Psalms', 115, 11, 'You who fear the LORD, trust in the LORD! He is their help and their shield.'),
  ('Psalms', 115, 12, 'The LORD remembers us. He will bless us. He will bless the house of Israel. He will bless the house of Aaron.'),
  ('Psalms', 115, 13, 'He will bless those who fear the LORD, both small and great.'),
  ('Psalms', 115, 14, 'May the LORD increase you more and more, you and your children.'),
  ('Psalms', 115, 15, 'Blessed are you by the LORD, who made heaven and earth.'),
  ('Psalms', 115, 16, 'The heavens are the LORD’s heavens, but he has given the earth to the children of men.'),
  ('Psalms', 115, 17, 'The dead don’t praise the LORD, nor any who go down into silence,'),
  ('Psalms', 115, 18, 'but we will bless the LORD, from this time forward and forever more. Praise the LORD!'),
  ('Psalms', 116, 1, 'I love the LORD, because he listens to my voice, and my cries for mercy.'),
  ('Psalms', 116, 2, 'Because he has turned his ear to me, therefore I will call on him as long as I live.'),
  ('Psalms', 116, 3, 'The cords of death surrounded me, the pains of Sheol got a hold of me. I found trouble and sorrow.'),
  ('Psalms', 116, 4, 'Then I called on the LORD’s name: “LORD, I beg you, deliver my soul.”'),
  ('Psalms', 116, 5, 'The LORD is gracious and righteous. Yes, our God is merciful.'),
  ('Psalms', 116, 6, 'The LORD preserves the simple. I was brought low, and he saved me.'),
  ('Psalms', 116, 7, 'Return to your rest, my soul, for the LORD has dealt bountifully with you.'),
  ('Psalms', 116, 8, 'For you have delivered my soul from death, my eyes from tears, and my feet from falling.'),
  ('Psalms', 116, 9, 'I will walk before the LORD in the land of the living.'),
  ('Psalms', 116, 10, 'I believed, therefore I said, “I was greatly afflicted.”'),
  ('Psalms', 116, 11, 'I said in my haste, “All people are liars.”'),
  ('Psalms', 116, 12, 'What will I give to the LORD for all his benefits toward me?'),
  ('Psalms', 116, 13, 'I will take the cup of salvation, and call on the LORD’s name.'),
  ('Psalms', 116, 14, 'I will pay my vows to the LORD, yes, in the presence of all his people.'),
  ('Psalms', 116, 15, 'Precious in the LORD’s sight is the death of his saints.'),
  ('Psalms', 116, 16, 'LORD, truly I am your servant. I am your servant, the son of your servant girl. You have freed me from my chains.'),
  ('Psalms', 116, 17, 'I will offer to you the sacrifice of thanksgiving, and will call on the LORD’s name.'),
  ('Psalms', 116, 18, 'I will pay my vows to the LORD, yes, in the presence of all his people,'),
  ('Psalms', 116, 19, 'in the courts of the LORD’s house, in the middle of you, Jerusalem. Praise the LORD!'),
  ('Psalms', 117, 1, 'Praise the LORD, all you nations! Extol him, all you peoples!'),
  ('Psalms', 117, 2, 'For his loving kindness is great toward us. The LORD’s faithfulness endures forever. Praise the LORD!'),
  ('Psalms', 118, 1, 'Give thanks to the LORD, for he is good, for his loving kindness endures forever.'),
  ('Psalms', 118, 2, 'Let Israel now say that his loving kindness endures forever.'),
  ('Psalms', 118, 3, 'Let the house of Aaron now say that his loving kindness endures forever.'),
  ('Psalms', 118, 4, 'Now let those who fear the LORD say that his loving kindness endures forever.'),
  ('Psalms', 118, 5, 'Out of my distress, I called on the LORD. The LORD answered me with freedom.'),
  ('Psalms', 118, 6, 'The LORD is on my side. I will not be afraid. What can man do to me?'),
  ('Psalms', 118, 7, 'The LORD is on my side among those who help me. Therefore I will look in triumph at those who hate me.'),
  ('Psalms', 118, 8, 'It is better to take refuge in the LORD, than to put confidence in man.'),
  ('Psalms', 118, 9, 'It is better to take refuge in the LORD, than to put confidence in princes.'),
  ('Psalms', 118, 10, 'All the nations surrounded me, but in the LORD’s name I cut them off.'),
  ('Psalms', 118, 11, 'They surrounded me, yes, they surrounded me. In the LORD’s name I indeed cut them off.'),
  ('Psalms', 118, 12, 'They surrounded me like bees. They are quenched like the burning thorns. In the LORD’s name I cut them off.'),
  ('Psalms', 118, 13, 'You pushed me back hard, to make me fall, but the LORD helped me.'),
  ('Psalms', 118, 14, 'The LORD is my strength and song. He has become my salvation.'),
  ('Psalms', 118, 15, 'The voice of rejoicing and salvation is in the tents of the righteous. “The right hand of the LORD does valiantly.'),
  ('Psalms', 118, 16, 'The right hand of the LORD is exalted! The right hand of the LORD does valiantly!”'),
  ('Psalms', 118, 17, 'I will not die, but live, and declare the LORD’s works.'),
  ('Psalms', 118, 18, 'The LORD has punished me severely, but he has not given me over to death.'),
  ('Psalms', 118, 19, 'Open to me the gates of righteousness. I will enter into them. I will give thanks to the LORD.'),
  ('Psalms', 118, 20, 'This is the gate of the LORD; the righteous will enter into it.'),
  ('Psalms', 118, 21, 'I will give thanks to you, for you have answered me, and have become my salvation.'),
  ('Psalms', 118, 22, 'The stone which the builders rejected has become the cornerstone.'),
  ('Psalms', 118, 23, 'This is the LORD’s doing. It is marvelous in our eyes.'),
  ('Psalms', 118, 24, 'This is the day that the LORD has made. We will rejoice and be glad in it!'),
  ('Psalms', 118, 25, 'Save us now, we beg you, LORD! LORD, we beg you, send prosperity now.'),
  ('Psalms', 118, 26, 'Blessed is he who comes in the LORD’s name! We have blessed you out of the LORD’s house.'),
  ('Psalms', 118, 27, 'The LORD is God, and he has given us light. Bind the sacrifice with cords, even to the horns of the altar.'),
  ('Psalms', 118, 28, 'You are my God, and I will give thanks to you. You are my God, I will exalt you.'),
  ('Psalms', 118, 29, 'Oh give thanks to the LORD, for he is good, for his loving kindness endures forever.'),
  ('Psalms', 119, 1, 'ALEPH Blessed are those whose ways are blameless, who walk according to the LORD’s law.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 119, 2, 'Blessed are those who keep his statutes, who seek him with their whole heart.'),
  ('Psalms', 119, 3, 'Yes, they do nothing wrong. They walk in his ways.'),
  ('Psalms', 119, 4, 'You have commanded your precepts, that we should fully obey them.'),
  ('Psalms', 119, 5, 'Oh that my ways were steadfast to obey your statutes!'),
  ('Psalms', 119, 6, 'Then I wouldn’t be disappointed, when I consider all of your commandments.'),
  ('Psalms', 119, 7, 'I will give thanks to you with uprightness of heart, when I learn your righteous judgments.'),
  ('Psalms', 119, 8, 'I will observe your statutes. Don’t utterly forsake me. BETH'),
  ('Psalms', 119, 9, 'How can a young man keep his way pure? By living according to your word.'),
  ('Psalms', 119, 10, 'With my whole heart I have sought you. Don’t let me wander from your commandments.'),
  ('Psalms', 119, 11, 'I have hidden your word in my heart, that I might not sin against you.'),
  ('Psalms', 119, 12, 'Blessed are you, LORD. Teach me your statutes.'),
  ('Psalms', 119, 13, 'With my lips, I have declared all the ordinances of your mouth.'),
  ('Psalms', 119, 14, 'I have rejoiced in the way of your testimonies, as much as in all riches.'),
  ('Psalms', 119, 15, 'I will meditate on your precepts, and consider your ways.'),
  ('Psalms', 119, 16, 'I will delight myself in your statutes. I will not forget your word. GIMEL'),
  ('Psalms', 119, 17, 'Do good to your servant. I will live and I will obey your word.'),
  ('Psalms', 119, 18, 'Open my eyes, that I may see wondrous things out of your law.'),
  ('Psalms', 119, 19, 'I am a stranger on the earth. Don’t hide your commandments from me.'),
  ('Psalms', 119, 20, 'My soul is consumed with longing for your ordinances at all times.'),
  ('Psalms', 119, 21, 'You have rebuked the proud who are cursed, who wander from your commandments.'),
  ('Psalms', 119, 22, 'Take reproach and contempt away from me, for I have kept your statutes.'),
  ('Psalms', 119, 23, 'Though princes sit and slander me, your servant will meditate on your statutes.'),
  ('Psalms', 119, 24, 'Indeed your statutes are my delight, and my counselors. DALETH'),
  ('Psalms', 119, 25, 'My soul is laid low in the dust. Revive me according to your word!'),
  ('Psalms', 119, 26, 'I declared my ways, and you answered me. Teach me your statutes.'),
  ('Psalms', 119, 27, 'Let me understand the teaching of your precepts! Then I will meditate on your wondrous works.'),
  ('Psalms', 119, 28, 'My soul is weary with sorrow; strengthen me according to your word.'),
  ('Psalms', 119, 29, 'Keep me from the way of deceit. Grant me your law graciously!'),
  ('Psalms', 119, 30, 'I have chosen the way of truth. I have set your ordinances before me.'),
  ('Psalms', 119, 31, 'I cling to your statutes, LORD. Don’t let me be disappointed.'),
  ('Psalms', 119, 32, 'I run in the path of your commandments, for you have set my heart free. HE'),
  ('Psalms', 119, 33, 'Teach me, LORD, the way of your statutes. I will keep them to the end.'),
  ('Psalms', 119, 34, 'Give me understanding, and I will keep your law. Yes, I will obey it with my whole heart.'),
  ('Psalms', 119, 35, 'Direct me in the path of your commandments, for I delight in them.'),
  ('Psalms', 119, 36, 'Turn my heart toward your statutes, not toward selfish gain.'),
  ('Psalms', 119, 37, 'Turn my eyes away from looking at worthless things. Revive me in your ways.'),
  ('Psalms', 119, 38, 'Fulfill your promise to your servant, that you may be feared.'),
  ('Psalms', 119, 39, 'Take away my disgrace that I dread, for your ordinances are good.'),
  ('Psalms', 119, 40, 'Behold, I long for your precepts! Revive me in your righteousness. VAV'),
  ('Psalms', 119, 41, 'Let your loving kindness also come to me, LORD, your salvation, according to your word.'),
  ('Psalms', 119, 42, 'So I will have an answer for him who reproaches me, for I trust in your word.'),
  ('Psalms', 119, 43, 'Don’t snatch the word of truth out of my mouth, for I put my hope in your ordinances.'),
  ('Psalms', 119, 44, 'So I will obey your law continually, forever and ever.'),
  ('Psalms', 119, 45, 'I will walk in liberty, for I have sought your precepts.'),
  ('Psalms', 119, 46, 'I will also speak of your statutes before kings, and will not be disappointed.'),
  ('Psalms', 119, 47, 'I will delight myself in your commandments, because I love them.'),
  ('Psalms', 119, 48, 'I reach out my hands for your commandments, which I love. I will meditate on your statutes. ZAYIN'),
  ('Psalms', 119, 49, 'Remember your word to your servant, because you gave me hope.'),
  ('Psalms', 119, 50, 'This is my comfort in my affliction, for your word has revived me.'),
  ('Psalms', 119, 51, 'The arrogant mock me excessively, but I don’t swerve from your law.'),
  ('Psalms', 119, 52, 'I remember your ordinances of old, LORD, and have comforted myself.'),
  ('Psalms', 119, 53, 'Indignation has taken hold on me, because of the wicked who forsake your law.'),
  ('Psalms', 119, 54, 'Your statutes have been my songs in the house where I live.'),
  ('Psalms', 119, 55, 'I have remembered your name, LORD, in the night, and I obey your law.'),
  ('Psalms', 119, 56, 'This is my way, that I keep your precepts. HETH'),
  ('Psalms', 119, 57, 'The LORD is my portion. I promised to obey your words.'),
  ('Psalms', 119, 58, 'I sought your favor with my whole heart. Be merciful to me according to your word.'),
  ('Psalms', 119, 59, 'I considered my ways, and turned my steps to your statutes.'),
  ('Psalms', 119, 60, 'I will hurry, and not delay, to obey your commandments.'),
  ('Psalms', 119, 61, 'The ropes of the wicked bind me, but I won’t forget your law.'),
  ('Psalms', 119, 62, 'At midnight I will rise to give thanks to you, because of your righteous ordinances.'),
  ('Psalms', 119, 63, 'I am a friend of all those who fear you, of those who observe your precepts.'),
  ('Psalms', 119, 64, 'The earth is full of your loving kindness, LORD. Teach me your statutes. TETH'),
  ('Psalms', 119, 65, 'You have treated your servant well, according to your word, LORD.'),
  ('Psalms', 119, 66, 'Teach me good judgment and knowledge, for I believe in your commandments.'),
  ('Psalms', 119, 67, 'Before I was afflicted, I went astray; but now I observe your word.'),
  ('Psalms', 119, 68, 'You are good, and do good. Teach me your statutes.'),
  ('Psalms', 119, 69, 'The proud have smeared a lie upon me. With my whole heart, I will keep your precepts.'),
  ('Psalms', 119, 70, 'Their heart is as callous as the fat, but I delight in your law.'),
  ('Psalms', 119, 71, 'It is good for me that I have been afflicted, that I may learn your statutes.'),
  ('Psalms', 119, 72, 'The law of your mouth is better to me than thousands of pieces of gold and silver. YODH'),
  ('Psalms', 119, 73, 'Your hands have made me and formed me. Give me understanding, that I may learn your commandments.'),
  ('Psalms', 119, 74, 'Those who fear you will see me and be glad, because I have put my hope in your word.'),
  ('Psalms', 119, 75, 'LORD, I know that your judgments are righteous, that in faithfulness you have afflicted me.'),
  ('Psalms', 119, 76, 'Please let your loving kindness be for my comfort, according to your word to your servant.'),
  ('Psalms', 119, 77, 'Let your tender mercies come to me, that I may live; for your law is my delight.'),
  ('Psalms', 119, 78, 'Let the proud be disappointed, for they have overthrown me wrongfully. I will meditate on your precepts.'),
  ('Psalms', 119, 79, 'Let those who fear you turn to me. They will know your statutes.'),
  ('Psalms', 119, 80, 'Let my heart be blameless toward your decrees, that I may not be disappointed. KAPF'),
  ('Psalms', 119, 81, 'My soul faints for your salvation. I hope in your word.'),
  ('Psalms', 119, 82, 'My eyes fail for your word. I say, “When will you comfort me?”'),
  ('Psalms', 119, 83, 'For I have become like a wineskin in the smoke. I don’t forget your statutes.'),
  ('Psalms', 119, 84, 'How many are the days of your servant? When will you execute judgment on those who persecute me?'),
  ('Psalms', 119, 85, 'The proud have dug pits for me, contrary to your law.'),
  ('Psalms', 119, 86, 'All of your commandments are faithful. They persecute me wrongfully. Help me!'),
  ('Psalms', 119, 87, 'They had almost wiped me from the earth, but I didn’t forsake your precepts.'),
  ('Psalms', 119, 88, 'Preserve my life according to your loving kindness, so I will obey the statutes of your mouth. LAMEDH'),
  ('Psalms', 119, 89, 'LORD, your word is settled in heaven forever.'),
  ('Psalms', 119, 90, 'Your faithfulness is to all generations. You have established the earth, and it remains.'),
  ('Psalms', 119, 91, 'Your laws remain to this day, for all things serve you.'),
  ('Psalms', 119, 92, 'Unless your law had been my delight, I would have perished in my affliction.'),
  ('Psalms', 119, 93, 'I will never forget your precepts, for with them, you have revived me.'),
  ('Psalms', 119, 94, 'I am yours. Save me, for I have sought your precepts.'),
  ('Psalms', 119, 95, 'The wicked have waited for me, to destroy me. I will consider your statutes.'),
  ('Psalms', 119, 96, 'I have seen a limit to all perfection, but your commands are boundless. MEM'),
  ('Psalms', 119, 97, 'How I love your law! It is my meditation all day.'),
  ('Psalms', 119, 98, 'Your commandments make me wiser than my enemies, for your commandments are always with me.'),
  ('Psalms', 119, 99, 'I have more understanding than all my teachers, for your testimonies are my meditation.'),
  ('Psalms', 119, 100, 'I understand more than the aged, because I have kept your precepts.'),
  ('Psalms', 119, 101, 'I have kept my feet from every evil way, that I might observe your word.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 119, 102, 'I have not turned away from your ordinances, for you have taught me.'),
  ('Psalms', 119, 103, 'How sweet are your promises to my taste, more than honey to my mouth!'),
  ('Psalms', 119, 104, 'Through your precepts, I get understanding; therefore I hate every false way. NUN'),
  ('Psalms', 119, 105, 'Your word is a lamp to my feet, and a light for my path.'),
  ('Psalms', 119, 106, 'I have sworn, and have confirmed it, that I will obey your righteous ordinances.'),
  ('Psalms', 119, 107, 'I am afflicted very much. Revive me, LORD, according to your word.'),
  ('Psalms', 119, 108, 'Accept, I beg you, the willing offerings of my mouth. LORD, teach me your ordinances.'),
  ('Psalms', 119, 109, 'My soul is continually in my hand, yet I won’t forget your law.'),
  ('Psalms', 119, 110, 'The wicked have laid a snare for me, yet I haven’t gone astray from your precepts.'),
  ('Psalms', 119, 111, 'I have taken your testimonies as a heritage forever, for they are the joy of my heart.'),
  ('Psalms', 119, 112, 'I have set my heart to perform your statutes forever, even to the end. SAMEKH'),
  ('Psalms', 119, 113, 'I hate double-minded men, but I love your law.'),
  ('Psalms', 119, 114, 'You are my hiding place and my shield. I hope in your word.'),
  ('Psalms', 119, 115, 'Depart from me, you evildoers, that I may keep the commandments of my God.'),
  ('Psalms', 119, 116, 'Uphold me according to your word, that I may live. Let me not be ashamed of my hope.'),
  ('Psalms', 119, 117, 'Hold me up, and I will be safe, and will have respect for your statutes continually.'),
  ('Psalms', 119, 118, 'You reject all those who stray from your statutes, for their deceit is in vain.'),
  ('Psalms', 119, 119, 'You put away all the wicked of the earth like dross. Therefore I love your testimonies.'),
  ('Psalms', 119, 120, 'My flesh trembles for fear of you. I am afraid of your judgments. AYIN'),
  ('Psalms', 119, 121, 'I have done what is just and righteous. Don’t leave me to my oppressors.'),
  ('Psalms', 119, 122, 'Ensure your servant’s well-being. Don’t let the proud oppress me.'),
  ('Psalms', 119, 123, 'My eyes fail looking for your salvation, for your righteous word.'),
  ('Psalms', 119, 124, 'Deal with your servant according to your loving kindness. Teach me your statutes.'),
  ('Psalms', 119, 125, 'I am your servant. Give me understanding, that I may know your testimonies.'),
  ('Psalms', 119, 126, 'It is time to act, LORD, for they break your law.'),
  ('Psalms', 119, 127, 'Therefore I love your commandments more than gold, yes, more than pure gold.'),
  ('Psalms', 119, 128, 'Therefore I consider all of your precepts to be right. I hate every false way. PE'),
  ('Psalms', 119, 129, 'Your testimonies are wonderful, therefore my soul keeps them.'),
  ('Psalms', 119, 130, 'The entrance of your words gives light. It gives understanding to the simple.'),
  ('Psalms', 119, 131, 'I opened my mouth wide and panted, for I longed for your commandments.'),
  ('Psalms', 119, 132, 'Turn to me, and have mercy on me, as you always do to those who love your name.'),
  ('Psalms', 119, 133, 'Establish my footsteps in your word. Don’t let any iniquity have dominion over me.'),
  ('Psalms', 119, 134, 'Redeem me from the oppression of man, so I will observe your precepts.'),
  ('Psalms', 119, 135, 'Make your face shine on your servant. Teach me your statutes.'),
  ('Psalms', 119, 136, 'Streams of tears run down my eyes, because they don’t observe your law. TZADHE'),
  ('Psalms', 119, 137, 'You are righteous, LORD. Your judgments are upright.'),
  ('Psalms', 119, 138, 'You have commanded your statutes in righteousness. They are fully trustworthy.'),
  ('Psalms', 119, 139, 'My zeal wears me out, because my enemies ignore your words.'),
  ('Psalms', 119, 140, 'Your promises have been thoroughly tested, and your servant loves them.'),
  ('Psalms', 119, 141, 'I am small and despised. I don’t forget your precepts.'),
  ('Psalms', 119, 142, 'Your righteousness is an everlasting righteousness. Your law is truth.'),
  ('Psalms', 119, 143, 'Trouble and anguish have taken hold of me. Your commandments are my delight.'),
  ('Psalms', 119, 144, 'Your testimonies are righteous forever. Give me understanding, that I may live. QOPH'),
  ('Psalms', 119, 145, 'I have called with my whole heart. Answer me, LORD! I will keep your statutes.'),
  ('Psalms', 119, 146, 'I have called to you. Save me! I will obey your statutes.'),
  ('Psalms', 119, 147, 'I rise before dawn and cry for help. I put my hope in your words.'),
  ('Psalms', 119, 148, 'My eyes stay open through the night watches, that I might meditate on your word.'),
  ('Psalms', 119, 149, 'Hear my voice according to your loving kindness. Revive me, LORD, according to your ordinances.'),
  ('Psalms', 119, 150, 'They draw near who follow after wickedness. They are far from your law.'),
  ('Psalms', 119, 151, 'You are near, LORD. All your commandments are truth.'),
  ('Psalms', 119, 152, 'Of old I have known from your testimonies, that you have founded them forever. RESH'),
  ('Psalms', 119, 153, 'Consider my affliction, and deliver me, for I don’t forget your law.'),
  ('Psalms', 119, 154, 'Plead my cause, and redeem me! Revive me according to your promise.'),
  ('Psalms', 119, 155, 'Salvation is far from the wicked, for they don’t seek your statutes.'),
  ('Psalms', 119, 156, 'Great are your tender mercies, LORD. Revive me according to your ordinances.'),
  ('Psalms', 119, 157, 'Many are my persecutors and my adversaries. I haven’t swerved from your testimonies.'),
  ('Psalms', 119, 158, 'I look at the faithless with loathing, because they don’t observe your word.'),
  ('Psalms', 119, 159, 'Consider how I love your precepts. Revive me, LORD, according to your loving kindness.'),
  ('Psalms', 119, 160, 'All of your words are truth. Every one of your righteous ordinances endures forever. SIN AND SHIN'),
  ('Psalms', 119, 161, 'Princes have persecuted me without a cause, but my heart stands in awe of your words.'),
  ('Psalms', 119, 162, 'I rejoice at your word, as one who finds great plunder.'),
  ('Psalms', 119, 163, 'I hate and abhor falsehood. I love your law.'),
  ('Psalms', 119, 164, 'Seven times a day, I praise you, because of your righteous ordinances.'),
  ('Psalms', 119, 165, 'Those who love your law have great peace. Nothing causes them to stumble.'),
  ('Psalms', 119, 166, 'I have hoped for your salvation, LORD. I have done your commandments.'),
  ('Psalms', 119, 167, 'My soul has observed your testimonies. I love them exceedingly.'),
  ('Psalms', 119, 168, 'I have obeyed your precepts and your testimonies, for all my ways are before you. TAV'),
  ('Psalms', 119, 169, 'Let my cry come before you, LORD. Give me understanding according to your word.'),
  ('Psalms', 119, 170, 'Let my supplication come before you. Deliver me according to your word.'),
  ('Psalms', 119, 171, 'Let my lips utter praise, for you teach me your statutes.'),
  ('Psalms', 119, 172, 'Let my tongue sing of your word, for all your commandments are righteousness.'),
  ('Psalms', 119, 173, 'Let your hand be ready to help me, for I have chosen your precepts.'),
  ('Psalms', 119, 174, 'I have longed for your salvation, LORD. Your law is my delight.'),
  ('Psalms', 119, 175, 'Let my soul live, that I may praise you. Let your ordinances help me.'),
  ('Psalms', 119, 176, 'I have gone astray like a lost sheep. Seek your servant, for I don’t forget your commandments.'),
  ('Psalms', 120, 1, 'A Song of Ascents. In my distress, I cried to the LORD. He answered me.'),
  ('Psalms', 120, 2, 'Deliver my soul, LORD, from lying lips, from a deceitful tongue.'),
  ('Psalms', 120, 3, 'What will be given to you, and what will be done more to you, you deceitful tongue?'),
  ('Psalms', 120, 4, 'Sharp arrows of the mighty, with coals of juniper.'),
  ('Psalms', 120, 5, 'Woe is me, that I live in Meshech, that I dwell among the tents of Kedar!'),
  ('Psalms', 120, 6, 'My soul has had her dwelling too long with him who hates peace.'),
  ('Psalms', 120, 7, 'I am for peace, but when I speak, they are for war.'),
  ('Psalms', 121, 1, 'A Song of Ascents. I will lift up my eyes to the hills. Where does my help come from?'),
  ('Psalms', 121, 2, 'My help comes from the LORD, who made heaven and earth.'),
  ('Psalms', 121, 3, 'He will not allow your foot to be moved. He who keeps you will not slumber.'),
  ('Psalms', 121, 4, 'Behold, he who keeps Israel will neither slumber nor sleep.'),
  ('Psalms', 121, 5, 'The LORD is your keeper. The LORD is your shade on your right hand.'),
  ('Psalms', 121, 6, 'The sun will not harm you by day, nor the moon by night.'),
  ('Psalms', 121, 7, 'The LORD will keep you from all evil. He will keep your soul.'),
  ('Psalms', 121, 8, 'The LORD will keep your going out and your coming in, from this time forward, and forever more.'),
  ('Psalms', 122, 1, 'A Song of Ascents. By David. I was glad when they said to me, “Let’s go to the LORD’s house!”'),
  ('Psalms', 122, 2, 'Our feet are standing within your gates, Jerusalem!'),
  ('Psalms', 122, 3, 'Jerusalem is built as a city that is compact together,'),
  ('Psalms', 122, 4, 'where the tribes go up, even the LORD’s tribes, according to an ordinance for Israel, to give thanks to the LORD’s name.'),
  ('Psalms', 122, 5, 'For there are set thrones for judgment, the thrones of David’s house.'),
  ('Psalms', 122, 6, 'Pray for the peace of Jerusalem. Those who love you will prosper.'),
  ('Psalms', 122, 7, 'Peace be within your walls, and prosperity within your palaces.'),
  ('Psalms', 122, 8, 'For my brothers’ and companions’ sakes, I will now say, “Peace be within you.”'),
  ('Psalms', 122, 9, 'For the sake of the house of the LORD our God, I will seek your good.'),
  ('Psalms', 123, 1, 'A Song of Ascents. I lift up my eyes to you, you who sit in the heavens.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 123, 2, 'Behold, as the eyes of servants look to the hand of their master, as the eyes of a maid to the hand of her mistress, so our eyes look to the LORD, our God, until he has mercy on us.'),
  ('Psalms', 123, 3, 'Have mercy on us, LORD, have mercy on us, for we have endured much contempt.'),
  ('Psalms', 123, 4, 'Our soul is exceedingly filled with the scoffing of those who are at ease, with the contempt of the proud.'),
  ('Psalms', 124, 1, 'A Song of Ascents. By David. If it had not been the LORD who was on our side, let Israel now say,'),
  ('Psalms', 124, 2, 'if it had not been the LORD who was on our side, when men rose up against us,'),
  ('Psalms', 124, 3, 'then they would have swallowed us up alive, when their wrath was kindled against us,'),
  ('Psalms', 124, 4, 'then the waters would have overwhelmed us, the stream would have gone over our soul.'),
  ('Psalms', 124, 5, 'Then the proud waters would have gone over our soul.'),
  ('Psalms', 124, 6, 'Blessed be the LORD, who has not given us as a prey to their teeth.'),
  ('Psalms', 124, 7, 'Our soul has escaped like a bird out of the fowler’s snare. The snare is broken, and we have escaped.'),
  ('Psalms', 124, 8, 'Our help is in the LORD’s name, who made heaven and earth.'),
  ('Psalms', 125, 1, 'A Song of Ascents. Those who trust in the LORD are as Mount Zion, which can’t be moved, but remains forever.'),
  ('Psalms', 125, 2, 'As the mountains surround Jerusalem, so the LORD surrounds his people from this time forward and forever more.'),
  ('Psalms', 125, 3, 'For the scepter of wickedness won’t remain over the allotment of the righteous, so that the righteous won’t use their hands to do evil.'),
  ('Psalms', 125, 4, 'Do good, LORD, to those who are good, to those who are upright in their hearts.'),
  ('Psalms', 125, 5, 'But as for those who turn away to their crooked ways, the LORD will lead them away with the workers of iniquity. Peace be on Israel.'),
  ('Psalms', 126, 1, 'A Song of Ascents. When the LORD brought back those who returned to Zion, we were like those who dream.'),
  ('Psalms', 126, 2, 'Then our mouth was filled with laughter, and our tongue with singing. Then they said among the nations, “The LORD has done great things for them.”'),
  ('Psalms', 126, 3, 'The LORD has done great things for us, and we are glad.'),
  ('Psalms', 126, 4, 'Restore our fortunes again, LORD, like the streams in the Negev.'),
  ('Psalms', 126, 5, 'Those who sow in tears will reap in joy.'),
  ('Psalms', 126, 6, 'He who goes out weeping, carrying seed for sowing, will certainly come again with joy, carrying his sheaves.'),
  ('Psalms', 127, 1, 'A Song of Ascents. By Solomon. Unless the LORD builds the house, they who build it labor in vain. Unless the LORD watches over the city, the watchman guards it in vain.'),
  ('Psalms', 127, 2, 'It is vain for you to rise up early, to stay up late, eating the bread of toil, for he gives sleep to his loved ones.'),
  ('Psalms', 127, 3, 'Behold, children are a heritage of the LORD. The fruit of the womb is his reward.'),
  ('Psalms', 127, 4, 'As arrows in the hand of a mighty man, so are the children of youth.'),
  ('Psalms', 127, 5, 'Happy is the man who has his quiver full of them. They won’t be disappointed when they speak with their enemies in the gate.'),
  ('Psalms', 128, 1, 'A Song of Ascents. Blessed is everyone who fears the LORD, who walks in his ways.'),
  ('Psalms', 128, 2, 'For you will eat the labor of your hands. You will be happy, and it will be well with you.'),
  ('Psalms', 128, 3, 'Your wife will be as a fruitful vine in the innermost parts of your house, your children like olive shoots around your table.'),
  ('Psalms', 128, 4, 'Behold, this is how the man who fears the LORD is blessed.'),
  ('Psalms', 128, 5, 'May the LORD bless you out of Zion, and may you see the good of Jerusalem all the days of your life.'),
  ('Psalms', 128, 6, 'Yes, may you see your children’s children. Peace be upon Israel.'),
  ('Psalms', 129, 1, 'A Song of Ascents. Many times they have afflicted me from my youth up. Let Israel now say:'),
  ('Psalms', 129, 2, 'many times they have afflicted me from my youth up, yet they have not prevailed against me.'),
  ('Psalms', 129, 3, 'The plowers plowed on my back. They made their furrows long.'),
  ('Psalms', 129, 4, 'The LORD is righteous. He has cut apart the cords of the wicked.'),
  ('Psalms', 129, 5, 'Let them be disappointed and turned backward, all those who hate Zion.'),
  ('Psalms', 129, 6, 'Let them be as the grass on the housetops, which withers before it grows up,'),
  ('Psalms', 129, 7, 'with which the reaper doesn’t fill his hand, nor he who binds sheaves, his bosom.'),
  ('Psalms', 129, 8, 'Neither do those who go by say, “The blessing of the LORD be on you. We bless you in the LORD’s name.”'),
  ('Psalms', 130, 1, 'A Song of Ascents. Out of the depths I have cried to you, LORD.'),
  ('Psalms', 130, 2, 'Lord, hear my voice. Let your ears be attentive to the voice of my petitions.'),
  ('Psalms', 130, 3, 'If you, LORD, kept a record of sins, Lord, who could stand?'),
  ('Psalms', 130, 4, 'But there is forgiveness with you, therefore you are feared.'),
  ('Psalms', 130, 5, 'I wait for the LORD. My soul waits. I hope in his word.'),
  ('Psalms', 130, 6, 'My soul longs for the Lord more than watchmen long for the morning, more than watchmen for the morning.'),
  ('Psalms', 130, 7, 'Israel, hope in the LORD, for there is loving kindness with the LORD. Abundant redemption is with him.'),
  ('Psalms', 130, 8, 'He will redeem Israel from all their sins.'),
  ('Psalms', 131, 1, 'A Song of Ascents. By David. LORD, my heart isn’t arrogant, nor my eyes lofty; nor do I concern myself with great matters, or things too wonderful for me.'),
  ('Psalms', 131, 2, 'Surely I have stilled and quieted my soul, like a weaned child with his mother, like a weaned child is my soul within me.'),
  ('Psalms', 131, 3, 'Israel, hope in the LORD, from this time forward and forever more.'),
  ('Psalms', 132, 1, 'A Song of Ascents. LORD, remember David and all his affliction,'),
  ('Psalms', 132, 2, 'how he swore to the LORD, and vowed to the Mighty One of Jacob:'),
  ('Psalms', 132, 3, '“Surely I will not come into the structure of my house, nor go up into my bed;'),
  ('Psalms', 132, 4, 'I will not give sleep to my eyes, or slumber to my eyelids,'),
  ('Psalms', 132, 5, 'until I find out a place for the LORD, a dwelling for the Mighty One of Jacob.”'),
  ('Psalms', 132, 6, 'Behold, we heard of it in Ephrathah. We found it in the field of Jaar.'),
  ('Psalms', 132, 7, '“We will go into his dwelling place. We will worship at his footstool.”'),
  ('Psalms', 132, 8, 'Arise, LORD, into your resting place, you, and the ark of your strength.'),
  ('Psalms', 132, 9, 'Let your priests be clothed with righteousness. Let your saints shout for joy!'),
  ('Psalms', 132, 10, 'For your servant David’s sake, don’t turn away the face of your anointed one.'),
  ('Psalms', 132, 11, 'The LORD has sworn to David in truth. He will not turn from it: “I will set the fruit of your body on your throne.'),
  ('Psalms', 132, 12, 'If your children will keep my covenant, my testimony that I will teach them, their children also will sit on your throne forever more.”'),
  ('Psalms', 132, 13, 'For the LORD has chosen Zion. He has desired it for his habitation.'),
  ('Psalms', 132, 14, '“This is my resting place forever. I will live here, for I have desired it.'),
  ('Psalms', 132, 15, 'I will abundantly bless her provision. I will satisfy her poor with bread.'),
  ('Psalms', 132, 16, 'I will also clothe her priests with salvation. Her saints will shout aloud for joy.'),
  ('Psalms', 132, 17, 'I will make the horn of David to bud there. I have ordained a lamp for my anointed.'),
  ('Psalms', 132, 18, 'I will clothe his enemies with shame, but on himself, his crown will shine.”'),
  ('Psalms', 133, 1, 'A Song of Ascents. By David. See how good and how pleasant it is for brothers to live together in unity!'),
  ('Psalms', 133, 2, 'It is like the precious oil on the head, that ran down on the beard, even Aaron’s beard, that came down on the edge of his robes,'),
  ('Psalms', 133, 3, 'like the dew of Hermon, that comes down on the hills of Zion; for there the LORD gives the blessing, even life forever more.'),
  ('Psalms', 134, 1, 'A Song of Ascents. Look! Praise the LORD, all you servants of the LORD, who stand by night in the LORD’s house!'),
  ('Psalms', 134, 2, 'Lift up your hands in the sanctuary. Praise the LORD!'),
  ('Psalms', 134, 3, 'May the LORD bless you from Zion, even he who made heaven and earth.'),
  ('Psalms', 135, 1, 'Praise the LORD! Praise the LORD’s name! Praise him, you servants of the LORD,'),
  ('Psalms', 135, 2, 'you who stand in the LORD’s house, in the courts of our God’s house.'),
  ('Psalms', 135, 3, 'Praise the LORD, for the LORD is good. Sing praises to his name, for that is pleasant.'),
  ('Psalms', 135, 4, 'For the LORD has chosen Jacob for himself, Israel for his own possession.'),
  ('Psalms', 135, 5, 'For I know that the LORD is great, that our Lord is above all gods.'),
  ('Psalms', 135, 6, 'Whatever the LORD pleased, that he has done, in heaven and in earth, in the seas and in all deeps.'),
  ('Psalms', 135, 7, 'He causes the clouds to rise from the ends of the earth. He makes lightnings with the rain. He brings the wind out of his treasuries.'),
  ('Psalms', 135, 8, 'He struck the firstborn of Egypt, both of man and animal.'),
  ('Psalms', 135, 9, 'He sent signs and wonders into the middle of you, Egypt, on Pharaoh, and on all his servants.'),
  ('Psalms', 135, 10, 'He struck many nations, and killed mighty kings—'),
  ('Psalms', 135, 11, 'Sihon king of the Amorites, Og king of Bashan, and all the kingdoms of Canaan—'),
  ('Psalms', 135, 12, 'and gave their land for a heritage, a heritage to Israel, his people.'),
  ('Psalms', 135, 13, 'Your name, LORD, endures forever; your renown, LORD, throughout all generations.'),
  ('Psalms', 135, 14, 'For the LORD will judge his people and have compassion on his servants.'),
  ('Psalms', 135, 15, 'The idols of the nations are silver and gold, the work of men’s hands.'),
  ('Psalms', 135, 16, 'They have mouths, but they can’t speak. They have eyes, but they can’t see.'),
  ('Psalms', 135, 17, 'They have ears, but they can’t hear, neither is there any breath in their mouths.'),
  ('Psalms', 135, 18, 'Those who make them will be like them, yes, everyone who trusts in them.'),
  ('Psalms', 135, 19, 'House of Israel, praise the LORD! House of Aaron, praise the LORD!'),
  ('Psalms', 135, 20, 'House of Levi, praise the LORD! You who fear the LORD, praise the LORD!'),
  ('Psalms', 135, 21, 'Blessed be the LORD from Zion, who dwells in Jerusalem. Praise the LORD!'),
  ('Psalms', 136, 1, 'Give thanks to the LORD, for he is good, for his loving kindness endures forever.'),
  ('Psalms', 136, 2, 'Give thanks to the God of gods, for his loving kindness endures forever.'),
  ('Psalms', 136, 3, 'Give thanks to the Lord of lords, for his loving kindness endures forever;');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 136, 4, 'to him who alone does great wonders, for his loving kindness endures forever;'),
  ('Psalms', 136, 5, 'to him who by understanding made the heavens, for his loving kindness endures forever;'),
  ('Psalms', 136, 6, 'to him who spread out the earth above the waters, for his loving kindness endures forever;'),
  ('Psalms', 136, 7, 'to him who made the great lights, for his loving kindness endures forever;'),
  ('Psalms', 136, 8, 'the sun to rule by day, for his loving kindness endures forever;'),
  ('Psalms', 136, 9, 'the moon and stars to rule by night, for his loving kindness endures forever;'),
  ('Psalms', 136, 10, 'to him who struck down the Egyptian firstborn, for his loving kindness endures forever;'),
  ('Psalms', 136, 11, 'and brought out Israel from among them, for his loving kindness endures forever;'),
  ('Psalms', 136, 12, 'with a strong hand, and with an outstretched arm, for his loving kindness endures forever;'),
  ('Psalms', 136, 13, 'to him who divided the Red Sea apart, for his loving kindness endures forever;'),
  ('Psalms', 136, 14, 'and made Israel to pass through the middle of it, for his loving kindness endures forever;'),
  ('Psalms', 136, 15, 'but overthrew Pharaoh and his army in the Red Sea, for his loving kindness endures forever;'),
  ('Psalms', 136, 16, 'to him who led his people through the wilderness, for his loving kindness endures forever;'),
  ('Psalms', 136, 17, 'to him who struck great kings, for his loving kindness endures forever;'),
  ('Psalms', 136, 18, 'and killed mighty kings, for his loving kindness endures forever;'),
  ('Psalms', 136, 19, 'Sihon king of the Amorites, for his loving kindness endures forever;'),
  ('Psalms', 136, 20, 'Og king of Bashan, for his loving kindness endures forever;'),
  ('Psalms', 136, 21, 'and gave their land as an inheritance, for his loving kindness endures forever;'),
  ('Psalms', 136, 22, 'even a heritage to Israel his servant, for his loving kindness endures forever;'),
  ('Psalms', 136, 23, 'who remembered us in our low estate, for his loving kindness endures forever;'),
  ('Psalms', 136, 24, 'and has delivered us from our adversaries, for his loving kindness endures forever;'),
  ('Psalms', 136, 25, 'who gives food to every creature, for his loving kindness endures forever.'),
  ('Psalms', 136, 26, 'Oh give thanks to the God of heaven, for his loving kindness endures forever.'),
  ('Psalms', 137, 1, 'By the rivers of Babylon, there we sat down. Yes, we wept, when we remembered Zion.'),
  ('Psalms', 137, 2, 'On the willows in that land, we hung up our harps.'),
  ('Psalms', 137, 3, 'For there, those who led us captive asked us for songs. Those who tormented us demanded songs of joy: “Sing us one of the songs of Zion!”'),
  ('Psalms', 137, 4, 'How can we sing the LORD’s song in a foreign land?'),
  ('Psalms', 137, 5, 'If I forget you, Jerusalem, let my right hand forget its skill.'),
  ('Psalms', 137, 6, 'Let my tongue stick to the roof of my mouth if I don’t remember you, if I don’t prefer Jerusalem above my chief joy.'),
  ('Psalms', 137, 7, 'Remember, LORD, against the children of Edom in the day of Jerusalem, who said, “Raze it! Raze it even to its foundation!”'),
  ('Psalms', 137, 8, 'Daughter of Babylon, doomed to destruction, he will be happy who repays you, as you have done to us.'),
  ('Psalms', 137, 9, 'Happy shall he be, who takes and dashes your little ones against the rock.'),
  ('Psalms', 138, 1, 'By David. I will give you thanks with my whole heart. Before the gods, I will sing praises to you.'),
  ('Psalms', 138, 2, 'I will bow down toward your holy temple, and give thanks to your Name for your loving kindness and for your truth; for you have exalted your Name and your Word above all.'),
  ('Psalms', 138, 3, 'In the day that I called, you answered me. You encouraged me with strength in my soul.'),
  ('Psalms', 138, 4, 'All the kings of the earth will give you thanks, LORD, for they have heard the words of your mouth.'),
  ('Psalms', 138, 5, 'Yes, they will sing of the ways of the LORD, for the LORD’s glory is great!'),
  ('Psalms', 138, 6, 'For though the LORD is high, yet he looks after the lowly; but he knows the proud from afar.'),
  ('Psalms', 138, 7, 'Though I walk in the middle of trouble, you will revive me. You will stretch out your hand against the wrath of my enemies. Your right hand will save me.'),
  ('Psalms', 138, 8, 'The LORD will fulfill that which concerns me. Your loving kindness, LORD, endures forever. Don’t forsake the works of your own hands.'),
  ('Psalms', 139, 1, 'For the Chief Musician. A Psalm by David. LORD, you have searched me, and you know me.'),
  ('Psalms', 139, 2, 'You know my sitting down and my rising up. You perceive my thoughts from afar.'),
  ('Psalms', 139, 3, 'You search out my path and my lying down, and are acquainted with all my ways.'),
  ('Psalms', 139, 4, 'For there is not a word on my tongue, but behold, LORD, you know it altogether.'),
  ('Psalms', 139, 5, 'You hem me in behind and before. You laid your hand on me.'),
  ('Psalms', 139, 6, 'This knowledge is beyond me. It’s lofty. I can’t attain it.'),
  ('Psalms', 139, 7, 'Where could I go from your Spirit? Or where could I flee from your presence?'),
  ('Psalms', 139, 8, 'If I ascend up into heaven, you are there. If I make my bed in Sheol, behold, you are there!'),
  ('Psalms', 139, 9, 'If I take the wings of the dawn, and settle in the uttermost parts of the sea,'),
  ('Psalms', 139, 10, 'even there your hand will lead me, and your right hand will hold me.'),
  ('Psalms', 139, 11, 'If I say, “Surely the darkness will overwhelm me. The light around me will be night,”'),
  ('Psalms', 139, 12, 'even the darkness doesn’t hide from you, but the night shines as the day. The darkness is like light to you.'),
  ('Psalms', 139, 13, 'For you formed my inmost being. You knit me together in my mother’s womb.'),
  ('Psalms', 139, 14, 'I will give thanks to you, for I am fearfully and wonderfully made. Your works are wonderful. My soul knows that very well.'),
  ('Psalms', 139, 15, 'My frame wasn’t hidden from you, when I was made in secret, woven together in the depths of the earth.'),
  ('Psalms', 139, 16, 'Your eyes saw my body. In your book they were all written, the days that were ordained for me, when as yet there were none of them.'),
  ('Psalms', 139, 17, 'How precious to me are your thoughts, God! How vast is their sum!'),
  ('Psalms', 139, 18, 'If I would count them, they are more in number than the sand. When I wake up, I am still with you.'),
  ('Psalms', 139, 19, 'If only you, God, would kill the wicked. Get away from me, you bloodthirsty men!'),
  ('Psalms', 139, 20, 'For they speak against you wickedly. Your enemies take your name in vain.'),
  ('Psalms', 139, 21, 'LORD, don’t I hate those who hate you? Am I not grieved with those who rise up against you?'),
  ('Psalms', 139, 22, 'I hate them with perfect hatred. They have become my enemies.'),
  ('Psalms', 139, 23, 'Search me, God, and know my heart. Try me, and know my thoughts.'),
  ('Psalms', 139, 24, 'See if there is any wicked way in me, and lead me in the everlasting way.'),
  ('Psalms', 140, 1, 'For the Chief Musician. A Psalm by David. Deliver me, LORD, from evil men. Preserve me from violent men:'),
  ('Psalms', 140, 2, 'those who devise mischief in their hearts. They continually gather themselves together for war.'),
  ('Psalms', 140, 3, 'They have sharpened their tongues like a serpent. Viper’s poison is under their lips. Selah.'),
  ('Psalms', 140, 4, 'LORD, keep me from the hands of the wicked. Preserve me from the violent men who have determined to trip my feet.'),
  ('Psalms', 140, 5, 'The proud have hidden a snare for me, they have spread the cords of a net by the path. They have set traps for me. Selah.'),
  ('Psalms', 140, 6, 'I said to the LORD, “You are my God.” Listen to the cry of my petitions, LORD.'),
  ('Psalms', 140, 7, 'LORD, the Lord, the strength of my salvation, you have covered my head in the day of battle.'),
  ('Psalms', 140, 8, 'LORD, don’t grant the desires of the wicked. Don’t let their evil plans succeed, or they will become proud. Selah.'),
  ('Psalms', 140, 9, 'As for the head of those who surround me, let the mischief of their own lips cover them.'),
  ('Psalms', 140, 10, 'Let burning coals fall on them. Let them be thrown into the fire, into miry pits, from where they never rise.'),
  ('Psalms', 140, 11, 'An evil speaker won’t be established in the earth. Evil will hunt the violent man to overthrow him.'),
  ('Psalms', 140, 12, 'I know that the LORD will maintain the cause of the afflicted, and justice for the needy.'),
  ('Psalms', 140, 13, 'Surely the righteous will give thanks to your name. The upright will dwell in your presence.'),
  ('Psalms', 141, 1, 'A Psalm by David. LORD, I have called on you. Come to me quickly! Listen to my voice when I call to you.'),
  ('Psalms', 141, 2, 'Let my prayer be set before you like incense; the lifting up of my hands like the evening sacrifice.'),
  ('Psalms', 141, 3, 'Set a watch, LORD, before my mouth. Keep the door of my lips.'),
  ('Psalms', 141, 4, 'Don’t incline my heart to any evil thing, to practice deeds of wickedness with men who work iniquity. Don’t let me eat of their delicacies.'),
  ('Psalms', 141, 5, 'Let the righteous strike me, it is kindness; let him reprove me, it is like oil on the head; don’t let my head refuse it; Yet my prayer is always against evil deeds.'),
  ('Psalms', 141, 6, 'Their judges are thrown down by the sides of the rock. They will hear my words, for they are well spoken.'),
  ('Psalms', 141, 7, '“As when one plows and breaks up the earth, our bones are scattered at the mouth of Sheol.”'),
  ('Psalms', 141, 8, 'For my eyes are on you, LORD, the Lord. I take refuge in you. Don’t leave my soul destitute.'),
  ('Psalms', 141, 9, 'Keep me from the snare which they have laid for me, from the traps of the workers of iniquity.'),
  ('Psalms', 141, 10, 'Let the wicked fall together into their own nets while I pass by.'),
  ('Psalms', 142, 1, 'A contemplation by David, when he was in the cave. A Prayer. I cry with my voice to the LORD. With my voice, I ask the LORD for mercy.'),
  ('Psalms', 142, 2, 'I pour out my complaint before him. I tell him my troubles.'),
  ('Psalms', 142, 3, 'When my spirit was overwhelmed within me, you knew my route. On the path in which I walk, they have hidden a snare for me.'),
  ('Psalms', 142, 4, 'Look on my right, and see; for there is no one who is concerned for me. Refuge has fled from me. No one cares for my soul.'),
  ('Psalms', 142, 5, 'I cried to you, LORD. I said, “You are my refuge, my portion in the land of the living.”'),
  ('Psalms', 142, 6, 'Listen to my cry, for I am in desperate need. Deliver me from my persecutors, for they are too strong for me.'),
  ('Psalms', 142, 7, 'Bring my soul out of prison, that I may give thanks to your name. The righteous will surround me, for you will be good to me.'),
  ('Psalms', 143, 1, 'A Psalm by David. Hear my prayer, LORD. Listen to my petitions. In your faithfulness and righteousness, relieve me.'),
  ('Psalms', 143, 2, 'Don’t enter into judgment with your servant, for in your sight no man living is righteous.'),
  ('Psalms', 143, 3, 'For the enemy pursues my soul. He has struck my life down to the ground. He has made me live in dark places, as those who have been long dead.'),
  ('Psalms', 143, 4, 'Therefore my spirit is overwhelmed within me. My heart within me is desolate.'),
  ('Psalms', 143, 5, 'I remember the days of old. I meditate on all your doings. I contemplate the work of your hands.'),
  ('Psalms', 143, 6, 'I spread out my hands to you. My soul thirsts for you, like a parched land. Selah.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 143, 7, 'Hurry to answer me, LORD. My spirit fails. Don’t hide your face from me, so that I don’t become like those who go down into the pit.'),
  ('Psalms', 143, 8, 'Cause me to hear your loving kindness in the morning, for I trust in you. Cause me to know the way in which I should walk, for I lift up my soul to you.'),
  ('Psalms', 143, 9, 'Deliver me, LORD, from my enemies. I flee to you to hide me.'),
  ('Psalms', 143, 10, 'Teach me to do your will, for you are my God. Your Spirit is good. Lead me in the land of uprightness.'),
  ('Psalms', 143, 11, 'Revive me, LORD, for your name’s sake. In your righteousness, bring my soul out of trouble.'),
  ('Psalms', 143, 12, 'In your loving kindness, cut off my enemies, and destroy all those who afflict my soul, for I am your servant.'),
  ('Psalms', 144, 1, 'By David. Blessed be the LORD, my rock, who trains my hands to war, and my fingers to battle—'),
  ('Psalms', 144, 2, 'my loving kindness, my fortress, my high tower, my deliverer, my shield, and he in whom I take refuge, who subdues my people under me.'),
  ('Psalms', 144, 3, 'LORD, what is man, that you care for him? Or the son of man, that you think of him?'),
  ('Psalms', 144, 4, 'Man is like a breath. His days are like a shadow that passes away.'),
  ('Psalms', 144, 5, 'Part your heavens, LORD, and come down. Touch the mountains, and they will smoke.'),
  ('Psalms', 144, 6, 'Throw out lightning, and scatter them. Send out your arrows, and rout them.'),
  ('Psalms', 144, 7, 'Stretch out your hand from above, rescue me, and deliver me out of great waters, out of the hands of foreigners,'),
  ('Psalms', 144, 8, 'whose mouths speak deceit, whose right hand is a right hand of falsehood.'),
  ('Psalms', 144, 9, 'I will sing a new song to you, God. On a ten-stringed lyre, I will sing praises to you.'),
  ('Psalms', 144, 10, 'You are he who gives salvation to kings, who rescues David, his servant, from the deadly sword.'),
  ('Psalms', 144, 11, 'Rescue me, and deliver me out of the hands of foreigners, whose mouths speak deceit, whose right hand is a right hand of falsehood.'),
  ('Psalms', 144, 12, 'Then our sons will be like well-nurtured plants, our daughters like pillars carved to adorn a palace.'),
  ('Psalms', 144, 13, 'Our barns are full, filled with all kinds of provision. Our sheep produce thousands and ten thousands in our fields.'),
  ('Psalms', 144, 14, 'Our oxen will pull heavy loads. There is no breaking in, and no going away, and no outcry in our streets.'),
  ('Psalms', 144, 15, 'Happy are the people who are in such a situation. Happy are the people whose God is the LORD.'),
  ('Psalms', 145, 1, 'A praise psalm by David. I will exalt you, my God, the King. I will praise your name forever and ever.'),
  ('Psalms', 145, 2, 'Every day I will praise you. I will extol your name forever and ever.'),
  ('Psalms', 145, 3, 'Great is the LORD, and greatly to be praised! His greatness is unsearchable.'),
  ('Psalms', 145, 4, 'One generation will commend your works to another, and will declare your mighty acts.'),
  ('Psalms', 145, 5, 'I will meditate on the glorious majesty of your honor, on your wondrous works.'),
  ('Psalms', 145, 6, 'Men will speak of the might of your awesome acts. I will declare your greatness.'),
  ('Psalms', 145, 7, 'They will utter the memory of your great goodness, and will sing of your righteousness.'),
  ('Psalms', 145, 8, 'The LORD is gracious, merciful, slow to anger, and of great loving kindness.'),
  ('Psalms', 145, 9, 'The LORD is good to all. His tender mercies are over all his works.'),
  ('Psalms', 145, 10, 'All your works will give thanks to you, LORD. Your saints will extol you.'),
  ('Psalms', 145, 11, 'They will speak of the glory of your kingdom, and talk about your power,'),
  ('Psalms', 145, 12, 'to make known to the sons of men his mighty acts, the glory of the majesty of his kingdom.'),
  ('Psalms', 145, 13, 'Your kingdom is an everlasting kingdom. Your dominion endures throughout all generations. The LORD is faithful in all his words, and loving in all his deeds.'),
  ('Psalms', 145, 14, 'The LORD upholds all who fall, and raises up all those who are bowed down.'),
  ('Psalms', 145, 15, 'The eyes of all wait for you. You give them their food in due season.'),
  ('Psalms', 145, 16, 'You open your hand, and satisfy the desire of every living thing.'),
  ('Psalms', 145, 17, 'The LORD is righteous in all his ways, and gracious in all his works.'),
  ('Psalms', 145, 18, 'The LORD is near to all those who call on him, to all who call on him in truth.'),
  ('Psalms', 145, 19, 'He will fulfill the desire of those who fear him. He also will hear their cry, and will save them.'),
  ('Psalms', 145, 20, 'The LORD preserves all those who love him, but he will destroy all the wicked.'),
  ('Psalms', 145, 21, 'My mouth will speak the praise of the LORD. Let all flesh bless his holy name forever and ever.'),
  ('Psalms', 146, 1, 'Praise the LORD! Praise the LORD, my soul.'),
  ('Psalms', 146, 2, 'While I live, I will praise the LORD. I will sing praises to my God as long as I exist.'),
  ('Psalms', 146, 3, 'Don’t put your trust in princes, in a son of man in whom there is no help.'),
  ('Psalms', 146, 4, 'His spirit departs, and he returns to the earth. In that very day, his thoughts perish.'),
  ('Psalms', 146, 5, 'Happy is he who has the God of Jacob for his help, whose hope is in the LORD, his God,'),
  ('Psalms', 146, 6, 'who made heaven and earth, the sea, and all that is in them; who keeps truth forever;'),
  ('Psalms', 146, 7, 'who executes justice for the oppressed; who gives food to the hungry. The LORD frees the prisoners.'),
  ('Psalms', 146, 8, 'The LORD opens the eyes of the blind. The LORD raises up those who are bowed down. The LORD loves the righteous.'),
  ('Psalms', 146, 9, 'The LORD preserves the foreigners. He upholds the fatherless and widow, but he turns the way of the wicked upside down.'),
  ('Psalms', 146, 10, 'The LORD will reign forever; your God, O Zion, to all generations. Praise the LORD!'),
  ('Psalms', 147, 1, 'Praise the LORD, for it is good to sing praises to our God; for it is pleasant and fitting to praise him.'),
  ('Psalms', 147, 2, 'The LORD builds up Jerusalem. He gathers together the outcasts of Israel.'),
  ('Psalms', 147, 3, 'He heals the broken in heart, and binds up their wounds.'),
  ('Psalms', 147, 4, 'He counts the number of the stars. He calls them all by their names.'),
  ('Psalms', 147, 5, 'Great is our Lord, and mighty in power. His understanding is infinite.'),
  ('Psalms', 147, 6, 'The LORD upholds the humble. He brings the wicked down to the ground.'),
  ('Psalms', 147, 7, 'Sing to the LORD with thanksgiving. Sing praises on the harp to our God,'),
  ('Psalms', 147, 8, 'who covers the sky with clouds, who prepares rain for the earth, who makes grass grow on the mountains.'),
  ('Psalms', 147, 9, 'He provides food for the livestock, and for the young ravens when they call.'),
  ('Psalms', 147, 10, 'He doesn’t delight in the strength of the horse. He takes no pleasure in the legs of a man.'),
  ('Psalms', 147, 11, 'The LORD takes pleasure in those who fear him, in those who hope in his loving kindness.'),
  ('Psalms', 147, 12, 'Praise the LORD, Jerusalem! Praise your God, Zion!'),
  ('Psalms', 147, 13, 'For he has strengthened the bars of your gates. He has blessed your children within you.'),
  ('Psalms', 147, 14, 'He makes peace in your borders. He fills you with the finest of the wheat.'),
  ('Psalms', 147, 15, 'He sends out his commandment to the earth. His word runs very swiftly.'),
  ('Psalms', 147, 16, 'He gives snow like wool, and scatters frost like ashes.'),
  ('Psalms', 147, 17, 'He hurls down his hail like pebbles. Who can stand before his cold?'),
  ('Psalms', 147, 18, 'He sends out his word, and melts them. He causes his wind to blow, and the waters flow.'),
  ('Psalms', 147, 19, 'He shows his word to Jacob, his statutes and his ordinances to Israel.'),
  ('Psalms', 147, 20, 'He has not done this for just any nation. They don’t know his ordinances. Praise the LORD!'),
  ('Psalms', 148, 1, 'Praise the LORD! Praise the LORD from the heavens! Praise him in the heights!'),
  ('Psalms', 148, 2, 'Praise him, all his angels! Praise him, all his army!'),
  ('Psalms', 148, 3, 'Praise him, sun and moon! Praise him, all you shining stars!'),
  ('Psalms', 148, 4, 'Praise him, you heavens of heavens, you waters that are above the heavens.'),
  ('Psalms', 148, 5, 'Let them praise the LORD’s name, for he commanded, and they were created.'),
  ('Psalms', 148, 6, 'He has also established them forever and ever. He has made a decree which will not pass away.'),
  ('Psalms', 148, 7, 'Praise the LORD from the earth, you great sea creatures, and all depths,'),
  ('Psalms', 148, 8, 'lightning and hail, snow and clouds, stormy wind, fulfilling his word,'),
  ('Psalms', 148, 9, 'mountains and all hills, fruit trees and all cedars,'),
  ('Psalms', 148, 10, 'wild animals and all livestock, small creatures and flying birds,'),
  ('Psalms', 148, 11, 'kings of the earth and all peoples, princes and all judges of the earth,'),
  ('Psalms', 148, 12, 'both young men and maidens, old men and children.'),
  ('Psalms', 148, 13, 'Let them praise the LORD’s name, for his name alone is exalted. His glory is above the earth and the heavens.'),
  ('Psalms', 148, 14, 'He has lifted up the horn of his people, the praise of all his saints, even of the children of Israel, a people near to him. Praise the LORD!'),
  ('Psalms', 149, 1, 'Praise the LORD! Sing to the LORD a new song, his praise in the assembly of the saints.'),
  ('Psalms', 149, 2, 'Let Israel rejoice in him who made them. Let the children of Zion be joyful in their King.'),
  ('Psalms', 149, 3, 'Let them praise his name in the dance! Let them sing praises to him with tambourine and harp!'),
  ('Psalms', 149, 4, 'For the LORD takes pleasure in his people. He crowns the humble with salvation.'),
  ('Psalms', 149, 5, 'Let the saints rejoice in honor. Let them sing for joy on their beds.'),
  ('Psalms', 149, 6, 'May the high praises of God be in their mouths, and a two-edged sword in their hand,'),
  ('Psalms', 149, 7, 'to execute vengeance on the nations, and punishments on the peoples;'),
  ('Psalms', 149, 8, 'to bind their kings with chains, and their nobles with fetters of iron;'),
  ('Psalms', 149, 9, 'to execute on them the written judgment. All his saints have this honor. Praise the LORD!'),
  ('Psalms', 150, 1, 'Praise the LORD! Praise God in his sanctuary! Praise him in his heavens for his acts of power!'),
  ('Psalms', 150, 2, 'Praise him for his mighty acts! Praise him according to his excellent greatness!'),
  ('Psalms', 150, 3, 'Praise him with the sounding of the trumpet! Praise him with harp and lyre!'),
  ('Psalms', 150, 4, 'Praise him with tambourine and dancing! Praise him with stringed instruments and flute!'),
  ('Psalms', 150, 5, 'Praise him with loud cymbals! Praise him with resounding cymbals!');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Psalms', 150, 6, 'Let everything that has breath praise the LORD! Praise the LORD!'),
  ('Proverbs', 1, 1, 'The proverbs of Solomon, the son of David, king of Israel:'),
  ('Proverbs', 1, 2, 'to know wisdom and instruction; to discern the words of understanding;'),
  ('Proverbs', 1, 3, 'to receive instruction in wise dealing, in righteousness, justice, and equity;'),
  ('Proverbs', 1, 4, 'to give prudence to the simple, knowledge and discretion to the young man—'),
  ('Proverbs', 1, 5, 'that the wise man may hear, and increase in learning; that the man of understanding may attain to sound counsel;'),
  ('Proverbs', 1, 6, 'to understand a proverb and parables, the words and riddles of the wise.'),
  ('Proverbs', 1, 7, 'The fear of the LORD is the beginning of knowledge, but the foolish despise wisdom and instruction.'),
  ('Proverbs', 1, 8, 'My son, listen to your father’s instruction, and don’t forsake your mother’s teaching;'),
  ('Proverbs', 1, 9, 'for they will be a garland to grace your head, and chains around your neck.'),
  ('Proverbs', 1, 10, 'My son, if sinners entice you, don’t consent.'),
  ('Proverbs', 1, 11, 'If they say, “Come with us. Let’s lie in wait for blood. Let’s lurk secretly for the innocent without cause.'),
  ('Proverbs', 1, 12, 'Let’s swallow them up alive like Sheol, and whole, like those who go down into the pit.'),
  ('Proverbs', 1, 13, 'We’ll find all valuable wealth. We’ll fill our houses with plunder.'),
  ('Proverbs', 1, 14, 'You shall cast your lot among us. We’ll all have one purse”—'),
  ('Proverbs', 1, 15, 'my son, don’t walk on the path with them. Keep your foot from their path,'),
  ('Proverbs', 1, 16, 'for their feet run to evil. They hurry to shed blood.'),
  ('Proverbs', 1, 17, 'For the net is spread in vain in the sight of any bird;'),
  ('Proverbs', 1, 18, 'but these lay in wait for their own blood. They lurk secretly for their own lives.'),
  ('Proverbs', 1, 19, 'So are the ways of everyone who is greedy for gain. It takes away the life of its owners.'),
  ('Proverbs', 1, 20, 'Wisdom calls aloud in the street. She utters her voice in the public squares.'),
  ('Proverbs', 1, 21, 'She calls at the head of noisy places. At the entrance of the city gates, she utters her words:'),
  ('Proverbs', 1, 22, '“How long, you simple ones, will you love simplicity? How long will mockers delight themselves in mockery, and fools hate knowledge?'),
  ('Proverbs', 1, 23, 'Turn at my reproof. Behold, I will pour out my spirit on you. I will make known my words to you.'),
  ('Proverbs', 1, 24, 'Because I have called, and you have refused; I have stretched out my hand, and no one has paid attention;'),
  ('Proverbs', 1, 25, 'but you have ignored all my counsel, and wanted none of my reproof;'),
  ('Proverbs', 1, 26, 'I also will laugh at your disaster. I will mock when calamity overtakes you,'),
  ('Proverbs', 1, 27, 'when calamity overtakes you like a storm, when your disaster comes on like a whirlwind, when distress and anguish come on you.'),
  ('Proverbs', 1, 28, 'Then they will call on me, but I will not answer. They will seek me diligently, but they will not find me,'),
  ('Proverbs', 1, 29, 'because they hated knowledge, and didn’t choose the fear of the LORD.'),
  ('Proverbs', 1, 30, 'They wanted none of my counsel. They despised all my reproof.'),
  ('Proverbs', 1, 31, 'Therefore they will eat of the fruit of their own way, and be filled with their own schemes.'),
  ('Proverbs', 1, 32, 'For the backsliding of the simple will kill them. The careless ease of fools will destroy them.'),
  ('Proverbs', 1, 33, 'But whoever listens to me will dwell securely, and will be at ease, without fear of harm.”'),
  ('Proverbs', 2, 1, 'My son, if you will receive my words, and store up my commandments within you,'),
  ('Proverbs', 2, 2, 'so as to turn your ear to wisdom, and apply your heart to understanding;'),
  ('Proverbs', 2, 3, 'yes, if you call out for discernment, and lift up your voice for understanding;'),
  ('Proverbs', 2, 4, 'if you seek her as silver, and search for her as for hidden treasures;'),
  ('Proverbs', 2, 5, 'then you will understand the fear of the LORD, and find the knowledge of God.'),
  ('Proverbs', 2, 6, 'For the LORD gives wisdom. Out of his mouth comes knowledge and understanding.'),
  ('Proverbs', 2, 7, 'He lays up sound wisdom for the upright. He is a shield to those who walk in integrity,'),
  ('Proverbs', 2, 8, 'that he may guard the paths of justice, and preserve the way of his saints.'),
  ('Proverbs', 2, 9, 'Then you will understand righteousness and justice, equity and every good path.'),
  ('Proverbs', 2, 10, 'For wisdom will enter into your heart. Knowledge will be pleasant to your soul.'),
  ('Proverbs', 2, 11, 'Discretion will watch over you. Understanding will keep you,'),
  ('Proverbs', 2, 12, 'to deliver you from the way of evil, from the men who speak perverse things,'),
  ('Proverbs', 2, 13, 'who forsake the paths of uprightness, to walk in the ways of darkness,'),
  ('Proverbs', 2, 14, 'who rejoice to do evil, and delight in the perverseness of evil,'),
  ('Proverbs', 2, 15, 'who are crooked in their ways, and wayward in their paths,'),
  ('Proverbs', 2, 16, 'to deliver you from the strange woman, even from the foreigner who flatters with her words,'),
  ('Proverbs', 2, 17, 'who forsakes the friend of her youth, and forgets the covenant of her God;'),
  ('Proverbs', 2, 18, 'for her house leads down to death, her paths to the departed spirits.'),
  ('Proverbs', 2, 19, 'None who go to her return again, neither do they attain to the paths of life.'),
  ('Proverbs', 2, 20, 'Therefore walk in the way of good men, and keep the paths of the righteous.'),
  ('Proverbs', 2, 21, 'For the upright will dwell in the land. The perfect will remain in it.'),
  ('Proverbs', 2, 22, 'But the wicked will be cut off from the land. The treacherous will be rooted out of it.'),
  ('Proverbs', 3, 1, 'My son, don’t forget my teaching, but let your heart keep my commandments,'),
  ('Proverbs', 3, 2, 'for they will add to you length of days, years of life, and peace.'),
  ('Proverbs', 3, 3, 'Don’t let kindness and truth forsake you. Bind them around your neck. Write them on the tablet of your heart.'),
  ('Proverbs', 3, 4, 'So you will find favor, and good understanding in the sight of God and man.'),
  ('Proverbs', 3, 5, 'Trust in the LORD with all your heart, and don’t lean on your own understanding.'),
  ('Proverbs', 3, 6, 'In all your ways acknowledge him, and he will make your paths straight.'),
  ('Proverbs', 3, 7, 'Don’t be wise in your own eyes. Fear the LORD, and depart from evil.'),
  ('Proverbs', 3, 8, 'It will be health to your body, and nourishment to your bones.'),
  ('Proverbs', 3, 9, 'Honor the LORD with your substance, with the first fruits of all your increase;'),
  ('Proverbs', 3, 10, 'so your barns will be filled with plenty, and your vats will overflow with new wine.'),
  ('Proverbs', 3, 11, 'My son, don’t despise the LORD’s discipline, neither be weary of his correction;'),
  ('Proverbs', 3, 12, 'for whom the LORD loves, he corrects, even as a father reproves the son in whom he delights.'),
  ('Proverbs', 3, 13, 'Happy is the man who finds wisdom, the man who gets understanding.'),
  ('Proverbs', 3, 14, 'For her good profit is better than getting silver, and her return is better than fine gold.'),
  ('Proverbs', 3, 15, 'She is more precious than rubies. None of the things you can desire are to be compared to her.'),
  ('Proverbs', 3, 16, 'Length of days is in her right hand. In her left hand are riches and honor.'),
  ('Proverbs', 3, 17, 'Her ways are ways of pleasantness. All her paths are peace.'),
  ('Proverbs', 3, 18, 'She is a tree of life to those who lay hold of her. Happy is everyone who retains her.'),
  ('Proverbs', 3, 19, 'By wisdom the LORD founded the earth. By understanding, he established the heavens.'),
  ('Proverbs', 3, 20, 'By his knowledge, the depths were broken up, and the skies drop down the dew.'),
  ('Proverbs', 3, 21, 'My son, let them not depart from your eyes. Keep sound wisdom and discretion,'),
  ('Proverbs', 3, 22, 'so they will be life to your soul, and grace for your neck.'),
  ('Proverbs', 3, 23, 'Then you shall walk in your way securely. Your foot won’t stumble.'),
  ('Proverbs', 3, 24, 'When you lie down, you will not be afraid. Yes, you will lie down, and your sleep will be sweet.'),
  ('Proverbs', 3, 25, 'Don’t be afraid of sudden fear, neither of the desolation of the wicked, when it comes;'),
  ('Proverbs', 3, 26, 'for the LORD will be your confidence, and will keep your foot from being taken.'),
  ('Proverbs', 3, 27, 'Don’t withhold good from those to whom it is due, when it is in the power of your hand to do it.'),
  ('Proverbs', 3, 28, 'Don’t say to your neighbor, “Go, and come again; tomorrow I will give it to you,” when you have it by you.'),
  ('Proverbs', 3, 29, 'Don’t devise evil against your neighbor, since he dwells securely by you.'),
  ('Proverbs', 3, 30, 'Don’t strive with a man without cause, if he has done you no harm.'),
  ('Proverbs', 3, 31, 'Don’t envy the man of violence. Choose none of his ways.'),
  ('Proverbs', 3, 32, 'For the perverse is an abomination to the LORD, but his friendship is with the upright.'),
  ('Proverbs', 3, 33, 'The LORD’s curse is in the house of the wicked, but he blesses the habitation of the righteous.'),
  ('Proverbs', 3, 34, 'Surely he mocks the mockers, but he gives grace to the humble.'),
  ('Proverbs', 3, 35, 'The wise will inherit glory, but shame will be the promotion of fools.'),
  ('Proverbs', 4, 1, 'Listen, sons, to a father’s instruction. Pay attention and know understanding;'),
  ('Proverbs', 4, 2, 'for I give you sound learning. Don’t forsake my law.'),
  ('Proverbs', 4, 3, 'For I was a son to my father, tender and an only child in the sight of my mother.'),
  ('Proverbs', 4, 4, 'He taught me, and said to me: “Let your heart retain my words. Keep my commandments, and live.'),
  ('Proverbs', 4, 5, 'Get wisdom. Get understanding. Don’t forget, and don’t deviate from the words of my mouth.'),
  ('Proverbs', 4, 6, 'Don’t forsake her, and she will preserve you. Love her, and she will keep you.'),
  ('Proverbs', 4, 7, 'Wisdom is supreme. Get wisdom. Yes, though it costs all your possessions, get understanding.'),
  ('Proverbs', 4, 8, 'Esteem her, and she will exalt you. She will bring you to honor when you embrace her.'),
  ('Proverbs', 4, 9, 'She will give to your head a garland of grace. She will deliver a crown of splendor to you.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Proverbs', 4, 10, 'Listen, my son, and receive my sayings. The years of your life will be many.'),
  ('Proverbs', 4, 11, 'I have taught you in the way of wisdom. I have led you in straight paths.'),
  ('Proverbs', 4, 12, 'When you go, your steps will not be hampered. When you run, you will not stumble.'),
  ('Proverbs', 4, 13, 'Take firm hold of instruction. Don’t let her go. Keep her, for she is your life.'),
  ('Proverbs', 4, 14, 'Don’t enter into the path of the wicked. Don’t walk in the way of evil men.'),
  ('Proverbs', 4, 15, 'Avoid it, and don’t pass by it. Turn from it, and pass on.'),
  ('Proverbs', 4, 16, 'For they don’t sleep unless they do evil. Their sleep is taken away, unless they make someone fall.'),
  ('Proverbs', 4, 17, 'For they eat the bread of wickedness and drink the wine of violence.'),
  ('Proverbs', 4, 18, 'But the path of the righteous is like the dawning light that shines more and more until the perfect day.'),
  ('Proverbs', 4, 19, 'The way of the wicked is like darkness. They don’t know what they stumble over.'),
  ('Proverbs', 4, 20, 'My son, attend to my words. Turn your ear to my sayings.'),
  ('Proverbs', 4, 21, 'Let them not depart from your eyes. Keep them in the center of your heart.'),
  ('Proverbs', 4, 22, 'For they are life to those who find them, and health to their whole body.'),
  ('Proverbs', 4, 23, 'Keep your heart with all diligence, for out of it is the wellspring of life.'),
  ('Proverbs', 4, 24, 'Put away from yourself a perverse mouth. Put corrupt lips far from you.'),
  ('Proverbs', 4, 25, 'Let your eyes look straight ahead. Fix your gaze directly before you.'),
  ('Proverbs', 4, 26, 'Make the path of your feet level. Let all of your ways be established.'),
  ('Proverbs', 4, 27, 'Don’t turn to the right hand nor to the left. Remove your foot from evil.'),
  ('Proverbs', 5, 1, 'My son, pay attention to my wisdom. Turn your ear to my understanding,'),
  ('Proverbs', 5, 2, 'that you may maintain discretion, that your lips may preserve knowledge.'),
  ('Proverbs', 5, 3, 'For the lips of an adulteress drip honey. Her mouth is smoother than oil,'),
  ('Proverbs', 5, 4, 'but in the end she is as bitter as wormwood, and as sharp as a two-edged sword.'),
  ('Proverbs', 5, 5, 'Her feet go down to death. Her steps lead straight to Sheol.'),
  ('Proverbs', 5, 6, 'She gives no thought to the way of life. Her ways are crooked, and she doesn’t know it.'),
  ('Proverbs', 5, 7, 'Now therefore, my sons, listen to me. Don’t depart from the words of my mouth.'),
  ('Proverbs', 5, 8, 'Remove your way far from her. Don’t come near the door of her house,'),
  ('Proverbs', 5, 9, 'lest you give your honor to others, and your years to the cruel one;'),
  ('Proverbs', 5, 10, 'lest strangers feast on your wealth, and your labors enrich another man’s house.'),
  ('Proverbs', 5, 11, 'You will groan at your latter end, when your flesh and your body are consumed,'),
  ('Proverbs', 5, 12, 'and say, “How I have hated instruction, and my heart despised reproof.'),
  ('Proverbs', 5, 13, 'I haven’t obeyed the voice of my teachers, nor turned my ear to those who instructed me!'),
  ('Proverbs', 5, 14, 'I have come to the brink of utter ruin, among the gathered assembly.”'),
  ('Proverbs', 5, 15, 'Drink water out of your own cistern, running water out of your own well.'),
  ('Proverbs', 5, 16, 'Should your springs overflow in the streets, streams of water in the public squares?'),
  ('Proverbs', 5, 17, 'Let them be for yourself alone, not for strangers with you.'),
  ('Proverbs', 5, 18, 'Let your spring be blessed. Rejoice in the wife of your youth.'),
  ('Proverbs', 5, 19, 'A loving doe and a graceful deer— let her breasts satisfy you at all times. Be captivated always with her love.'),
  ('Proverbs', 5, 20, 'For why should you, my son, be captivated with an adulteress? Why embrace the bosom of another?'),
  ('Proverbs', 5, 21, 'For the ways of man are before the LORD’s eyes. He examines all his paths.'),
  ('Proverbs', 5, 22, 'The evil deeds of the wicked ensnare him. The cords of his sin hold him firmly.'),
  ('Proverbs', 5, 23, 'He will die for lack of instruction. In the greatness of his folly, he will go astray.'),
  ('Proverbs', 6, 1, 'My son, if you have become collateral for your neighbor, if you have struck your hands in pledge for a stranger,'),
  ('Proverbs', 6, 2, 'you are trapped by the words of your mouth; you are ensnared with the words of your mouth.'),
  ('Proverbs', 6, 3, 'Do this now, my son, and deliver yourself, since you have come into the hand of your neighbor. Go, humble yourself. Press your plea with your neighbor.'),
  ('Proverbs', 6, 4, 'Give no sleep to your eyes, nor slumber to your eyelids.'),
  ('Proverbs', 6, 5, 'Free yourself, like a gazelle from the hand of the hunter, like a bird from the snare of the fowler.'),
  ('Proverbs', 6, 6, 'Go to the ant, you sluggard. Consider her ways, and be wise;'),
  ('Proverbs', 6, 7, 'which having no chief, overseer, or ruler,'),
  ('Proverbs', 6, 8, 'provides her bread in the summer, and gathers her food in the harvest.'),
  ('Proverbs', 6, 9, 'How long will you sleep, sluggard? When will you arise out of your sleep?'),
  ('Proverbs', 6, 10, 'A little sleep, a little slumber, a little folding of the hands to sleep—'),
  ('Proverbs', 6, 11, 'so your poverty will come as a robber, and your scarcity as an armed man.'),
  ('Proverbs', 6, 12, 'A worthless person, a man of iniquity, is he who walks with a perverse mouth,'),
  ('Proverbs', 6, 13, 'who winks with his eyes, who signals with his feet, who motions with his fingers,'),
  ('Proverbs', 6, 14, 'in whose heart is perverseness, who devises evil continually, who always sows discord.'),
  ('Proverbs', 6, 15, 'Therefore his calamity will come suddenly. He will be broken suddenly, and that without remedy.'),
  ('Proverbs', 6, 16, 'There are six things which the LORD hates; yes, seven which are an abomination to him:'),
  ('Proverbs', 6, 17, 'arrogant eyes, a lying tongue, hands that shed innocent blood,'),
  ('Proverbs', 6, 18, 'a heart that devises wicked schemes, feet that are swift in running to mischief,'),
  ('Proverbs', 6, 19, 'a false witness who utters lies, and he who sows discord among brothers.'),
  ('Proverbs', 6, 20, 'My son, keep your father’s commandment, and don’t forsake your mother’s teaching.'),
  ('Proverbs', 6, 21, 'Bind them continually on your heart. Tie them around your neck.'),
  ('Proverbs', 6, 22, 'When you walk, it will lead you. When you sleep, it will watch over you. When you awake, it will talk with you.'),
  ('Proverbs', 6, 23, 'For the commandment is a lamp, and the law is light. Reproofs of instruction are the way of life,'),
  ('Proverbs', 6, 24, 'to keep you from the immoral woman, from the flattery of the wayward wife’s tongue.'),
  ('Proverbs', 6, 25, 'Don’t lust after her beauty in your heart, neither let her captivate you with her eyelids.'),
  ('Proverbs', 6, 26, 'For a prostitute reduces you to a piece of bread. The adulteress hunts for your precious life.'),
  ('Proverbs', 6, 27, 'Can a man scoop fire into his lap, and his clothes not be burned?'),
  ('Proverbs', 6, 28, 'Or can one walk on hot coals, and his feet not be scorched?'),
  ('Proverbs', 6, 29, 'So is he who goes in to his neighbor’s wife. Whoever touches her will not be unpunished.'),
  ('Proverbs', 6, 30, 'Men don’t despise a thief if he steals to satisfy himself when he is hungry,'),
  ('Proverbs', 6, 31, 'but if he is found, he shall restore seven times. He shall give all the wealth of his house.'),
  ('Proverbs', 6, 32, 'He who commits adultery with a woman is void of understanding. He who does it destroys his own soul.'),
  ('Proverbs', 6, 33, 'He will get wounds and dishonor. His reproach will not be wiped away.'),
  ('Proverbs', 6, 34, 'For jealousy arouses the fury of the husband. He won’t spare in the day of vengeance.'),
  ('Proverbs', 6, 35, 'He won’t regard any ransom, neither will he rest content, though you give many gifts.'),
  ('Proverbs', 7, 1, 'My son, keep my words. Lay up my commandments within you.'),
  ('Proverbs', 7, 2, 'Keep my commandments and live! Guard my teaching as the apple of your eye.'),
  ('Proverbs', 7, 3, 'Bind them on your fingers. Write them on the tablet of your heart.'),
  ('Proverbs', 7, 4, 'Tell wisdom, “You are my sister.” Call understanding your relative,'),
  ('Proverbs', 7, 5, 'that they may keep you from the strange woman, from the foreigner who flatters with her words.'),
  ('Proverbs', 7, 6, 'For at the window of my house, I looked out through my lattice.'),
  ('Proverbs', 7, 7, 'I saw among the simple ones. I discerned among the youths a young man void of understanding,'),
  ('Proverbs', 7, 8, 'passing through the street near her corner, he went the way to her house,'),
  ('Proverbs', 7, 9, 'in the twilight, in the evening of the day, in the middle of the night and in the darkness.'),
  ('Proverbs', 7, 10, 'Behold, there a woman met him with the attire of a prostitute, and with crafty intent.'),
  ('Proverbs', 7, 11, 'She is loud and defiant. Her feet don’t stay in her house.'),
  ('Proverbs', 7, 12, 'Now she is in the streets, now in the squares, and lurking at every corner.'),
  ('Proverbs', 7, 13, 'So she caught him, and kissed him. With an impudent face she said to him:'),
  ('Proverbs', 7, 14, '“Sacrifices of peace offerings are with me. Today I have paid my vows.'),
  ('Proverbs', 7, 15, 'Therefore I came out to meet you, to diligently seek your face, and I have found you.'),
  ('Proverbs', 7, 16, 'I have spread my couch with carpets of tapestry, with striped cloths of the yarn of Egypt.'),
  ('Proverbs', 7, 17, 'I have perfumed my bed with myrrh, aloes, and cinnamon.'),
  ('Proverbs', 7, 18, 'Come, let’s take our fill of loving until the morning. Let’s solace ourselves with loving.'),
  ('Proverbs', 7, 19, 'For my husband isn’t at home. He has gone on a long journey.'),
  ('Proverbs', 7, 20, 'He has taken a bag of money with him. He will come home at the full moon.”'),
  ('Proverbs', 7, 21, 'With persuasive words, she led him astray. With the flattering of her lips, she seduced him.'),
  ('Proverbs', 7, 22, 'He followed her immediately, as an ox goes to the slaughter, as a fool stepping into a noose.'),
  ('Proverbs', 7, 23, 'Until an arrow strikes through his liver, as a bird hurries to the snare, and doesn’t know that it will cost his life.'),
  ('Proverbs', 7, 24, 'Now therefore, sons, listen to me. Pay attention to the words of my mouth.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Proverbs', 7, 25, 'Don’t let your heart turn to her ways. Don’t go astray in her paths,'),
  ('Proverbs', 7, 26, 'for she has thrown down many wounded. Yes, all her slain are a mighty army.'),
  ('Proverbs', 7, 27, 'Her house is the way to Sheol, going down to the rooms of death.'),
  ('Proverbs', 8, 1, 'Doesn’t wisdom cry out? Doesn’t understanding raise her voice?'),
  ('Proverbs', 8, 2, 'On the top of high places by the way, where the paths meet, she stands.'),
  ('Proverbs', 8, 3, 'Beside the gates, at the entry of the city, at the entry doors, she cries aloud:'),
  ('Proverbs', 8, 4, '“I call to you men! I send my voice to the sons of mankind.'),
  ('Proverbs', 8, 5, 'You simple, understand prudence! You fools, be of an understanding heart!'),
  ('Proverbs', 8, 6, 'Hear, for I will speak excellent things. The opening of my lips is for right things.'),
  ('Proverbs', 8, 7, 'For my mouth speaks truth. Wickedness is an abomination to my lips.'),
  ('Proverbs', 8, 8, 'All the words of my mouth are in righteousness. There is nothing crooked or perverse in them.'),
  ('Proverbs', 8, 9, 'They are all plain to him who understands, right to those who find knowledge.'),
  ('Proverbs', 8, 10, 'Receive my instruction rather than silver, knowledge rather than choice gold.'),
  ('Proverbs', 8, 11, 'For wisdom is better than rubies. All the things that may be desired can’t be compared to it.'),
  ('Proverbs', 8, 12, '“I, wisdom, have made prudence my dwelling. Find out knowledge and discretion.'),
  ('Proverbs', 8, 13, 'The fear of the LORD is to hate evil. I hate pride, arrogance, the evil way, and the perverse mouth.'),
  ('Proverbs', 8, 14, 'Counsel and sound knowledge are mine. I have understanding and power.'),
  ('Proverbs', 8, 15, 'By me kings reign, and princes decree justice.'),
  ('Proverbs', 8, 16, 'By me princes rule, nobles, and all the righteous rulers of the earth.'),
  ('Proverbs', 8, 17, 'I love those who love me. Those who seek me diligently will find me.'),
  ('Proverbs', 8, 18, 'With me are riches, honor, enduring wealth, and prosperity.'),
  ('Proverbs', 8, 19, 'My fruit is better than gold, yes, than fine gold, my yield than choice silver.'),
  ('Proverbs', 8, 20, 'I walk in the way of righteousness, in the middle of the paths of justice,'),
  ('Proverbs', 8, 21, 'that I may give wealth to those who love me. I fill their treasuries.'),
  ('Proverbs', 8, 22, '“The LORD possessed me in the beginning of his work, before his deeds of old.'),
  ('Proverbs', 8, 23, 'I was set up from everlasting, from the beginning, before the earth existed.'),
  ('Proverbs', 8, 24, 'When there were no depths, I was born, when there were no springs abounding with water.'),
  ('Proverbs', 8, 25, 'Before the mountains were settled in place, before the hills, I was born;'),
  ('Proverbs', 8, 26, 'while as yet he had not made the earth, nor the fields, nor the beginning of the dust of the world.'),
  ('Proverbs', 8, 27, 'When he established the heavens, I was there. When he set a circle on the surface of the deep,'),
  ('Proverbs', 8, 28, 'when he established the clouds above, when the springs of the deep became strong,'),
  ('Proverbs', 8, 29, 'when he gave to the sea its boundary, that the waters should not violate his commandment, when he marked out the foundations of the earth,'),
  ('Proverbs', 8, 30, 'then I was the craftsman by his side. I was a delight day by day, always rejoicing before him,'),
  ('Proverbs', 8, 31, 'rejoicing in his whole world. My delight was with the sons of men.'),
  ('Proverbs', 8, 32, '“Now therefore, my sons, listen to me, for blessed are those who keep my ways.'),
  ('Proverbs', 8, 33, 'Hear instruction, and be wise. Don’t refuse it.'),
  ('Proverbs', 8, 34, 'Blessed is the man who hears me, watching daily at my gates, waiting at my door posts.'),
  ('Proverbs', 8, 35, 'For whoever finds me finds life, and will obtain favor from the LORD.'),
  ('Proverbs', 8, 36, 'But he who sins against me wrongs his own soul. All those who hate me love death.”'),
  ('Proverbs', 9, 1, 'Wisdom has built her house. She has carved out her seven pillars.'),
  ('Proverbs', 9, 2, 'She has prepared her meat. She has mixed her wine. She has also set her table.'),
  ('Proverbs', 9, 3, 'She has sent out her maidens. She cries from the highest places of the city:'),
  ('Proverbs', 9, 4, '“Whoever is simple, let him turn in here!” As for him who is void of understanding, she says to him,'),
  ('Proverbs', 9, 5, '“Come, eat some of my bread, Drink some of the wine which I have mixed!'),
  ('Proverbs', 9, 6, 'Leave your simple ways, and live. Walk in the way of understanding.”'),
  ('Proverbs', 9, 7, 'One who corrects a mocker invites insult. One who reproves a wicked man invites abuse.'),
  ('Proverbs', 9, 8, 'Don’t reprove a scoffer, lest he hate you. Reprove a wise person, and he will love you.'),
  ('Proverbs', 9, 9, 'Instruct a wise person, and he will be still wiser. Teach a righteous person, and he will increase in learning.'),
  ('Proverbs', 9, 10, 'The fear of the LORD is the beginning of wisdom. The knowledge of the Holy One is understanding.'),
  ('Proverbs', 9, 11, 'For by me your days will be multiplied. The years of your life will be increased.'),
  ('Proverbs', 9, 12, 'If you are wise, you are wise for yourself. If you mock, you alone will bear it.'),
  ('Proverbs', 9, 13, 'The foolish woman is loud, undisciplined, and knows nothing.'),
  ('Proverbs', 9, 14, 'She sits at the door of her house, on a seat in the high places of the city,'),
  ('Proverbs', 9, 15, 'to call to those who pass by, who go straight on their ways,'),
  ('Proverbs', 9, 16, '“Whoever is simple, let him turn in here.” As for him who is void of understanding, she says to him,'),
  ('Proverbs', 9, 17, '“Stolen water is sweet. Food eaten in secret is pleasant.”'),
  ('Proverbs', 9, 18, 'But he doesn’t know that the departed spirits are there, that her guests are in the depths of Sheol.'),
  ('Proverbs', 10, 1, 'The proverbs of Solomon. A wise son makes a glad father; but a foolish son brings grief to his mother.'),
  ('Proverbs', 10, 2, 'Treasures of wickedness profit nothing, but righteousness delivers from death.'),
  ('Proverbs', 10, 3, 'The LORD will not allow the soul of the righteous to go hungry, but he thrusts away the desire of the wicked.'),
  ('Proverbs', 10, 4, 'He becomes poor who works with a lazy hand, but the hand of the diligent brings wealth.'),
  ('Proverbs', 10, 5, 'He who gathers in summer is a wise son, but he who sleeps during the harvest is a son who causes shame.'),
  ('Proverbs', 10, 6, 'Blessings are on the head of the righteous, but violence covers the mouth of the wicked.'),
  ('Proverbs', 10, 7, 'The memory of the righteous is blessed, but the name of the wicked will rot.'),
  ('Proverbs', 10, 8, 'The wise in heart accept commandments, but a chattering fool will fall.'),
  ('Proverbs', 10, 9, 'He who walks blamelessly walks surely, but he who perverts his ways will be found out.'),
  ('Proverbs', 10, 10, 'One who winks with the eye causes sorrow, but a chattering fool will fall.'),
  ('Proverbs', 10, 11, 'The mouth of the righteous is a spring of life, but violence covers the mouth of the wicked.'),
  ('Proverbs', 10, 12, 'Hatred stirs up strife, but love covers all wrongs.'),
  ('Proverbs', 10, 13, 'Wisdom is found on the lips of him who has discernment, but a rod is for the back of him who is void of understanding.'),
  ('Proverbs', 10, 14, 'Wise men lay up knowledge, but the mouth of the foolish is near ruin.'),
  ('Proverbs', 10, 15, 'The rich man’s wealth is his strong city. The destruction of the poor is their poverty.'),
  ('Proverbs', 10, 16, 'The labor of the righteous leads to life. The increase of the wicked leads to sin.'),
  ('Proverbs', 10, 17, 'He is in the way of life who heeds correction, but he who forsakes reproof leads others astray.'),
  ('Proverbs', 10, 18, 'He who hides hatred has lying lips. He who utters a slander is a fool.'),
  ('Proverbs', 10, 19, 'In the multitude of words there is no lack of disobedience, but he who restrains his lips does wisely.'),
  ('Proverbs', 10, 20, 'The tongue of the righteous is like choice silver. The heart of the wicked is of little worth.'),
  ('Proverbs', 10, 21, 'The lips of the righteous feed many, but the foolish die for lack of understanding.'),
  ('Proverbs', 10, 22, 'The LORD’s blessing brings wealth, and he adds no trouble to it.'),
  ('Proverbs', 10, 23, 'It is a fool’s pleasure to do wickedness, but wisdom is a man of understanding’s pleasure.'),
  ('Proverbs', 10, 24, 'What the wicked fear will overtake them, but the desire of the righteous will be granted.'),
  ('Proverbs', 10, 25, 'When the whirlwind passes, the wicked is no more; but the righteous stand firm forever.'),
  ('Proverbs', 10, 26, 'As vinegar to the teeth, and as smoke to the eyes, so is the sluggard to those who send him.'),
  ('Proverbs', 10, 27, 'The fear of the LORD prolongs days, but the years of the wicked shall be shortened.'),
  ('Proverbs', 10, 28, 'The prospect of the righteous is joy, but the hope of the wicked will perish.'),
  ('Proverbs', 10, 29, 'The way of the LORD is a stronghold to the upright, but it is a destruction to the workers of iniquity.'),
  ('Proverbs', 10, 30, 'The righteous will never be removed, but the wicked will not dwell in the land.'),
  ('Proverbs', 10, 31, 'The mouth of the righteous produces wisdom, but the perverse tongue will be cut off.'),
  ('Proverbs', 10, 32, 'The lips of the righteous know what is acceptable, but the mouth of the wicked is perverse.'),
  ('Proverbs', 11, 1, 'A false balance is an abomination to the LORD, but accurate weights are his delight.'),
  ('Proverbs', 11, 2, 'When pride comes, then comes shame, but with humility comes wisdom.'),
  ('Proverbs', 11, 3, 'The integrity of the upright shall guide them, but the perverseness of the treacherous shall destroy them.'),
  ('Proverbs', 11, 4, 'Riches don’t profit in the day of wrath, but righteousness delivers from death.'),
  ('Proverbs', 11, 5, 'The righteousness of the blameless will direct his way, but the wicked shall fall by his own wickedness.'),
  ('Proverbs', 11, 6, 'The righteousness of the upright shall deliver them, but the unfaithful will be trapped by evil desires.'),
  ('Proverbs', 11, 7, 'When a wicked man dies, hope perishes, and expectation of power comes to nothing.'),
  ('Proverbs', 11, 8, 'A righteous person is delivered out of trouble, and the wicked takes his place.'),
  ('Proverbs', 11, 9, 'With his mouth the godless man destroys his neighbor, but the righteous will be delivered through knowledge.'),
  ('Proverbs', 11, 10, 'When it goes well with the righteous, the city rejoices. When the wicked perish, there is shouting.'),
  ('Proverbs', 11, 11, 'By the blessing of the upright, the city is exalted, but it is overthrown by the mouth of the wicked.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Proverbs', 11, 12, 'One who despises his neighbor is void of wisdom, but a man of understanding holds his peace.'),
  ('Proverbs', 11, 13, 'One who brings gossip betrays a confidence, but one who is of a trustworthy spirit is one who keeps a secret.'),
  ('Proverbs', 11, 14, 'Where there is no wise guidance, the nation falls, but in the multitude of counselors there is victory.'),
  ('Proverbs', 11, 15, 'He who is collateral for a stranger will suffer for it, but he who refuses pledges of collateral is secure.'),
  ('Proverbs', 11, 16, 'A gracious woman obtains honor, but violent men obtain riches.'),
  ('Proverbs', 11, 17, 'The merciful man does good to his own soul, but he who is cruel troubles his own flesh.'),
  ('Proverbs', 11, 18, 'Wicked people earn deceitful wages, but one who sows righteousness reaps a sure reward.'),
  ('Proverbs', 11, 19, 'He who is truly righteous gets life. He who pursues evil gets death.'),
  ('Proverbs', 11, 20, 'Those who are perverse in heart are an abomination to the LORD, but those whose ways are blameless are his delight.'),
  ('Proverbs', 11, 21, 'Most certainly, the evil man will not be unpunished, but the offspring of the righteous will be delivered.'),
  ('Proverbs', 11, 22, 'Like a gold ring in a pig’s snout, is a beautiful woman who lacks discretion.'),
  ('Proverbs', 11, 23, 'The desire of the righteous is only good. The expectation of the wicked is wrath.'),
  ('Proverbs', 11, 24, 'There is one who scatters, and increases yet more. There is one who withholds more than is appropriate, but gains poverty.'),
  ('Proverbs', 11, 25, 'The liberal soul shall be made fat. He who waters shall be watered also himself.'),
  ('Proverbs', 11, 26, 'People curse someone who withholds grain, but blessing will be on the head of him who sells it.'),
  ('Proverbs', 11, 27, 'He who diligently seeks good seeks favor, but he who searches after evil, it shall come to him.'),
  ('Proverbs', 11, 28, 'He who trusts in his riches will fall, but the righteous shall flourish as the green leaf.'),
  ('Proverbs', 11, 29, 'He who troubles his own house shall inherit the wind. The foolish shall be servant to the wise of heart.'),
  ('Proverbs', 11, 30, 'The fruit of the righteous is a tree of life. He who is wise wins souls.'),
  ('Proverbs', 11, 31, 'Behold, the righteous shall be repaid in the earth, how much more the wicked and the sinner!'),
  ('Proverbs', 12, 1, 'Whoever loves correction loves knowledge, but he who hates reproof is stupid.'),
  ('Proverbs', 12, 2, 'A good man shall obtain favor from the LORD, but he will condemn a man of wicked plans.'),
  ('Proverbs', 12, 3, 'A man shall not be established by wickedness, but the root of the righteous shall not be moved.'),
  ('Proverbs', 12, 4, 'A worthy woman is the crown of her husband, but a disgraceful wife is as rottenness in his bones.'),
  ('Proverbs', 12, 5, 'The thoughts of the righteous are just, but the advice of the wicked is deceitful.'),
  ('Proverbs', 12, 6, 'The words of the wicked are about lying in wait for blood, but the speech of the upright rescues them.'),
  ('Proverbs', 12, 7, 'The wicked are overthrown, and are no more, but the house of the righteous shall stand.'),
  ('Proverbs', 12, 8, 'A man shall be commended according to his wisdom, but he who has a warped mind shall be despised.'),
  ('Proverbs', 12, 9, 'Better is he who is little known, and has a servant, than he who honors himself and lacks bread.'),
  ('Proverbs', 12, 10, 'A righteous man respects the life of his animal, but the tender mercies of the wicked are cruel.'),
  ('Proverbs', 12, 11, 'He who tills his land shall have plenty of bread, but he who chases fantasies is void of understanding.'),
  ('Proverbs', 12, 12, 'The wicked desires the plunder of evil men, but the root of the righteous flourishes.'),
  ('Proverbs', 12, 13, 'An evil man is trapped by sinfulness of lips, but the righteous shall come out of trouble.'),
  ('Proverbs', 12, 14, 'A man shall be satisfied with good by the fruit of his mouth. The work of a man’s hands shall be rewarded to him.'),
  ('Proverbs', 12, 15, 'The way of a fool is right in his own eyes, but he who is wise listens to counsel.'),
  ('Proverbs', 12, 16, 'A fool shows his annoyance the same day, but one who overlooks an insult is prudent.'),
  ('Proverbs', 12, 17, 'He who is truthful testifies honestly, but a false witness lies.'),
  ('Proverbs', 12, 18, 'There is one who speaks rashly like the piercing of a sword, but the tongue of the wise heals.'),
  ('Proverbs', 12, 19, 'Truth’s lips will be established forever, but a lying tongue is only momentary.'),
  ('Proverbs', 12, 20, 'Deceit is in the heart of those who plot evil, but joy comes to the promoters of peace.'),
  ('Proverbs', 12, 21, 'No mischief shall happen to the righteous, but the wicked shall be filled with evil.'),
  ('Proverbs', 12, 22, 'Lying lips are an abomination to the LORD, but those who do the truth are his delight.'),
  ('Proverbs', 12, 23, 'A prudent man keeps his knowledge, but the hearts of fools proclaim foolishness.'),
  ('Proverbs', 12, 24, 'The hands of the diligent ones shall rule, but laziness ends in slave labor.'),
  ('Proverbs', 12, 25, 'Anxiety in a man’s heart weighs it down, but a kind word makes it glad.'),
  ('Proverbs', 12, 26, 'A righteous person is cautious in friendship, but the way of the wicked leads them astray.'),
  ('Proverbs', 12, 27, 'The slothful man doesn’t roast his game, but the possessions of diligent men are prized.'),
  ('Proverbs', 12, 28, 'In the way of righteousness is life; in its path there is no death.'),
  ('Proverbs', 13, 1, 'A wise son listens to his father’s instruction, but a scoffer doesn’t listen to rebuke.'),
  ('Proverbs', 13, 2, 'By the fruit of his lips, a man enjoys good things, but the unfaithful crave violence.'),
  ('Proverbs', 13, 3, 'He who guards his mouth guards his soul. One who opens wide his lips comes to ruin.'),
  ('Proverbs', 13, 4, 'The soul of the sluggard desires, and has nothing, but the desire of the diligent shall be fully satisfied.'),
  ('Proverbs', 13, 5, 'A righteous man hates lies, but a wicked man brings shame and disgrace.'),
  ('Proverbs', 13, 6, 'Righteousness guards the way of integrity, but wickedness overthrows the sinner.'),
  ('Proverbs', 13, 7, 'There are some who pretend to be rich, yet have nothing. There are some who pretend to be poor, yet have great wealth.'),
  ('Proverbs', 13, 8, 'The ransom of a man’s life is his riches, but the poor hear no threats.'),
  ('Proverbs', 13, 9, 'The light of the righteous shines brightly, but the lamp of the wicked is snuffed out.'),
  ('Proverbs', 13, 10, 'Pride only breeds quarrels, but wisdom is with people who take advice.'),
  ('Proverbs', 13, 11, 'Wealth gained dishonestly dwindles away, but he who gathers by hand makes it grow.'),
  ('Proverbs', 13, 12, 'Hope deferred makes the heart sick, but when longing is fulfilled, it is a tree of life.'),
  ('Proverbs', 13, 13, 'Whoever despises instruction will pay for it, but he who respects a command will be rewarded.'),
  ('Proverbs', 13, 14, 'The teaching of the wise is a spring of life, to turn from the snares of death.'),
  ('Proverbs', 13, 15, 'Good understanding wins favor, but the way of the unfaithful is hard.'),
  ('Proverbs', 13, 16, 'Every prudent man acts from knowledge, but a fool exposes folly.'),
  ('Proverbs', 13, 17, 'A wicked messenger falls into trouble, but a trustworthy envoy gains healing.'),
  ('Proverbs', 13, 18, 'Poverty and shame come to him who refuses discipline, but he who heeds correction shall be honored.'),
  ('Proverbs', 13, 19, 'Longing fulfilled is sweet to the soul, but fools detest turning from evil.'),
  ('Proverbs', 13, 20, 'One who walks with wise men grows wise, but a companion of fools suffers harm.'),
  ('Proverbs', 13, 21, 'Misfortune pursues sinners, but prosperity rewards the righteous.'),
  ('Proverbs', 13, 22, 'A good man leaves an inheritance to his children’s children, but the wealth of the sinner is stored for the righteous.'),
  ('Proverbs', 13, 23, 'An abundance of food is in poor people’s fields, but injustice sweeps it away.'),
  ('Proverbs', 13, 24, 'One who spares the rod hates his son, but one who loves him is careful to discipline him.'),
  ('Proverbs', 13, 25, 'The righteous one eats to the satisfying of his soul, but the belly of the wicked goes hungry.'),
  ('Proverbs', 14, 1, 'Every wise woman builds her house, but the foolish one tears it down with her own hands.'),
  ('Proverbs', 14, 2, 'He who walks in his uprightness fears the LORD, but he who is perverse in his ways despises him.'),
  ('Proverbs', 14, 3, 'The fool’s talk brings a rod to his back, but the lips of the wise protect them.'),
  ('Proverbs', 14, 4, 'Where no oxen are, the crib is clean, but much increase is by the strength of the ox.'),
  ('Proverbs', 14, 5, 'A truthful witness will not lie, but a false witness pours out lies.'),
  ('Proverbs', 14, 6, 'A scoffer seeks wisdom, and doesn’t find it, but knowledge comes easily to a discerning person.'),
  ('Proverbs', 14, 7, 'Stay away from a foolish man, for you won’t find knowledge on his lips.'),
  ('Proverbs', 14, 8, 'The wisdom of the prudent is to think about his way, but the folly of fools is deceit.'),
  ('Proverbs', 14, 9, 'Fools mock at making atonement for sins, but among the upright there is good will.'),
  ('Proverbs', 14, 10, 'The heart knows its own bitterness and joy; he will not share these with a stranger.'),
  ('Proverbs', 14, 11, 'The house of the wicked will be overthrown, but the tent of the upright will flourish.'),
  ('Proverbs', 14, 12, 'There is a way which seems right to a man, but in the end it leads to death.'),
  ('Proverbs', 14, 13, 'Even in laughter the heart may be sorrowful, and mirth may end in heaviness.'),
  ('Proverbs', 14, 14, 'The unfaithful will be repaid for his own ways; likewise a good man will be rewarded for his ways.'),
  ('Proverbs', 14, 15, 'A simple man believes everything, but the prudent man carefully considers his ways.'),
  ('Proverbs', 14, 16, 'A wise man fears and shuns evil, but the fool is hot headed and reckless.'),
  ('Proverbs', 14, 17, 'He who is quick to become angry will commit folly, and a crafty man is hated.'),
  ('Proverbs', 14, 18, 'The simple inherit folly, but the prudent are crowned with knowledge.'),
  ('Proverbs', 14, 19, 'The evil bow down before the good, and the wicked at the gates of the righteous.'),
  ('Proverbs', 14, 20, 'The poor person is shunned even by his own neighbor, but the rich person has many friends.'),
  ('Proverbs', 14, 21, 'He who despises his neighbor sins, but he who has pity on the poor is blessed.'),
  ('Proverbs', 14, 22, 'Don’t they go astray who plot evil? But love and faithfulness belong to those who plan good.'),
  ('Proverbs', 14, 23, 'In all hard work there is profit, but the talk of the lips leads only to poverty.'),
  ('Proverbs', 14, 24, 'The crown of the wise is their riches, but the folly of fools crowns them with folly.'),
  ('Proverbs', 14, 25, 'A truthful witness saves souls, but a false witness is deceitful.'),
  ('Proverbs', 14, 26, 'In the fear of the LORD is a secure fortress, and he will be a refuge for his children.'),
  ('Proverbs', 14, 27, 'The fear of the LORD is a fountain of life, turning people from the snares of death.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Proverbs', 14, 28, 'In the multitude of people is the king’s glory, but in the lack of people is the destruction of the prince.'),
  ('Proverbs', 14, 29, 'He who is slow to anger has great understanding, but he who has a quick temper displays folly.'),
  ('Proverbs', 14, 30, 'The life of the body is a heart at peace, but envy rots the bones.'),
  ('Proverbs', 14, 31, 'He who oppresses the poor shows contempt for his Maker, but he who is kind to the needy honors him.'),
  ('Proverbs', 14, 32, 'The wicked is brought down in his calamity, but in death, the righteous has a refuge.'),
  ('Proverbs', 14, 33, 'Wisdom rests in the heart of one who has understanding, and is even made known in the inward part of fools.'),
  ('Proverbs', 14, 34, 'Righteousness exalts a nation, but sin is a disgrace to any people.'),
  ('Proverbs', 14, 35, 'The king’s favor is toward a servant who deals wisely, but his wrath is toward one who causes shame.'),
  ('Proverbs', 15, 1, 'A gentle answer turns away wrath, but a harsh word stirs up anger.'),
  ('Proverbs', 15, 2, 'The tongue of the wise commends knowledge, but the mouths of fools gush out folly.'),
  ('Proverbs', 15, 3, 'The LORD’s eyes are everywhere, keeping watch on the evil and the good.'),
  ('Proverbs', 15, 4, 'A gentle tongue is a tree of life, but deceit in it crushes the spirit.'),
  ('Proverbs', 15, 5, 'A fool despises his father’s correction, but he who heeds reproof shows prudence.'),
  ('Proverbs', 15, 6, 'In the house of the righteous is much treasure, but the income of the wicked brings trouble.'),
  ('Proverbs', 15, 7, 'The lips of the wise spread knowledge; not so with the heart of fools.'),
  ('Proverbs', 15, 8, 'The sacrifice made by the wicked is an abomination to the LORD, but the prayer of the upright is his delight.'),
  ('Proverbs', 15, 9, 'The way of the wicked is an abomination to the LORD, but he loves him who follows after righteousness.'),
  ('Proverbs', 15, 10, 'There is stern discipline for one who forsakes the way. Whoever hates reproof shall die.'),
  ('Proverbs', 15, 11, 'Sheol and Abaddon are before the LORD— how much more then the hearts of the children of men!'),
  ('Proverbs', 15, 12, 'A scoffer doesn’t love to be reproved; he will not go to the wise.'),
  ('Proverbs', 15, 13, 'A glad heart makes a cheerful face, but an aching heart breaks the spirit.'),
  ('Proverbs', 15, 14, 'The heart of one who has understanding seeks knowledge, but the mouths of fools feed on folly.'),
  ('Proverbs', 15, 15, 'All the days of the afflicted are wretched, but one who has a cheerful heart enjoys a continual feast.'),
  ('Proverbs', 15, 16, 'Better is little, with the fear of the LORD, than great treasure with trouble.'),
  ('Proverbs', 15, 17, 'Better is a dinner of herbs, where love is, than a fattened calf with hatred.'),
  ('Proverbs', 15, 18, 'A wrathful man stirs up contention, but one who is slow to anger appeases strife.'),
  ('Proverbs', 15, 19, 'The way of the sluggard is like a thorn patch, but the path of the upright is a highway.'),
  ('Proverbs', 15, 20, 'A wise son makes a father glad, but a foolish man despises his mother.'),
  ('Proverbs', 15, 21, 'Folly is joy to one who is void of wisdom, but a man of understanding keeps his way straight.'),
  ('Proverbs', 15, 22, 'Where there is no counsel, plans fail; but in a multitude of counselors they are established.'),
  ('Proverbs', 15, 23, 'Joy comes to a man with the reply of his mouth. How good is a word at the right time!'),
  ('Proverbs', 15, 24, 'The path of life leads upward for the wise, to keep him from going downward to Sheol.'),
  ('Proverbs', 15, 25, 'The LORD will uproot the house of the proud, but he will keep the widow’s borders intact.'),
  ('Proverbs', 15, 26, 'The LORD detests the thoughts of the wicked, but the thoughts of the pure are pleasing.'),
  ('Proverbs', 15, 27, 'He who is greedy for gain troubles his own house, but he who hates bribes will live.'),
  ('Proverbs', 15, 28, 'The heart of the righteous weighs answers, but the mouth of the wicked gushes out evil.'),
  ('Proverbs', 15, 29, 'The LORD is far from the wicked, but he hears the prayer of the righteous.'),
  ('Proverbs', 15, 30, 'The light of the eyes rejoices the heart. Good news gives health to the bones.'),
  ('Proverbs', 15, 31, 'The ear that listens to reproof lives, and will be at home among the wise.'),
  ('Proverbs', 15, 32, 'He who refuses correction despises his own soul, but he who listens to reproof gets understanding.'),
  ('Proverbs', 15, 33, 'The fear of the LORD teaches wisdom. Before honor is humility.'),
  ('Proverbs', 16, 1, 'The plans of the heart belong to man, but the answer of the tongue is from the LORD.'),
  ('Proverbs', 16, 2, 'All the ways of a man are clean in his own eyes, but the LORD weighs the motives.'),
  ('Proverbs', 16, 3, 'Commit your deeds to the LORD, and your plans shall succeed.'),
  ('Proverbs', 16, 4, 'The LORD has made everything for its own end— yes, even the wicked for the day of evil.'),
  ('Proverbs', 16, 5, 'Everyone who is proud in heart is an abomination to the LORD; they shall certainly not be unpunished.'),
  ('Proverbs', 16, 6, 'By mercy and truth iniquity is atoned for. By the fear of the LORD men depart from evil.'),
  ('Proverbs', 16, 7, 'When a man’s ways please the LORD, he makes even his enemies to be at peace with him.'),
  ('Proverbs', 16, 8, 'Better is a little with righteousness, than great revenues with injustice.'),
  ('Proverbs', 16, 9, 'A man’s heart plans his course, but the LORD directs his steps.'),
  ('Proverbs', 16, 10, 'Inspired judgments are on the lips of the king. He shall not betray his mouth.'),
  ('Proverbs', 16, 11, 'Honest balances and scales are the LORD’s; all the weights in the bag are his work.'),
  ('Proverbs', 16, 12, 'It is an abomination for kings to do wrong, for the throne is established by righteousness.'),
  ('Proverbs', 16, 13, 'Righteous lips are the delight of kings. They value one who speaks the truth.'),
  ('Proverbs', 16, 14, 'The king’s wrath is a messenger of death, but a wise man will pacify it.'),
  ('Proverbs', 16, 15, 'In the light of the king’s face is life. His favor is like a cloud of the spring rain.'),
  ('Proverbs', 16, 16, 'How much better it is to get wisdom than gold! Yes, to get understanding is to be chosen rather than silver.'),
  ('Proverbs', 16, 17, 'The highway of the upright is to depart from evil. He who keeps his way preserves his soul.'),
  ('Proverbs', 16, 18, 'Pride goes before destruction, and an arrogant spirit before a fall.'),
  ('Proverbs', 16, 19, 'It is better to be of a lowly spirit with the poor, than to divide the plunder with the proud.'),
  ('Proverbs', 16, 20, 'He who heeds the Word finds prosperity. Whoever trusts in the LORD is blessed.'),
  ('Proverbs', 16, 21, 'The wise in heart shall be called prudent. Pleasantness of the lips promotes instruction.'),
  ('Proverbs', 16, 22, 'Understanding is a fountain of life to one who has it, but the punishment of fools is their folly.'),
  ('Proverbs', 16, 23, 'The heart of the wise instructs his mouth, and adds learning to his lips.'),
  ('Proverbs', 16, 24, 'Pleasant words are a honeycomb, sweet to the soul, and health to the bones.'),
  ('Proverbs', 16, 25, 'There is a way which seems right to a man, but in the end it leads to death.'),
  ('Proverbs', 16, 26, 'The appetite of the laboring man labors for him, for his mouth urges him on.'),
  ('Proverbs', 16, 27, 'A worthless man devises mischief. His speech is like a scorching fire.'),
  ('Proverbs', 16, 28, 'A perverse man stirs up strife. A whisperer separates close friends.'),
  ('Proverbs', 16, 29, 'A man of violence entices his neighbor, and leads him in a way that is not good.'),
  ('Proverbs', 16, 30, 'One who winks his eyes to plot perversities, one who compresses his lips, is bent on evil.'),
  ('Proverbs', 16, 31, 'Gray hair is a crown of glory. It is attained by a life of righteousness.'),
  ('Proverbs', 16, 32, 'One who is slow to anger is better than the mighty; one who rules his spirit, than he who takes a city.'),
  ('Proverbs', 16, 33, 'The lot is cast into the lap, but its every decision is from the LORD.'),
  ('Proverbs', 17, 1, 'Better is a dry morsel with quietness, than a house full of feasting with strife.'),
  ('Proverbs', 17, 2, 'A servant who deals wisely will rule over a son who causes shame, and shall have a part in the inheritance among the brothers.'),
  ('Proverbs', 17, 3, 'The refining pot is for silver, and the furnace for gold, but the LORD tests the hearts.'),
  ('Proverbs', 17, 4, 'An evildoer heeds wicked lips. A liar gives ear to a mischievous tongue.'),
  ('Proverbs', 17, 5, 'Whoever mocks the poor reproaches his Maker. He who is glad at calamity shall not be unpunished.'),
  ('Proverbs', 17, 6, 'Children’s children are the crown of old men; the glory of children is their parents.'),
  ('Proverbs', 17, 7, 'Excellent speech isn’t fitting for a fool, much less do lying lips fit a prince.'),
  ('Proverbs', 17, 8, 'A bribe is a precious stone in the eyes of him who gives it; wherever he turns, he prospers.'),
  ('Proverbs', 17, 9, 'He who covers an offense promotes love; but he who repeats a matter separates best friends.'),
  ('Proverbs', 17, 10, 'A rebuke enters deeper into one who has understanding than a hundred lashes into a fool.'),
  ('Proverbs', 17, 11, 'An evil man seeks only rebellion; therefore a cruel messenger shall be sent against him.'),
  ('Proverbs', 17, 12, 'Let a bear robbed of her cubs meet a man, rather than a fool in his folly.'),
  ('Proverbs', 17, 13, 'Whoever rewards evil for good, evil shall not depart from his house.'),
  ('Proverbs', 17, 14, 'The beginning of strife is like breaching a dam, therefore stop contention before quarreling breaks out.'),
  ('Proverbs', 17, 15, 'He who justifies the wicked, and he who condemns the righteous, both of them alike are an abomination to the LORD.'),
  ('Proverbs', 17, 16, 'Why is there money in the hand of a fool to buy wisdom, since he has no understanding?'),
  ('Proverbs', 17, 17, 'A friend loves at all times; and a brother is born for adversity.'),
  ('Proverbs', 17, 18, 'A man void of understanding strikes hands, and becomes collateral in the presence of his neighbor.'),
  ('Proverbs', 17, 19, 'He who loves disobedience loves strife. One who builds a high gate seeks destruction.'),
  ('Proverbs', 17, 20, 'One who has a perverse heart doesn’t find prosperity, and one who has a deceitful tongue falls into trouble.'),
  ('Proverbs', 17, 21, 'He who becomes the father of a fool grieves. The father of a fool has no joy.'),
  ('Proverbs', 17, 22, 'A cheerful heart makes good medicine, but a crushed spirit dries up the bones.'),
  ('Proverbs', 17, 23, 'A wicked man receives a bribe in secret, to pervert the ways of justice.'),
  ('Proverbs', 17, 24, 'Wisdom is before the face of one who has understanding, but the eyes of a fool wander to the ends of the earth.'),
  ('Proverbs', 17, 25, 'A foolish son brings grief to his father, and bitterness to her who bore him.'),
  ('Proverbs', 17, 26, 'Also to punish the righteous is not good, nor to flog officials for their integrity.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Proverbs', 17, 27, 'He who spares his words has knowledge. He who is even tempered is a man of understanding.'),
  ('Proverbs', 17, 28, 'Even a fool, when he keeps silent, is counted wise. When he shuts his lips, he is thought to be discerning.'),
  ('Proverbs', 18, 1, 'A man who isolates himself pursues selfishness, and defies all sound judgment.'),
  ('Proverbs', 18, 2, 'A fool has no delight in understanding, but only in revealing his own opinion.'),
  ('Proverbs', 18, 3, 'When wickedness comes, contempt also comes, and with shame comes disgrace.'),
  ('Proverbs', 18, 4, 'The words of a man’s mouth are like deep waters. The fountain of wisdom is like a flowing brook.'),
  ('Proverbs', 18, 5, 'To be partial to the faces of the wicked is not good, nor to deprive the innocent of justice.'),
  ('Proverbs', 18, 6, 'A fool’s lips come into strife, and his mouth invites beatings.'),
  ('Proverbs', 18, 7, 'A fool’s mouth is his destruction, and his lips are a snare to his soul.'),
  ('Proverbs', 18, 8, 'The words of a gossip are like dainty morsels: they go down into a person’s innermost parts.'),
  ('Proverbs', 18, 9, 'One who is slack in his work is brother to him who is a master of destruction.'),
  ('Proverbs', 18, 10, 'The LORD’s name is a strong tower: the righteous run to him, and are safe.'),
  ('Proverbs', 18, 11, 'The rich man’s wealth is his strong city, like an unscalable wall in his own imagination.'),
  ('Proverbs', 18, 12, 'Before destruction the heart of man is proud, but before honor is humility.'),
  ('Proverbs', 18, 13, 'He who answers before he hears, that is folly and shame to him.'),
  ('Proverbs', 18, 14, 'A man’s spirit will sustain him in sickness, but a crushed spirit, who can bear?'),
  ('Proverbs', 18, 15, 'The heart of the discerning gets knowledge. The ear of the wise seeks knowledge.'),
  ('Proverbs', 18, 16, 'A man’s gift makes room for him, and brings him before great men.'),
  ('Proverbs', 18, 17, 'He who pleads his cause first seems right— until another comes and questions him.'),
  ('Proverbs', 18, 18, 'The lot settles disputes, and keeps strong ones apart.'),
  ('Proverbs', 18, 19, 'A brother offended is more difficult than a fortified city. Disputes are like the bars of a fortress.'),
  ('Proverbs', 18, 20, 'A man’s stomach is filled with the fruit of his mouth. With the harvest of his lips he is satisfied.'),
  ('Proverbs', 18, 21, 'Death and life are in the power of the tongue; those who love it will eat its fruit.'),
  ('Proverbs', 18, 22, 'Whoever finds a wife finds a good thing, and obtains favor of the LORD.'),
  ('Proverbs', 18, 23, 'The poor plead for mercy, but the rich answer harshly.'),
  ('Proverbs', 18, 24, 'A man of many companions may be ruined, but there is a friend who sticks closer than a brother.'),
  ('Proverbs', 19, 1, 'Better is the poor who walks in his integrity than he who is perverse in his lips and is a fool.'),
  ('Proverbs', 19, 2, 'It isn’t good to have zeal without knowledge, nor to be hasty with one’s feet and miss the way.'),
  ('Proverbs', 19, 3, 'The foolishness of man subverts his way; his heart rages against the LORD.'),
  ('Proverbs', 19, 4, 'Wealth adds many friends, but the poor is separated from his friend.'),
  ('Proverbs', 19, 5, 'A false witness shall not be unpunished. He who pours out lies shall not go free.'),
  ('Proverbs', 19, 6, 'Many will entreat the favor of a ruler, and everyone is a friend to a man who gives gifts.'),
  ('Proverbs', 19, 7, 'All the relatives of the poor shun him; how much more do his friends avoid him! He pursues them with pleas, but they are gone.'),
  ('Proverbs', 19, 8, 'He who gets wisdom loves his own soul. He who keeps understanding shall find good.'),
  ('Proverbs', 19, 9, 'A false witness shall not be unpunished. He who utters lies shall perish.'),
  ('Proverbs', 19, 10, 'Delicate living is not appropriate for a fool, much less for a servant to have rule over princes.'),
  ('Proverbs', 19, 11, 'The discretion of a man makes him slow to anger. It is his glory to overlook an offense.'),
  ('Proverbs', 19, 12, 'The king’s wrath is like the roaring of a lion, but his favor is like dew on the grass.'),
  ('Proverbs', 19, 13, 'A foolish son is the calamity of his father. A wife’s quarrels are a continual dripping.'),
  ('Proverbs', 19, 14, 'House and riches are an inheritance from fathers, but a prudent wife is from the LORD.'),
  ('Proverbs', 19, 15, 'Slothfulness casts into a deep sleep. The idle soul shall suffer hunger.'),
  ('Proverbs', 19, 16, 'He who keeps the commandment keeps his soul, but he who is contemptuous in his ways shall die.'),
  ('Proverbs', 19, 17, 'He who has pity on the poor lends to the LORD; he will reward him.'),
  ('Proverbs', 19, 18, 'Discipline your son, for there is hope; don’t be a willing party to his death.'),
  ('Proverbs', 19, 19, 'A hot-tempered man must pay the penalty, for if you rescue him, you must do it again.'),
  ('Proverbs', 19, 20, 'Listen to counsel and receive instruction, that you may be wise in your latter end.'),
  ('Proverbs', 19, 21, 'There are many plans in a man’s heart, but the LORD’s counsel will prevail.'),
  ('Proverbs', 19, 22, 'That which makes a man to be desired is his kindness. A poor man is better than a liar.'),
  ('Proverbs', 19, 23, 'The fear of the LORD leads to life, then contentment; he rests and will not be touched by trouble.'),
  ('Proverbs', 19, 24, 'The sluggard buries his hand in the dish; he will not so much as bring it to his mouth again.'),
  ('Proverbs', 19, 25, 'Flog a scoffer, and the simple will learn prudence; rebuke one who has understanding, and he will gain knowledge.'),
  ('Proverbs', 19, 26, 'He who robs his father and drives away his mother is a son who causes shame and brings reproach.'),
  ('Proverbs', 19, 27, 'If you stop listening to instruction, my son, you will stray from the words of knowledge.'),
  ('Proverbs', 19, 28, 'A corrupt witness mocks justice, and the mouth of the wicked gulps down iniquity.'),
  ('Proverbs', 19, 29, 'Penalties are prepared for scoffers, and beatings for the backs of fools.'),
  ('Proverbs', 20, 1, 'Wine is a mocker and beer is a brawler. Whoever is led astray by them is not wise.'),
  ('Proverbs', 20, 2, 'The terror of a king is like the roaring of a lion. He who provokes him to anger forfeits his own life.'),
  ('Proverbs', 20, 3, 'It is an honor for a man to keep aloof from strife, but every fool will be quarreling.'),
  ('Proverbs', 20, 4, 'The sluggard will not plow by reason of the winter; therefore he shall beg in harvest, and have nothing.'),
  ('Proverbs', 20, 5, 'Counsel in the heart of man is like deep water, but a man of understanding will draw it out.'),
  ('Proverbs', 20, 6, 'Many men claim to be men of unfailing love, but who can find a faithful man?'),
  ('Proverbs', 20, 7, 'A righteous man walks in integrity. Blessed are his children after him.'),
  ('Proverbs', 20, 8, 'A king who sits on the throne of judgment scatters away all evil with his eyes.'),
  ('Proverbs', 20, 9, 'Who can say, “I have made my heart pure. I am clean and without sin”?'),
  ('Proverbs', 20, 10, 'Differing weights and differing measures, both of them alike are an abomination to the LORD.'),
  ('Proverbs', 20, 11, 'Even a child makes himself known by his doings, whether his work is pure, and whether it is right.'),
  ('Proverbs', 20, 12, 'The hearing ear, and the seeing eye, the LORD has made even both of them.'),
  ('Proverbs', 20, 13, 'Don’t love sleep, lest you come to poverty. Open your eyes, and you shall be satisfied with bread.'),
  ('Proverbs', 20, 14, '“It’s no good, it’s no good,” says the buyer; but when he is gone his way, then he boasts.'),
  ('Proverbs', 20, 15, 'There is gold and abundance of rubies, but the lips of knowledge are a rare jewel.'),
  ('Proverbs', 20, 16, 'Take the garment of one who puts up collateral for a stranger; and hold him in pledge for a wayward woman.'),
  ('Proverbs', 20, 17, 'Fraudulent food is sweet to a man, but afterwards his mouth is filled with gravel.'),
  ('Proverbs', 20, 18, 'Plans are established by advice; by wise guidance you wage war!'),
  ('Proverbs', 20, 19, 'He who goes about as a tale-bearer reveals secrets; therefore don’t keep company with him who opens wide his lips.'),
  ('Proverbs', 20, 20, 'Whoever curses his father or his mother, his lamp shall be put out in blackness of darkness.'),
  ('Proverbs', 20, 21, 'An inheritance quickly gained at the beginning won’t be blessed in the end.'),
  ('Proverbs', 20, 22, 'Don’t say, “I will pay back evil.” Wait for the LORD, and he will save you.'),
  ('Proverbs', 20, 23, 'The LORD detests differing weights, and dishonest scales are not pleasing.'),
  ('Proverbs', 20, 24, 'A man’s steps are from the LORD; how then can man understand his way?'),
  ('Proverbs', 20, 25, 'It is a snare to a man to make a rash dedication, then later to consider his vows.'),
  ('Proverbs', 20, 26, 'A wise king winnows out the wicked, and drives the threshing wheel over them.'),
  ('Proverbs', 20, 27, 'The spirit of man is the LORD’s lamp, searching all his innermost parts.'),
  ('Proverbs', 20, 28, 'Love and faithfulness keep the king safe. His throne is sustained by love.'),
  ('Proverbs', 20, 29, 'The glory of young men is their strength. The splendor of old men is their gray hair.'),
  ('Proverbs', 20, 30, 'Wounding blows cleanse away evil, and beatings purge the innermost parts.'),
  ('Proverbs', 21, 1, 'The king’s heart is in the LORD’s hand like the watercourses. He turns it wherever he desires.'),
  ('Proverbs', 21, 2, 'Every way of a man is right in his own eyes, but the LORD weighs the hearts.'),
  ('Proverbs', 21, 3, 'To do righteousness and justice is more acceptable to the LORD than sacrifice.'),
  ('Proverbs', 21, 4, 'A high look and a proud heart, the lamp of the wicked, is sin.'),
  ('Proverbs', 21, 5, 'The plans of the diligent surely lead to profit; and everyone who is hasty surely rushes to poverty.'),
  ('Proverbs', 21, 6, 'Getting treasures by a lying tongue is a fleeting vapor for those who seek death.'),
  ('Proverbs', 21, 7, 'The violence of the wicked will drive them away, because they refuse to do what is right.'),
  ('Proverbs', 21, 8, 'The way of the guilty is devious, but the conduct of the innocent is upright.'),
  ('Proverbs', 21, 9, 'It is better to dwell in the corner of the housetop than to share a house with a contentious woman.'),
  ('Proverbs', 21, 10, 'The soul of the wicked desires evil; his neighbor finds no mercy in his eyes.'),
  ('Proverbs', 21, 11, 'When the mocker is punished, the simple gains wisdom. When the wise is instructed, he receives knowledge.'),
  ('Proverbs', 21, 12, 'The Righteous One considers the house of the wicked, and brings the wicked to ruin.'),
  ('Proverbs', 21, 13, 'Whoever stops his ears at the cry of the poor, he will also cry out, but shall not be heard.'),
  ('Proverbs', 21, 14, 'A gift in secret pacifies anger, and a bribe in the cloak, strong wrath.'),
  ('Proverbs', 21, 15, 'It is joy to the righteous to do justice; but it is a destruction to the workers of iniquity.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Proverbs', 21, 16, 'The man who wanders out of the way of understanding shall rest in the assembly of the departed spirits.'),
  ('Proverbs', 21, 17, 'He who loves pleasure will be a poor man. He who loves wine and oil won’t be rich.'),
  ('Proverbs', 21, 18, 'The wicked is a ransom for the righteous, the treacherous for the upright.'),
  ('Proverbs', 21, 19, 'It is better to dwell in a desert land, than with a contentious and fretful woman.'),
  ('Proverbs', 21, 20, 'There is precious treasure and oil in the dwelling of the wise, but a foolish man swallows it up.'),
  ('Proverbs', 21, 21, 'He who follows after righteousness and kindness finds life, righteousness, and honor.'),
  ('Proverbs', 21, 22, 'A wise man scales the city of the mighty, and brings down the strength of its confidence.'),
  ('Proverbs', 21, 23, 'Whoever guards his mouth and his tongue keeps his soul from troubles.'),
  ('Proverbs', 21, 24, 'The proud and arrogant man—“Scoffer” is his name— he works in the arrogance of pride.'),
  ('Proverbs', 21, 25, 'The desire of the sluggard kills him, for his hands refuse to labor.'),
  ('Proverbs', 21, 26, 'There are those who covet greedily all day long; but the righteous give and don’t withhold.'),
  ('Proverbs', 21, 27, 'The sacrifice of the wicked is an abomination— how much more, when he brings it with a wicked mind!'),
  ('Proverbs', 21, 28, 'A false witness will perish. A man who listens speaks to eternity.'),
  ('Proverbs', 21, 29, 'A wicked man hardens his face; but as for the upright, he establishes his ways.'),
  ('Proverbs', 21, 30, 'There is no wisdom nor understanding nor counsel against the LORD.'),
  ('Proverbs', 21, 31, 'The horse is prepared for the day of battle; but victory is with the LORD.'),
  ('Proverbs', 22, 1, 'A good name is more desirable than great riches, and loving favor is better than silver and gold.'),
  ('Proverbs', 22, 2, 'The rich and the poor have this in common: The LORD is the maker of them all.'),
  ('Proverbs', 22, 3, 'A prudent man sees danger and hides himself; but the simple pass on, and suffer for it.'),
  ('Proverbs', 22, 4, 'The result of humility and the fear of the LORD is wealth, honor, and life.'),
  ('Proverbs', 22, 5, 'Thorns and snares are in the path of the wicked; whoever guards his soul stays far from them.'),
  ('Proverbs', 22, 6, 'Train up a child in the way he should go, and when he is old he will not depart from it.'),
  ('Proverbs', 22, 7, 'The rich rule over the poor. The borrower is servant to the lender.'),
  ('Proverbs', 22, 8, 'He who sows wickedness reaps trouble, and the rod of his fury will be destroyed.'),
  ('Proverbs', 22, 9, 'He who has a generous eye will be blessed, for he shares his food with the poor.'),
  ('Proverbs', 22, 10, 'Drive out the mocker, and strife will go out; yes, quarrels and insults will stop.'),
  ('Proverbs', 22, 11, 'He who loves purity of heart and speaks gracefully is the king’s friend.'),
  ('Proverbs', 22, 12, 'The LORD’s eyes watch over knowledge, but he frustrates the words of the unfaithful.'),
  ('Proverbs', 22, 13, 'The sluggard says, “There is a lion outside! I will be killed in the streets!”'),
  ('Proverbs', 22, 14, 'The mouth of an adulteress is a deep pit. He who is under the LORD’s wrath will fall into it.'),
  ('Proverbs', 22, 15, 'Folly is bound up in the heart of a child; the rod of discipline drives it far from him.'),
  ('Proverbs', 22, 16, 'Whoever oppresses the poor for his own increase and whoever gives to the rich, both come to poverty.'),
  ('Proverbs', 22, 17, 'Turn your ear, and listen to the words of the wise. Apply your heart to my teaching.'),
  ('Proverbs', 22, 18, 'For it is a pleasant thing if you keep them within you, if all of them are ready on your lips.'),
  ('Proverbs', 22, 19, 'I teach you today, even you, so that your trust may be in the LORD.'),
  ('Proverbs', 22, 20, 'Haven’t I written to you thirty excellent things of counsel and knowledge,'),
  ('Proverbs', 22, 21, 'To teach you truth, reliable words, to give sound answers to the ones who sent you?'),
  ('Proverbs', 22, 22, 'Don’t exploit the poor because he is poor; and don’t crush the needy in court;'),
  ('Proverbs', 22, 23, 'for the LORD will plead their case, and plunder the life of those who plunder them.'),
  ('Proverbs', 22, 24, 'Don’t befriend a hot-tempered man. Don’t associate with one who harbors anger,'),
  ('Proverbs', 22, 25, 'lest you learn his ways and ensnare your soul.'),
  ('Proverbs', 22, 26, 'Don’t you be one of those who strike hands, of those who are collateral for debts.'),
  ('Proverbs', 22, 27, 'If you don’t have means to pay, why should he take away your bed from under you?'),
  ('Proverbs', 22, 28, 'Don’t move the ancient boundary stone which your fathers have set up.'),
  ('Proverbs', 22, 29, 'Do you see a man skilled in his work? He will serve kings. He won’t serve obscure men.'),
  ('Proverbs', 23, 1, 'When you sit to eat with a ruler, consider diligently what is before you;'),
  ('Proverbs', 23, 2, 'put a knife to your throat if you are a man given to appetite.'),
  ('Proverbs', 23, 3, 'Don’t be desirous of his dainties, since they are deceitful food.'),
  ('Proverbs', 23, 4, 'Don’t weary yourself to be rich. In your wisdom, show restraint.'),
  ('Proverbs', 23, 5, 'Why do you set your eyes on that which is not? For it certainly sprouts wings like an eagle and flies in the sky.'),
  ('Proverbs', 23, 6, 'Don’t eat the food of him who has a stingy eye, and don’t crave his delicacies,'),
  ('Proverbs', 23, 7, 'for as he thinks about the cost, so he is. “Eat and drink!” he says to you, but his heart is not with you.'),
  ('Proverbs', 23, 8, 'You will vomit up the morsel which you have eaten and waste your pleasant words.'),
  ('Proverbs', 23, 9, 'Don’t speak in the ears of a fool, for he will despise the wisdom of your words.'),
  ('Proverbs', 23, 10, 'Don’t move the ancient boundary stone. Don’t encroach on the fields of the fatherless,'),
  ('Proverbs', 23, 11, 'for their Defender is strong. He will plead their case against you.'),
  ('Proverbs', 23, 12, 'Apply your heart to instruction, and your ears to the words of knowledge.'),
  ('Proverbs', 23, 13, 'Don’t withhold correction from a child. If you punish him with the rod, he will not die.'),
  ('Proverbs', 23, 14, 'Punish him with the rod, and save his soul from Sheol.'),
  ('Proverbs', 23, 15, 'My son, if your heart is wise, then my heart will be glad, even mine.'),
  ('Proverbs', 23, 16, 'Yes, my heart will rejoice when your lips speak what is right.'),
  ('Proverbs', 23, 17, 'Don’t let your heart envy sinners, but rather fear the LORD all day long.'),
  ('Proverbs', 23, 18, 'Indeed surely there is a future hope, and your hope will not be cut off.'),
  ('Proverbs', 23, 19, 'Listen, my son, and be wise, and keep your heart on the right path!'),
  ('Proverbs', 23, 20, 'Don’t be among ones drinking too much wine, or those who gorge themselves on meat;'),
  ('Proverbs', 23, 21, 'for the drunkard and the glutton shall become poor; and drowsiness clothes them in rags.'),
  ('Proverbs', 23, 22, 'Listen to your father who gave you life, and don’t despise your mother when she is old.'),
  ('Proverbs', 23, 23, 'Buy the truth, and don’t sell it. Get wisdom, discipline, and understanding.'),
  ('Proverbs', 23, 24, 'The father of the righteous has great joy. Whoever fathers a wise child delights in him.'),
  ('Proverbs', 23, 25, 'Let your father and your mother be glad! Let her who bore you rejoice!'),
  ('Proverbs', 23, 26, 'My son, give me your heart; and let your eyes keep in my ways.'),
  ('Proverbs', 23, 27, 'For a prostitute is a deep pit; and a wayward wife is a narrow well.'),
  ('Proverbs', 23, 28, 'Yes, she lies in wait like a robber, and increases the unfaithful among men.'),
  ('Proverbs', 23, 29, 'Who has woe? Who has sorrow? Who has strife? Who has complaints? Who has needless bruises? Who has bloodshot eyes?'),
  ('Proverbs', 23, 30, 'Those who stay long at the wine; those who go to seek out mixed wine.'),
  ('Proverbs', 23, 31, 'Don’t look at the wine when it is red, when it sparkles in the cup, when it goes down smoothly.'),
  ('Proverbs', 23, 32, 'In the end, it bites like a snake, and poisons like a viper.'),
  ('Proverbs', 23, 33, 'Your eyes will see strange things, and your mind will imagine confusing things.'),
  ('Proverbs', 23, 34, 'Yes, you will be as he who lies down in the middle of the sea, or as he who lies on top of the rigging:'),
  ('Proverbs', 23, 35, '“They hit me, and I was not hurt! They beat me, and I don’t feel it! When will I wake up? I can do it again. I will look for more.”'),
  ('Proverbs', 24, 1, 'Don’t be envious of evil men, neither desire to be with them;'),
  ('Proverbs', 24, 2, 'for their hearts plot violence and their lips talk about mischief.'),
  ('Proverbs', 24, 3, 'Through wisdom a house is built; by understanding it is established;'),
  ('Proverbs', 24, 4, 'by knowledge the rooms are filled with all rare and beautiful treasure.'),
  ('Proverbs', 24, 5, 'A wise man has great power. A knowledgeable man increases strength,'),
  ('Proverbs', 24, 6, 'for by wise guidance you wage your war, and victory is in many advisors.'),
  ('Proverbs', 24, 7, 'Wisdom is too high for a fool. He doesn’t open his mouth in the gate.'),
  ('Proverbs', 24, 8, 'One who plots to do evil will be called a schemer.'),
  ('Proverbs', 24, 9, 'The schemes of folly are sin. The mocker is detested by men.'),
  ('Proverbs', 24, 10, 'If you falter in the time of trouble, your strength is small.'),
  ('Proverbs', 24, 11, 'Rescue those who are being led away to death! Indeed, hold back those who are staggering to the slaughter!'),
  ('Proverbs', 24, 12, 'If you say, “Behold, we didn’t know this,” doesn’t he who weighs the hearts consider it? He who keeps your soul, doesn’t he know it? Shall he not give to every man according to his work?'),
  ('Proverbs', 24, 13, 'My son, eat honey, for it is good, the droppings of the honeycomb, which are sweet to your taste;'),
  ('Proverbs', 24, 14, 'so you shall know wisdom to be to your soul. If you have found it, then there will be a reward: Your hope will not be cut off.'),
  ('Proverbs', 24, 15, 'Don’t lay in wait, wicked man, against the habitation of the righteous. Don’t destroy his resting place;'),
  ('Proverbs', 24, 16, 'for a righteous man falls seven times and rises up again, but the wicked are overthrown by calamity.'),
  ('Proverbs', 24, 17, 'Don’t rejoice when your enemy falls. Don’t let your heart be glad when he is overthrown,'),
  ('Proverbs', 24, 18, 'lest the LORD see it, and it displease him, and he turn away his wrath from him.'),
  ('Proverbs', 24, 19, 'Don’t fret yourself because of evildoers, neither be envious of the wicked;'),
  ('Proverbs', 24, 20, 'for there will be no reward to the evil man. The lamp of the wicked will be snuffed out.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Proverbs', 24, 21, 'My son, fear the LORD and the king. Don’t join those who are rebellious,'),
  ('Proverbs', 24, 22, 'for their calamity will rise suddenly. Who knows what destruction may come from them both?'),
  ('Proverbs', 24, 23, 'These also are sayings of the wise: To show partiality in judgment is not good.'),
  ('Proverbs', 24, 24, 'He who says to the wicked, “You are righteous,” peoples will curse him, and nations will abhor him—'),
  ('Proverbs', 24, 25, 'but it will go well with those who convict the guilty, and a rich blessing will come on them.'),
  ('Proverbs', 24, 26, 'An honest answer is like a kiss on the lips.'),
  ('Proverbs', 24, 27, 'Prepare your work outside, and get your fields ready. Afterwards, build your house.'),
  ('Proverbs', 24, 28, 'Don’t be a witness against your neighbor without cause. Don’t deceive with your lips.'),
  ('Proverbs', 24, 29, 'Don’t say, “I will do to him as he has done to me; I will repay the man according to his work.”'),
  ('Proverbs', 24, 30, 'I went by the field of the sluggard, by the vineyard of the man void of understanding.'),
  ('Proverbs', 24, 31, 'Behold, it was all grown over with thorns. Its surface was covered with nettles, and its stone wall was broken down.'),
  ('Proverbs', 24, 32, 'Then I saw, and considered well. I saw, and received instruction:'),
  ('Proverbs', 24, 33, 'a little sleep, a little slumber, a little folding of the hands to sleep,'),
  ('Proverbs', 24, 34, 'so your poverty will come as a robber and your want as an armed man.'),
  ('Proverbs', 25, 1, 'These also are proverbs of Solomon, which the men of Hezekiah king of Judah copied out.'),
  ('Proverbs', 25, 2, 'It is the glory of God to conceal a thing, but the glory of kings is to search out a matter.'),
  ('Proverbs', 25, 3, 'As the heavens for height, and the earth for depth, so the hearts of kings are unsearchable.'),
  ('Proverbs', 25, 4, 'Take away the dross from the silver, and material comes out for the refiner.'),
  ('Proverbs', 25, 5, 'Take away the wicked from the king’s presence, and his throne will be established in righteousness.'),
  ('Proverbs', 25, 6, 'Don’t exalt yourself in the presence of the king, or claim a place among great men;'),
  ('Proverbs', 25, 7, 'for it is better that it be said to you, “Come up here,” than that you should be put lower in the presence of the prince, whom your eyes have seen.'),
  ('Proverbs', 25, 8, 'Don’t be hasty in bringing charges to court. What will you do in the end when your neighbor shames you?'),
  ('Proverbs', 25, 9, 'Debate your case with your neighbor, and don’t betray the confidence of another,'),
  ('Proverbs', 25, 10, 'lest one who hears it put you to shame, and your bad reputation never depart.'),
  ('Proverbs', 25, 11, 'A word fitly spoken is like apples of gold in settings of silver.'),
  ('Proverbs', 25, 12, 'As an earring of gold, and an ornament of fine gold, so is a wise reprover to an obedient ear.'),
  ('Proverbs', 25, 13, 'As the cold of snow in the time of harvest, so is a faithful messenger to those who send him; for he refreshes the soul of his masters.'),
  ('Proverbs', 25, 14, 'As clouds and wind without rain, so is he who boasts of gifts deceptively.'),
  ('Proverbs', 25, 15, 'By patience a ruler is persuaded. A soft tongue breaks the bone.'),
  ('Proverbs', 25, 16, 'Have you found honey? Eat as much as is sufficient for you, lest you eat too much, and vomit it.'),
  ('Proverbs', 25, 17, 'Let your foot be seldom in your neighbor’s house, lest he be weary of you, and hate you.'),
  ('Proverbs', 25, 18, 'A man who gives false testimony against his neighbor is like a club, a sword, or a sharp arrow.'),
  ('Proverbs', 25, 19, 'Confidence in someone unfaithful in time of trouble is like a bad tooth or a lame foot.'),
  ('Proverbs', 25, 20, 'As one who takes away a garment in cold weather, or vinegar on soda, so is one who sings songs to a heavy heart.'),
  ('Proverbs', 25, 21, 'If your enemy is hungry, give him food to eat. If he is thirsty, give him water to drink;'),
  ('Proverbs', 25, 22, 'for you will heap coals of fire on his head, and the LORD will reward you.'),
  ('Proverbs', 25, 23, 'The north wind produces rain; so a backbiting tongue brings an angry face.'),
  ('Proverbs', 25, 24, 'It is better to dwell in the corner of the housetop than to share a house with a contentious woman.'),
  ('Proverbs', 25, 25, 'Like cold water to a thirsty soul, so is good news from a far country.'),
  ('Proverbs', 25, 26, 'Like a muddied spring and a polluted well, so is a righteous man who gives way before the wicked.'),
  ('Proverbs', 25, 27, 'It is not good to eat much honey, nor is it honorable to seek one’s own honor.'),
  ('Proverbs', 25, 28, 'Like a city that is broken down and without walls is a man whose spirit is without restraint.'),
  ('Proverbs', 26, 1, 'Like snow in summer, and as rain in harvest, so honor is not fitting for a fool.'),
  ('Proverbs', 26, 2, 'Like a fluttering sparrow, like a darting swallow, so the undeserved curse doesn’t come to rest.'),
  ('Proverbs', 26, 3, 'A whip is for the horse, a bridle for the donkey, and a rod for the back of fools!'),
  ('Proverbs', 26, 4, 'Don’t answer a fool according to his folly, lest you also be like him.'),
  ('Proverbs', 26, 5, 'Answer a fool according to his folly, lest he be wise in his own eyes.'),
  ('Proverbs', 26, 6, 'One who sends a message by the hand of a fool is cutting off feet and drinking violence.'),
  ('Proverbs', 26, 7, 'Like the legs of the lame that hang loose, so is a parable in the mouth of fools.'),
  ('Proverbs', 26, 8, 'As one who binds a stone in a sling, so is he who gives honor to a fool.'),
  ('Proverbs', 26, 9, 'Like a thorn bush that goes into the hand of a drunkard, so is a parable in the mouth of fools.'),
  ('Proverbs', 26, 10, 'As an archer who wounds all, so is he who hires a fool or he who hires those who pass by.'),
  ('Proverbs', 26, 11, 'As a dog that returns to his vomit, so is a fool who repeats his folly.'),
  ('Proverbs', 26, 12, 'Do you see a man wise in his own eyes? There is more hope for a fool than for him.'),
  ('Proverbs', 26, 13, 'The sluggard says, “There is a lion in the road! A fierce lion roams the streets!”'),
  ('Proverbs', 26, 14, 'As the door turns on its hinges, so does the sluggard on his bed.'),
  ('Proverbs', 26, 15, 'The sluggard buries his hand in the dish. He is too lazy to bring it back to his mouth.'),
  ('Proverbs', 26, 16, 'The sluggard is wiser in his own eyes than seven men who answer with discretion.'),
  ('Proverbs', 26, 17, 'Like one who grabs a dog’s ears is one who passes by and meddles in a quarrel not his own.'),
  ('Proverbs', 26, 18, 'Like a madman who shoots torches, arrows, and death,'),
  ('Proverbs', 26, 19, 'is the man who deceives his neighbor and says, “Am I not joking?”'),
  ('Proverbs', 26, 20, 'For lack of wood a fire goes out. Without gossip, a quarrel dies down.'),
  ('Proverbs', 26, 21, 'As coals are to hot embers, and wood to fire, so is a contentious man to kindling strife.'),
  ('Proverbs', 26, 22, 'The words of a whisperer are as dainty morsels, they go down into the innermost parts.'),
  ('Proverbs', 26, 23, 'Like silver dross on an earthen vessel are the lips of a fervent one with an evil heart.'),
  ('Proverbs', 26, 24, 'A malicious man disguises himself with his lips, but he harbors evil in his heart.'),
  ('Proverbs', 26, 25, 'When his speech is charming, don’t believe him, for there are seven abominations in his heart.'),
  ('Proverbs', 26, 26, 'His malice may be concealed by deception, but his wickedness will be exposed in the assembly.'),
  ('Proverbs', 26, 27, 'Whoever digs a pit shall fall into it. Whoever rolls a stone, it will come back on him.'),
  ('Proverbs', 26, 28, 'A lying tongue hates those it hurts; and a flattering mouth works ruin.'),
  ('Proverbs', 27, 1, 'Don’t boast about tomorrow; for you don’t know what a day may bring.'),
  ('Proverbs', 27, 2, 'Let another man praise you, and not your own mouth; a stranger, and not your own lips.'),
  ('Proverbs', 27, 3, 'A stone is heavy, and sand is a burden; but a fool’s provocation is heavier than both.'),
  ('Proverbs', 27, 4, 'Wrath is cruel, and anger is overwhelming; but who is able to stand before jealousy?'),
  ('Proverbs', 27, 5, 'Better is open rebuke than hidden love.'),
  ('Proverbs', 27, 6, 'The wounds of a friend are faithful, although the kisses of an enemy are profuse.'),
  ('Proverbs', 27, 7, 'A full soul loathes a honeycomb; but to a hungry soul, every bitter thing is sweet.'),
  ('Proverbs', 27, 8, 'As a bird that wanders from her nest, so is a man who wanders from his home.'),
  ('Proverbs', 27, 9, 'Perfume and incense bring joy to the heart; so does earnest counsel from a man’s friend.'),
  ('Proverbs', 27, 10, 'Don’t forsake your friend and your father’s friend. Don’t go to your brother’s house in the day of your disaster. A neighbor who is near is better than a distant brother.'),
  ('Proverbs', 27, 11, 'Be wise, my son, and bring joy to my heart, then I can answer my tormentor.'),
  ('Proverbs', 27, 12, 'A prudent man sees danger and takes refuge; but the simple pass on, and suffer for it.'),
  ('Proverbs', 27, 13, 'Take his garment when he puts up collateral for a stranger. Hold it for a wayward woman!'),
  ('Proverbs', 27, 14, 'He who blesses his neighbor with a loud voice early in the morning, it will be taken as a curse by him.'),
  ('Proverbs', 27, 15, 'A continual dropping on a rainy day and a contentious wife are alike:'),
  ('Proverbs', 27, 16, 'restraining her is like restraining the wind, or like grasping oil in his right hand.'),
  ('Proverbs', 27, 17, 'Iron sharpens iron; so a man sharpens his friend’s countenance.'),
  ('Proverbs', 27, 18, 'Whoever tends the fig tree shall eat its fruit. He who looks after his master shall be honored.'),
  ('Proverbs', 27, 19, 'Like water reflects a face, so a man’s heart reflects the man.'),
  ('Proverbs', 27, 20, 'Sheol and Abaddon are never satisfied; and a man’s eyes are never satisfied.'),
  ('Proverbs', 27, 21, 'The crucible is for silver, and the furnace for gold; but man is refined by his praise.'),
  ('Proverbs', 27, 22, 'Though you grind a fool in a mortar with a pestle along with grain, yet his foolishness will not be removed from him.'),
  ('Proverbs', 27, 23, 'Know well the state of your flocks, and pay attention to your herds,'),
  ('Proverbs', 27, 24, 'for riches are not forever, nor does the crown endure to all generations.'),
  ('Proverbs', 27, 25, 'The hay is removed, and the new growth appears, the grasses of the hills are gathered in.'),
  ('Proverbs', 27, 26, 'The lambs are for your clothing, and the goats are the price of a field.'),
  ('Proverbs', 27, 27, 'There will be plenty of goats’ milk for your food, for your family’s food, and for the nourishment of your servant girls.'),
  ('Proverbs', 28, 1, 'The wicked flee when no one pursues; but the righteous are as bold as a lion.'),
  ('Proverbs', 28, 2, 'In rebellion, a land has many rulers, but order is maintained by a man of understanding and knowledge.'),
  ('Proverbs', 28, 3, 'A needy man who oppresses the poor is like a driving rain which leaves no crops.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Proverbs', 28, 4, 'Those who forsake the law praise the wicked; but those who keep the law contend with them.'),
  ('Proverbs', 28, 5, 'Evil men don’t understand justice; but those who seek the LORD understand it fully.'),
  ('Proverbs', 28, 6, 'Better is the poor who walks in his integrity than he who is perverse in his ways, and he is rich.'),
  ('Proverbs', 28, 7, 'Whoever keeps the law is a wise son; but he who is a companion of gluttons shames his father.'),
  ('Proverbs', 28, 8, 'He who increases his wealth by excessive interest gathers it for one who has pity on the poor.'),
  ('Proverbs', 28, 9, 'He who turns away his ear from hearing the law, even his prayer is an abomination.'),
  ('Proverbs', 28, 10, 'Whoever causes the upright to go astray in an evil way, he will fall into his own trap; but the blameless will inherit good.'),
  ('Proverbs', 28, 11, 'The rich man is wise in his own eyes; but the poor who has understanding sees through him.'),
  ('Proverbs', 28, 12, 'When the righteous triumph, there is great glory; but when the wicked rise, men hide themselves.'),
  ('Proverbs', 28, 13, 'He who conceals his sins doesn’t prosper, but whoever confesses and renounces them finds mercy.'),
  ('Proverbs', 28, 14, 'Blessed is the man who always fears; but one who hardens his heart falls into trouble.'),
  ('Proverbs', 28, 15, 'As a roaring lion or a charging bear, so is a wicked ruler over helpless people.'),
  ('Proverbs', 28, 16, 'A tyrannical ruler lacks judgment. One who hates ill-gotten gain will have long days.'),
  ('Proverbs', 28, 17, 'A man who is tormented by blood guilt will be a fugitive until death. No one will support him.'),
  ('Proverbs', 28, 18, 'Whoever walks blamelessly is kept safe; but one with perverse ways will fall suddenly.'),
  ('Proverbs', 28, 19, 'One who works his land will have an abundance of food; but one who chases fantasies will have his fill of poverty.'),
  ('Proverbs', 28, 20, 'A faithful man is rich with blessings; but one who is eager to be rich will not go unpunished.'),
  ('Proverbs', 28, 21, 'To show partiality is not good, yet a man will do wrong for a piece of bread.'),
  ('Proverbs', 28, 22, 'A stingy man hurries after riches, and doesn’t know that poverty waits for him.'),
  ('Proverbs', 28, 23, 'One who rebukes a man will afterward find more favor than one who flatters with the tongue.'),
  ('Proverbs', 28, 24, 'Whoever robs his father or his mother and says, “It’s not wrong,” is a partner with a destroyer.'),
  ('Proverbs', 28, 25, 'One who is greedy stirs up strife; but one who trusts in the LORD will prosper.'),
  ('Proverbs', 28, 26, 'One who trusts in himself is a fool; but one who walks in wisdom is kept safe.'),
  ('Proverbs', 28, 27, 'One who gives to the poor has no lack; but one who closes his eyes will have many curses.'),
  ('Proverbs', 28, 28, 'When the wicked rise, men hide themselves; but when they perish, the righteous thrive.'),
  ('Proverbs', 29, 1, 'He who is often rebuked and stiffens his neck will be destroyed suddenly, with no remedy.'),
  ('Proverbs', 29, 2, 'When the righteous thrive, the people rejoice; but when the wicked rule, the people groan.'),
  ('Proverbs', 29, 3, 'Whoever loves wisdom brings joy to his father; but a companion of prostitutes squanders his wealth.'),
  ('Proverbs', 29, 4, 'The king by justice makes the land stable, but he who takes bribes tears it down.'),
  ('Proverbs', 29, 5, 'A man who flatters his neighbor spreads a net for his feet.'),
  ('Proverbs', 29, 6, 'An evil man is snared by his sin, but the righteous can sing and be glad.'),
  ('Proverbs', 29, 7, 'The righteous care about justice for the poor. The wicked aren’t concerned about knowledge.'),
  ('Proverbs', 29, 8, 'Mockers stir up a city, but wise men turn away anger.'),
  ('Proverbs', 29, 9, 'If a wise man goes to court with a foolish man, the fool rages or scoffs, and there is no peace.'),
  ('Proverbs', 29, 10, 'The bloodthirsty hate a man of integrity; and they seek the life of the upright.'),
  ('Proverbs', 29, 11, 'A fool vents all of his anger, but a wise man brings himself under control.'),
  ('Proverbs', 29, 12, 'If a ruler listens to lies, all of his officials are wicked.'),
  ('Proverbs', 29, 13, 'The poor man and the oppressor have this in common: The LORD gives sight to the eyes of both.'),
  ('Proverbs', 29, 14, 'The king who fairly judges the poor, his throne shall be established forever.'),
  ('Proverbs', 29, 15, 'The rod of correction gives wisdom, but a child left to himself causes shame to his mother.'),
  ('Proverbs', 29, 16, 'When the wicked increase, sin increases; but the righteous will see their downfall.'),
  ('Proverbs', 29, 17, 'Correct your son, and he will give you peace; yes, he will bring delight to your soul.'),
  ('Proverbs', 29, 18, 'Where there is no revelation, the people cast off restraint; but one who keeps the law is blessed.'),
  ('Proverbs', 29, 19, 'A servant can’t be corrected by words. Though he understands, yet he will not respond.'),
  ('Proverbs', 29, 20, 'Do you see a man who is hasty in his words? There is more hope for a fool than for him.'),
  ('Proverbs', 29, 21, 'He who pampers his servant from youth will have him become a son in the end.'),
  ('Proverbs', 29, 22, 'An angry man stirs up strife, and a wrathful man abounds in sin.'),
  ('Proverbs', 29, 23, 'A man’s pride brings him low, but one of lowly spirit gains honor.'),
  ('Proverbs', 29, 24, 'Whoever is an accomplice of a thief is an enemy of his own soul. He takes an oath, but dares not testify.'),
  ('Proverbs', 29, 25, 'The fear of man proves to be a snare, but whoever puts his trust in the LORD is kept safe.'),
  ('Proverbs', 29, 26, 'Many seek the ruler’s favor, but a man’s justice comes from the LORD.'),
  ('Proverbs', 29, 27, 'A dishonest man detests the righteous, and the upright in their ways detest the wicked.'),
  ('Proverbs', 30, 1, 'The words of Agur the son of Jakeh, the revelation: the man says to Ithiel, to Ithiel and Ucal:'),
  ('Proverbs', 30, 2, '“Surely I am the most ignorant man, and don’t have a man’s understanding.'),
  ('Proverbs', 30, 3, 'I have not learned wisdom, neither do I have the knowledge of the Holy One.'),
  ('Proverbs', 30, 4, 'Who has ascended up into heaven, and descended? Who has gathered the wind in his fists? Who has bound the waters in his garment? Who has established all the ends of the earth? What is his name, and what is his son’s name, if you know?'),
  ('Proverbs', 30, 5, '“Every word of God is flawless. He is a shield to those who take refuge in him.'),
  ('Proverbs', 30, 6, 'Don’t you add to his words, lest he reprove you, and you be found a liar.'),
  ('Proverbs', 30, 7, '“Two things I have asked of you. Don’t deny me before I die.'),
  ('Proverbs', 30, 8, 'Remove far from me falsehood and lies. Give me neither poverty nor riches. Feed me with the food that is needful for me,'),
  ('Proverbs', 30, 9, 'lest I be full, deny you, and say, ‘Who is the LORD?’ or lest I be poor, and steal, and so dishonor the name of my God.'),
  ('Proverbs', 30, 10, '“Don’t slander a servant to his master, lest he curse you, and you be held guilty.'),
  ('Proverbs', 30, 11, 'There is a generation that curses their father, and doesn’t bless their mother.'),
  ('Proverbs', 30, 12, 'There is a generation that is pure in their own eyes, yet are not washed from their filthiness.'),
  ('Proverbs', 30, 13, 'There is a generation, oh how lofty are their eyes! Their eyelids are lifted up.'),
  ('Proverbs', 30, 14, 'There is a generation whose teeth are like swords, and their jaws like knives, to devour the poor from the earth, and the needy from among men.'),
  ('Proverbs', 30, 15, '“The leech has two daughters: ‘Give, give.’ “There are three things that are never satisfied; four that don’t say, ‘Enough!’:'),
  ('Proverbs', 30, 16, 'Sheol, the barren womb, the earth that is not satisfied with water, and the fire that doesn’t say, ‘Enough!’'),
  ('Proverbs', 30, 17, '“The eye that mocks at his father, and scorns obedience to his mother, the ravens of the valley shall pick it out, the young eagles shall eat it.'),
  ('Proverbs', 30, 18, '“There are three things which are too amazing for me, four which I don’t understand:'),
  ('Proverbs', 30, 19, 'The way of an eagle in the air, the way of a serpent on a rock, the way of a ship in the middle of the sea, and the way of a man with a maiden.'),
  ('Proverbs', 30, 20, '“So is the way of an adulterous woman: She eats and wipes her mouth, and says, ‘I have done nothing wrong.’'),
  ('Proverbs', 30, 21, '“For three things the earth trembles, and under four, it can’t bear up:'),
  ('Proverbs', 30, 22, 'For a servant when he is king, a fool when he is filled with food,'),
  ('Proverbs', 30, 23, 'for an unloved woman when she is married, and a servant who is heir to her mistress.'),
  ('Proverbs', 30, 24, '“There are four things which are little on the earth, but they are exceedingly wise:'),
  ('Proverbs', 30, 25, 'The ants are not a strong people, yet they provide their food in the summer.'),
  ('Proverbs', 30, 26, 'The hyraxes are but a feeble folk, yet make they their houses in the rocks.'),
  ('Proverbs', 30, 27, 'The locusts have no king, yet they advance in ranks.'),
  ('Proverbs', 30, 28, 'You can catch a lizard with your hands, yet it is in kings’ palaces.'),
  ('Proverbs', 30, 29, '“There are three things which are stately in their march, four which are stately in going:'),
  ('Proverbs', 30, 30, 'The lion, which is mightiest among animals, and doesn’t turn away for any;'),
  ('Proverbs', 30, 31, 'the greyhound; the male goat; and the king against whom there is no rising up.'),
  ('Proverbs', 30, 32, '“If you have done foolishly in lifting up yourself, or if you have thought evil, put your hand over your mouth.'),
  ('Proverbs', 30, 33, 'For as the churning of milk produces butter, and the wringing of the nose produces blood, so the forcing of wrath produces strife.”'),
  ('Proverbs', 31, 1, 'The words of King Lemuel—the revelation which his mother taught him:'),
  ('Proverbs', 31, 2, '“Oh, my son! Oh, son of my womb! Oh, son of my vows!'),
  ('Proverbs', 31, 3, 'Don’t give your strength to women, nor your ways to that which destroys kings.'),
  ('Proverbs', 31, 4, 'It is not for kings, Lemuel, it is not for kings to drink wine, nor for princes to say, ‘Where is strong drink?’'),
  ('Proverbs', 31, 5, 'lest they drink, and forget the law, and pervert the justice due to anyone who is afflicted.'),
  ('Proverbs', 31, 6, 'Give strong drink to him who is ready to perish, and wine to the bitter in soul.'),
  ('Proverbs', 31, 7, 'Let him drink, and forget his poverty, and remember his misery no more.'),
  ('Proverbs', 31, 8, 'Open your mouth for the mute, in the cause of all who are left desolate.'),
  ('Proverbs', 31, 9, 'Open your mouth, judge righteously, and serve justice to the poor and needy.”'),
  ('Proverbs', 31, 10, 'Who can find a worthy woman? For her value is far above rubies.'),
  ('Proverbs', 31, 11, 'The heart of her husband trusts in her. He shall have no lack of gain.'),
  ('Proverbs', 31, 12, 'She does him good, and not harm, all the days of her life.'),
  ('Proverbs', 31, 13, 'She seeks wool and flax, and works eagerly with her hands.'),
  ('Proverbs', 31, 14, 'She is like the merchant ships. She brings her bread from afar.'),
  ('Proverbs', 31, 15, 'She rises also while it is yet night, gives food to her household, and portions for her servant girls.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Proverbs', 31, 16, 'She considers a field, and buys it. With the fruit of her hands, she plants a vineyard.'),
  ('Proverbs', 31, 17, 'She arms her waist with strength, and makes her arms strong.'),
  ('Proverbs', 31, 18, 'She perceives that her merchandise is profitable. Her lamp doesn’t go out by night.'),
  ('Proverbs', 31, 19, 'She lays her hands to the distaff, and her hands hold the spindle.'),
  ('Proverbs', 31, 20, 'She opens her arms to the poor; yes, she extends her hands to the needy.'),
  ('Proverbs', 31, 21, 'She is not afraid of the snow for her household, for all her household are clothed with scarlet.'),
  ('Proverbs', 31, 22, 'She makes for herself carpets of tapestry. Her clothing is fine linen and purple.'),
  ('Proverbs', 31, 23, 'Her husband is respected in the gates, when he sits among the elders of the land.'),
  ('Proverbs', 31, 24, 'She makes linen garments and sells them, and delivers sashes to the merchant.'),
  ('Proverbs', 31, 25, 'Strength and dignity are her clothing. She laughs at the time to come.'),
  ('Proverbs', 31, 26, 'She opens her mouth with wisdom. Kind instruction is on her tongue.'),
  ('Proverbs', 31, 27, 'She looks well to the ways of her household, and doesn’t eat the bread of idleness.'),
  ('Proverbs', 31, 28, 'Her children rise up and call her blessed. Her husband also praises her:'),
  ('Proverbs', 31, 29, '“Many women do noble things, but you excel them all.”'),
  ('Proverbs', 31, 30, 'Charm is deceitful, and beauty is vain; but a woman who fears the LORD, she shall be praised.'),
  ('Proverbs', 31, 31, 'Give her of the fruit of her hands! Let her works praise her in the gates!'),
  ('Ecclesiastes', 1, 1, 'The words of the Preacher, the son of David, king in Jerusalem:'),
  ('Ecclesiastes', 1, 2, '“Vanity of vanities,” says the Preacher; “Vanity of vanities, all is vanity.”'),
  ('Ecclesiastes', 1, 3, 'What does man gain from all his labor in which he labors under the sun?'),
  ('Ecclesiastes', 1, 4, 'One generation goes, and another generation comes; but the earth remains forever.'),
  ('Ecclesiastes', 1, 5, 'The sun also rises, and the sun goes down, and hurries to its place where it rises.'),
  ('Ecclesiastes', 1, 6, 'The wind goes toward the south, and turns around to the north. It turns around continually as it goes, and the wind returns again to its courses.'),
  ('Ecclesiastes', 1, 7, 'All the rivers run into the sea, yet the sea is not full. To the place where the rivers flow, there they flow again.'),
  ('Ecclesiastes', 1, 8, 'All things are full of weariness beyond uttering. The eye is not satisfied with seeing, nor the ear filled with hearing.'),
  ('Ecclesiastes', 1, 9, 'That which has been is that which shall be, and that which has been done is that which shall be done; and there is no new thing under the sun.'),
  ('Ecclesiastes', 1, 10, 'Is there a thing of which it may be said, “Behold, this is new”? It has been long ago, in the ages which were before us.'),
  ('Ecclesiastes', 1, 11, 'There is no memory of the former; neither shall there be any memory of the latter that are to come, among those that shall come after.'),
  ('Ecclesiastes', 1, 12, 'I, the Preacher, was king over Israel in Jerusalem.'),
  ('Ecclesiastes', 1, 13, 'I applied my heart to seek and to search out by wisdom concerning all that is done under the sky. It is a heavy burden that God has given to the sons of men to be afflicted with.'),
  ('Ecclesiastes', 1, 14, 'I have seen all the works that are done under the sun; and behold, all is vanity and a chasing after wind.'),
  ('Ecclesiastes', 1, 15, 'That which is crooked can’t be made straight; and that which is lacking can’t be counted.'),
  ('Ecclesiastes', 1, 16, 'I said to myself, “Behold, I have obtained for myself great wisdom above all who were before me in Jerusalem. Yes, my heart has had great experience of wisdom and knowledge.”'),
  ('Ecclesiastes', 1, 17, 'I applied my heart to know wisdom, and to know madness and folly. I perceived that this also was a chasing after wind.'),
  ('Ecclesiastes', 1, 18, 'For in much wisdom is much grief; and he who increases knowledge increases sorrow.'),
  ('Ecclesiastes', 2, 1, 'I said in my heart, “Come now, I will test you with mirth; therefore enjoy pleasure;” and behold, this also was vanity.'),
  ('Ecclesiastes', 2, 2, 'I said of laughter, “It is foolishness;” and of mirth, “What does it accomplish?”'),
  ('Ecclesiastes', 2, 3, 'I searched in my heart how to cheer my flesh with wine, my heart yet guiding me with wisdom, and how to lay hold of folly, until I might see what it was good for the sons of men that they should do under heaven all the days of their lives.'),
  ('Ecclesiastes', 2, 4, 'I made myself great works. I built myself houses. I planted myself vineyards.'),
  ('Ecclesiastes', 2, 5, 'I made myself gardens and parks, and I planted trees in them of all kinds of fruit.'),
  ('Ecclesiastes', 2, 6, 'I made myself pools of water, to water the forest where trees were grown.'),
  ('Ecclesiastes', 2, 7, 'I bought male servants and female servants, and had servants born in my house. I also had great possessions of herds and flocks, above all who were before me in Jerusalem.'),
  ('Ecclesiastes', 2, 8, 'I also gathered silver and gold for myself, and the treasure of kings and of the provinces. I got myself male and female singers, and the delights of the sons of men: musical instruments of all sorts.'),
  ('Ecclesiastes', 2, 9, 'So I was great, and increased more than all who were before me in Jerusalem. My wisdom also remained with me.'),
  ('Ecclesiastes', 2, 10, 'Whatever my eyes desired, I didn’t keep from them. I didn’t withhold my heart from any joy, for my heart rejoiced because of all my labor, and this was my portion from all my labor.'),
  ('Ecclesiastes', 2, 11, 'Then I looked at all the works that my hands had worked, and at the labor that I had labored to do; and behold, all was vanity and a chasing after wind, and there was no profit under the sun.'),
  ('Ecclesiastes', 2, 12, 'I turned myself to consider wisdom, madness, and folly; for what can the king’s successor do? Just that which has been done long ago.'),
  ('Ecclesiastes', 2, 13, 'Then I saw that wisdom excels folly, as far as light excels darkness.'),
  ('Ecclesiastes', 2, 14, 'The wise man’s eyes are in his head, and the fool walks in darkness—and yet I perceived that one event happens to them all.'),
  ('Ecclesiastes', 2, 15, 'Then I said in my heart, “As it happens to the fool, so will it happen even to me; and why was I then more wise?” Then I said in my heart that this also is vanity.'),
  ('Ecclesiastes', 2, 16, 'For of the wise man, even as of the fool, there is no memory forever, since in the days to come all will have been long forgotten. Indeed, the wise man must die just like the fool!'),
  ('Ecclesiastes', 2, 17, 'So I hated life, because the work that is worked under the sun was grievous to me; for all is vanity and a chasing after wind.'),
  ('Ecclesiastes', 2, 18, 'I hated all my labor in which I labored under the sun, because I must leave it to the man who comes after me.'),
  ('Ecclesiastes', 2, 19, 'Who knows whether he will be a wise man or a fool? Yet he will have rule over all of my labor in which I have labored, and in which I have shown myself wise under the sun. This also is vanity.'),
  ('Ecclesiastes', 2, 20, 'Therefore I began to cause my heart to despair concerning all the labor in which I had labored under the sun.'),
  ('Ecclesiastes', 2, 21, 'For there is a man whose labor is with wisdom, with knowledge, and with skillfulness; yet he shall leave it for his portion to a man who has not labored for it. This also is vanity and a great evil.'),
  ('Ecclesiastes', 2, 22, 'For what does a man have of all his labor and of the striving of his heart, in which he labors under the sun?'),
  ('Ecclesiastes', 2, 23, 'For all his days are sorrows, and his travail is grief; yes, even in the night his heart takes no rest. This also is vanity.'),
  ('Ecclesiastes', 2, 24, 'There is nothing better for a man than that he should eat and drink, and make his soul enjoy good in his labor. This also I saw, that it is from the hand of God.'),
  ('Ecclesiastes', 2, 25, 'For who can eat, or who can have enjoyment, more than I?'),
  ('Ecclesiastes', 2, 26, 'For to the man who pleases him, God gives wisdom, knowledge, and joy; but to the sinner he gives travail, to gather and to heap up, that he may give to him who pleases God. This also is vanity and a chasing after wind.'),
  ('Ecclesiastes', 3, 1, 'For everything there is a season, and a time for every purpose under heaven:'),
  ('Ecclesiastes', 3, 2, 'a time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;'),
  ('Ecclesiastes', 3, 3, 'a time to kill, and a time to heal; a time to break down, and a time to build up;'),
  ('Ecclesiastes', 3, 4, 'a time to weep, and a time to laugh; a time to mourn, and a time to dance;'),
  ('Ecclesiastes', 3, 5, 'a time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;'),
  ('Ecclesiastes', 3, 6, 'a time to seek, and a time to lose; a time to keep, and a time to cast away;'),
  ('Ecclesiastes', 3, 7, 'a time to tear, and a time to sew; a time to keep silence, and a time to speak;'),
  ('Ecclesiastes', 3, 8, 'a time to love, and a time to hate; a time for war, and a time for peace.'),
  ('Ecclesiastes', 3, 9, 'What profit has he who works in that in which he labors?'),
  ('Ecclesiastes', 3, 10, 'I have seen the burden which God has given to the sons of men to be afflicted with.'),
  ('Ecclesiastes', 3, 11, 'He has made everything beautiful in its time. He has also set eternity in their hearts, yet so that man can’t find out the work that God has done from the beginning even to the end.'),
  ('Ecclesiastes', 3, 12, 'I know that there is nothing better for them than to rejoice, and to do good as long as they live.'),
  ('Ecclesiastes', 3, 13, 'Also that every man should eat and drink, and enjoy good in all his labor, is the gift of God.'),
  ('Ecclesiastes', 3, 14, 'I know that whatever God does, it shall be forever. Nothing can be added to it, nor anything taken from it; and God has done it, that men should fear before him.'),
  ('Ecclesiastes', 3, 15, 'That which is has been long ago, and that which is to be has been long ago. God seeks again that which is passed away.'),
  ('Ecclesiastes', 3, 16, 'Moreover I saw under the sun, in the place of justice, that wickedness was there; and in the place of righteousness, that wickedness was there.'),
  ('Ecclesiastes', 3, 17, 'I said in my heart, “God will judge the righteous and the wicked; for there is a time there for every purpose and for every work.”'),
  ('Ecclesiastes', 3, 18, 'I said in my heart, “As for the sons of men, God tests them, so that they may see that they themselves are like animals.'),
  ('Ecclesiastes', 3, 19, 'For that which happens to the sons of men happens to animals. Even one thing happens to them. As the one dies, so the other dies. Yes, they have all one breath; and man has no advantage over the animals, for all is vanity.'),
  ('Ecclesiastes', 3, 20, 'All go to one place. All are from the dust, and all turn to dust again.'),
  ('Ecclesiastes', 3, 21, 'Who knows the spirit of man, whether it goes upward, and the spirit of the animal, whether it goes downward to the earth?”'),
  ('Ecclesiastes', 3, 22, 'Therefore I saw that there is nothing better than that a man should rejoice in his works, for that is his portion; for who can bring him to see what will be after him?'),
  ('Ecclesiastes', 4, 1, 'Then I returned and saw all the oppressions that are done under the sun: and behold, the tears of those who were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter.'),
  ('Ecclesiastes', 4, 2, 'Therefore I praised the dead who have been long dead more than the living who are yet alive.'),
  ('Ecclesiastes', 4, 3, 'Yes, better than them both is him who has not yet been, who has not seen the evil work that is done under the sun.'),
  ('Ecclesiastes', 4, 4, 'Then I saw all the labor and achievement that is the envy of a man’s neighbor. This also is vanity and a striving after wind.'),
  ('Ecclesiastes', 4, 5, 'The fool folds his hands together and ruins himself.'),
  ('Ecclesiastes', 4, 6, 'Better is a handful, with quietness, than two handfuls with labor and chasing after wind.'),
  ('Ecclesiastes', 4, 7, 'Then I returned and saw vanity under the sun.'),
  ('Ecclesiastes', 4, 8, 'There is one who is alone, and he has neither son nor brother. There is no end to all of his labor, neither are his eyes satisfied with wealth. “For whom then do I labor and deprive my soul of enjoyment?” This also is vanity. Yes, it is a miserable business.'),
  ('Ecclesiastes', 4, 9, 'Two are better than one, because they have a good reward for their labor.'),
  ('Ecclesiastes', 4, 10, 'For if they fall, the one will lift up his fellow; but woe to him who is alone when he falls, and doesn’t have another to lift him up.'),
  ('Ecclesiastes', 4, 11, 'Again, if two lie together, then they have warmth; but how can one keep warm alone?'),
  ('Ecclesiastes', 4, 12, 'If a man prevails against one who is alone, two shall withstand him; and a threefold cord is not quickly broken.'),
  ('Ecclesiastes', 4, 13, 'Better is a poor and wise youth than an old and foolish king who doesn’t know how to receive admonition any more.'),
  ('Ecclesiastes', 4, 14, 'For out of prison he came out to be king; yes, even in his kingdom he was born poor.'),
  ('Ecclesiastes', 4, 15, 'I saw all the living who walk under the sun, that they were with the youth, the other, who succeeded him.'),
  ('Ecclesiastes', 4, 16, 'There was no end of all the people, even of all them over whom he was—yet those who come after shall not rejoice in him. Surely this also is vanity and a chasing after wind.'),
  ('Ecclesiastes', 5, 1, 'Guard your steps when you go to God’s house; for to draw near to listen is better than to give the sacrifice of fools, for they don’t know that they do evil.'),
  ('Ecclesiastes', 5, 2, 'Don’t be rash with your mouth, and don’t let your heart be hasty to utter anything before God; for God is in heaven, and you on earth. Therefore let your words be few.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Ecclesiastes', 5, 3, 'For as a dream comes with a multitude of cares, so a fool’s speech with a multitude of words.'),
  ('Ecclesiastes', 5, 4, 'When you vow a vow to God, don’t defer to pay it; for he has no pleasure in fools. Pay that which you vow.'),
  ('Ecclesiastes', 5, 5, 'It is better that you should not vow, than that you should vow and not pay.'),
  ('Ecclesiastes', 5, 6, 'Don’t allow your mouth to lead you into sin. Don’t protest before the messenger that this was a mistake. Why should God be angry at your voice, and destroy the work of your hands?'),
  ('Ecclesiastes', 5, 7, 'For in the multitude of dreams there are vanities, as well as in many words; but you must fear God.'),
  ('Ecclesiastes', 5, 8, 'If you see the oppression of the poor, and the violent taking away of justice and righteousness in a district, don’t marvel at the matter, for one official is eyed by a higher one, and there are officials over them.'),
  ('Ecclesiastes', 5, 9, 'Moreover the profit of the earth is for all. The king profits from the field.'),
  ('Ecclesiastes', 5, 10, 'He who loves silver shall not be satisfied with silver, nor he who loves abundance, with increase. This also is vanity.'),
  ('Ecclesiastes', 5, 11, 'When goods increase, those who eat them are increased; and what advantage is there to its owner, except to feast on them with his eyes?'),
  ('Ecclesiastes', 5, 12, 'The sleep of a laboring man is sweet, whether he eats little or much; but the abundance of the rich will not allow him to sleep.'),
  ('Ecclesiastes', 5, 13, 'There is a grievous evil which I have seen under the sun: wealth kept by its owner to his harm.'),
  ('Ecclesiastes', 5, 14, 'Those riches perish by misfortune, and if he has fathered a son, there is nothing in his hand.'),
  ('Ecclesiastes', 5, 15, 'As he came out of his mother’s womb, naked shall he go again as he came, and shall take nothing for his labor, which he may carry away in his hand.'),
  ('Ecclesiastes', 5, 16, 'This also is a grievous evil, that in all points as he came, so shall he go. And what profit does he have who labors for the wind?'),
  ('Ecclesiastes', 5, 17, 'All his days he also eats in darkness, he is frustrated, and has sickness and wrath.'),
  ('Ecclesiastes', 5, 18, 'Behold, that which I have seen to be good and proper is for one to eat and to drink, and to enjoy good in all his labor, in which he labors under the sun, all the days of his life which God has given him; for this is his portion.'),
  ('Ecclesiastes', 5, 19, 'Every man also to whom God has given riches and wealth, and has given him power to eat of it, and to take his portion, and to rejoice in his labor—this is the gift of God.'),
  ('Ecclesiastes', 5, 20, 'For he shall not often reflect on the days of his life, because God occupies him with the joy of his heart.'),
  ('Ecclesiastes', 6, 1, 'There is an evil which I have seen under the sun, and it is heavy on men:'),
  ('Ecclesiastes', 6, 2, 'a man to whom God gives riches, wealth, and honor, so that he lacks nothing for his soul of all that he desires, yet God gives him no power to eat of it, but an alien eats it. This is vanity, and it is an evil disease.'),
  ('Ecclesiastes', 6, 3, 'If a man fathers a hundred children, and lives many years, so that the days of his years are many, but his soul is not filled with good, and moreover he has no burial, I say that a stillborn child is better than he;'),
  ('Ecclesiastes', 6, 4, 'for it comes in vanity, and departs in darkness, and its name is covered with darkness.'),
  ('Ecclesiastes', 6, 5, 'Moreover it has not seen the sun nor known it. This has rest rather than the other.'),
  ('Ecclesiastes', 6, 6, 'Yes, though he live a thousand years twice told, and yet fails to enjoy good, don’t all go to one place?'),
  ('Ecclesiastes', 6, 7, 'All the labor of man is for his mouth, and yet the appetite is not filled.'),
  ('Ecclesiastes', 6, 8, 'For what advantage has the wise more than the fool? What has the poor man, that knows how to walk before the living?'),
  ('Ecclesiastes', 6, 9, 'Better is the sight of the eyes than the wandering of the desire. This also is vanity and a chasing after wind.'),
  ('Ecclesiastes', 6, 10, 'Whatever has been, its name was given long ago; and it is known what man is; neither can he contend with him who is mightier than he.'),
  ('Ecclesiastes', 6, 11, 'For there are many words that create vanity. What does that profit man?'),
  ('Ecclesiastes', 6, 12, 'For who knows what is good for man in life, all the days of his vain life which he spends like a shadow? For who can tell a man what will be after him under the sun?'),
  ('Ecclesiastes', 7, 1, 'A good name is better than fine perfume; and the day of death better than the day of one’s birth.'),
  ('Ecclesiastes', 7, 2, 'It is better to go to the house of mourning than to go to the house of feasting; for that is the end of all men, and the living should take this to heart.'),
  ('Ecclesiastes', 7, 3, 'Sorrow is better than laughter; for by the sadness of the face the heart is made good.'),
  ('Ecclesiastes', 7, 4, 'The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth.'),
  ('Ecclesiastes', 7, 5, 'It is better to hear the rebuke of the wise than for a man to hear the song of fools.'),
  ('Ecclesiastes', 7, 6, 'For as the crackling of thorns under a pot, so is the laughter of the fool. This also is vanity.'),
  ('Ecclesiastes', 7, 7, 'Surely extortion makes the wise man foolish; and a bribe destroys the understanding.'),
  ('Ecclesiastes', 7, 8, 'Better is the end of a thing than its beginning. The patient in spirit is better than the proud in spirit.'),
  ('Ecclesiastes', 7, 9, 'Don’t be hasty in your spirit to be angry, for anger rests in the bosom of fools.'),
  ('Ecclesiastes', 7, 10, 'Don’t say, “Why were the former days better than these?” For you do not ask wisely about this.'),
  ('Ecclesiastes', 7, 11, 'Wisdom is as good as an inheritance. Yes, it is more excellent for those who see the sun.'),
  ('Ecclesiastes', 7, 12, 'For wisdom is a defense, even as money is a defense; but the excellency of knowledge is that wisdom preserves the life of him who has it.'),
  ('Ecclesiastes', 7, 13, 'Consider the work of God, for who can make that straight which he has made crooked?'),
  ('Ecclesiastes', 7, 14, 'In the day of prosperity be joyful, and in the day of adversity consider; yes, God has made the one side by side with the other, to the end that man should not find out anything after him.'),
  ('Ecclesiastes', 7, 15, 'All this I have seen in my days of vanity: there is a righteous man who perishes in his righteousness, and there is a wicked man who lives long in his evildoing.'),
  ('Ecclesiastes', 7, 16, 'Don’t be overly righteous, neither make yourself overly wise. Why should you destroy yourself?'),
  ('Ecclesiastes', 7, 17, 'Don’t be too wicked, neither be foolish. Why should you die before your time?'),
  ('Ecclesiastes', 7, 18, 'It is good that you should take hold of this. Yes, also don’t withdraw your hand from that; for he who fears God will come out of them all.'),
  ('Ecclesiastes', 7, 19, 'Wisdom is a strength to the wise man more than ten rulers who are in a city.'),
  ('Ecclesiastes', 7, 20, 'Surely there is not a righteous man on earth who does good and doesn’t sin.'),
  ('Ecclesiastes', 7, 21, 'Also don’t take heed to all words that are spoken, lest you hear your servant curse you;'),
  ('Ecclesiastes', 7, 22, 'for often your own heart knows that you yourself have likewise cursed others.'),
  ('Ecclesiastes', 7, 23, 'All this I have proved in wisdom. I said, “I will be wise;” but it was far from me.'),
  ('Ecclesiastes', 7, 24, 'That which is, is far off and exceedingly deep. Who can find it out?'),
  ('Ecclesiastes', 7, 25, 'I turned around, and my heart sought to know and to search out, and to seek wisdom and the scheme of things, and to know that wickedness is stupidity, and that foolishness is madness.'),
  ('Ecclesiastes', 7, 26, 'I find more bitter than death the woman whose heart is snares and traps, whose hands are chains. Whoever pleases God shall escape from her; but the sinner will be ensnared by her.'),
  ('Ecclesiastes', 7, 27, '“Behold, I have found this,” says the Preacher, “to one another, to find an explanation'),
  ('Ecclesiastes', 7, 28, 'which my soul still seeks, but I have not found. I have found one man among a thousand, but I have not found a woman among all those.'),
  ('Ecclesiastes', 7, 29, 'Behold, I have only found this: that God made mankind upright; but they search for many inventions.”'),
  ('Ecclesiastes', 8, 1, 'Who is like the wise man? And who knows the interpretation of a thing? A man’s wisdom makes his face shine, and the hardness of his face is changed.'),
  ('Ecclesiastes', 8, 2, 'I say, “Keep the king’s command!” because of the oath to God.'),
  ('Ecclesiastes', 8, 3, 'Don’t be hasty to go out of his presence. Don’t persist in an evil thing, for he does whatever pleases him,'),
  ('Ecclesiastes', 8, 4, 'for the king’s word is supreme. Who can say to him, “What are you doing?”'),
  ('Ecclesiastes', 8, 5, 'Whoever keeps the commandment shall not come to harm, and his wise heart will know the time and procedure.'),
  ('Ecclesiastes', 8, 6, 'For there is a time and procedure for every purpose, although the misery of man is heavy on him.'),
  ('Ecclesiastes', 8, 7, 'For he doesn’t know that which will be; for who can tell him how it will be?'),
  ('Ecclesiastes', 8, 8, 'There is no man who has power over the spirit to contain the spirit; neither does he have power over the day of death. There is no discharge in war; neither shall wickedness deliver those who practice it.'),
  ('Ecclesiastes', 8, 9, 'All this I have seen, and applied my mind to every work that is done under the sun. There is a time in which one man has power over another to his hurt.'),
  ('Ecclesiastes', 8, 10, 'So I saw the wicked buried. Indeed they came also from holiness. They went and were forgotten in the city where they did this. This also is vanity.'),
  ('Ecclesiastes', 8, 11, 'Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil.'),
  ('Ecclesiastes', 8, 12, 'Though a sinner commits crimes a hundred times, and lives long, yet surely I know that it will be better with those who fear God, who are reverent before him.'),
  ('Ecclesiastes', 8, 13, 'But it shall not be well with the wicked, neither shall he lengthen days like a shadow, because he doesn’t fear God.'),
  ('Ecclesiastes', 8, 14, 'There is a vanity which is done on the earth, that there are righteous men to whom it happens according to the work of the wicked. Again, there are wicked men to whom it happens according to the work of the righteous. I said that this also is vanity.'),
  ('Ecclesiastes', 8, 15, 'Then I commended mirth, because a man has no better thing under the sun than to eat, to drink, and to be joyful: for that will accompany him in his labor all the days of his life which God has given him under the sun.'),
  ('Ecclesiastes', 8, 16, 'When I applied my heart to know wisdom, and to see the business that is done on the earth (even though eyes see no sleep day or night),'),
  ('Ecclesiastes', 8, 17, 'then I saw all the work of God, that man can’t find out the work that is done under the sun, because however much a man labors to seek it out, yet he won’t find it. Yes even though a wise man thinks he can comprehend it, he won’t be able to find it.'),
  ('Ecclesiastes', 9, 1, 'For all this I laid to my heart, even to explore all this: that the righteous, and the wise, and their works, are in the hand of God; whether it is love or hatred, man doesn’t know it; all is before them.'),
  ('Ecclesiastes', 9, 2, 'All things come alike to all. There is one event to the righteous and to the wicked; to the good, to the clean, to the unclean, to him who sacrifices, and to him who doesn’t sacrifice. As is the good, so is the sinner; he who takes an oath, as he who fears an oath.'),
  ('Ecclesiastes', 9, 3, 'This is an evil in all that is done under the sun, that there is one event to all. Yes also, the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead.'),
  ('Ecclesiastes', 9, 4, 'For to him who is joined with all the living there is hope; for a living dog is better than a dead lion.'),
  ('Ecclesiastes', 9, 5, 'For the living know that they will die, but the dead don’t know anything, neither do they have any more a reward; for their memory is forgotten.'),
  ('Ecclesiastes', 9, 6, 'Also their love, their hatred, and their envy has perished long ago; neither do they any longer have a portion forever in anything that is done under the sun.'),
  ('Ecclesiastes', 9, 7, 'Go your way—eat your bread with joy, and drink your wine with a merry heart; for God has already accepted your works.'),
  ('Ecclesiastes', 9, 8, 'Let your garments be always white, and don’t let your head lack oil.'),
  ('Ecclesiastes', 9, 9, 'Live joyfully with the wife whom you love all the days of your life of vanity, which he has given you under the sun, all your days of vanity, for that is your portion in life, and in your labor in which you labor under the sun.'),
  ('Ecclesiastes', 9, 10, 'Whatever your hand finds to do, do it with your might; for there is no work, nor plan, nor knowledge, nor wisdom, in Sheol, where you are going.'),
  ('Ecclesiastes', 9, 11, 'I returned and saw under the sun that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favor to men of skill; but time and chance happen to them all.'),
  ('Ecclesiastes', 9, 12, 'For man also doesn’t know his time. As the fish that are taken in an evil net, and as the birds that are caught in the snare, even so are the sons of men snared in an evil time, when it falls suddenly on them.'),
  ('Ecclesiastes', 9, 13, 'I have also seen wisdom under the sun in this way, and it seemed great to me.'),
  ('Ecclesiastes', 9, 14, 'There was a little city, and few men within it; and a great king came against it, besieged it, and built great bulwarks against it.'),
  ('Ecclesiastes', 9, 15, 'Now a poor wise man was found in it, and he by his wisdom delivered the city; yet no man remembered that same poor man.'),
  ('Ecclesiastes', 9, 16, 'Then I said, “Wisdom is better than strength.” Nevertheless the poor man’s wisdom is despised, and his words are not heard.'),
  ('Ecclesiastes', 9, 17, 'The words of the wise heard in quiet are better than the cry of him who rules among fools.'),
  ('Ecclesiastes', 9, 18, 'Wisdom is better than weapons of war; but one sinner destroys much good.'),
  ('Ecclesiastes', 10, 1, 'Dead flies cause the oil of the perfumer to produce an evil odor; so does a little folly outweigh wisdom and honor.'),
  ('Ecclesiastes', 10, 2, 'A wise man’s heart is at his right hand, but a fool’s heart at his left.'),
  ('Ecclesiastes', 10, 3, 'Yes also when the fool walks by the way, his understanding fails him, and he says to everyone that he is a fool.'),
  ('Ecclesiastes', 10, 4, 'If the spirit of the ruler rises up against you, don’t leave your place; for gentleness lays great offenses to rest.'),
  ('Ecclesiastes', 10, 5, 'There is an evil which I have seen under the sun, the sort of error which proceeds from the ruler.'),
  ('Ecclesiastes', 10, 6, 'Folly is set in great dignity, and the rich sit in a low place.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Ecclesiastes', 10, 7, 'I have seen servants on horses, and princes walking like servants on the earth.'),
  ('Ecclesiastes', 10, 8, 'He who digs a pit may fall into it; and whoever breaks through a wall may be bitten by a snake.'),
  ('Ecclesiastes', 10, 9, 'Whoever carves out stones may be injured by them. Whoever splits wood may be endangered by it.'),
  ('Ecclesiastes', 10, 10, 'If the ax is blunt, and one doesn’t sharpen the edge, then he must use more strength; but skill brings success.'),
  ('Ecclesiastes', 10, 11, 'If the snake bites before it is charmed, then is there no profit for the charmer’s tongue.'),
  ('Ecclesiastes', 10, 12, 'The words of a wise man’s mouth are gracious; but a fool is swallowed by his own lips.'),
  ('Ecclesiastes', 10, 13, 'The beginning of the words of his mouth is foolishness; and the end of his talk is mischievous madness.'),
  ('Ecclesiastes', 10, 14, 'A fool also multiplies words. Man doesn’t know what will be; and that which will be after him, who can tell him?'),
  ('Ecclesiastes', 10, 15, 'The labor of fools wearies every one of them; for he doesn’t know how to go to the city.'),
  ('Ecclesiastes', 10, 16, 'Woe to you, land, when your king is a child, and your princes eat in the morning!'),
  ('Ecclesiastes', 10, 17, 'Happy are you, land, when your king is the son of nobles, and your princes eat in due season, for strength, and not for drunkenness!'),
  ('Ecclesiastes', 10, 18, 'By slothfulness the roof sinks in; and through idleness of the hands the house leaks.'),
  ('Ecclesiastes', 10, 19, 'A feast is made for laughter, and wine makes the life glad; and money is the answer for all things.'),
  ('Ecclesiastes', 10, 20, 'Don’t curse the king, no, not in your thoughts; and don’t curse the rich in your bedroom, for a bird of the sky may carry your voice, and that which has wings may tell the matter.'),
  ('Ecclesiastes', 11, 1, 'Cast your bread on the waters; for you shall find it after many days.'),
  ('Ecclesiastes', 11, 2, 'Give a portion to seven, yes, even to eight; for you don’t know what evil will be on the earth.'),
  ('Ecclesiastes', 11, 3, 'If the clouds are full of rain, they empty themselves on the earth; and if a tree falls toward the south, or toward the north, in the place where the tree falls, there shall it be.'),
  ('Ecclesiastes', 11, 4, 'He who observes the wind won’t sow; and he who regards the clouds won’t reap.'),
  ('Ecclesiastes', 11, 5, 'As you don’t know what is the way of the wind, nor how the bones grow in the womb of her who is with child; even so you don’t know the work of God who does all.'),
  ('Ecclesiastes', 11, 6, 'In the morning sow your seed, and in the evening don’t withhold your hand; for you don’t know which will prosper, whether this or that, or whether they both will be equally good.'),
  ('Ecclesiastes', 11, 7, 'Truly the light is sweet, and it is a pleasant thing for the eyes to see the sun.'),
  ('Ecclesiastes', 11, 8, 'Yes, if a man lives many years, let him rejoice in them all; but let him remember the days of darkness, for they shall be many. All that comes is vanity.'),
  ('Ecclesiastes', 11, 9, 'Rejoice, young man, in your youth, and let your heart cheer you in the days of your youth, and walk in the ways of your heart, and in the sight of your eyes; but know that for all these things God will bring you into judgment.'),
  ('Ecclesiastes', 11, 10, 'Therefore remove sorrow from your heart, and put away evil from your flesh; for youth and the dawn of life are vanity.'),
  ('Ecclesiastes', 12, 1, 'Remember also your Creator in the days of your youth, before the evil days come, and the years draw near, when you will say, “I have no pleasure in them;”'),
  ('Ecclesiastes', 12, 2, 'Before the sun, the light, the moon, and the stars are darkened, and the clouds return after the rain;'),
  ('Ecclesiastes', 12, 3, 'in the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those who look out of the windows are darkened,'),
  ('Ecclesiastes', 12, 4, 'and the doors shall be shut in the street; when the sound of the grinding is low, and one shall rise up at the voice of a bird, and all the daughters of music shall be brought low;'),
  ('Ecclesiastes', 12, 5, 'yes, they shall be afraid of heights, and terrors will be on the way; and the almond tree shall blossom, and the grasshopper shall be a burden, and desire shall fail; because man goes to his everlasting home, and the mourners go about the streets;'),
  ('Ecclesiastes', 12, 6, 'before the silver cord is severed, or the golden bowl is broken, or the pitcher is broken at the spring, or the wheel broken at the cistern,'),
  ('Ecclesiastes', 12, 7, 'and the dust returns to the earth as it was, and the spirit returns to God who gave it.'),
  ('Ecclesiastes', 12, 8, '“Vanity of vanities,” says the Preacher. “All is vanity!”'),
  ('Ecclesiastes', 12, 9, 'Further, because the Preacher was wise, he still taught the people knowledge. Yes, he pondered, sought out, and set in order many proverbs.'),
  ('Ecclesiastes', 12, 10, 'The Preacher sought to find out acceptable words, and that which was written blamelessly, words of truth.'),
  ('Ecclesiastes', 12, 11, 'The words of the wise are like goads; and like nails well fastened are words from the masters of assemblies, which are given from one shepherd.'),
  ('Ecclesiastes', 12, 12, 'Furthermore, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh.'),
  ('Ecclesiastes', 12, 13, 'This is the end of the matter. All has been heard. Fear God and keep his commandments; for this is the whole duty of man.'),
  ('Ecclesiastes', 12, 14, 'For God will bring every work into judgment, with every hidden thing, whether it is good, or whether it is evil.'),
  ('Song of Solomon', 1, 1, 'The Song of songs, which is Solomon’s.'),
  ('Song of Solomon', 1, 2, 'Let him kiss me with the kisses of his mouth; for your love is better than wine.'),
  ('Song of Solomon', 1, 3, 'Your oils have a pleasing fragrance. Your name is oil poured out, therefore the virgins love you.'),
  ('Song of Solomon', 1, 4, 'Take me away with you. Let’s hurry. The king has brought me into his rooms. Friends We will be glad and rejoice in you. We will praise your love more than wine! Beloved They are right to love you.'),
  ('Song of Solomon', 1, 5, 'I am dark, but lovely, you daughters of Jerusalem, like Kedar’s tents, like Solomon’s curtains.'),
  ('Song of Solomon', 1, 6, 'Don’t stare at me because I am dark, because the sun has scorched me. My mother’s sons were angry with me. They made me keeper of the vineyards. I haven’t kept my own vineyard.'),
  ('Song of Solomon', 1, 7, 'Tell me, you whom my soul loves, where you graze your flock, where you rest them at noon; for why should I be as one who is veiled beside the flocks of your companions?'),
  ('Song of Solomon', 1, 8, 'If you don’t know, most beautiful among women, follow the tracks of the sheep. Graze your young goats beside the shepherds’ tents.'),
  ('Song of Solomon', 1, 9, 'I have compared you, my love, to a steed in Pharaoh’s chariots.'),
  ('Song of Solomon', 1, 10, 'Your cheeks are beautiful with earrings, your neck with strings of jewels.'),
  ('Song of Solomon', 1, 11, 'We will make you earrings of gold, with studs of silver.'),
  ('Song of Solomon', 1, 12, 'While the king sat at his table, my perfume spread its fragrance.'),
  ('Song of Solomon', 1, 13, 'My beloved is to me a sachet of myrrh, that lies between my breasts.'),
  ('Song of Solomon', 1, 14, 'My beloved is to me a cluster of henna blossoms from the vineyards of En Gedi.'),
  ('Song of Solomon', 1, 15, 'Behold, you are beautiful, my love. Behold, you are beautiful. Your eyes are like doves.'),
  ('Song of Solomon', 1, 16, 'Behold, you are beautiful, my beloved, yes, pleasant; and our couch is verdant.'),
  ('Song of Solomon', 1, 17, 'The beams of our house are cedars. Our rafters are firs.'),
  ('Song of Solomon', 2, 1, 'I am a rose of Sharon, a lily of the valleys.'),
  ('Song of Solomon', 2, 2, 'As a lily among thorns, so is my love among the daughters.'),
  ('Song of Solomon', 2, 3, 'As the apple tree among the trees of the wood, so is my beloved among the sons. I sat down under his shadow with great delight, his fruit was sweet to my taste.'),
  ('Song of Solomon', 2, 4, 'He brought me to the banquet hall. His banner over me is love.'),
  ('Song of Solomon', 2, 5, 'Strengthen me with raisins, refresh me with apples; for I am faint with love.'),
  ('Song of Solomon', 2, 6, 'His left hand is under my head. His right hand embraces me.'),
  ('Song of Solomon', 2, 7, 'I adjure you, daughters of Jerusalem, by the roes, or by the hinds of the field, that you not stir up, nor awaken love, until it so desires.'),
  ('Song of Solomon', 2, 8, 'The voice of my beloved! Behold, he comes, leaping on the mountains, skipping on the hills.'),
  ('Song of Solomon', 2, 9, 'My beloved is like a roe or a young deer. Behold, he stands behind our wall! He looks in at the windows. He glances through the lattice.'),
  ('Song of Solomon', 2, 10, 'My beloved spoke, and said to me, “Rise up, my love, my beautiful one, and come away.'),
  ('Song of Solomon', 2, 11, 'For behold, the winter is past. The rain is over and gone.'),
  ('Song of Solomon', 2, 12, 'The flowers appear on the earth. The time of the singing has come, and the voice of the turtledove is heard in our land.'),
  ('Song of Solomon', 2, 13, 'The fig tree ripens her green figs. The vines are in blossom. They give out their fragrance. Arise, my love, my beautiful one, and come away.”'),
  ('Song of Solomon', 2, 14, 'My dove in the clefts of the rock, in the hiding places of the mountainside, let me see your face. Let me hear your voice; for your voice is sweet and your face is lovely.'),
  ('Song of Solomon', 2, 15, 'Catch for us the foxes, the little foxes that plunder the vineyards; for our vineyards are in blossom.'),
  ('Song of Solomon', 2, 16, 'My beloved is mine, and I am his. He browses among the lilies.'),
  ('Song of Solomon', 2, 17, 'Until the day is cool, and the shadows flee away, turn, my beloved, and be like a roe or a young deer on the mountains of Bether.'),
  ('Song of Solomon', 3, 1, 'By night on my bed, I sought him whom my soul loves. I sought him, but I didn’t find him.'),
  ('Song of Solomon', 3, 2, 'I will get up now, and go about the city; in the streets and in the squares I will seek him whom my soul loves. I sought him, but I didn’t find him.'),
  ('Song of Solomon', 3, 3, 'The watchmen who go about the city found me; “Have you seen him whom my soul loves?”'),
  ('Song of Solomon', 3, 4, 'I had scarcely passed from them, when I found him whom my soul loves. I held him, and would not let him go, until I had brought him into my mother’s house, into the room of her who conceived me.'),
  ('Song of Solomon', 3, 5, 'I adjure you, daughters of Jerusalem, by the roes, or by the hinds of the field, that you not stir up nor awaken love, until it so desires.'),
  ('Song of Solomon', 3, 6, 'Who is this who comes up from the wilderness like pillars of smoke, perfumed with myrrh and frankincense, with all spices of the merchant?'),
  ('Song of Solomon', 3, 7, 'Behold, it is Solomon’s carriage! Sixty mighty men are around it, of the mighty men of Israel.'),
  ('Song of Solomon', 3, 8, 'They all handle the sword, and are expert in war. Every man has his sword on his thigh, because of fear in the night.'),
  ('Song of Solomon', 3, 9, 'King Solomon made himself a carriage of the wood of Lebanon.'),
  ('Song of Solomon', 3, 10, 'He made its pillars of silver, its bottom of gold, its seat of purple, the middle of it being paved with love, from the daughters of Jerusalem.'),
  ('Song of Solomon', 3, 11, 'Go out, you daughters of Zion, and see King Solomon, with the crown with which his mother has crowned him, in the day of his weddings, in the day of the gladness of his heart.'),
  ('Song of Solomon', 4, 1, 'Behold, you are beautiful, my love. Behold, you are beautiful. Your eyes are like doves behind your veil. Your hair is as a flock of goats, that descend from Mount Gilead.'),
  ('Song of Solomon', 4, 2, 'Your teeth are like a newly shorn flock, which have come up from the washing, where every one of them has twins. None is bereaved among them.'),
  ('Song of Solomon', 4, 3, 'Your lips are like scarlet thread. Your mouth is lovely. Your temples are like a piece of a pomegranate behind your veil.'),
  ('Song of Solomon', 4, 4, 'Your neck is like David’s tower built for an armory, on which a thousand shields hang, all the shields of the mighty men.'),
  ('Song of Solomon', 4, 5, 'Your two breasts are like two fawns that are twins of a roe, which feed among the lilies.'),
  ('Song of Solomon', 4, 6, 'Until the day is cool, and the shadows flee away, I will go to the mountain of myrrh, to the hill of frankincense.'),
  ('Song of Solomon', 4, 7, 'You are all beautiful, my love. There is no spot in you.'),
  ('Song of Solomon', 4, 8, 'Come with me from Lebanon, my bride, with me from Lebanon. Look from the top of Amana, from the top of Senir and Hermon, from the lions’ dens, from the mountains of the leopards.'),
  ('Song of Solomon', 4, 9, 'You have ravished my heart, my sister, my bride. You have ravished my heart with one of your eyes, with one chain of your neck.'),
  ('Song of Solomon', 4, 10, 'How beautiful is your love, my sister, my bride! How much better is your love than wine, the fragrance of your perfumes than all kinds of spices!'),
  ('Song of Solomon', 4, 11, 'Your lips, my bride, drip like the honeycomb. Honey and milk are under your tongue. The smell of your garments is like the smell of Lebanon.'),
  ('Song of Solomon', 4, 12, 'My sister, my bride, is a locked up garden; a locked up spring, a sealed fountain.'),
  ('Song of Solomon', 4, 13, 'Your shoots are an orchard of pomegranates, with precious fruits, henna with spikenard plants,'),
  ('Song of Solomon', 4, 14, 'spikenard and saffron, calamus and cinnamon, with every kind of incense tree; myrrh and aloes, with all the best spices,'),
  ('Song of Solomon', 4, 15, 'a fountain of gardens, a well of living waters, flowing streams from Lebanon.'),
  ('Song of Solomon', 4, 16, 'Awake, north wind, and come, you south! Blow on my garden, that its spices may flow out. Let my beloved come into his garden, and taste his precious fruits.'),
  ('Song of Solomon', 5, 1, 'I have come into my garden, my sister, my bride. I have gathered my myrrh with my spice; I have eaten my honeycomb with my honey; I have drunk my wine with my milk. Friends Eat, friends! Drink, yes, drink abundantly, beloved.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Song of Solomon', 5, 2, 'I was asleep, but my heart was awake. It is the voice of my beloved who knocks: “Open to me, my sister, my love, my dove, my undefiled; for my head is filled with dew, and my hair with the dampness of the night.”'),
  ('Song of Solomon', 5, 3, 'I have taken off my robe. Indeed, must I put it on? I have washed my feet. Indeed, must I soil them?'),
  ('Song of Solomon', 5, 4, 'My beloved thrust his hand in through the latch opening. My heart pounded for him.'),
  ('Song of Solomon', 5, 5, 'I rose up to open for my beloved. My hands dripped with myrrh, my fingers with liquid myrrh, on the handles of the lock.'),
  ('Song of Solomon', 5, 6, 'I opened to my beloved; but my beloved left, and had gone away. My heart went out when he spoke. I looked for him, but I didn’t find him. I called him, but he didn’t answer.'),
  ('Song of Solomon', 5, 7, 'The watchmen who go about the city found me. They beat me. They bruised me. The keepers of the walls took my cloak away from me.'),
  ('Song of Solomon', 5, 8, 'I adjure you, daughters of Jerusalem, If you find my beloved, that you tell him that I am faint with love.'),
  ('Song of Solomon', 5, 9, 'How is your beloved better than another beloved, you fairest among women? How is your beloved better than another beloved, that you do so adjure us?'),
  ('Song of Solomon', 5, 10, 'My beloved is white and ruddy. The best among ten thousand.'),
  ('Song of Solomon', 5, 11, 'His head is like the purest gold. His hair is bushy, black as a raven.'),
  ('Song of Solomon', 5, 12, 'His eyes are like doves beside the water brooks, washed with milk, mounted like jewels.'),
  ('Song of Solomon', 5, 13, 'His cheeks are like a bed of spices with towers of perfumes. His lips are like lilies, dropping liquid myrrh.'),
  ('Song of Solomon', 5, 14, 'His hands are like rings of gold set with beryl. His body is like ivory work overlaid with sapphires.'),
  ('Song of Solomon', 5, 15, 'His legs are like pillars of marble set on sockets of fine gold. His appearance is like Lebanon, excellent as the cedars.'),
  ('Song of Solomon', 5, 16, 'His mouth is sweetness; yes, he is altogether lovely. This is my beloved, and this is my friend, daughters of Jerusalem.'),
  ('Song of Solomon', 6, 1, 'Where has your beloved gone, you fairest among women? Where has your beloved turned, that we may seek him with you?'),
  ('Song of Solomon', 6, 2, 'My beloved has gone down to his garden, to the beds of spices, to pasture his flock in the gardens, and to gather lilies.'),
  ('Song of Solomon', 6, 3, 'I am my beloved’s, and my beloved is mine. He browses among the lilies.'),
  ('Song of Solomon', 6, 4, 'You are beautiful, my love, as Tirzah, lovely as Jerusalem, awesome as an army with banners.'),
  ('Song of Solomon', 6, 5, 'Turn away your eyes from me, for they have overcome me. Your hair is like a flock of goats, that lie along the side of Gilead.'),
  ('Song of Solomon', 6, 6, 'Your teeth are like a flock of ewes, which have come up from the washing, of which every one has twins; not one is bereaved among them.'),
  ('Song of Solomon', 6, 7, 'Your temples are like a piece of a pomegranate behind your veil.'),
  ('Song of Solomon', 6, 8, 'There are sixty queens, eighty concubines, and virgins without number.'),
  ('Song of Solomon', 6, 9, 'My dove, my perfect one, is unique. She is her mother’s only daughter. She is the favorite one of her who bore her. The daughters saw her, and called her blessed. The queens and the concubines saw her, and they praised her.'),
  ('Song of Solomon', 6, 10, 'Who is she who looks out as the morning, beautiful as the moon, clear as the sun, and awesome as an army with banners?'),
  ('Song of Solomon', 6, 11, 'I went down into the nut tree grove, to see the green plants of the valley, to see whether the vine budded, and the pomegranates were in flower.'),
  ('Song of Solomon', 6, 12, 'Without realizing it, my desire set me with my royal people’s chariots.'),
  ('Song of Solomon', 6, 13, 'Return, return, Shulammite! Return, return, that we may gaze at you. Lover Why do you desire to gaze at the Shulammite, as at the dance of Mahanaim?'),
  ('Song of Solomon', 7, 1, 'How beautiful are your feet in sandals, prince’s daughter! Your rounded thighs are like jewels, the work of the hands of a skillful workman.'),
  ('Song of Solomon', 7, 2, 'Your body is like a round goblet, no mixed wine is wanting. Your waist is like a heap of wheat, set about with lilies.'),
  ('Song of Solomon', 7, 3, 'Your two breasts are like two fawns, that are twins of a roe.'),
  ('Song of Solomon', 7, 4, 'Your neck is like an ivory tower. Your eyes are like the pools in Heshbon by the gate of Bathrabbim. Your nose is like the tower of Lebanon which looks toward Damascus.'),
  ('Song of Solomon', 7, 5, 'Your head on you is like Carmel. The hair of your head like purple. The king is held captive in its tresses.'),
  ('Song of Solomon', 7, 6, 'How beautiful and how pleasant you are, love, for delights!'),
  ('Song of Solomon', 7, 7, 'This, your stature, is like a palm tree, your breasts like its fruit.'),
  ('Song of Solomon', 7, 8, 'I said, “I will climb up into the palm tree. I will take hold of its fruit.” Let your breasts be like clusters of the vine, the smell of your breath like apples.'),
  ('Song of Solomon', 7, 9, 'Your mouth is like the best wine, that goes down smoothly for my beloved, gliding through the lips of those who are asleep.'),
  ('Song of Solomon', 7, 10, 'I am my beloved’s. His desire is toward me.'),
  ('Song of Solomon', 7, 11, 'Come, my beloved! Let’s go out into the field. Let’s lodge in the villages.'),
  ('Song of Solomon', 7, 12, 'Let’s go early up to the vineyards. Let’s see whether the vine has budded, its blossom is open, and the pomegranates are in flower. There I will give you my love.'),
  ('Song of Solomon', 7, 13, 'The mandrakes produce fragrance. At our doors are all kinds of precious fruits, new and old, which I have stored up for you, my beloved.'),
  ('Song of Solomon', 8, 1, 'Oh that you were like my brother, who nursed from the breasts of my mother! If I found you outside, I would kiss you; yes, and no one would despise me.'),
  ('Song of Solomon', 8, 2, 'I would lead you, bringing you into the house of my mother, who would instruct me. I would have you drink spiced wine, of the juice of my pomegranate.'),
  ('Song of Solomon', 8, 3, 'His left hand would be under my head. His right hand would embrace me.'),
  ('Song of Solomon', 8, 4, 'I adjure you, daughters of Jerusalem, that you not stir up, nor awaken love, until it so desires.'),
  ('Song of Solomon', 8, 5, 'Who is this who comes up from the wilderness, leaning on her beloved? Beloved Under the apple tree I awakened you. There your mother conceived you. There she was in labor and bore you.'),
  ('Song of Solomon', 8, 6, 'Set me as a seal on your heart, as a seal on your arm; for love is strong as death. Jealousy is as cruel as Sheol. Its flashes are flashes of fire, a very flame of the LORD.'),
  ('Song of Solomon', 8, 7, 'Many waters can’t quench love, neither can floods drown it. If a man would give all the wealth of his house for love, he would be utterly scorned.'),
  ('Song of Solomon', 8, 8, 'We have a little sister. She has no breasts. What shall we do for our sister in the day when she is to be spoken for?'),
  ('Song of Solomon', 8, 9, 'If she is a wall, we will build on her a turret of silver. If she is a door, we will enclose her with boards of cedar.'),
  ('Song of Solomon', 8, 10, 'I am a wall, and my breasts like towers, then I was in his eyes like one who found peace.'),
  ('Song of Solomon', 8, 11, 'Solomon had a vineyard at Baal Hamon. He leased out the vineyard to keepers. Each was to bring a thousand shekels of silver for its fruit.'),
  ('Song of Solomon', 8, 12, 'My own vineyard is before me. The thousand are for you, Solomon, two hundred for those who tend its fruit.'),
  ('Song of Solomon', 8, 13, 'You who dwell in the gardens, with friends in attendance, let me hear your voice!'),
  ('Song of Solomon', 8, 14, 'Come away, my beloved! Be like a gazelle or a young stag on the mountains of spices!'),
  ('Isaiah', 1, 1, 'The vision of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.'),
  ('Isaiah', 1, 2, 'Hear, heavens, and listen, earth; for the LORD has spoken: “I have nourished and brought up children and they have rebelled against me.'),
  ('Isaiah', 1, 3, 'The ox knows his owner, and the donkey his master’s crib; but Israel doesn’t know. My people don’t consider.”'),
  ('Isaiah', 1, 4, 'Ah sinful nation, a people loaded with iniquity, offspring of evildoers, children who deal corruptly! They have forsaken the LORD. They have despised the Holy One of Israel. They are estranged and backward.'),
  ('Isaiah', 1, 5, 'Why should you be beaten more, that you revolt more and more? The whole head is sick, and the whole heart faint.'),
  ('Isaiah', 1, 6, 'From the sole of the foot even to the head there is no soundness in it, but wounds, welts, and open sores. They haven’t been closed, bandaged, or soothed with oil.'),
  ('Isaiah', 1, 7, 'Your country is desolate. Your cities are burned with fire. Strangers devour your land in your presence and it is desolate, as overthrown by strangers.'),
  ('Isaiah', 1, 8, 'The daughter of Zion is left like a shelter in a vineyard, like a hut in a field of melons, like a besieged city.'),
  ('Isaiah', 1, 9, 'Unless the LORD of Armies had left to us a very small remnant, we would have been as Sodom. We would have been like Gomorrah.'),
  ('Isaiah', 1, 10, 'Hear the LORD’s word, you rulers of Sodom! Listen to the law of our God, you people of Gomorrah!'),
  ('Isaiah', 1, 11, '“What are the multitude of your sacrifices to me?”, says the LORD. “I have had enough of the burnt offerings of rams and the fat of fed animals. I don’t delight in the blood of bulls, or of lambs, or of male goats.'),
  ('Isaiah', 1, 12, 'When you come to appear before me, who has required this at your hand, to trample my courts?'),
  ('Isaiah', 1, 13, 'Bring no more vain offerings. Incense is an abomination to me. New moons, Sabbaths, and convocations— I can’t stand evil assemblies.'),
  ('Isaiah', 1, 14, 'My soul hates your New Moons and your appointed feasts. They are a burden to me. I am weary of bearing them.'),
  ('Isaiah', 1, 15, 'When you spread out your hands, I will hide my eyes from you. Yes, when you make many prayers, I will not hear. Your hands are full of blood.'),
  ('Isaiah', 1, 16, 'Wash yourselves. Make yourself clean. Put away the evil of your doings from before my eyes. Cease to do evil.'),
  ('Isaiah', 1, 17, 'Learn to do well. Seek justice. Relieve the oppressed. Defend the fatherless. Plead for the widow.”'),
  ('Isaiah', 1, 18, '“Come now, and let’s reason together,” says the LORD: “Though your sins are as scarlet, they shall be as white as snow. Though they are red like crimson, they shall be as wool.'),
  ('Isaiah', 1, 19, 'If you are willing and obedient, you will eat the good of the land;'),
  ('Isaiah', 1, 20, 'but if you refuse and rebel, you will be devoured with the sword; for the LORD’s mouth has spoken it.”'),
  ('Isaiah', 1, 21, 'How the faithful city has become a prostitute! She was full of justice. Righteousness lodged in her, but now there are murderers.'),
  ('Isaiah', 1, 22, 'Your silver has become dross, your wine mixed with water.'),
  ('Isaiah', 1, 23, 'Your princes are rebellious and companions of thieves. Everyone loves bribes and follows after rewards. They don’t defend the fatherless, neither does the cause of the widow come to them.'),
  ('Isaiah', 1, 24, 'Therefore the Lord, GOD of Armies, the Mighty One of Israel, says: “Ah, I will get relief from my adversaries, and avenge myself on my enemies.'),
  ('Isaiah', 1, 25, 'I will turn my hand on you, thoroughly purge away your dross, and will take away all your tin.'),
  ('Isaiah', 1, 26, 'I will restore your judges as at the first, and your counselors as at the beginning. Afterward you shall be called ‘The city of righteousness, a faithful town.’'),
  ('Isaiah', 1, 27, 'Zion shall be redeemed with justice, and her converts with righteousness.'),
  ('Isaiah', 1, 28, 'But the destruction of transgressors and sinners shall be together, and those who forsake the LORD shall be consumed.'),
  ('Isaiah', 1, 29, 'For they shall be ashamed of the oaks which you have desired, and you shall be confounded for the gardens that you have chosen.'),
  ('Isaiah', 1, 30, 'For you shall be as an oak whose leaf fades, and as a garden that has no water.'),
  ('Isaiah', 1, 31, 'The strong will be like tinder, and his work like a spark. They will both burn together, and no one will quench them.”'),
  ('Isaiah', 2, 1, 'This is what Isaiah the son of Amoz saw concerning Judah and Jerusalem.'),
  ('Isaiah', 2, 2, 'It shall happen in the latter days, that the mountain of the LORD’s house shall be established on the top of the mountains, and shall be raised above the hills; and all nations shall flow to it.'),
  ('Isaiah', 2, 3, 'Many peoples shall go and say, “Come, let’s go up to the mountain of the LORD, to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths.” For the law shall go out of Zion, and the LORD’s word from Jerusalem.'),
  ('Isaiah', 2, 4, 'He will judge between the nations, and will decide concerning many peoples. They shall beat their swords into plowshares, and their spears into pruning hooks. Nation shall not lift up sword against nation, neither shall they learn war any more.'),
  ('Isaiah', 2, 5, 'House of Jacob, come, and let’s walk in the light of the LORD.'),
  ('Isaiah', 2, 6, 'For you have forsaken your people, the house of Jacob, because they are filled from the east, with those who practice divination like the Philistines, and they clasp hands with the children of foreigners.'),
  ('Isaiah', 2, 7, 'Their land is full of silver and gold, neither is there any end of their treasures. Their land also is full of horses, neither is there any end of their chariots.'),
  ('Isaiah', 2, 8, 'Their land also is full of idols. They worship the work of their own hands, that which their own fingers have made.'),
  ('Isaiah', 2, 9, 'Man is brought low, and mankind is humbled; therefore don’t forgive them.'),
  ('Isaiah', 2, 10, 'Enter into the rock, and hide in the dust, from before the terror of the LORD, and from the glory of his majesty.'),
  ('Isaiah', 2, 11, 'The lofty looks of man will be brought low, the arrogance of men will be bowed down, and the LORD alone will be exalted in that day.'),
  ('Isaiah', 2, 12, 'For there will be a day of the LORD of Armies for all that is proud and arrogant, and for all that is lifted up, and it shall be brought low—'),
  ('Isaiah', 2, 13, 'for all the cedars of Lebanon, that are high and lifted up, for all the oaks of Bashan,'),
  ('Isaiah', 2, 14, 'for all the high mountains, for all the hills that are lifted up,');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 2, 15, 'for every lofty tower, for every fortified wall,'),
  ('Isaiah', 2, 16, 'for all the ships of Tarshish, and for all pleasant imagery.'),
  ('Isaiah', 2, 17, 'The loftiness of man shall be bowed down, and the arrogance of men shall be brought low; and the LORD alone shall be exalted in that day.'),
  ('Isaiah', 2, 18, 'The idols shall utterly pass away.'),
  ('Isaiah', 2, 19, 'Men shall go into the caves of the rocks, and into the holes of the earth, from before the terror of the LORD, and from the glory of his majesty, when he arises to shake the earth mightily.'),
  ('Isaiah', 2, 20, 'In that day, men shall cast away their idols of silver and their idols of gold, which have been made for themselves to worship, to the moles and to the bats,'),
  ('Isaiah', 2, 21, 'to go into the caverns of the rocks, and into the clefts of the ragged rocks, from before the terror of the LORD, and from the glory of his majesty, when he arises to shake the earth mightily.'),
  ('Isaiah', 2, 22, 'Stop trusting in man, whose breath is in his nostrils; for of what account is he?'),
  ('Isaiah', 3, 1, 'For, behold, the Lord, GOD of Armies, takes away from Jerusalem and from Judah supply and support, the whole supply of bread, and the whole supply of water;'),
  ('Isaiah', 3, 2, 'the mighty man, the man of war, the judge, the prophet, the diviner, the elder,'),
  ('Isaiah', 3, 3, 'the captain of fifty, the honorable man, the counselor, the skilled craftsman, and the clever enchanter.'),
  ('Isaiah', 3, 4, 'I will give boys to be their princes, and children shall rule over them.'),
  ('Isaiah', 3, 5, 'The people will be oppressed, everyone by another, and everyone by his neighbor. The child will behave himself proudly against the old man, and the wicked against the honorable.'),
  ('Isaiah', 3, 6, 'Indeed a man shall take hold of his brother in the house of his father, saying, “You have clothing, you be our ruler, and let this ruin be under your hand.”'),
  ('Isaiah', 3, 7, 'In that day he will cry out, saying, “I will not be a healer; for in my house is neither bread nor clothing. You shall not make me ruler of the people.”'),
  ('Isaiah', 3, 8, 'For Jerusalem is ruined, and Judah is fallen; because their tongue and their doings are against the LORD, to provoke the eyes of his glory.'),
  ('Isaiah', 3, 9, 'The look of their faces testify against them. They parade their sin like Sodom. They don’t hide it. Woe to their soul! For they have brought disaster upon themselves.'),
  ('Isaiah', 3, 10, 'Tell the righteous that it will be well with them, for they will eat the fruit of their deeds.'),
  ('Isaiah', 3, 11, 'Woe to the wicked! Disaster is upon them, for the deeds of their hands will be paid back to them.'),
  ('Isaiah', 3, 12, 'As for my people, children are their oppressors, and women rule over them. My people, those who lead you cause you to err, and destroy the way of your paths.'),
  ('Isaiah', 3, 13, 'The LORD stands up to contend, and stands to judge the peoples.'),
  ('Isaiah', 3, 14, 'The LORD will enter into judgment with the elders of his people and their leaders: “It is you who have eaten up the vineyard. The plunder of the poor is in your houses.'),
  ('Isaiah', 3, 15, 'What do you mean that you crush my people, and grind the face of the poor?” says the Lord, GOD of Armies.'),
  ('Isaiah', 3, 16, 'Moreover the LORD said, “Because the daughters of Zion are arrogant, and walk with outstretched necks and flirting eyes, walking daintily as they go, jingling ornaments on their feet;'),
  ('Isaiah', 3, 17, 'therefore the Lord brings sores on the crown of the head of the women of Zion, and the LORD will make their scalps bald.”'),
  ('Isaiah', 3, 18, 'In that day the Lord will take away the beauty of their anklets, the headbands, the crescent necklaces,'),
  ('Isaiah', 3, 19, 'the earrings, the bracelets, the veils,'),
  ('Isaiah', 3, 20, 'the headdresses, the ankle chains, the sashes, the perfume containers, the charms,'),
  ('Isaiah', 3, 21, 'the signet rings, the nose rings,'),
  ('Isaiah', 3, 22, 'the fine robes, the capes, the cloaks, the purses,'),
  ('Isaiah', 3, 23, 'the hand mirrors, the fine linen garments, the tiaras, and the shawls.'),
  ('Isaiah', 3, 24, 'It shall happen that instead of sweet spices, there shall be rottenness; instead of a belt, a rope; instead of well set hair, baldness; instead of a robe, a wearing of sackcloth; and branding instead of beauty.'),
  ('Isaiah', 3, 25, 'Your men shall fall by the sword, and your mighty in the war.'),
  ('Isaiah', 3, 26, 'Her gates shall lament and mourn. She shall be desolate and sit on the ground.'),
  ('Isaiah', 4, 1, 'Seven women shall take hold of one man in that day, saying, “We will eat our own bread, and wear our own clothing. Just let us be called by your name. Take away our reproach.”'),
  ('Isaiah', 4, 2, 'In that day, the LORD’s branch will be beautiful and glorious, and the fruit of the land will be the beauty and glory of the survivors of Israel.'),
  ('Isaiah', 4, 3, 'It will happen that he who is left in Zion and he who remains in Jerusalem shall be called holy, even everyone who is written among the living in Jerusalem,'),
  ('Isaiah', 4, 4, 'when the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from within it, by the spirit of justice and by the spirit of burning.'),
  ('Isaiah', 4, 5, 'The LORD will create over the whole habitation of Mount Zion and over her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night, for over all the glory will be a canopy.'),
  ('Isaiah', 4, 6, 'There will be a pavilion for a shade in the daytime from the heat, and for a refuge and for a shelter from storm and from rain.'),
  ('Isaiah', 5, 1, 'Let me sing for my well beloved a song of my beloved about his vineyard. My beloved had a vineyard on a very fruitful hill.'),
  ('Isaiah', 5, 2, 'He dug it up, gathered out its stones, planted it with the choicest vine, built a tower in the middle of it, and also cut out a wine press in it. He looked for it to yield grapes, but it yielded wild grapes.'),
  ('Isaiah', 5, 3, '“Now, inhabitants of Jerusalem and men of Judah, please judge between me and my vineyard.'),
  ('Isaiah', 5, 4, 'What could have been done more to my vineyard, that I have not done in it? Why, when I looked for it to yield grapes, did it yield wild grapes?'),
  ('Isaiah', 5, 5, 'Now I will tell you what I will do to my vineyard. I will take away its hedge, and it will be eaten up. I will break down its wall, and it will be trampled down.'),
  ('Isaiah', 5, 6, 'I will lay it a wasteland. It won’t be pruned or hoed, but it will grow briers and thorns. I will also command the clouds that they rain no rain on it.”'),
  ('Isaiah', 5, 7, 'For the vineyard of the LORD of Armies is the house of Israel, and the men of Judah his pleasant plant. He looked for justice, but behold, oppression, for righteousness, but behold, a cry of distress.'),
  ('Isaiah', 5, 8, 'Woe to those who join house to house, who lay field to field, until there is no room, and you are made to dwell alone in the middle of the land!'),
  ('Isaiah', 5, 9, 'In my ears, the LORD of Armies says: “Surely many houses will be desolate, even great and beautiful, unoccupied.'),
  ('Isaiah', 5, 10, 'For ten acres of vineyard shall yield one bath, and a homer of seed shall yield an ephah.”'),
  ('Isaiah', 5, 11, 'Woe to those who rise up early in the morning, that they may follow strong drink, who stay late into the night, until wine inflames them!'),
  ('Isaiah', 5, 12, 'The harp, lyre, tambourine, and flute, with wine, are at their feasts; but they don’t respect the work of the LORD, neither have they considered the operation of his hands.'),
  ('Isaiah', 5, 13, 'Therefore my people go into captivity for lack of knowledge. Their honorable men are famished, and their multitudes are parched with thirst.'),
  ('Isaiah', 5, 14, 'Therefore Sheol has enlarged its desire, and opened its mouth without measure; and their glory, their multitude, their pomp, and he who rejoices among them, descend into it.'),
  ('Isaiah', 5, 15, 'So man is brought low, mankind is humbled, and the eyes of the arrogant ones are humbled;'),
  ('Isaiah', 5, 16, 'but the LORD of Armies is exalted in justice, and God the Holy One is sanctified in righteousness.'),
  ('Isaiah', 5, 17, 'Then the lambs will graze as in their pasture, and strangers will eat the ruins of the rich.'),
  ('Isaiah', 5, 18, 'Woe to those who draw iniquity with cords of falsehood, and wickedness as with cart rope,'),
  ('Isaiah', 5, 19, 'who say, “Let him make haste, let him hasten his work, that we may see it; let the counsel of the Holy One of Israel draw near and come, that we may know it!”'),
  ('Isaiah', 5, 20, 'Woe to those who call evil good, and good evil; who put darkness for light, and light for darkness; who put bitter for sweet, and sweet for bitter!'),
  ('Isaiah', 5, 21, 'Woe to those who are wise in their own eyes, and prudent in their own sight!'),
  ('Isaiah', 5, 22, 'Woe to those who are mighty to drink wine, and champions at mixing strong drink;'),
  ('Isaiah', 5, 23, 'who acquit the guilty for a bribe, but deny justice for the innocent!'),
  ('Isaiah', 5, 24, 'Therefore as the tongue of fire devours the stubble, and as the dry grass sinks down in the flame, so their root shall be as rottenness, and their blossom shall go up as dust, because they have rejected the law of the LORD of Armies, and despised the word of the Holy One of Israel.'),
  ('Isaiah', 5, 25, 'Therefore the LORD’s anger burns against his people, and he has stretched out his hand against them and has struck them. The mountains tremble, and their dead bodies are as refuse in the middle of the streets. For all this, his anger is not turned away, but his hand is still stretched out.'),
  ('Isaiah', 5, 26, 'He will lift up a banner to the nations from far away, and he will whistle for them from the end of the earth. Behold, they will come speedily and swiftly.'),
  ('Isaiah', 5, 27, 'No one shall be weary nor stumble among them; no one shall slumber nor sleep, neither shall the belt of their waist be untied, nor the strap of their sandals be broken,'),
  ('Isaiah', 5, 28, 'whose arrows are sharp, and all their bows bent. Their horses’ hoofs will be like flint, and their wheels like a whirlwind.'),
  ('Isaiah', 5, 29, 'Their roaring will be like a lioness. They will roar like young lions. Yes, they shall roar, and seize their prey and carry it off, and there will be no one to deliver.'),
  ('Isaiah', 5, 30, 'They will roar against them in that day like the roaring of the sea. If one looks to the land, behold, darkness and distress. The light is darkened in its clouds.'),
  ('Isaiah', 6, 1, 'In the year that King Uzziah died, I saw the Lord sitting on a throne, high and lifted up; and his train filled the temple.'),
  ('Isaiah', 6, 2, 'Above him stood the seraphim. Each one had six wings. With two he covered his face. With two he covered his feet. With two he flew.'),
  ('Isaiah', 6, 3, 'One called to another, and said, “Holy, holy, holy, is the LORD of Armies! The whole earth is full of his glory!”'),
  ('Isaiah', 6, 4, 'The foundations of the thresholds shook at the voice of him who called, and the house was filled with smoke.'),
  ('Isaiah', 6, 5, 'Then I said, “Woe is me! For I am undone, because I am a man of unclean lips and I live among a people of unclean lips, for my eyes have seen the King, the LORD of Armies!”'),
  ('Isaiah', 6, 6, 'Then one of the seraphim flew to me, having a live coal in his hand, which he had taken with the tongs from off the altar.'),
  ('Isaiah', 6, 7, 'He touched my mouth with it, and said, “Behold, this has touched your lips; and your iniquity is taken away, and your sin forgiven.”'),
  ('Isaiah', 6, 8, 'I heard the Lord’s voice, saying, “Whom shall I send, and who will go for us?” Then I said, “Here I am. Send me!”'),
  ('Isaiah', 6, 9, 'He said, “Go, and tell this people, ‘You hear indeed, but don’t understand. You see indeed, but don’t perceive.’'),
  ('Isaiah', 6, 10, 'Make the heart of this people fat. Make their ears heavy, and shut their eyes; lest they see with their eyes, hear with their ears, understand with their heart, and turn again, and be healed.”'),
  ('Isaiah', 6, 11, 'Then I said, “Lord, how long?” He answered, “Until cities are waste without inhabitant, houses without man, the land becomes utterly waste,'),
  ('Isaiah', 6, 12, 'and the LORD has removed men far away, and the forsaken places are many within the land.'),
  ('Isaiah', 6, 13, 'If there is a tenth left in it, that also will in turn be consumed, as a terebinth, and as an oak whose stump remains when they are cut down, so the holy seed is its stump.”'),
  ('Isaiah', 7, 1, 'In the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, Rezin the king of Syria and Pekah the son of Remaliah, king of Israel, went up to Jerusalem to war against it, but could not prevail against it.'),
  ('Isaiah', 7, 2, 'David’s house was told, “Syria is allied with Ephraim.” His heart trembled, and the heart of his people, as the trees of the forest tremble with the wind.'),
  ('Isaiah', 7, 3, 'Then the LORD said to Isaiah, “Go out now to meet Ahaz, you, and Shearjashub your son, at the end of the conduit of the upper pool, on the highway of the fuller’s field.'),
  ('Isaiah', 7, 4, 'Tell him, ‘Be careful, and keep calm. Don’t be afraid, neither let your heart be faint because of these two tails of smoking torches, for the fierce anger of Rezin and Syria, and of the son of Remaliah.'),
  ('Isaiah', 7, 5, 'Because Syria, Ephraim, and the son of Remaliah, have plotted evil against you, saying,'),
  ('Isaiah', 7, 6, '“Let’s go up against Judah, and tear it apart, and let’s divide it among ourselves, and set up a king within it, even the son of Tabeel.”'),
  ('Isaiah', 7, 7, 'This is what the Lord GOD says: “It shall not stand, neither shall it happen.”'),
  ('Isaiah', 7, 8, 'For the head of Syria is Damascus, and the head of Damascus is Rezin. Within sixty-five years Ephraim shall be broken in pieces, so that it shall not be a people.'),
  ('Isaiah', 7, 9, 'The head of Ephraim is Samaria, and the head of Samaria is Remaliah’s son. If you will not believe, surely you shall not be established.’”'),
  ('Isaiah', 7, 10, 'The LORD spoke again to Ahaz, saying,'),
  ('Isaiah', 7, 11, '“Ask a sign of the LORD your God; ask it either in the depth, or in the height above.”'),
  ('Isaiah', 7, 12, 'But Ahaz said, “I won’t ask. I won’t tempt the LORD.”'),
  ('Isaiah', 7, 13, 'He said, “Listen now, house of David. Is it not enough for you to try the patience of men, that you will try the patience of my God also?'),
  ('Isaiah', 7, 14, 'Therefore the Lord himself will give you a sign. Behold, the virgin will conceive, and bear a son, and shall call his name Immanuel.'),
  ('Isaiah', 7, 15, 'He shall eat butter and honey when he knows to refuse the evil and choose the good.'),
  ('Isaiah', 7, 16, 'For before the child knows to refuse the evil and choose the good, the land whose two kings you abhor shall be forsaken.'),
  ('Isaiah', 7, 17, 'The LORD will bring on you, on your people, and on your father’s house days that have not come, from the day that Ephraim departed from Judah, even the king of Assyria.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 7, 18, 'It will happen in that day that the LORD will whistle for the fly that is in the uttermost part of the rivers of Egypt, and for the bee that is in the land of Assyria.'),
  ('Isaiah', 7, 19, 'They shall come, and shall all rest in the desolate valleys, in the clefts of the rocks, on all thorn hedges, and on all pastures.'),
  ('Isaiah', 7, 20, 'In that day the Lord will shave with a razor that is hired in the parts beyond the River, even with the king of Assyria, the head and the hair of the feet; and it shall also consume the beard.'),
  ('Isaiah', 7, 21, 'It shall happen in that day that a man shall keep alive a young cow, and two sheep.'),
  ('Isaiah', 7, 22, 'It shall happen, that because of the abundance of milk which they shall give he shall eat butter, for everyone will eat butter and honey that is left within the land.'),
  ('Isaiah', 7, 23, 'It will happen in that day that every place where there were a thousand vines worth a thousand silver shekels, will be for briers and thorns.'),
  ('Isaiah', 7, 24, 'People will go there with arrows and with bow, because all the land will be briers and thorns.'),
  ('Isaiah', 7, 25, 'All the hills that were cultivated with the hoe, you shall not come there for fear of briers and thorns; but it shall be for the sending out of oxen, and for sheep to tread on.”'),
  ('Isaiah', 8, 1, 'The LORD said to me, “Take a large tablet, and write on it with a man’s pen, ‘For Maher Shalal Hash Baz’;'),
  ('Isaiah', 8, 2, 'and I will take for myself faithful witnesses to testify: Uriah the priest, and Zechariah the son of Jeberechiah.”'),
  ('Isaiah', 8, 3, 'I went to the prophetess, and she conceived, and bore a son. Then the LORD said to me, “Call his name ‘Maher Shalal Hash Baz.’'),
  ('Isaiah', 8, 4, 'For before the child knows how to say, ‘My father’ and ‘My mother,’ the riches of Damascus and the plunder of Samaria will be carried away by the king of Assyria.”'),
  ('Isaiah', 8, 5, 'The LORD spoke to me yet again, saying,'),
  ('Isaiah', 8, 6, '“Because this people has refused the waters of Shiloah that go softly, and rejoice in Rezin and Remaliah’s son;'),
  ('Isaiah', 8, 7, 'now therefore, behold, the Lord brings upon them the mighty flood waters of the River: the king of Assyria and all his glory. It will come up over all its channels, and go over all its banks.'),
  ('Isaiah', 8, 8, 'It will sweep onward into Judah. It will overflow and pass through. It will reach even to the neck. The stretching out of its wings will fill the width of your land, O Immanuel.'),
  ('Isaiah', 8, 9, 'Make an uproar, you peoples, and be broken in pieces! Listen, all you from far countries: dress for battle, and be shattered! Dress for battle, and be shattered!'),
  ('Isaiah', 8, 10, 'Take counsel together, and it will be brought to nothing; speak the word, and it will not stand, for God is with us.”'),
  ('Isaiah', 8, 11, 'For the LORD spoke this to me with a strong hand, and instructed me not to walk in the way of this people, saying,'),
  ('Isaiah', 8, 12, '“Don’t call a conspiracy all that this people call a conspiracy. Don’t fear their threats or be terrorized.'),
  ('Isaiah', 8, 13, 'The LORD of Armies is who you must respect as holy. He is the one you must fear. He is the one you must dread.'),
  ('Isaiah', 8, 14, 'He will be a sanctuary, but for both houses of Israel, he will be a stumbling stone and a rock that makes them fall. For the people of Jerusalem, he will be a trap and a snare.'),
  ('Isaiah', 8, 15, 'Many will stumble over it, fall, be broken, be snared, and be captured.”'),
  ('Isaiah', 8, 16, 'Wrap up the covenant. Seal the law among my disciples.'),
  ('Isaiah', 8, 17, 'I will wait for the LORD, who hides his face from the house of Jacob, and I will look for him.'),
  ('Isaiah', 8, 18, 'Behold, I and the children whom the LORD has given me are for signs and for wonders in Israel from the LORD of Armies, who dwells in Mount Zion.'),
  ('Isaiah', 8, 19, 'When they tell you, “Consult with those who have familiar spirits and with the wizards, who chirp and who mutter,” shouldn’t a people consult with their God? Should they consult the dead on behalf of the living?'),
  ('Isaiah', 8, 20, 'Turn to the law and to the covenant! If they don’t speak according to this word, surely there is no morning for them.'),
  ('Isaiah', 8, 21, 'They will pass through it, very distressed and hungry. It will happen that when they are hungry, they will worry, and curse their king and their God. They will turn their faces upward,'),
  ('Isaiah', 8, 22, 'then look to the earth and see distress, darkness, and the gloom of anguish. They will be driven into thick darkness.'),
  ('Isaiah', 9, 1, 'But there shall be no more gloom for her who was in anguish. In the former time, he brought into contempt the land of Zebulun and the land of Naphtali; but in the latter time he has made it glorious, by the way of the sea, beyond the Jordan, Galilee of the nations.'),
  ('Isaiah', 9, 2, 'The people who walked in darkness have seen a great light. The light has shined on those who lived in the land of the shadow of death.'),
  ('Isaiah', 9, 3, 'You have multiplied the nation. You have increased their joy. They rejoice before you according to the joy in harvest, as men rejoice when they divide the plunder.'),
  ('Isaiah', 9, 4, 'For the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, you have broken as in the day of Midian.'),
  ('Isaiah', 9, 5, 'For all the armor of the armed man in the noisy battle, and the garments rolled in blood, will be for burning, fuel for the fire.'),
  ('Isaiah', 9, 6, 'For a child is born to us. A son is given to us; and the government will be on his shoulders. His name will be called Wonderful Counselor, Mighty God, Everlasting Father, Prince of Peace.'),
  ('Isaiah', 9, 7, 'Of the increase of his government and of peace there shall be no end, on David’s throne, and on his kingdom, to establish it, and to uphold it with justice and with righteousness from that time on, even forever. The zeal of the LORD of Armies will perform this.'),
  ('Isaiah', 9, 8, 'The Lord sent a word into Jacob, and it falls on Israel.'),
  ('Isaiah', 9, 9, 'All the people will know, including Ephraim and the inhabitants of Samaria, who say in pride and in arrogance of heart,'),
  ('Isaiah', 9, 10, '“The bricks have fallen, but we will build with cut stone. The sycamore fig trees have been cut down, but we will put cedars in their place.”'),
  ('Isaiah', 9, 11, 'Therefore the LORD will set up on high against him the adversaries of Rezin, and will stir up his enemies,'),
  ('Isaiah', 9, 12, 'The Syrians in front, and the Philistines behind; and they will devour Israel with open mouth. For all this, his anger is not turned away, but his hand is stretched out still.'),
  ('Isaiah', 9, 13, 'Yet the people have not turned to him who struck them, neither have they sought the LORD of Armies.'),
  ('Isaiah', 9, 14, 'Therefore the LORD will cut off from Israel head and tail, palm branch and reed, in one day.'),
  ('Isaiah', 9, 15, 'The elder and the honorable man is the head, and the prophet who teaches lies is the tail.'),
  ('Isaiah', 9, 16, 'For those who lead this people lead them astray; and those who are led by them are destroyed.'),
  ('Isaiah', 9, 17, 'Therefore the Lord will not rejoice over their young men, neither will he have compassion on their fatherless and widows; for everyone is profane and an evildoer, and every mouth speaks folly. For all this his anger is not turned away, but his hand is stretched out still.'),
  ('Isaiah', 9, 18, 'For wickedness burns like a fire. It devours the briers and thorns; yes, it kindles in the thickets of the forest, and they roll upward in a column of smoke.'),
  ('Isaiah', 9, 19, 'Through the LORD of Armies’ wrath, the land is burned up; and the people are the fuel for the fire. No one spares his brother.'),
  ('Isaiah', 9, 20, 'One will devour on the right hand, and be hungry; and he will eat on the left hand, and they will not be satisfied. Everyone will eat the flesh of his own arm:'),
  ('Isaiah', 9, 21, 'Manasseh eating Ephraim and Ephraim eating Manasseh, and they together will be against Judah. For all this his anger is not turned away, but his hand is stretched out still.'),
  ('Isaiah', 10, 1, 'Woe to those who decree unrighteous decrees, and to the writers who write oppressive decrees'),
  ('Isaiah', 10, 2, 'to deprive the needy of justice, and to rob the poor among my people of their rights, that widows may be their plunder, and that they may make the fatherless their prey!'),
  ('Isaiah', 10, 3, 'What will you do in the day of visitation, and in the desolation which will come from afar? To whom will you flee for help? Where will you leave your wealth?'),
  ('Isaiah', 10, 4, 'They will only bow down under the prisoners, and will fall under the slain. For all this his anger is not turned away, but his hand is stretched out still.'),
  ('Isaiah', 10, 5, 'Alas Assyrian, the rod of my anger, the staff in whose hand is my indignation!'),
  ('Isaiah', 10, 6, 'I will send him against a profane nation, and against the people who anger me I will give him a command to take the plunder and to take the prey, and to tread them down like the mire of the streets.'),
  ('Isaiah', 10, 7, 'However, he doesn’t mean so, neither does his heart think so; but it is in his heart to destroy, and to cut off not a few nations.'),
  ('Isaiah', 10, 8, 'For he says, “Aren’t all of my princes kings?'),
  ('Isaiah', 10, 9, 'Isn’t Calno like Carchemish? Isn’t Hamath like Arpad? Isn’t Samaria like Damascus?”'),
  ('Isaiah', 10, 10, 'As my hand has found the kingdoms of the idols, whose engraved images exceeded those of Jerusalem and of Samaria,'),
  ('Isaiah', 10, 11, 'shall I not, as I have done to Samaria and her idols, so do to Jerusalem and her idols?'),
  ('Isaiah', 10, 12, 'Therefore it will happen that when the Lord has performed his whole work on Mount Zion and on Jerusalem, I will punish the fruit of the willful proud heart of the king of Assyria, and the insolence of his arrogant looks.'),
  ('Isaiah', 10, 13, 'For he has said, “By the strength of my hand I have done it, and by my wisdom, for I have understanding. I have removed the boundaries of the peoples, and have robbed their treasures. Like a valiant man I have brought down their rulers.'),
  ('Isaiah', 10, 14, 'My hand has found the riches of the peoples like a nest, and like one gathers eggs that are abandoned, I have gathered all the earth. There was no one who moved their wing, or that opened their mouth, or chirped.”'),
  ('Isaiah', 10, 15, 'Should an ax brag against him who chops with it? Should a saw exalt itself above him who saws with it? As if a rod should lift those who lift it up, or as if a staff should lift up someone who is not wood.'),
  ('Isaiah', 10, 16, 'Therefore the Lord, GOD of Armies, will send among his fat ones leanness; and under his glory a burning will be kindled like the burning of fire.'),
  ('Isaiah', 10, 17, 'The light of Israel will be for a fire, and his Holy One for a flame; and it will burn and devour his thorns and his briers in one day.'),
  ('Isaiah', 10, 18, 'He will consume the glory of his forest and of his fruitful field, both soul and body. It will be as when a standard bearer faints.'),
  ('Isaiah', 10, 19, 'The remnant of the trees of his forest shall be few, so that a child could write their number.'),
  ('Isaiah', 10, 20, 'It will come to pass in that day that the remnant of Israel, and those who have escaped from the house of Jacob will no more again lean on him who struck them, but shall lean on the LORD, the Holy One of Israel, in truth.'),
  ('Isaiah', 10, 21, 'A remnant will return, even the remnant of Jacob, to the mighty God.'),
  ('Isaiah', 10, 22, 'For though your people, Israel, are like the sand of the sea, only a remnant of them will return. A destruction is determined, overflowing with righteousness.'),
  ('Isaiah', 10, 23, 'For the Lord, GOD of Armies, will make a full end, and that determined, throughout all the earth.'),
  ('Isaiah', 10, 24, 'Therefore the Lord, GOD of Armies, says, “My people who dwell in Zion, don’t be afraid of the Assyrian, though he strike you with the rod, and lift up his staff against you, as Egypt did.'),
  ('Isaiah', 10, 25, 'For yet a very little while, and the indignation against you will be accomplished, and my anger will be directed to his destruction.”'),
  ('Isaiah', 10, 26, 'The LORD of Armies will stir up a scourge against him, as in the slaughter of Midian at the rock of Oreb. His rod will be over the sea, and he will lift it up like he did against Egypt.'),
  ('Isaiah', 10, 27, 'It will happen in that day that his burden will depart from off your shoulder, and his yoke from off your neck, and the yoke shall be destroyed because of the anointing oil.'),
  ('Isaiah', 10, 28, 'He has come to Aiath. He has passed through Migron. At Michmash he stores his baggage.'),
  ('Isaiah', 10, 29, 'They have gone over the pass. They have taken up their lodging at Geba. Ramah trembles. Gibeah of Saul has fled.'),
  ('Isaiah', 10, 30, 'Cry aloud with your voice, daughter of Gallim! Listen, Laishah! You poor Anathoth!'),
  ('Isaiah', 10, 31, 'Madmenah is a fugitive. The inhabitants of Gebim flee for safety.'),
  ('Isaiah', 10, 32, 'This very day he will halt at Nob. He shakes his hand at the mountain of the daughter of Zion, the hill of Jerusalem.'),
  ('Isaiah', 10, 33, 'Behold, the Lord, GOD of Armies, will lop the boughs with terror. The tall will be cut down, and the lofty will be brought low.'),
  ('Isaiah', 10, 34, 'He will cut down the thickets of the forest with iron, and Lebanon will fall by the Mighty One.'),
  ('Isaiah', 11, 1, 'A shoot will come out of the stock of Jesse, and a branch out of his roots will bear fruit.'),
  ('Isaiah', 11, 2, 'The LORD’s Spirit will rest on him: the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of the LORD.'),
  ('Isaiah', 11, 3, 'His delight will be in the fear of the LORD. He will not judge by the sight of his eyes, neither decide by the hearing of his ears;'),
  ('Isaiah', 11, 4, 'but he will judge the poor with righteousness, and decide with equity for the humble of the earth. He will strike the earth with the rod of his mouth; and with the breath of his lips he will kill the wicked.'),
  ('Isaiah', 11, 5, 'Righteousness will be the belt around his waist, and faithfulness the belt around his waist.'),
  ('Isaiah', 11, 6, 'The wolf will live with the lamb, and the leopard will lie down with the young goat, the calf, the young lion, and the fattened calf together; and a little child will lead them.'),
  ('Isaiah', 11, 7, 'The cow and the bear will graze. Their young ones will lie down together. The lion will eat straw like the ox.'),
  ('Isaiah', 11, 8, 'The nursing child will play near a cobra’s hole, and the weaned child will put his hand on the viper’s den.'),
  ('Isaiah', 11, 9, 'They will not hurt nor destroy in all my holy mountain; for the earth will be full of the knowledge of the LORD, as the waters cover the sea.'),
  ('Isaiah', 11, 10, 'It will happen in that day that the nations will seek the root of Jesse, who stands as a banner of the peoples; and his resting place will be glorious.'),
  ('Isaiah', 11, 11, 'It will happen in that day that the Lord will set his hand again the second time to recover the remnant that is left of his people from Assyria, from Egypt, from Pathros, from Cush, from Elam, from Shinar, from Hamath, and from the islands of the sea.'),
  ('Isaiah', 11, 12, 'He will set up a banner for the nations, and will assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth.'),
  ('Isaiah', 11, 13, 'The envy also of Ephraim will depart, and those who persecute Judah will be cut off. Ephraim won’t envy Judah, and Judah won’t persecute Ephraim.'),
  ('Isaiah', 11, 14, 'They will fly down on the shoulders of the Philistines on the west. Together they will plunder the children of the east. They will extend their power over Edom and Moab, and the children of Ammon will obey them.'),
  ('Isaiah', 11, 15, 'The LORD will utterly destroy the tongue of the Egyptian sea; and with his scorching wind he will wave his hand over the River, and will split it into seven streams, and cause men to march over in sandals.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 11, 16, 'There will be a highway for the remnant that is left of his people from Assyria, like there was for Israel in the day that he came up out of the land of Egypt.'),
  ('Isaiah', 12, 1, 'In that day you will say, “I will give thanks to you, the LORD; for though you were angry with me, your anger has turned away and you comfort me.'),
  ('Isaiah', 12, 2, 'Behold, God is my salvation. I will trust, and will not be afraid; for the LORD, the LORD, is my strength and song; and he has become my salvation.”'),
  ('Isaiah', 12, 3, 'Therefore with joy you will draw water out of the wells of salvation.'),
  ('Isaiah', 12, 4, 'In that day you will say, “Give thanks to the LORD! Call on his name! Declare his doings among the peoples! Proclaim that his name is exalted!'),
  ('Isaiah', 12, 5, 'Sing to the LORD, for he has done excellent things! Let this be known in all the earth!'),
  ('Isaiah', 12, 6, 'Cry aloud and shout, you inhabitant of Zion, for the Holy One of Israel is great among you!”'),
  ('Isaiah', 13, 1, 'The burden of Babylon, which Isaiah the son of Amoz saw.'),
  ('Isaiah', 13, 2, 'Set up a banner on the bare mountain! Lift up your voice to them! Wave your hand, that they may go into the gates of the nobles.'),
  ('Isaiah', 13, 3, 'I have commanded my consecrated ones; yes, I have called my mighty men for my anger, even my proudly exulting ones.'),
  ('Isaiah', 13, 4, 'The noise of a multitude is in the mountains, as of a great people; the noise of an uproar of the kingdoms of the nations gathered together! The LORD of Armies is mustering the army for the battle.'),
  ('Isaiah', 13, 5, 'They come from a far country, from the uttermost part of heaven, even the LORD, and the weapons of his indignation, to destroy the whole land.'),
  ('Isaiah', 13, 6, 'Wail, for the LORD’s day is at hand! It will come as destruction from the Almighty.'),
  ('Isaiah', 13, 7, 'Therefore all hands will be feeble, and everyone’s heart will melt.'),
  ('Isaiah', 13, 8, 'They will be dismayed. Pangs and sorrows will seize them. They will be in pain like a woman in labor. They will look in amazement one at another. Their faces will be faces of flame.'),
  ('Isaiah', 13, 9, 'Behold, the day of the LORD comes, cruel, with wrath and fierce anger; to make the land a desolation, and to destroy its sinners out of it.'),
  ('Isaiah', 13, 10, 'For the stars of the sky and its constellations will not give their light. The sun will be darkened in its going out, and the moon will not cause its light to shine.'),
  ('Isaiah', 13, 11, 'I will punish the world for their evil, and the wicked for their iniquity. I will cause the arrogance of the proud to cease, and will humble the arrogance of the terrible.'),
  ('Isaiah', 13, 12, 'I will make people more rare than fine gold, even a person than the pure gold of Ophir.'),
  ('Isaiah', 13, 13, 'Therefore I will make the heavens tremble, and the earth will be shaken out of its place in the LORD of Armies’ wrath, and in the day of his fierce anger.'),
  ('Isaiah', 13, 14, 'It will happen that like a hunted gazelle and like sheep that no one gathers, they will each turn to their own people, and will each flee to their own land.'),
  ('Isaiah', 13, 15, 'Everyone who is found will be thrust through. Everyone who is captured will fall by the sword.'),
  ('Isaiah', 13, 16, 'Their infants also will be dashed in pieces before their eyes. Their houses will be ransacked, and their wives raped.'),
  ('Isaiah', 13, 17, 'Behold, I will stir up the Medes against them, who will not value silver, and as for gold, they will not delight in it.'),
  ('Isaiah', 13, 18, 'Their bows will dash the young men in pieces; and they shall have no pity on the fruit of the womb. Their eyes will not spare children.'),
  ('Isaiah', 13, 19, 'Babylon, the glory of kingdoms, the beauty of the Chaldeans’ pride, will be like when God overthrew Sodom and Gomorrah.'),
  ('Isaiah', 13, 20, 'It will never be inhabited, neither will it be lived in from generation to generation. The Arabian will not pitch a tent there, neither will shepherds make their flocks lie down there.'),
  ('Isaiah', 13, 21, 'But wild animals of the desert will lie there, and their houses will be full of jackals. Ostriches will dwell there, and wild goats will frolic there.'),
  ('Isaiah', 13, 22, 'Hyenas will cry in their fortresses, and jackals in the pleasant palaces. Her time is near to come, and her days will not be prolonged.'),
  ('Isaiah', 14, 1, 'For the LORD will have compassion on Jacob, and will yet choose Israel, and set them in their own land. The foreigner will join himself with them, and they will unite with the house of Jacob.'),
  ('Isaiah', 14, 2, 'The peoples will take them, and bring them to their place. The house of Israel will possess them in the LORD’s land for servants and for handmaids. They will take as captives those whose captives they were; and they shall rule over their oppressors.'),
  ('Isaiah', 14, 3, 'It will happen in the day that the LORD will give you rest from your sorrow, from your trouble, and from the hard service in which you were made to serve,'),
  ('Isaiah', 14, 4, 'that you will take up this parable against the king of Babylon, and say, “How the oppressor has ceased! The golden city has ceased!”'),
  ('Isaiah', 14, 5, 'The LORD has broken the staff of the wicked, the scepter of the rulers,'),
  ('Isaiah', 14, 6, 'who struck the peoples in wrath with a continual stroke, who ruled the nations in anger, with a persecution that no one restrained.'),
  ('Isaiah', 14, 7, 'The whole earth is at rest, and is quiet. They break out in song.'),
  ('Isaiah', 14, 8, 'Yes, the cypress trees rejoice with you, with the cedars of Lebanon, saying, “Since you are humbled, no lumberjack has come up against us.”'),
  ('Isaiah', 14, 9, 'Sheol from beneath has moved for you to meet you at your coming. It stirs up the departed spirits for you, even all the rulers of the earth. It has raised up from their thrones all the kings of the nations.'),
  ('Isaiah', 14, 10, 'They all will answer and ask you, “Have you also become as weak as we are? Have you become like us?”'),
  ('Isaiah', 14, 11, 'Your pomp is brought down to Sheol, with the sound of your stringed instruments. Maggots are spread out under you, and worms cover you.'),
  ('Isaiah', 14, 12, 'How you have fallen from heaven, shining one, son of the dawn! How you are cut down to the ground, who laid the nations low!'),
  ('Isaiah', 14, 13, 'You said in your heart, “I will ascend into heaven! I will exalt my throne above the stars of God! I will sit on the mountain of assembly, in the far north!'),
  ('Isaiah', 14, 14, 'I will ascend above the heights of the clouds! I will make myself like the Most High!”'),
  ('Isaiah', 14, 15, 'Yet you shall be brought down to Sheol, to the depths of the pit.'),
  ('Isaiah', 14, 16, 'Those who see you will stare at you. They will ponder you, saying, “Is this the man who made the earth to tremble, who shook kingdoms,'),
  ('Isaiah', 14, 17, 'who made the world like a wilderness, and overthrew its cities, who didn’t release his prisoners to their home?”'),
  ('Isaiah', 14, 18, 'All the kings of the nations sleep in glory, everyone in his own house.'),
  ('Isaiah', 14, 19, 'But you are cast away from your tomb like an abominable branch, clothed with the slain who are thrust through with the sword, who go down to the stones of the pit; like a dead body trodden under foot.'),
  ('Isaiah', 14, 20, 'You will not join them in burial, because you have destroyed your land. You have killed your people. The offspring of evildoers will not be named forever.'),
  ('Isaiah', 14, 21, 'Prepare for slaughter of his children because of the iniquity of their fathers, that they not rise up and possess the earth, and fill the surface of the world with cities.'),
  ('Isaiah', 14, 22, '“I will rise up against them,” says the LORD of Armies, “and cut off from Babylon name and remnant, and son and son’s son,” says the LORD.'),
  ('Isaiah', 14, 23, '“I will also make it a possession for the porcupine, and pools of water. I will sweep it with the broom of destruction,” says the LORD of Armies.'),
  ('Isaiah', 14, 24, 'The LORD of Armies has sworn, saying, “Surely, as I have thought, so shall it happen; and as I have purposed, so shall it stand:'),
  ('Isaiah', 14, 25, 'that I will break the Assyrian in my land, and tread him under foot on my mountains. Then his yoke will leave them, and his burden leave their shoulders.'),
  ('Isaiah', 14, 26, 'This is the plan that is determined for the whole earth. This is the hand that is stretched out over all the nations.'),
  ('Isaiah', 14, 27, 'For the LORD of Armies has planned, and who can stop it? His hand is stretched out, and who can turn it back?”'),
  ('Isaiah', 14, 28, 'This burden was in the year that King Ahaz died.'),
  ('Isaiah', 14, 29, 'Don’t rejoice, O Philistia, all of you, because the rod that struck you is broken; for out of the serpent’s root an adder will emerge, and his fruit will be a fiery flying serpent.'),
  ('Isaiah', 14, 30, 'The firstborn of the poor will eat, and the needy will lie down in safety; and I will kill your root with famine, and your remnant will be killed.'),
  ('Isaiah', 14, 31, 'Howl, gate! Cry, city! You are melted away, Philistia, all of you; for smoke comes out of the north, and there is no straggler in his ranks.'),
  ('Isaiah', 14, 32, 'What will they answer the messengers of the nation? That the LORD has founded Zion, and in her the afflicted of his people will take refuge.'),
  ('Isaiah', 15, 1, 'The burden of Moab. For in a night, Ar of Moab is laid waste, and brought to nothing. For in a night Kir of Moab is laid waste, and brought to nothing.'),
  ('Isaiah', 15, 2, 'They have gone up to Bayith, and to Dibon, to the high places, to weep. Moab wails over Nebo and over Medeba. Baldness is on all of their heads. Every beard is cut off.'),
  ('Isaiah', 15, 3, 'In their streets, they clothe themselves in sackcloth. In their streets and on their housetops, everyone wails, weeping abundantly.'),
  ('Isaiah', 15, 4, 'Heshbon cries out with Elealeh. Their voice is heard even to Jahaz. Therefore the armed men of Moab cry aloud. Their souls tremble within them.'),
  ('Isaiah', 15, 5, 'My heart cries out for Moab! Her nobles flee to Zoar, to Eglath Shelishiyah; for they go up by the ascent of Luhith with weeping; for on the way to Horonaim, they raise up a cry of destruction.'),
  ('Isaiah', 15, 6, 'For the waters of Nimrim will be desolate; for the grass has withered away, the tender grass fails, there is no green thing.'),
  ('Isaiah', 15, 7, 'Therefore they will carry away the abundance they have gotten, and that which they have stored up, over the brook of the willows.'),
  ('Isaiah', 15, 8, 'For the cry has gone around the borders of Moab, its wailing to Eglaim, and its wailing to Beer Elim.'),
  ('Isaiah', 15, 9, 'For the waters of Dimon are full of blood; for I will bring yet more on Dimon, a lion on those of Moab who escape, and on the remnant of the land.'),
  ('Isaiah', 16, 1, 'Send the lambs for the ruler of the land from Selah to the wilderness, to the mountain of the daughter of Zion.'),
  ('Isaiah', 16, 2, 'For it will be that as wandering birds, as a scattered nest, so will the daughters of Moab be at the fords of the Arnon.'),
  ('Isaiah', 16, 3, 'Give counsel! Execute justice! Make your shade like the night in the middle of the noonday! Hide the outcasts! Don’t betray the fugitive!'),
  ('Isaiah', 16, 4, 'Let my outcasts dwell with you! As for Moab, be a hiding place for him from the face of the destroyer. For the extortionist is brought to nothing. Destruction ceases. The oppressors are consumed out of the land.'),
  ('Isaiah', 16, 5, 'A throne will be established in loving kindness. One will sit on it in truth, in the tent of David, judging, seeking justice, and swift to do righteousness.'),
  ('Isaiah', 16, 6, 'We have heard of the pride of Moab, that he is very proud; even of his arrogance, his pride, and his wrath. His boastings are nothing.'),
  ('Isaiah', 16, 7, 'Therefore Moab will wail for Moab. Everyone will wail. You will mourn for the raisin cakes of Kir Hareseth, utterly stricken.'),
  ('Isaiah', 16, 8, 'For the fields of Heshbon languish with the vine of Sibmah. The lords of the nations have broken down its choice branches, which reached even to Jazer, which wandered into the wilderness. Its shoots were spread abroad. They passed over the sea.'),
  ('Isaiah', 16, 9, 'Therefore I will weep with the weeping of Jazer for the vine of Sibmah. I will water you with my tears, Heshbon, and Elealeh: for on your summer fruits and on your harvest the battle shout has fallen.'),
  ('Isaiah', 16, 10, 'Gladness is taken away, and joy out of the fruitful field; and in the vineyards there will be no singing, neither joyful noise. Nobody will tread out wine in the presses. I have made the shouting stop.'),
  ('Isaiah', 16, 11, 'Therefore my heart sounds like a harp for Moab, and my inward parts for Kir Heres.'),
  ('Isaiah', 16, 12, 'It will happen that when Moab presents himself, when he wearies himself on the high place, and comes to his sanctuary to pray, that he will not prevail.'),
  ('Isaiah', 16, 13, 'This is the word that the LORD spoke concerning Moab in time past.'),
  ('Isaiah', 16, 14, 'But now the LORD has spoken, saying, “Within three years, as a worker bound by contract would count them, the glory of Moab shall be brought into contempt, with all his great multitude; and the remnant will be very small and feeble.”'),
  ('Isaiah', 17, 1, 'The burden of Damascus. “Behold, Damascus is taken away from being a city, and it will be a ruinous heap.'),
  ('Isaiah', 17, 2, 'The cities of Aroer are forsaken. They will be for flocks, which shall lie down, and no one shall make them afraid.'),
  ('Isaiah', 17, 3, 'The fortress shall cease from Ephraim, and the kingdom from Damascus, and the remnant of Syria. They will be as the glory of the children of Israel,” says the LORD of Armies.'),
  ('Isaiah', 17, 4, '“It will happen in that day that the glory of Jacob will be made thin, and the fatness of his flesh will become lean.'),
  ('Isaiah', 17, 5, 'It will be like when the harvester gathers the wheat, and his arm reaps the grain. Yes, it will be like when one gleans grain in the valley of Rephaim.'),
  ('Isaiah', 17, 6, 'Yet gleanings will be left there, like the shaking of an olive tree, two or three olives in the top of the uppermost bough, four or five in the outermost branches of a fruitful tree,” says the LORD, the God of Israel.'),
  ('Isaiah', 17, 7, 'In that day, people will look to their Maker, and their eyes will have respect for the Holy One of Israel.'),
  ('Isaiah', 17, 8, 'They will not look to the altars, the work of their hands; neither shall they respect that which their fingers have made, either the Asherah poles or the incense altars.'),
  ('Isaiah', 17, 9, 'In that day, their strong cities will be like the forsaken places in the woods and on the mountain top, which were forsaken from before the children of Israel; and it will be a desolation.'),
  ('Isaiah', 17, 10, 'For you have forgotten the God of your salvation, and have not remembered the rock of your strength. Therefore you plant pleasant plants, and set out foreign seedlings.'),
  ('Isaiah', 17, 11, 'In the day of your planting, you hedge it in. In the morning, you make your seed blossom, but the harvest flees away in the day of grief and of desperate sorrow.'),
  ('Isaiah', 17, 12, 'Ah, the uproar of many peoples who roar like the roaring of the seas; and the rushing of nations that rush like the rushing of mighty waters!'),
  ('Isaiah', 17, 13, 'The nations will rush like the rushing of many waters, but he will rebuke them, and they will flee far off, and will be chased like the chaff of the mountains before the wind, and like the whirling dust before the storm.'),
  ('Isaiah', 17, 14, 'At evening, behold, terror! Before the morning, they are no more. This is the portion of those who plunder us, and the lot of those who rob us.'),
  ('Isaiah', 18, 1, 'Ah, the land of the rustling of wings, which is beyond the rivers of Ethiopia;'),
  ('Isaiah', 18, 2, 'that sends ambassadors by the sea, even in vessels of papyrus on the waters, saying, “Go, you swift messengers, to a nation tall and smooth, to a people awesome from their beginning onward, a nation that measures out and treads down, whose land the rivers divide!”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 18, 3, 'All you inhabitants of the world, and you dwellers on the earth, when a banner is lifted up on the mountains, look! When the trumpet is blown, listen!'),
  ('Isaiah', 18, 4, 'For the LORD said to me, “I will be still, and I will see in my dwelling place, like clear heat in sunshine, like a cloud of dew in the heat of harvest.”'),
  ('Isaiah', 18, 5, 'For before the harvest, when the blossom is over, and the flower becomes a ripening grape, he will cut off the sprigs with pruning hooks, and he will cut down and take away the spreading branches.'),
  ('Isaiah', 18, 6, 'They will be left together for the ravenous birds of the mountains, and for the animals of the earth. The ravenous birds will eat them in the summer, and all the animals of the earth will eat them in the winter.'),
  ('Isaiah', 18, 7, 'In that time, a present will be brought to the LORD of Armies from a people tall and smooth, even from a people awesome from their beginning onward, a nation that measures out and treads down, whose land the rivers divide, to the place of the name of the LORD of Armies, Mount Zion.'),
  ('Isaiah', 19, 1, 'The burden of Egypt. “Behold, the LORD rides on a swift cloud, and comes to Egypt. The idols of Egypt will tremble at his presence; and the heart of Egypt will melt within it.'),
  ('Isaiah', 19, 2, 'I will stir up the Egyptians against the Egyptians, and they will fight everyone against his brother, and everyone against his neighbor; city against city, and kingdom against kingdom.'),
  ('Isaiah', 19, 3, 'The spirit of the Egyptians will fail within them. I will destroy their counsel. They will seek the idols, the charmers, those who have familiar spirits, and the wizards.'),
  ('Isaiah', 19, 4, 'I will give over the Egyptians into the hand of a cruel lord. A fierce king will rule over them,” says the Lord, GOD of Armies.'),
  ('Isaiah', 19, 5, 'The waters will fail from the sea, and the river will be wasted and become dry.'),
  ('Isaiah', 19, 6, 'The rivers will become foul. The streams of Egypt will be diminished and dried up. The reeds and flags will wither away.'),
  ('Isaiah', 19, 7, 'The meadows by the Nile, by the brink of the Nile, and all the sown fields of the Nile, will become dry, be driven away, and be no more.'),
  ('Isaiah', 19, 8, 'The fishermen will lament, and all those who fish in the Nile will mourn, and those who spread nets on the waters will languish.'),
  ('Isaiah', 19, 9, 'Moreover those who work in combed flax, and those who weave white cloth, will be confounded.'),
  ('Isaiah', 19, 10, 'The pillars will be broken in pieces. All those who work for hire will be grieved in soul.'),
  ('Isaiah', 19, 11, 'The princes of Zoan are utterly foolish. The counsel of the wisest counselors of Pharaoh has become stupid. How do you say to Pharaoh, “I am the son of the wise, the son of ancient kings”?'),
  ('Isaiah', 19, 12, 'Where then are your wise men? Let them tell you now; and let them know what the LORD of Armies has purposed concerning Egypt.'),
  ('Isaiah', 19, 13, 'The princes of Zoan have become fools. The princes of Memphis are deceived. They have caused Egypt to go astray, those who are the cornerstone of her tribes.'),
  ('Isaiah', 19, 14, 'The LORD has mixed a spirit of perverseness in the middle of her; and they have caused Egypt to go astray in all of its works, like a drunken man staggers in his vomit.'),
  ('Isaiah', 19, 15, 'Neither shall there be any work for Egypt, which head or tail, palm branch or rush, may do.'),
  ('Isaiah', 19, 16, 'In that day the Egyptians will be like women. They will tremble and fear because of the shaking of the LORD of Armies’s hand, which he shakes over them.'),
  ('Isaiah', 19, 17, 'The land of Judah will become a terror to Egypt. Everyone to whom mention is made of it will be afraid, because of the plans of the LORD of Armies, which he determines against it.'),
  ('Isaiah', 19, 18, 'In that day, there will be five cities in the land of Egypt that speak the language of Canaan, and swear to the LORD of Armies. One will be called “The city of destruction.”'),
  ('Isaiah', 19, 19, 'In that day, there will be an altar to the LORD in the middle of the land of Egypt, and a pillar to the LORD at its border.'),
  ('Isaiah', 19, 20, 'It will be for a sign and for a witness to the LORD of Armies in the land of Egypt; for they will cry to the LORD because of oppressors, and he will send them a savior and a defender, and he will deliver them.'),
  ('Isaiah', 19, 21, 'The LORD will be known to Egypt, and the Egyptians will know the LORD in that day. Yes, they will worship with sacrifice and offering, and will vow a vow to the LORD, and will perform it.'),
  ('Isaiah', 19, 22, 'The LORD will strike Egypt, striking and healing. They will return to the LORD, and he will be entreated by them, and will heal them.'),
  ('Isaiah', 19, 23, 'In that day there will be a highway out of Egypt to Assyria, and the Assyrian shall come into Egypt, and the Egyptian into Assyria; and the Egyptians will worship with the Assyrians.'),
  ('Isaiah', 19, 24, 'In that day, Israel will be the third with Egypt and with Assyria, a blessing within the earth;'),
  ('Isaiah', 19, 25, 'because the LORD of Armies has blessed them, saying, “Blessed be Egypt my people, Assyria the work of my hands, and Israel my inheritance.”'),
  ('Isaiah', 20, 1, 'In the year that Tartan came to Ashdod, when Sargon the king of Assyria sent him, and he fought against Ashdod and took it;'),
  ('Isaiah', 20, 2, 'at that time the LORD spoke by Isaiah the son of Amoz, saying, “Go, and loosen the sackcloth from off your waist, and take your sandals from off your feet.” He did so, walking naked and barefoot.'),
  ('Isaiah', 20, 3, 'The LORD said, “As my servant Isaiah has walked naked and barefoot three years for a sign and a wonder concerning Egypt and concerning Ethiopia,'),
  ('Isaiah', 20, 4, 'so the king of Assyria will lead away the captives of Egypt and the exiles of Ethiopia, young and old, naked and barefoot, and with buttocks uncovered, to the shame of Egypt.'),
  ('Isaiah', 20, 5, 'They will be dismayed and confounded, because of Ethiopia their expectation, and of Egypt their glory.'),
  ('Isaiah', 20, 6, 'The inhabitants of this coast land will say in that day, ‘Behold, this is our expectation, where we fled for help to be delivered from the king of Assyria. And we, how will we escape?’”'),
  ('Isaiah', 21, 1, 'The burden of the wilderness of the sea. As whirlwinds in the South sweep through, it comes from the wilderness, from an awesome land.'),
  ('Isaiah', 21, 2, 'A grievous vision is declared to me. The treacherous man deals treacherously, and the destroyer destroys. Go up, Elam; attack! I have stopped all of Media’s sighing.'),
  ('Isaiah', 21, 3, 'Therefore my thighs are filled with anguish. Pains have seized me, like the pains of a woman in labor. I am in so much pain that I can’t hear. I am so dismayed that I can’t see.'),
  ('Isaiah', 21, 4, 'My heart flutters. Horror has frightened me. The twilight that I desired has been turned into trembling for me.'),
  ('Isaiah', 21, 5, 'They prepare the table. They set the watch. They eat. They drink. Rise up, you princes, oil the shield!'),
  ('Isaiah', 21, 6, 'For the Lord said to me, “Go, set a watchman. Let him declare what he sees.'),
  ('Isaiah', 21, 7, 'When he sees a troop, horsemen in pairs, a troop of donkeys, a troop of camels, he shall listen diligently with great attentiveness.”'),
  ('Isaiah', 21, 8, 'He cried like a lion: “Lord, I stand continually on the watchtower in the daytime, and every night I stay at my post.'),
  ('Isaiah', 21, 9, 'Behold, here comes a troop of men, horsemen in pairs.” He answered, “Fallen, fallen is Babylon; and all the engraved images of her gods are broken to the ground.'),
  ('Isaiah', 21, 10, 'You are my threshing, and the grain of my floor!” That which I have heard from the LORD of Armies, the God of Israel, I have declared to you.'),
  ('Isaiah', 21, 11, 'The burden of Dumah. One calls to me out of Seir, “Watchman, what of the night? Watchman, what of the night?”'),
  ('Isaiah', 21, 12, 'The watchman said, “The morning comes, and also the night. If you will inquire, inquire. Come back again.”'),
  ('Isaiah', 21, 13, 'The burden on Arabia. You will lodge in the thickets in Arabia, you caravans of Dedanites.'),
  ('Isaiah', 21, 14, 'They brought water to him who was thirsty. The inhabitants of the land of Tema met the fugitives with their bread.'),
  ('Isaiah', 21, 15, 'For they fled away from the swords, from the drawn sword, from the bent bow, and from the heat of battle.'),
  ('Isaiah', 21, 16, 'For the Lord said to me, “Within a year, as a worker bound by contract would count it, all the glory of Kedar will fail,'),
  ('Isaiah', 21, 17, 'and the residue of the number of the archers, the mighty men of the children of Kedar, will be few; for the LORD, the God of Israel, has spoken it.”'),
  ('Isaiah', 22, 1, 'The burden of the valley of vision. What ails you now, that you have all gone up to the housetops?'),
  ('Isaiah', 22, 2, 'You that are full of shouting, a tumultuous city, a joyous town, your slain are not slain with the sword, neither are they dead in battle.'),
  ('Isaiah', 22, 3, 'All your rulers fled away together. They were bound by the archers. All who were found by you were bound together. They fled far away.'),
  ('Isaiah', 22, 4, 'Therefore I said, “Look away from me. I will weep bitterly. Don’t labor to comfort me for the destruction of the daughter of my people.'),
  ('Isaiah', 22, 5, 'For it is a day of confusion, and of treading down, and of perplexity from the Lord, GOD of Armies, in the valley of vision, a breaking down of the walls, and a crying to the mountains.”'),
  ('Isaiah', 22, 6, 'Elam carried his quiver, with chariots of men and horsemen; and Kir uncovered the shield.'),
  ('Isaiah', 22, 7, 'Your choicest valleys were full of chariots, and the horsemen set themselves in array at the gate.'),
  ('Isaiah', 22, 8, 'He took away the covering of Judah; and you looked in that day to the armor in the house of the forest.'),
  ('Isaiah', 22, 9, 'You saw the breaches of David’s city, that they were many; and you gathered together the waters of the lower pool.'),
  ('Isaiah', 22, 10, 'You counted the houses of Jerusalem, and you broke down the houses to fortify the wall.'),
  ('Isaiah', 22, 11, 'You also made a reservoir between the two walls for the water of the old pool. But you didn’t look to him who had done this, neither did you have respect for him who planned it long ago.'),
  ('Isaiah', 22, 12, 'In that day, the Lord, GOD of Armies, called to weeping, to mourning, to baldness, and to dressing in sackcloth;'),
  ('Isaiah', 22, 13, 'and behold, there is joy and gladness, killing cattle and killing sheep, eating meat and drinking wine: “Let’s eat and drink, for tomorrow we will die.”'),
  ('Isaiah', 22, 14, 'The LORD of Armies revealed himself in my ears, “Surely this iniquity will not be forgiven you until you die,” says the Lord, GOD of Armies.'),
  ('Isaiah', 22, 15, 'The Lord, GOD of Armies says, “Go, get yourself to this treasurer, even to Shebna, who is over the house, and say,'),
  ('Isaiah', 22, 16, '‘What are you doing here? Who has you here, that you have dug out a tomb here?’ Cutting himself out a tomb on high, chiseling a habitation for himself in the rock!”'),
  ('Isaiah', 22, 17, 'Behold, the LORD will overcome you and hurl you away violently. Yes, he will grasp you firmly.'),
  ('Isaiah', 22, 18, 'He will surely wind you around and around, and throw you like a ball into a large country. There you will die, and there the chariots of your glory will be, you disgrace of your lord’s house.'),
  ('Isaiah', 22, 19, 'I will thrust you from your office. You will be pulled down from your station.'),
  ('Isaiah', 22, 20, 'It will happen in that day that I will call my servant Eliakim the son of Hilkiah,'),
  ('Isaiah', 22, 21, 'and I will clothe him with your robe, and strengthen him with your belt. I will commit your government into his hand; and he will be a father to the inhabitants of Jerusalem, and to the house of Judah.'),
  ('Isaiah', 22, 22, 'I will lay the key of David’s house on his shoulder. He will open, and no one will shut. He will shut, and no one will open.'),
  ('Isaiah', 22, 23, 'I will fasten him like a nail in a sure place. He will be for a throne of glory to his father’s house.'),
  ('Isaiah', 22, 24, 'They will hang on him all the glory of his father’s house, the offspring and the issue, every small vessel, from the cups even to all the pitchers.'),
  ('Isaiah', 22, 25, '“In that day,” says the LORD of Armies, “the nail that was fastened in a sure place will give way. It will be cut down and fall. The burden that was on it will be cut off, for the LORD has spoken it.”'),
  ('Isaiah', 23, 1, 'The burden of Tyre. Howl, you ships of Tarshish! For it is laid waste, so that there is no house, no entering in. From the land of Kittim it is revealed to them.'),
  ('Isaiah', 23, 2, 'Be still, you inhabitants of the coast, you whom the merchants of Sidon that pass over the sea have replenished.'),
  ('Isaiah', 23, 3, 'On great waters, the seed of the Shihor, the harvest of the Nile, was her revenue. She was the market of nations.'),
  ('Isaiah', 23, 4, 'Be ashamed, Sidon; for the sea has spoken, the stronghold of the sea, saying, “I have not travailed, nor given birth, neither have I nourished young men, nor brought up virgins.”'),
  ('Isaiah', 23, 5, 'When the report comes to Egypt, they will be in anguish at the report of Tyre.'),
  ('Isaiah', 23, 6, 'Pass over to Tarshish! Wail, you inhabitants of the coast!'),
  ('Isaiah', 23, 7, 'Is this your joyous city, whose antiquity is of ancient days, whose feet carried her far away to travel?'),
  ('Isaiah', 23, 8, 'Who has planned this against Tyre, the giver of crowns, whose merchants are princes, whose traders are the honorable of the earth?'),
  ('Isaiah', 23, 9, 'The LORD of Armies has planned it, to stain the pride of all glory, to bring into contempt all the honorable of the earth.'),
  ('Isaiah', 23, 10, 'Pass through your land like the Nile, daughter of Tarshish. There is no restraint any more.'),
  ('Isaiah', 23, 11, 'He has stretched out his hand over the sea. He has shaken the kingdoms. The LORD has ordered the destruction of Canaan’s strongholds.'),
  ('Isaiah', 23, 12, 'He said, “You shall rejoice no more, you oppressed virgin daughter of Sidon. Arise, pass over to Kittim. Even there you will have no rest.”'),
  ('Isaiah', 23, 13, 'Behold, the land of the Chaldeans. This people didn’t exist. The Assyrians founded it for those who dwell in the wilderness. They set up their towers. They overthrew its palaces. They made it a ruin.'),
  ('Isaiah', 23, 14, 'Howl, you ships of Tarshish, for your stronghold is laid waste!'),
  ('Isaiah', 23, 15, 'It will come to pass in that day that Tyre will be forgotten seventy years, according to the days of one king. After the end of seventy years it will be to Tyre like in the song of the prostitute.'),
  ('Isaiah', 23, 16, 'Take a harp; go about the city, you prostitute that has been forgotten. Make sweet melody. Sing many songs, that you may be remembered.'),
  ('Isaiah', 23, 17, 'It will happen after the end of seventy years that the LORD will visit Tyre. She will return to her wages, and will play the prostitute with all the kingdoms of the world on the surface of the earth.'),
  ('Isaiah', 23, 18, 'Her merchandise and her wages will be holiness to the LORD. It will not be treasured nor laid up; for her merchandise will be for those who dwell before the LORD, to eat sufficiently, and for durable clothing.'),
  ('Isaiah', 24, 1, 'Behold, the LORD makes the earth empty, makes it waste, turns it upside down, and scatters its inhabitants.'),
  ('Isaiah', 24, 2, 'It will be as with the people, so with the priest; as with the servant, so with his master; as with the maid, so with her mistress; as with the buyer, so with the seller; as with the creditor, so with the debtor; as with the taker of interest, so with the giver of interest.'),
  ('Isaiah', 24, 3, 'The earth will be utterly emptied and utterly laid waste; for the LORD has spoken this word.'),
  ('Isaiah', 24, 4, 'The earth mourns and fades away. The world languishes and fades away. The lofty people of the earth languish.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 24, 5, 'The earth also is polluted under its inhabitants, because they have transgressed the laws, violated the statutes, and broken the everlasting covenant.'),
  ('Isaiah', 24, 6, 'Therefore the curse has devoured the earth, and those who dwell therein are found guilty. Therefore the inhabitants of the earth are burned, and few men are left.'),
  ('Isaiah', 24, 7, 'The new wine mourns. The vine languishes. All the merry-hearted sigh.'),
  ('Isaiah', 24, 8, 'The mirth of tambourines ceases. The sound of those who rejoice ends. The joy of the harp ceases.'),
  ('Isaiah', 24, 9, 'They will not drink wine with a song. Strong drink will be bitter to those who drink it.'),
  ('Isaiah', 24, 10, 'The confused city is broken down. Every house is shut up, that no man may come in.'),
  ('Isaiah', 24, 11, 'There is a crying in the streets because of the wine. All joy is darkened. The mirth of the land is gone.'),
  ('Isaiah', 24, 12, 'The city is left in desolation, and the gate is struck with destruction.'),
  ('Isaiah', 24, 13, 'For it will be so within the earth among the peoples, as the shaking of an olive tree, as the gleanings when the vintage is done.'),
  ('Isaiah', 24, 14, 'These shall lift up their voice. They will shout for the majesty of the LORD. They cry aloud from the sea.'),
  ('Isaiah', 24, 15, 'Therefore glorify the LORD in the east, even the name of the LORD, the God of Israel, in the islands of the sea!'),
  ('Isaiah', 24, 16, 'From the uttermost part of the earth have we heard songs. Glory to the righteous! But I said, “I pine away! I pine away! woe is me!” The treacherous have dealt treacherously. Yes, the treacherous have dealt very treacherously.'),
  ('Isaiah', 24, 17, 'Fear, the pit, and the snare are on you who inhabit the earth.'),
  ('Isaiah', 24, 18, 'It will happen that he who flees from the noise of the fear will fall into the pit; and he who comes up out of the middle of the pit will be taken in the snare; for the windows on high are opened, and the foundations of the earth tremble.'),
  ('Isaiah', 24, 19, 'The earth is utterly broken. The earth is torn apart. The earth is shaken violently.'),
  ('Isaiah', 24, 20, 'The earth will stagger like a drunken man, and will sway back and forth like a hammock. Its disobedience will be heavy on it, and it will fall and not rise again.'),
  ('Isaiah', 24, 21, 'It will happen in that day that the LORD will punish the army of the high ones on high, and the kings of the earth on the earth.'),
  ('Isaiah', 24, 22, 'They will be gathered together, as prisoners are gathered in the pit, and will be shut up in the prison; and after many days they will be visited.'),
  ('Isaiah', 24, 23, 'Then the moon will be confounded, and the sun ashamed; for the LORD of Armies will reign on Mount Zion and in Jerusalem; and glory will be before his elders.'),
  ('Isaiah', 25, 1, 'The LORD, you are my God. I will exalt you! I will praise your name, for you have done wonderful things, things planned long ago, in complete faithfulness and truth.'),
  ('Isaiah', 25, 2, 'For you have made a city into a heap, a fortified city into a ruin, a palace of strangers to be no city. It will never be built.'),
  ('Isaiah', 25, 3, 'Therefore a strong people will glorify you. A city of awesome nations will fear you.'),
  ('Isaiah', 25, 4, 'For you have been a stronghold to the poor, a stronghold to the needy in his distress, a refuge from the storm, a shade from the heat, when the blast of the dreaded ones is like a storm against the wall.'),
  ('Isaiah', 25, 5, 'As the heat in a dry place you will bring down the noise of strangers; as the heat by the shade of a cloud, the song of the dreaded ones will be brought low.'),
  ('Isaiah', 25, 6, 'In this mountain, the LORD of Armies will make all peoples a feast of choice meat, a feast of choice wines, of choice meat full of marrow, of well refined choice wines.'),
  ('Isaiah', 25, 7, 'He will destroy in this mountain the surface of the covering that covers all peoples, and the veil that is spread over all nations.'),
  ('Isaiah', 25, 8, 'He has swallowed up death forever! The Lord GOD will wipe away tears from off all faces. He will take the reproach of his people away from off all the earth, for the LORD has spoken it.'),
  ('Isaiah', 25, 9, 'It shall be said in that day, “Behold, this is our God! We have waited for him, and he will save us! This is the LORD! We have waited for him. We will be glad and rejoice in his salvation!”'),
  ('Isaiah', 25, 10, 'For the LORD’s hand will rest in this mountain. Moab will be trodden down in his place, even like straw is trodden down in the water of the dunghill.'),
  ('Isaiah', 25, 11, 'He will spread out his hands in the middle of it, like one who swims spreads out hands to swim, but his pride will be humbled together with the craft of his hands.'),
  ('Isaiah', 25, 12, 'He has brought the high fortress of your walls down, laid low, and brought to the ground, even to the dust.'),
  ('Isaiah', 26, 1, 'In that day, this song will be sung in the land of Judah: “We have a strong city. God appoints salvation for walls and bulwarks.'),
  ('Isaiah', 26, 2, 'Open the gates, that the righteous nation may enter: the one which keeps faith.'),
  ('Isaiah', 26, 3, 'You will keep whoever’s mind is steadfast in perfect peace, because he trusts in you.'),
  ('Isaiah', 26, 4, 'Trust in the LORD forever; for in the LORD, the LORD, is an everlasting Rock.'),
  ('Isaiah', 26, 5, 'For he has brought down those who dwell on high, the lofty city. He lays it low. He lays it low even to the ground. He brings it even to the dust.'),
  ('Isaiah', 26, 6, 'The foot shall tread it down, even the feet of the poor and the steps of the needy.”'),
  ('Isaiah', 26, 7, 'The way of the just is uprightness. You who are upright make the path of the righteous level.'),
  ('Isaiah', 26, 8, 'Yes, in the way of your judgments, LORD, we have waited for you. Your name and your renown are the desire of our soul.'),
  ('Isaiah', 26, 9, 'With my soul I have desired you in the night. Yes, with my spirit within me I will seek you earnestly; for when your judgments are in the earth, the inhabitants of the world learn righteousness.'),
  ('Isaiah', 26, 10, 'Let favor be shown to the wicked, yet he will not learn righteousness. In the land of uprightness he will deal wrongfully, and will not see the LORD’s majesty.'),
  ('Isaiah', 26, 11, 'LORD, your hand is lifted up, yet they don’t see; but they will see your zeal for the people and be disappointed. Yes, fire will consume your adversaries.'),
  ('Isaiah', 26, 12, 'LORD, you will ordain peace for us, for you have also done all our work for us.'),
  ('Isaiah', 26, 13, 'LORD our God, other lords besides you have had dominion over us, but we will only acknowledge your name.'),
  ('Isaiah', 26, 14, 'The dead shall not live. The departed spirits shall not rise. Therefore you have visited and destroyed them, and caused all memory of them to perish.'),
  ('Isaiah', 26, 15, 'You have increased the nation, O LORD. You have increased the nation! You are glorified! You have enlarged all the borders of the land.'),
  ('Isaiah', 26, 16, 'LORD, in trouble they have visited you. They poured out a prayer when your chastening was on them.'),
  ('Isaiah', 26, 17, 'Just as a woman with child, who draws near the time of her delivery, is in pain and cries out in her pangs, so we have been before you, LORD.'),
  ('Isaiah', 26, 18, 'We have been with child. We have been in pain. We gave birth, it seems, only to wind. We have not worked any deliverance in the earth; neither have the inhabitants of the world fallen.'),
  ('Isaiah', 26, 19, 'Your dead shall live. Their dead bodies shall arise. Awake and sing, you who dwell in the dust; for your dew is like the dew of herbs, and the earth will cast out the departed spirits.'),
  ('Isaiah', 26, 20, 'Come, my people, enter into your rooms, and shut your doors behind you. Hide yourself for a little moment, until the indignation is past.'),
  ('Isaiah', 26, 21, 'For, behold, the LORD comes out of his place to punish the inhabitants of the earth for their iniquity. The earth also will disclose her blood, and will no longer cover her slain.'),
  ('Isaiah', 27, 1, 'In that day, the LORD with his hard and great and strong sword will punish leviathan, the fleeing serpent, and leviathan, the twisted serpent; and he will kill the dragon that is in the sea.'),
  ('Isaiah', 27, 2, 'In that day, sing to her, “A pleasant vineyard!'),
  ('Isaiah', 27, 3, 'I, the LORD, am its keeper. I will water it every moment. Lest anyone damage it, I will keep it night and day.'),
  ('Isaiah', 27, 4, 'Wrath is not in me, but if I should find briers and thorns, I would do battle! I would march on them and I would burn them together.'),
  ('Isaiah', 27, 5, 'Or else let him take hold of my strength, that he may make peace with me. Let him make peace with me.”'),
  ('Isaiah', 27, 6, 'In days to come, Jacob will take root. Israel will blossom and bud. They will fill the surface of the world with fruit.'),
  ('Isaiah', 27, 7, 'Has he struck them as he struck those who struck them? Or are they killed like those who killed them were killed?'),
  ('Isaiah', 27, 8, 'In measure, when you send them away, you contend with them. He has removed them with his rough blast in the day of the east wind.'),
  ('Isaiah', 27, 9, 'Therefore by this the iniquity of Jacob will be forgiven, and this is all the fruit of taking away his sin: that he makes all the stones of the altar as chalk stones that are beaten in pieces, so that the Asherah poles and the incense altars shall rise no more.'),
  ('Isaiah', 27, 10, 'For the fortified city is solitary, a habitation deserted and forsaken, like the wilderness. The calf will feed there, and there he will lie down, and consume its branches.'),
  ('Isaiah', 27, 11, 'When its boughs are withered, they will be broken off. The women will come and set them on fire, for they are a people of no understanding. Therefore he who made them will not have compassion on them, and he who formed them will show them no favor.'),
  ('Isaiah', 27, 12, 'It will happen in that day that the LORD will thresh from the flowing stream of the Euphrates to the brook of Egypt; and you will be gathered one by one, children of Israel.'),
  ('Isaiah', 27, 13, 'It will happen in that day that a great trumpet will be blown; and those who were ready to perish in the land of Assyria, and those who were outcasts in the land of Egypt, shall come; and they will worship the LORD in the holy mountain at Jerusalem.'),
  ('Isaiah', 28, 1, 'Woe to the crown of pride of the drunkards of Ephraim, and to the fading flower of his glorious beauty, which is on the head of the fertile valley of those who are overcome with wine!'),
  ('Isaiah', 28, 2, 'Behold, the Lord has one who is mighty and strong. Like a storm of hail, a destroying storm, and like a storm of mighty waters overflowing, he will cast them down to the earth with his hand.'),
  ('Isaiah', 28, 3, 'The crown of pride of the drunkards of Ephraim will be trodden under foot.'),
  ('Isaiah', 28, 4, 'The fading flower of his glorious beauty, which is on the head of the fertile valley, shall be like the first-ripe fig before the summer, which someone picks and eats as soon as he sees it.'),
  ('Isaiah', 28, 5, 'In that day, the LORD of Armies will become a crown of glory and a diadem of beauty to the residue of his people,'),
  ('Isaiah', 28, 6, 'and a spirit of justice to him who sits in judgment, and strength to those who turn back the battle at the gate.'),
  ('Isaiah', 28, 7, 'They also reel with wine, and stagger with strong drink. The priest and the prophet reel with strong drink. They are swallowed up by wine. They stagger with strong drink. They err in vision. They stumble in judgment.'),
  ('Isaiah', 28, 8, 'For all tables are completely full of filthy vomit and filthiness.'),
  ('Isaiah', 28, 9, 'Whom will he teach knowledge? To whom will he explain the message? Those who are weaned from the milk, and drawn from the breasts?'),
  ('Isaiah', 28, 10, 'For it is precept on precept, precept on precept; line on line, line on line; here a little, there a little.'),
  ('Isaiah', 28, 11, 'But he will speak to this nation with stammering lips and in another language,'),
  ('Isaiah', 28, 12, 'to whom he said, “This is the resting place. Give rest to the weary,” and “This is the refreshing;” yet they would not hear.'),
  ('Isaiah', 28, 13, 'Therefore the LORD’s word will be to them precept on precept, precept on precept; line on line, line on line; here a little, there a little; that they may go, fall backward, be broken, be snared, and be taken.'),
  ('Isaiah', 28, 14, 'Therefore hear the LORD’s word, you scoffers, that rule this people in Jerusalem:'),
  ('Isaiah', 28, 15, '“Because you have said, ‘We have made a covenant with death, and we are in agreement with Sheol. When the overflowing scourge passes through, it won’t come to us; for we have made lies our refuge, and we have hidden ourselves under falsehood.’”'),
  ('Isaiah', 28, 16, 'Therefore the Lord GOD says, “Behold, I lay in Zion for a foundation a stone, a tried stone, a precious cornerstone of a sure foundation. He who believes shall not act hastily.'),
  ('Isaiah', 28, 17, 'I will make justice the measuring line, and righteousness the plumb line. The hail will sweep away the refuge of lies, and the waters will overflow the hiding place.'),
  ('Isaiah', 28, 18, 'Your covenant with death shall be annulled, and your agreement with Sheol shall not stand. When the overflowing scourge passes through, then you will be trampled down by it.'),
  ('Isaiah', 28, 19, 'As often as it passes through, it will seize you; for morning by morning it will pass through, by day and by night; and it will be nothing but terror to understand the message.”'),
  ('Isaiah', 28, 20, 'For the bed is too short to stretch out on, and the blanket is too narrow to wrap oneself in.'),
  ('Isaiah', 28, 21, 'For the LORD will rise up as on Mount Perazim. He will be angry as in the valley of Gibeon; that he may do his work, his unusual work, and bring to pass his act, his extraordinary act.'),
  ('Isaiah', 28, 22, 'Now therefore don’t be scoffers, lest your bonds be made strong; for I have heard a decree of destruction from the Lord, GOD of Armies, on the whole earth.'),
  ('Isaiah', 28, 23, 'Give ear, and hear my voice! Listen, and hear my speech!'),
  ('Isaiah', 28, 24, 'Does he who plows to sow plow continually? Does he keep turning the soil and breaking the clods?'),
  ('Isaiah', 28, 25, 'When he has leveled its surface, doesn’t he plant the dill, and scatter the cumin seed, and put in the wheat in rows, the barley in the appointed place, and the spelt in its place?'),
  ('Isaiah', 28, 26, 'For his God instructs him in right judgment and teaches him.'),
  ('Isaiah', 28, 27, 'For the dill isn’t threshed with a sharp instrument, neither is a cart wheel turned over the cumin; but the dill is beaten out with a stick, and the cumin with a rod.'),
  ('Isaiah', 28, 28, 'Bread flour must be ground; so he will not always be threshing it. Although he drives the wheel of his threshing cart over it, his horses don’t grind it.'),
  ('Isaiah', 28, 29, 'This also comes out from the LORD of Armies, who is wonderful in counsel, and excellent in wisdom.'),
  ('Isaiah', 29, 1, 'Woe to Ariel! Ariel, the city where David encamped! Add year to year; let the feasts come around;'),
  ('Isaiah', 29, 2, 'then I will distress Ariel, and there will be mourning and lamentation. She shall be to me as an altar hearth.'),
  ('Isaiah', 29, 3, 'I will encamp against you all around you, and will lay siege against you with posted troops. I will raise siege works against you.'),
  ('Isaiah', 29, 4, 'You will be brought down, and will speak out of the ground. Your speech will mumble out of the dust. Your voice will be as of one who has a familiar spirit, out of the ground, and your speech will whisper out of the dust.'),
  ('Isaiah', 29, 5, 'But the multitude of your foes will be like fine dust, and the multitude of the ruthless ones like chaff that blows away. Yes, it will be in an instant, suddenly.'),
  ('Isaiah', 29, 6, 'She will be visited by the LORD of Armies with thunder, with earthquake, with great noise, with whirlwind and storm, and with the flame of a devouring fire.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 29, 7, 'The multitude of all the nations that fight against Ariel, even all who fight against her and her stronghold, and who distress her, will be like a dream, a vision of the night.'),
  ('Isaiah', 29, 8, 'It will be like when a hungry man dreams, and behold, he eats; but he awakes, and his hunger isn’t satisfied; or like when a thirsty man dreams, and behold, he drinks; but he awakes, and behold, he is faint, and he is still thirsty. The multitude of all the nations that fight against Mount Zion will be like that.'),
  ('Isaiah', 29, 9, 'Pause and wonder! Blind yourselves and be blind! They are drunken, but not with wine; they stagger, but not with strong drink.'),
  ('Isaiah', 29, 10, 'For the LORD has poured out on you a spirit of deep sleep, and has closed your eyes, the prophets; and he has covered your heads, the seers.'),
  ('Isaiah', 29, 11, 'All vision has become to you like the words of a book that is sealed, which men deliver to one who is educated, saying, “Read this, please;” and he says, “I can’t, for it is sealed;”'),
  ('Isaiah', 29, 12, 'and the book is delivered to one who is not educated, saying, “Read this, please;” and he says, “I can’t read.”'),
  ('Isaiah', 29, 13, 'The Lord said, “Because this people draws near with their mouth and honors me with their lips, but they have removed their heart far from me, and their fear of me is a commandment of men which has been taught;'),
  ('Isaiah', 29, 14, 'therefore, behold, I will proceed to do a marvelous work among this people, even a marvelous work and a wonder; and the wisdom of their wise men will perish, and the understanding of their prudent men will be hidden.”'),
  ('Isaiah', 29, 15, 'Woe to those who deeply hide their counsel from the LORD, and whose deeds are in the dark, and who say, “Who sees us?” and “Who knows us?”'),
  ('Isaiah', 29, 16, 'You turn things upside down! Should the potter be thought to be like clay, that the thing made should say about him who made it, “He didn’t make me;” or the thing formed say of him who formed it, “He has no understanding”?'),
  ('Isaiah', 29, 17, 'Isn’t it yet a very little while, and Lebanon will be turned into a fruitful field, and the fruitful field will be regarded as a forest?'),
  ('Isaiah', 29, 18, 'In that day, the deaf will hear the words of the book, and the eyes of the blind will see out of obscurity and out of darkness.'),
  ('Isaiah', 29, 19, 'The humble also will increase their joy in the LORD, and the poor among men will rejoice in the Holy One of Israel.'),
  ('Isaiah', 29, 20, 'For the ruthless is brought to nothing, and the scoffer ceases, and all those who are alert to do evil are cut off—'),
  ('Isaiah', 29, 21, 'who cause a person to be indicted by a word, and lay a snare for one who reproves in the gate, and who deprive the innocent of justice with false testimony.'),
  ('Isaiah', 29, 22, 'Therefore the LORD, who redeemed Abraham, says concerning the house of Jacob: “Jacob shall no longer be ashamed, neither shall his face grow pale.'),
  ('Isaiah', 29, 23, 'But when he sees his children, the work of my hands, in the middle of him, they will sanctify my name. Yes, they will sanctify the Holy One of Jacob, and will stand in awe of the God of Israel.'),
  ('Isaiah', 29, 24, 'They also who err in spirit will come to understanding, and those who grumble will receive instruction.”'),
  ('Isaiah', 30, 1, '“Woe to the rebellious children”, says the LORD, “who take counsel, but not from me; and who make an alliance, but not with my Spirit, that they may add sin to sin;'),
  ('Isaiah', 30, 2, 'who set out to go down into Egypt without asking for my advice, to strengthen themselves in the strength of Pharaoh, and to take refuge in the shadow of Egypt!'),
  ('Isaiah', 30, 3, 'Therefore the strength of Pharaoh will be your shame, and the refuge in the shadow of Egypt your confusion.'),
  ('Isaiah', 30, 4, 'For their princes are at Zoan, and their ambassadors have come to Hanes.'),
  ('Isaiah', 30, 5, 'They shall all be ashamed because of a people that can’t profit them, that are not a help nor profit, but a shame, and also a reproach.”'),
  ('Isaiah', 30, 6, 'The burden of the animals of the South. Through the land of trouble and anguish, of the lioness and the lion, the viper and fiery flying serpent, they carry their riches on the shoulders of young donkeys, and their treasures on the humps of camels, to an unprofitable people.'),
  ('Isaiah', 30, 7, 'For Egypt helps in vain, and to no purpose; therefore I have called her Rahab who sits still.'),
  ('Isaiah', 30, 8, 'Now go, write it before them on a tablet, and inscribe it in a book, that it may be for the time to come forever and ever.'),
  ('Isaiah', 30, 9, 'For it is a rebellious people, lying children, children who will not hear the LORD’s law;'),
  ('Isaiah', 30, 10, 'who tell the seers, “Don’t see!” and the prophets, “Don’t prophesy to us right things. Tell us pleasant things. Prophesy deceits.'),
  ('Isaiah', 30, 11, 'Get out of the way. Turn away from the path. Cause the Holy One of Israel to cease from before us.”'),
  ('Isaiah', 30, 12, 'Therefore the Holy One of Israel says, “Because you despise this word, and trust in oppression and perverseness, and rely on it,'),
  ('Isaiah', 30, 13, 'therefore this iniquity shall be to you like a breach ready to fall, swelling out in a high wall, whose breaking comes suddenly in an instant.'),
  ('Isaiah', 30, 14, 'He will break it as a potter’s vessel is broken, breaking it in pieces without sparing, so that there won’t be found among the broken pieces a piece good enough to take fire from the hearth, or to dip up water out of the cistern.”'),
  ('Isaiah', 30, 15, 'For thus said the Lord GOD, the Holy One of Israel, “You will be saved in returning and rest. Your strength will be in quietness and in confidence.” You refused,'),
  ('Isaiah', 30, 16, 'but you said, “No, for we will flee on horses;” therefore you will flee; and, “We will ride on the swift;” therefore those who pursue you will be swift.'),
  ('Isaiah', 30, 17, 'One thousand will flee at the threat of one. At the threat of five, you will flee until you are left like a beacon on the top of a mountain, and like a banner on a hill.'),
  ('Isaiah', 30, 18, 'Therefore the LORD will wait, that he may be gracious to you; and therefore he will be exalted, that he may have mercy on you, for the LORD is a God of justice. Blessed are all those who wait for him.'),
  ('Isaiah', 30, 19, 'For the people will dwell in Zion at Jerusalem. You will weep no more. He will surely be gracious to you at the voice of your cry. When he hears you, he will answer you.'),
  ('Isaiah', 30, 20, 'Though the Lord may give you the bread of adversity and the water of affliction, yet your teachers won’t be hidden any more, but your eyes will see your teachers;'),
  ('Isaiah', 30, 21, 'and when you turn to the right hand, and when you turn to the left, your ears will hear a voice behind you, saying, “This is the way. Walk in it.”'),
  ('Isaiah', 30, 22, 'You shall defile the overlaying of your engraved images of silver, and the plating of your molten images of gold. You shall cast them away as an unclean thing. You shall tell it, “Go away!”'),
  ('Isaiah', 30, 23, 'He will give the rain for your seed, with which you will sow the ground; and bread of the increase of the ground will be rich and plentiful. In that day, your livestock will feed in large pastures.'),
  ('Isaiah', 30, 24, 'The oxen likewise and the young donkeys that till the ground will eat savory feed, which has been winnowed with the shovel and with the fork.'),
  ('Isaiah', 30, 25, 'There will be brooks and streams of water on every lofty mountain and on every high hill in the day of the great slaughter, when the towers fall.'),
  ('Isaiah', 30, 26, 'Moreover the light of the moon will be like the light of the sun, and the light of the sun will be seven times brighter, like the light of seven days, in the day that the LORD binds up the fracture of his people, and heals the wound they were struck with.'),
  ('Isaiah', 30, 27, 'Behold, the LORD’s name comes from far away, burning with his anger, and in thick rising smoke. His lips are full of indignation. His tongue is as a devouring fire.'),
  ('Isaiah', 30, 28, 'His breath is as an overflowing stream that reaches even to the neck, to sift the nations with the sieve of destruction. A bridle that leads to ruin will be in the jaws of the peoples.'),
  ('Isaiah', 30, 29, 'You will have a song, as in the night when a holy feast is kept, and gladness of heart, as when one goes with a flute to come to the LORD’s mountain, to Israel’s Rock.'),
  ('Isaiah', 30, 30, 'The LORD will cause his glorious voice to be heard, and will show the descent of his arm, with the indignation of his anger and the flame of a devouring fire, with a blast, storm, and hailstones.'),
  ('Isaiah', 30, 31, 'For through the LORD’s voice the Assyrian will be dismayed. He will strike him with his rod.'),
  ('Isaiah', 30, 32, 'Every stroke of the rod of punishment, which the LORD will lay on him, will be with the sound of tambourines and harps. He will fight with them in battles, brandishing weapons.'),
  ('Isaiah', 30, 33, 'For his burning place has long been ready. Yes, it is prepared for the king. He has made its pyre deep and large with fire and much wood. The LORD’s breath, like a stream of sulfur, kindles it.'),
  ('Isaiah', 31, 1, 'Woe to those who go down to Egypt for help, and rely on horses, and trust in chariots because they are many, and in horsemen because they are very strong, but they don’t look to the Holy One of Israel, and they don’t seek the LORD!'),
  ('Isaiah', 31, 2, 'Yet he also is wise, and will bring disaster, and will not call back his words, but will arise against the house of the evildoers, and against the help of those who work iniquity.'),
  ('Isaiah', 31, 3, 'Now the Egyptians are men, and not God; and their horses flesh, and not spirit. When the LORD stretches out his hand, both he who helps shall stumble, and he who is helped shall fall, and they all shall be consumed together.'),
  ('Isaiah', 31, 4, 'For the LORD says to me, “As the lion and the young lion growling over his prey, if a multitude of shepherds is called together against him, will not be dismayed at their voice, nor abase himself for their noise, so the LORD of Armies will come down to fight on Mount Zion and on its heights.'),
  ('Isaiah', 31, 5, 'As birds hovering, so the LORD of Armies will protect Jerusalem. He will protect and deliver it. He will pass over and preserve it.”'),
  ('Isaiah', 31, 6, 'Return to him from whom you have deeply revolted, children of Israel.'),
  ('Isaiah', 31, 7, 'For in that day everyone shall cast away his idols of silver and his idols of gold—sin which your own hands have made for you.'),
  ('Isaiah', 31, 8, '“The Assyrian will fall by the sword, not of man; and the sword, not of mankind, shall devour him. He will flee from the sword, and his young men will become subject to forced labor.'),
  ('Isaiah', 31, 9, 'His rock will pass away by reason of terror, and his princes will be afraid of the banner,” says the LORD, whose fire is in Zion, and his furnace in Jerusalem.'),
  ('Isaiah', 32, 1, 'Behold, a king shall reign in righteousness, and princes shall rule in justice.'),
  ('Isaiah', 32, 2, 'A man shall be as a hiding place from the wind, and a covert from the storm, as streams of water in a dry place, as the shade of a large rock in a weary land.'),
  ('Isaiah', 32, 3, 'The eyes of those who see will not be dim, and the ears of those who hear will listen.'),
  ('Isaiah', 32, 4, 'The heart of the rash will understand knowledge, and the tongue of the stammerers will be ready to speak plainly.'),
  ('Isaiah', 32, 5, 'The fool will no longer be called noble, nor the scoundrel be highly respected.'),
  ('Isaiah', 32, 6, 'For the fool will speak folly, and his heart will work iniquity, to practice profanity, and to utter error against the LORD, to make empty the soul of the hungry, and to cause the drink of the thirsty to fail.'),
  ('Isaiah', 32, 7, 'The ways of the scoundrel are evil. He devises wicked plans to destroy the humble with lying words, even when the needy speaks right.'),
  ('Isaiah', 32, 8, 'But the noble devises noble things, and he will continue in noble things.'),
  ('Isaiah', 32, 9, 'Rise up, you women who are at ease! Hear my voice! You careless daughters, give ear to my speech!'),
  ('Isaiah', 32, 10, 'For days beyond a year you will be troubled, you careless women; for the vintage will fail. The harvest won’t come.'),
  ('Isaiah', 32, 11, 'Tremble, you women who are at ease! Be troubled, you careless ones! Strip yourselves, make yourselves naked, and put sackcloth on your waist.'),
  ('Isaiah', 32, 12, 'Beat your breasts for the pleasant fields, for the fruitful vine.'),
  ('Isaiah', 32, 13, 'Thorns and briers will come up on my people’s land; yes, on all the houses of joy in the joyous city.'),
  ('Isaiah', 32, 14, 'For the palace will be forsaken. The populous city will be deserted. The hill and the watchtower will be for dens forever, a delight for wild donkeys, a pasture of flocks,'),
  ('Isaiah', 32, 15, 'until the Spirit is poured on us from on high, and the wilderness becomes a fruitful field, and the fruitful field is considered a forest.'),
  ('Isaiah', 32, 16, 'Then justice will dwell in the wilderness; and righteousness will remain in the fruitful field.'),
  ('Isaiah', 32, 17, 'The work of righteousness will be peace, and the effect of righteousness, quietness and confidence forever.'),
  ('Isaiah', 32, 18, 'My people will live in a peaceful habitation, in safe dwellings, and in quiet resting places,'),
  ('Isaiah', 32, 19, 'though hail flattens the forest, and the city is leveled completely.'),
  ('Isaiah', 32, 20, 'Blessed are you who sow beside all waters, who send out the feet of the ox and the donkey.'),
  ('Isaiah', 33, 1, 'Woe to you who destroy, but you weren’t destroyed, and who betray, but nobody betrayed you! When you have finished destroying, you will be destroyed; and when you have finished betrayal, you will be betrayed.'),
  ('Isaiah', 33, 2, 'LORD, be gracious to us. We have waited for you. Be our strength every morning, our salvation also in the time of trouble.'),
  ('Isaiah', 33, 3, 'At the noise of the thunder, the peoples have fled. When you lift yourself up, the nations are scattered.'),
  ('Isaiah', 33, 4, 'Your plunder will be gathered as the caterpillar gathers. Men will leap on it as locusts leap.'),
  ('Isaiah', 33, 5, 'The LORD is exalted, for he dwells on high. He has filled Zion with justice and righteousness.'),
  ('Isaiah', 33, 6, 'There will be stability in your times, abundance of salvation, wisdom, and knowledge. The fear of the LORD is your treasure.'),
  ('Isaiah', 33, 7, 'Behold, their valiant ones cry outside; the ambassadors of peace weep bitterly.'),
  ('Isaiah', 33, 8, 'The highways are desolate. The traveling man ceases. The covenant is broken. He has despised the cities. He doesn’t respect man.'),
  ('Isaiah', 33, 9, 'The land mourns and languishes. Lebanon is confounded and withers away. Sharon is like a desert, and Bashan and Carmel are stripped bare.'),
  ('Isaiah', 33, 10, '“Now I will arise,” says the LORD. “Now I will lift myself up. Now I will be exalted.'),
  ('Isaiah', 33, 11, 'You will conceive chaff. You will give birth to stubble. Your breath is a fire that will devour you.'),
  ('Isaiah', 33, 12, 'The peoples will be like the burning of lime, like thorns that are cut down and burned in the fire.'),
  ('Isaiah', 33, 13, 'Hear, you who are far off, what I have done; and, you who are near, acknowledge my might.”'),
  ('Isaiah', 33, 14, 'The sinners in Zion are afraid. Trembling has seized the godless ones. Who among us can live with the devouring fire? Who among us can live with everlasting burning?'),
  ('Isaiah', 33, 15, 'He who walks righteously and speaks blamelessly, he who despises the gain of oppressions, who gestures with his hands, refusing to take a bribe, who stops his ears from hearing of bloodshed, and shuts his eyes from looking at evil—'),
  ('Isaiah', 33, 16, 'he will dwell on high. His place of defense will be the fortress of rocks. His bread will be supplied. His waters will be sure.'),
  ('Isaiah', 33, 17, 'Your eyes will see the king in his beauty. They will see a distant land.'),
  ('Isaiah', 33, 18, 'Your heart will meditate on the terror. Where is he who counted? Where is he who weighed? Where is he who counted the towers?'),
  ('Isaiah', 33, 19, 'You will no longer see the fierce people, a people of a deep speech that you can’t comprehend, with a strange language that you can’t understand.'),
  ('Isaiah', 33, 20, 'Look at Zion, the city of our appointed festivals. Your eyes will see Jerusalem, a quiet habitation, a tent that won’t be removed. Its stakes will never be plucked up, nor will any of its cords be broken.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 33, 21, 'But there the LORD will be with us in majesty, a place of wide rivers and streams, in which no galley with oars will go, neither will any gallant ship pass by there.'),
  ('Isaiah', 33, 22, 'For the LORD is our judge. The LORD is our lawgiver. The LORD is our king. He will save us.'),
  ('Isaiah', 33, 23, 'Your rigging is untied. They couldn’t strengthen the foot of their mast. They couldn’t spread the sail. Then the prey of a great plunder was divided. The lame took the prey.'),
  ('Isaiah', 33, 24, 'The inhabitant won’t say, “I am sick.” The people who dwell therein will be forgiven their iniquity.'),
  ('Isaiah', 34, 1, 'Come near, you nations, to hear! Listen, you peoples. Let the earth and all it contains hear, the world, and everything that comes from it.'),
  ('Isaiah', 34, 2, 'For the LORD is enraged against all the nations, and angry with all their armies. He has utterly destroyed them. He has given them over for slaughter.'),
  ('Isaiah', 34, 3, 'Their slain will also be cast out, and the stench of their dead bodies will come up. The mountains will melt in their blood.'),
  ('Isaiah', 34, 4, 'All of the army of the sky will be dissolved. The sky will be rolled up like a scroll, and all its armies will fade away, as a leaf fades from off a vine or a fig tree.'),
  ('Isaiah', 34, 5, 'For my sword has drunk its fill in the sky. Behold, it will come down on Edom, and on the people of my curse, for judgment.'),
  ('Isaiah', 34, 6, 'The LORD’s sword is filled with blood. It is covered with fat, with the blood of lambs and goats, with the fat of the kidneys of rams; for the LORD has a sacrifice in Bozrah, and a great slaughter in the land of Edom.'),
  ('Isaiah', 34, 7, 'The wild oxen will come down with them, and the young bulls with the mighty bulls; and their land will be drunken with blood, and their dust made greasy with fat.'),
  ('Isaiah', 34, 8, 'For the LORD has a day of vengeance, a year of recompense for the cause of Zion.'),
  ('Isaiah', 34, 9, 'Its streams will be turned into pitch, its dust into sulfur, and its land will become burning pitch.'),
  ('Isaiah', 34, 10, 'It won’t be quenched night or day. Its smoke will go up forever. From generation to generation, it will lie waste. No one will pass through it forever and ever.'),
  ('Isaiah', 34, 11, 'But the pelican and the porcupine will possess it. The owl and the raven will dwell in it. He will stretch the line of confusion over it, and the plumb line of emptiness.'),
  ('Isaiah', 34, 12, 'They shall call its nobles to the kingdom, but none shall be there; and all its princes shall be nothing.'),
  ('Isaiah', 34, 13, 'Thorns will come up in its palaces, nettles and thistles in its fortresses; and it will be a habitation of jackals, a court for ostriches.'),
  ('Isaiah', 34, 14, 'The wild animals of the desert will meet with the wolves, and the wild goat will cry to his fellow. Yes, the night creature shall settle there, and shall find herself a place of rest.'),
  ('Isaiah', 34, 15, 'The arrow snake will make her nest there, and lay, hatch, and gather under her shade. Yes, the kites will be gathered there, every one with her mate.'),
  ('Isaiah', 34, 16, 'Search in the book of the LORD, and read: not one of these will be missing. None will lack her mate. For my mouth has commanded, and his Spirit has gathered them.'),
  ('Isaiah', 34, 17, 'He has cast the lot for them, and his hand has divided it to them with a measuring line. They shall possess it forever. From generation to generation they will dwell in it.'),
  ('Isaiah', 35, 1, 'The wilderness and the dry land will be glad. The desert will rejoice and blossom like a rose.'),
  ('Isaiah', 35, 2, 'It will blossom abundantly, and rejoice even with joy and singing. Lebanon’s glory will be given to it, the excellence of Carmel and Sharon. They will see the LORD’s glory, the excellence of our God.'),
  ('Isaiah', 35, 3, 'Strengthen the weak hands, and make the feeble knees firm.'),
  ('Isaiah', 35, 4, 'Tell those who have a fearful heart, “Be strong! Don’t be afraid! Behold, your God will come with vengeance, God’s retribution. He will come and save you.'),
  ('Isaiah', 35, 5, 'Then the eyes of the blind will be opened, and the ears of the deaf will be unstopped.'),
  ('Isaiah', 35, 6, 'Then the lame man will leap like a deer, and the tongue of the mute will sing; for waters will break out in the wilderness, and streams in the desert.'),
  ('Isaiah', 35, 7, 'The burning sand will become a pool, and the thirsty ground springs of water. Grass with reeds and rushes will be in the habitation of jackals, where they lay.'),
  ('Isaiah', 35, 8, 'A highway will be there, a road, and it will be called “The Holy Way”. The unclean shall not pass over it, but it will be for those who walk in the Way. Wicked fools shall not go there.'),
  ('Isaiah', 35, 9, 'No lion will be there, nor will any ravenous animal go up on it. They will not be found there; but the redeemed will walk there.'),
  ('Isaiah', 35, 10, 'Then the LORD’s ransomed ones will return, and come with singing to Zion; and everlasting joy will be on their heads. They will obtain gladness and joy, and sorrow and sighing will flee away.”'),
  ('Isaiah', 36, 1, 'Now in the fourteenth year of King Hezekiah, Sennacherib king of Assyria attacked all of the fortified cities of Judah and captured them.'),
  ('Isaiah', 36, 2, 'The king of Assyria sent Rabshakeh from Lachish to Jerusalem to King Hezekiah with a large army. He stood by the aqueduct from the upper pool in the fuller’s field highway.'),
  ('Isaiah', 36, 3, 'Then Eliakim the son of Hilkiah, who was over the household, and Shebna the scribe, and Joah, the son of Asaph the recorder came out to him.'),
  ('Isaiah', 36, 4, 'Rabshakeh said to them, “Now tell Hezekiah, ‘The great king, the king of Assyria, says, “What confidence is this in which you trust?'),
  ('Isaiah', 36, 5, 'I say that your counsel and strength for the war are only vain words. Now in whom do you trust, that you have rebelled against me?'),
  ('Isaiah', 36, 6, 'Behold, you trust in the staff of this bruised reed, even in Egypt, which if a man leans on it, it will go into his hand and pierce it. So is Pharaoh king of Egypt to all who trust in him.'),
  ('Isaiah', 36, 7, 'But if you tell me, ‘We trust in the LORD our God,’ isn’t that he whose high places and whose altars Hezekiah has taken away, and has said to Judah and to Jerusalem, ‘You shall worship before this altar’?”'),
  ('Isaiah', 36, 8, 'Now therefore, please make a pledge to my master the king of Assyria, and I will give you two thousand horses, if you are able on your part to set riders on them.'),
  ('Isaiah', 36, 9, 'How then can you turn away the face of one captain of the least of my master’s servants, and put your trust in Egypt for chariots and for horsemen?'),
  ('Isaiah', 36, 10, 'Have I come up now without the LORD against this land to destroy it? The LORD said to me, “Go up against this land, and destroy it.”’”'),
  ('Isaiah', 36, 11, 'Then Eliakim, Shebna and Joah said to Rabshakeh, “Please speak to your servants in Aramaic, for we understand it. Don’t speak to us in the Jews’ language in the hearing of the people who are on the wall.”'),
  ('Isaiah', 36, 12, 'But Rabshakeh said, “Has my master sent me only to your master and to you, to speak these words, and not to the men who sit on the wall, who will eat their own dung and drink their own urine with you?”'),
  ('Isaiah', 36, 13, 'Then Rabshakeh stood, and called out with a loud voice in the Jews’ language, and said, “Hear the words of the great king, the king of Assyria!'),
  ('Isaiah', 36, 14, 'The king says, ‘Don’t let Hezekiah deceive you; for he will not be able to deliver you.'),
  ('Isaiah', 36, 15, 'Don’t let Hezekiah make you trust in the LORD, saying, “The LORD will surely deliver us. This city won’t be given into the hand of the king of Assyria.”’'),
  ('Isaiah', 36, 16, 'Don’t listen to Hezekiah, for the king of Assyria says, ‘Make your peace with me, and come out to me; and each of you eat from his vine, and each one from his fig tree, and each one of you drink the waters of his own cistern;'),
  ('Isaiah', 36, 17, 'until I come and take you away to a land like your own land, a land of grain and new wine, a land of bread and vineyards.'),
  ('Isaiah', 36, 18, 'Beware lest Hezekiah persuade you, saying, “The LORD will deliver us.” Have any of the gods of the nations delivered their lands from the hand of the king of Assyria?'),
  ('Isaiah', 36, 19, 'Where are the gods of Hamath and Arpad? Where are the gods of Sepharvaim? Have they delivered Samaria from my hand?'),
  ('Isaiah', 36, 20, 'Who are they among all the gods of these countries that have delivered their country out of my hand, that the LORD should deliver Jerusalem out of my hand?’”'),
  ('Isaiah', 36, 21, 'But they remained silent, and said nothing in reply, for the king’s commandment was, “Don’t answer him.”'),
  ('Isaiah', 36, 22, 'Then Eliakim the son of Hilkiah, who was over the household, and Shebna the scribe, and Joah, the son of Asaph the recorder, came to Hezekiah with their clothes torn, and told him the words of Rabshakeh.'),
  ('Isaiah', 37, 1, 'When King Hezekiah heard it, he tore his clothes, covered himself with sackcloth, and went into the LORD’s house.'),
  ('Isaiah', 37, 2, 'He sent Eliakim, who was over the household, and Shebna the scribe, and the elders of the priests, covered with sackcloth, to Isaiah the prophet, the son of Amoz.'),
  ('Isaiah', 37, 3, 'They said to him, “Hezekiah says, ‘Today is a day of trouble, and of rebuke, and of rejection; for the children have come to the birth, and there is no strength to give birth.'),
  ('Isaiah', 37, 4, 'It may be the LORD your God will hear the words of Rabshakeh, whom the king of Assyria his master has sent to defy the living God, and will rebuke the words which the LORD your God has heard. Therefore lift up your prayer for the remnant that is left.’”'),
  ('Isaiah', 37, 5, 'So the servants of King Hezekiah came to Isaiah.'),
  ('Isaiah', 37, 6, 'Isaiah said to them, “Tell your master, ‘The LORD says, “Don’t be afraid of the words that you have heard, with which the servants of the king of Assyria have blasphemed me.'),
  ('Isaiah', 37, 7, 'Behold, I will put a spirit in him and he will hear news, and will return to his own land. I will cause him to fall by the sword in his own land.”’”'),
  ('Isaiah', 37, 8, 'So Rabshakeh returned, and found the king of Assyria warring against Libnah, for he heard that he had departed from Lachish.'),
  ('Isaiah', 37, 9, 'He heard news concerning Tirhakah king of Ethiopia, “He has come out to fight against you.” When he heard it, he sent messengers to Hezekiah, saying,'),
  ('Isaiah', 37, 10, '“Thus you shall speak to Hezekiah king of Judah, saying, ‘Don’t let your God in whom you trust deceive you, saying, “Jerusalem won’t be given into the hand of the king of Assyria.”'),
  ('Isaiah', 37, 11, 'Behold, you have heard what the kings of Assyria have done to all lands, by destroying them utterly. Shall you be delivered?'),
  ('Isaiah', 37, 12, 'Have the gods of the nations delivered them, which my fathers have destroyed, Gozan, Haran, Rezeph, and the children of Eden who were in Telassar?'),
  ('Isaiah', 37, 13, 'Where is the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, of Hena, and Ivvah?’”'),
  ('Isaiah', 37, 14, 'Hezekiah received the letter from the hand of the messengers and read it. Then Hezekiah went up to the LORD’s house, and spread it before the LORD.'),
  ('Isaiah', 37, 15, 'Hezekiah prayed to the LORD, saying,'),
  ('Isaiah', 37, 16, '“LORD of Armies, the God of Israel, who is enthroned among the cherubim, you are the God, even you alone, of all the kingdoms of the earth. You have made heaven and earth.'),
  ('Isaiah', 37, 17, 'Turn your ear, LORD, and hear. Open your eyes, LORD, and behold. Hear all of the words of Sennacherib, who has sent to defy the living God.'),
  ('Isaiah', 37, 18, 'Truly, LORD, the kings of Assyria have destroyed all the countries and their land,'),
  ('Isaiah', 37, 19, 'and have cast their gods into the fire; for they were no gods, but the work of men’s hands, wood and stone; therefore they have destroyed them.'),
  ('Isaiah', 37, 20, 'Now therefore, LORD our God, save us from his hand, that all the kingdoms of the earth may know that you are the LORD, even you only.”'),
  ('Isaiah', 37, 21, 'Then Isaiah the son of Amoz sent to Hezekiah, saying, “The LORD, the God of Israel says, ‘Because you have prayed to me against Sennacherib king of Assyria,'),
  ('Isaiah', 37, 22, 'this is the word which the LORD has spoken concerning him: The virgin daughter of Zion has despised you and ridiculed you. The daughter of Jerusalem has shaken her head at you.'),
  ('Isaiah', 37, 23, 'Whom have you defied and blasphemed? Against whom have you exalted your voice and lifted up your eyes on high? Against the Holy One of Israel.'),
  ('Isaiah', 37, 24, 'By your servants, you have defied the Lord, and have said, “With the multitude of my chariots I have come up to the height of the mountains, to the innermost parts of Lebanon. I will cut down its tall cedars and its choice cypress trees. I will enter into its farthest height, the forest of its fruitful field.'),
  ('Isaiah', 37, 25, 'I have dug and drunk water, and with the sole of my feet I will dry up all the rivers of Egypt.”'),
  ('Isaiah', 37, 26, '“‘Have you not heard how I have done it long ago, and formed it in ancient times? Now I have brought it to pass, that it should be yours to destroy fortified cities, turning them into ruinous heaps.'),
  ('Isaiah', 37, 27, 'Therefore their inhabitants had little power. They were dismayed and confounded. They were like the grass of the field, and like the green herb, like the grass on the housetops, and like a field before its crop has grown.'),
  ('Isaiah', 37, 28, 'But I know your sitting down, your going out, your coming in, and your raging against me.'),
  ('Isaiah', 37, 29, 'Because of your raging against me, and because your arrogance has come up into my ears, therefore I will put my hook in your nose and my bridle in your lips, and I will turn you back by the way by which you came.'),
  ('Isaiah', 37, 30, '“‘This shall be the sign to you: You will eat this year that which grows of itself, and in the second year that which springs from it; and in the third year sow and reap and plant vineyards, and eat their fruit.'),
  ('Isaiah', 37, 31, 'The remnant that is escaped of the house of Judah will again take root downward, and bear fruit upward.'),
  ('Isaiah', 37, 32, 'For out of Jerusalem a remnant will go out, and survivors will escape from Mount Zion. The zeal of the LORD of Armies will perform this.’'),
  ('Isaiah', 37, 33, '“Therefore the LORD says concerning the king of Assyria, ‘He will not come to this city, nor shoot an arrow there, neither will he come before it with shield, nor cast up a mound against it.'),
  ('Isaiah', 37, 34, 'He will return the way that he came, and he won’t come to this city,’ says the LORD.'),
  ('Isaiah', 37, 35, '‘For I will defend this city to save it, for my own sake, and for my servant David’s sake.’”'),
  ('Isaiah', 37, 36, 'Then the LORD’s angel went out and struck one hundred and eighty-five thousand men in the camp of the Assyrians. When men arose early in the morning, behold, these were all dead bodies.'),
  ('Isaiah', 37, 37, 'So Sennacherib king of Assyria departed, went away, returned to Nineveh, and stayed there.'),
  ('Isaiah', 37, 38, 'As he was worshiping in the house of Nisroch his god, Adrammelech and Sharezer his sons struck him with the sword; and they escaped into the land of Ararat. Esar Haddon his son reigned in his place.'),
  ('Isaiah', 38, 1, 'In those days Hezekiah was sick and near death. Isaiah the prophet, the son of Amoz, came to him, and said to him, “The LORD says, ‘Set your house in order, for you will die, and not live.’”'),
  ('Isaiah', 38, 2, 'Then Hezekiah turned his face to the wall and prayed to the LORD,'),
  ('Isaiah', 38, 3, 'and said, “Remember now, LORD, I beg you, how I have walked before you in truth and with a perfect heart, and have done that which is good in your sight.” Then Hezekiah wept bitterly.'),
  ('Isaiah', 38, 4, 'Then the LORD’s word came to Isaiah, saying,'),
  ('Isaiah', 38, 5, '“Go, and tell Hezekiah, ‘The LORD, the God of David your father, says, “I have heard your prayer. I have seen your tears. Behold, I will add fifteen years to your life.'),
  ('Isaiah', 38, 6, 'I will deliver you and this city out of the hand of the king of Assyria, and I will defend this city.'),
  ('Isaiah', 38, 7, 'This shall be the sign to you from the LORD, that the LORD will do this thing that he has spoken.'),
  ('Isaiah', 38, 8, 'Behold, I will cause the shadow on the sundial, which has gone down on the sundial of Ahaz with the sun, to return backward ten steps.”’” So the sun returned ten steps on the sundial on which it had gone down.'),
  ('Isaiah', 38, 9, 'The writing of Hezekiah king of Judah, when he had been sick, and had recovered of his sickness:');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 38, 10, 'I said, “In the middle of my life I go into the gates of Sheol. I am deprived of the residue of my years.”'),
  ('Isaiah', 38, 11, 'I said, “I won’t see the LORD, the LORD in the land of the living. I will see man no more with the inhabitants of the world.'),
  ('Isaiah', 38, 12, 'My dwelling is removed, and is carried away from me like a shepherd’s tent. I have rolled up my life like a weaver. He will cut me off from the loom. From day even to night you will make an end of me.'),
  ('Isaiah', 38, 13, 'I waited patiently until morning. He breaks all my bones like a lion. From day even to night you will make an end of me.'),
  ('Isaiah', 38, 14, 'I chattered like a swallow or a crane. I moaned like a dove. My eyes weaken looking upward. Lord, I am oppressed. Be my security.”'),
  ('Isaiah', 38, 15, 'What will I say? He has both spoken to me, and himself has done it. I will walk carefully all my years because of the anguish of my soul.'),
  ('Isaiah', 38, 16, 'Lord, men live by these things; and my spirit finds life in all of them. You restore me, and cause me to live.'),
  ('Isaiah', 38, 17, 'Behold, for peace I had great anguish, but you have in love for my soul delivered it from the pit of corruption; for you have cast all my sins behind your back.'),
  ('Isaiah', 38, 18, 'For Sheol can’t praise you. Death can’t celebrate you. Those who go down into the pit can’t hope for your truth.'),
  ('Isaiah', 38, 19, 'The living, the living, he shall praise you, as I do today. The father shall make known your truth to the children.'),
  ('Isaiah', 38, 20, 'The LORD will save me. Therefore we will sing my songs with stringed instruments all the days of our life in the LORD’s house.'),
  ('Isaiah', 38, 21, 'Now Isaiah had said, “Let them take a cake of figs, and lay it for a poultice on the boil, and he shall recover.”'),
  ('Isaiah', 38, 22, 'Hezekiah also had said, “What is the sign that I will go up to the LORD’s house?”'),
  ('Isaiah', 39, 1, 'At that time, Merodach-baladan the son of Baladan, king of Babylon, sent letters and a present to Hezekiah, for he heard that he had been sick, and had recovered.'),
  ('Isaiah', 39, 2, 'Hezekiah was pleased with them, and showed them the house of his precious things, the silver, the gold, the spices, and the precious oil, and all the house of his armor, and all that was found in his treasures. There was nothing in his house, nor in all his dominion, that Hezekiah didn’t show them.'),
  ('Isaiah', 39, 3, 'Then Isaiah the prophet came to King Hezekiah, and asked him, “What did these men say? From where did they come to you?” Hezekiah said, “They have come from a country far from me, even from Babylon.”'),
  ('Isaiah', 39, 4, 'Then he asked, “What have they seen in your house?” Hezekiah answered, “They have seen all that is in my house. There is nothing among my treasures that I have not shown them.”'),
  ('Isaiah', 39, 5, 'Then Isaiah said to Hezekiah, “Hear the word of the LORD of Armies:'),
  ('Isaiah', 39, 6, '‘Behold, the days are coming when all that is in your house, and that which your fathers have stored up until today, will be carried to Babylon. Nothing will be left,’ says the LORD.'),
  ('Isaiah', 39, 7, '‘They will take away your sons who will issue from you, whom you shall father, and they will be eunuchs in the king of Babylon’s palace.’”'),
  ('Isaiah', 39, 8, 'Then Hezekiah said to Isaiah, “The LORD’s word which you have spoken is good.” He said moreover, “For there will be peace and truth in my days.”'),
  ('Isaiah', 40, 1, '“Comfort, comfort my people,” says your God.'),
  ('Isaiah', 40, 2, '“Speak comfortably to Jerusalem, and call out to her that her warfare is accomplished, that her iniquity is pardoned, that she has received of the LORD’s hand double for all her sins.”'),
  ('Isaiah', 40, 3, 'The voice of one who calls out, “Prepare the way of the LORD in the wilderness! Make a level highway in the desert for our God.'),
  ('Isaiah', 40, 4, 'Every valley shall be exalted, and every mountain and hill shall be made low. The uneven shall be made level, and the rough places a plain.'),
  ('Isaiah', 40, 5, 'The LORD’s glory shall be revealed, and all flesh shall see it together; for the mouth of the LORD has spoken it.”'),
  ('Isaiah', 40, 6, 'The voice of one saying, “Cry out!” One said, “What shall I cry?” “All flesh is like grass, and all its glory is like the flower of the field.'),
  ('Isaiah', 40, 7, 'The grass withers, the flower fades, because the LORD’s breath blows on it. Surely the people are like grass.'),
  ('Isaiah', 40, 8, 'The grass withers, the flower fades; but the word of our God stands forever.”'),
  ('Isaiah', 40, 9, 'You who tell good news to Zion, go up on a high mountain. You who tell good news to Jerusalem, lift up your voice with strength! Lift it up! Don’t be afraid! Say to the cities of Judah, “Behold, your God!”'),
  ('Isaiah', 40, 10, 'Behold, the Lord GOD will come as a mighty one, and his arm will rule for him. Behold, his reward is with him, and his recompense before him.'),
  ('Isaiah', 40, 11, 'He will feed his flock like a shepherd. He will gather the lambs in his arm, and carry them in his bosom. He will gently lead those who have their young.'),
  ('Isaiah', 40, 12, 'Who has measured the waters in the hollow of his hand, and marked off the sky with his span, and calculated the dust of the earth in a measuring basket, and weighed the mountains in scales, and the hills in a balance?'),
  ('Isaiah', 40, 13, 'Who has directed the LORD’s Spirit, or has taught him as his counselor?'),
  ('Isaiah', 40, 14, 'Who did he take counsel with, and who instructed him, and taught him in the path of justice, and taught him knowledge, and showed him the way of understanding?'),
  ('Isaiah', 40, 15, 'Behold, the nations are like a drop in a bucket, and are regarded as a speck of dust on a balance. Behold, he lifts up the islands like a very little thing.'),
  ('Isaiah', 40, 16, 'Lebanon is not sufficient to burn, nor its animals sufficient for a burnt offering.'),
  ('Isaiah', 40, 17, 'All the nations are like nothing before him. They are regarded by him as less than nothing, and vanity.'),
  ('Isaiah', 40, 18, 'To whom then will you liken God? Or what likeness will you compare to him?'),
  ('Isaiah', 40, 19, 'A workman has cast an image, and the goldsmith overlays it with gold, and casts silver chains for it.'),
  ('Isaiah', 40, 20, 'He who is too impoverished for such an offering chooses a tree that will not rot. He seeks a skillful workman to set up a carved image for him that will not be moved.'),
  ('Isaiah', 40, 21, 'Haven’t you known? Haven’t you heard? Haven’t you been told from the beginning? Haven’t you understood from the foundations of the earth?'),
  ('Isaiah', 40, 22, 'It is he who sits above the circle of the earth, and its inhabitants are like grasshoppers; who stretches out the heavens like a curtain, and spreads them out like a tent to dwell in,'),
  ('Isaiah', 40, 23, 'who brings princes to nothing, who makes the judges of the earth meaningless.'),
  ('Isaiah', 40, 24, 'They are planted scarcely. They are sown scarcely. Their stock has scarcely taken root in the ground. He merely blows on them, and they wither, and the whirlwind takes them away as stubble.'),
  ('Isaiah', 40, 25, '“To whom then will you liken me? Who is my equal?” says the Holy One.'),
  ('Isaiah', 40, 26, 'Lift up your eyes on high, and see who has created these, who brings out their army by number. He calls them all by name. By the greatness of his might, and because he is strong in power, not one is lacking.'),
  ('Isaiah', 40, 27, 'Why do you say, Jacob, and speak, Israel, “My way is hidden from the LORD, and the justice due me is disregarded by my God”?'),
  ('Isaiah', 40, 28, 'Haven’t you known? Haven’t you heard? The everlasting God, the LORD, the Creator of the ends of the earth, doesn’t faint. He isn’t weary. His understanding is unsearchable.'),
  ('Isaiah', 40, 29, 'He gives power to the weak. He increases the strength of him who has no might.'),
  ('Isaiah', 40, 30, 'Even the youths faint and get weary, and the young men utterly fall;'),
  ('Isaiah', 40, 31, 'but those who wait for the LORD will renew their strength. They will mount up with wings like eagles. They will run, and not be weary. They will walk, and not faint.'),
  ('Isaiah', 41, 1, '“Keep silent before me, islands, and let the peoples renew their strength. Let them come near, then let them speak. Let’s meet together for judgment.'),
  ('Isaiah', 41, 2, 'Who has raised up one from the east? Who called him to his feet in righteousness? He hands over nations to him and makes him rule over kings. He gives them like the dust to his sword, like the driven stubble to his bow.'),
  ('Isaiah', 41, 3, 'He pursues them and passes by safely, even by a way that he had not gone with his feet.'),
  ('Isaiah', 41, 4, 'Who has worked and done it, calling the generations from the beginning? I, the LORD, the first, and with the last, I am he.”'),
  ('Isaiah', 41, 5, 'The islands have seen, and fear. The ends of the earth tremble. They approach, and come.'),
  ('Isaiah', 41, 6, 'Everyone helps his neighbor. They say to their brothers, “Be strong!”'),
  ('Isaiah', 41, 7, 'So the carpenter encourages the goldsmith. He who smooths with the hammer encourages him who strikes the anvil, saying of the soldering, “It is good;” and he fastens it with nails, that it might not totter.'),
  ('Isaiah', 41, 8, '“But you, Israel, my servant, Jacob whom I have chosen, the offspring of Abraham my friend,'),
  ('Isaiah', 41, 9, 'you whom I have taken hold of from the ends of the earth, and called from its corners, and said to you, ‘You are my servant. I have chosen you and have not cast you away.’'),
  ('Isaiah', 41, 10, 'Don’t you be afraid, for I am with you. Don’t be dismayed, for I am your God. I will strengthen you. Yes, I will help you. Yes, I will uphold you with the right hand of my righteousness.'),
  ('Isaiah', 41, 11, 'Behold, all those who are incensed against you will be disappointed and confounded. Those who strive with you will be like nothing, and shall perish.'),
  ('Isaiah', 41, 12, 'You will seek them, and won’t find them, even those who contend with you. Those who war against you will be as nothing, as a nonexistent thing.'),
  ('Isaiah', 41, 13, 'For I, the LORD your God, will hold your right hand, saying to you, ‘Don’t be afraid. I will help you.’'),
  ('Isaiah', 41, 14, 'Don’t be afraid, you worm Jacob, and you men of Israel. I will help you,” says the LORD. “Your Redeemer is the Holy One of Israel.'),
  ('Isaiah', 41, 15, 'Behold, I have made you into a new sharp threshing instrument with teeth. You will thresh the mountains, and beat them small, and will make the hills like chaff.'),
  ('Isaiah', 41, 16, 'You will winnow them, and the wind will carry them away, and the whirlwind will scatter them. You will rejoice in the LORD. You will glory in the Holy One of Israel.'),
  ('Isaiah', 41, 17, 'The poor and needy seek water, and there is none. Their tongue fails for thirst. I, the LORD, will answer them. I, the God of Israel, will not forsake them.'),
  ('Isaiah', 41, 18, 'I will open rivers on the bare heights, and springs in the middle of the valleys. I will make the wilderness a pool of water, and the dry land springs of water.'),
  ('Isaiah', 41, 19, 'I will put cedar, acacia, myrtle, and oil trees in the wilderness. I will set cypress trees, pine, and box trees together in the desert;'),
  ('Isaiah', 41, 20, 'that they may see, know, consider, and understand together, that the LORD’s hand has done this, and the Holy One of Israel has created it.'),
  ('Isaiah', 41, 21, 'Produce your cause,” says the LORD. “Bring out your strong reasons!” says the King of Jacob.'),
  ('Isaiah', 41, 22, '“Let them announce and declare to us what will happen! Declare the former things, what they are, that we may consider them, and know the latter end of them; or show us things to come.'),
  ('Isaiah', 41, 23, 'Declare the things that are to come hereafter, that we may know that you are gods. Yes, do good, or do evil, that we may be dismayed, and see it together.'),
  ('Isaiah', 41, 24, 'Behold, you are nothing, and your work is nothing. He who chooses you is an abomination.'),
  ('Isaiah', 41, 25, '“I have raised up one from the north, and he has come, from the rising of the sun, one who calls on my name, and he shall come on rulers as on mortar, and as the potter treads clay.'),
  ('Isaiah', 41, 26, 'Who has declared it from the beginning, that we may know? and before, that we may say, ‘He is right’? Surely, there is no one who declares. Surely, there is no one who shows. Surely, there is no one who hears your words.'),
  ('Isaiah', 41, 27, 'I am the first to say to Zion, ‘Behold, look at them;’ and I will give one who brings good news to Jerusalem.'),
  ('Isaiah', 41, 28, 'When I look, there is no man, even among them there is no counselor who, when I ask, can answer a word.'),
  ('Isaiah', 41, 29, 'Behold, all of their deeds are vanity and nothing. Their molten images are wind and confusion.'),
  ('Isaiah', 42, 1, '“Behold, my servant, whom I uphold, my chosen, in whom my soul delights: I have put my Spirit on him. He will bring justice to the nations.'),
  ('Isaiah', 42, 2, 'He will not shout, nor raise his voice, nor cause it to be heard in the street.'),
  ('Isaiah', 42, 3, 'He won’t break a bruised reed. He won’t quench a dimly burning wick. He will faithfully bring justice.'),
  ('Isaiah', 42, 4, 'He will not fail nor be discouraged, until he has set justice in the earth, and the islands wait for his law.”'),
  ('Isaiah', 42, 5, 'God the LORD, he who created the heavens and stretched them out, he who spread out the earth and that which comes out of it, he who gives breath to its people and spirit to those who walk in it, says:'),
  ('Isaiah', 42, 6, '“I, the LORD, have called you in righteousness. I will hold your hand. I will keep you, and make you a covenant for the people, as a light for the nations,'),
  ('Isaiah', 42, 7, 'to open the blind eyes, to bring the prisoners out of the dungeon, and those who sit in darkness out of the prison.'),
  ('Isaiah', 42, 8, '“I am the LORD. That is my name. I will not give my glory to another, nor my praise to engraved images.'),
  ('Isaiah', 42, 9, 'Behold, the former things have happened and I declare new things. I tell you about them before they come up.”'),
  ('Isaiah', 42, 10, 'Sing to the LORD a new song, and his praise from the end of the earth, you who go down to the sea, and all that is therein, the islands and their inhabitants.'),
  ('Isaiah', 42, 11, 'Let the wilderness and its cities raise their voices, with the villages that Kedar inhabits. Let the inhabitants of Sela sing. Let them shout from the top of the mountains!'),
  ('Isaiah', 42, 12, 'Let them give glory to the LORD, and declare his praise in the islands.'),
  ('Isaiah', 42, 13, 'The LORD will go out like a mighty man. He will stir up zeal like a man of war. He will raise a war cry. Yes, he will shout aloud. He will triumph over his enemies.'),
  ('Isaiah', 42, 14, '“I have been silent a long time. I have been quiet and restrained myself. Now I will cry out like a travailing woman. I will both gasp and pant.'),
  ('Isaiah', 42, 15, 'I will destroy mountains and hills, and dry up all their herbs. I will make the rivers islands, and will dry up the pools.'),
  ('Isaiah', 42, 16, 'I will bring the blind by a way that they don’t know. I will lead them in paths that they don’t know. I will make darkness light before them, and crooked places straight. I will do these things, and I will not forsake them.'),
  ('Isaiah', 42, 17, '“Those who trust in engraved images, who tell molten images, ‘You are our gods,’ will be turned back. They will be utterly disappointed.'),
  ('Isaiah', 42, 18, '“Hear, you deaf, and look, you blind, that you may see.'),
  ('Isaiah', 42, 19, 'Who is blind, but my servant? Or who is as deaf as my messenger whom I send? Who is as blind as he who is at peace, and as blind as the LORD’s servant?');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 42, 20, 'You see many things, but don’t observe. His ears are open, but he doesn’t listen.'),
  ('Isaiah', 42, 21, 'It pleased the LORD, for his righteousness’ sake, to magnify the law and make it honorable.'),
  ('Isaiah', 42, 22, 'But this is a robbed and plundered people. All of them are snared in holes, and they are hidden in prisons. They have become captives, and no one delivers, and a plunder, and no one says, ‘Restore them!’'),
  ('Isaiah', 42, 23, 'Who is there among you who will give ear to this? Who will listen and hear for the time to come?'),
  ('Isaiah', 42, 24, 'Who gave Jacob as plunder, and Israel to the robbers? Didn’t the LORD, he against whom we have sinned? For they would not walk in his ways, and they disobeyed his law.'),
  ('Isaiah', 42, 25, 'Therefore he poured the fierceness of his anger on him, and the strength of battle. It set him on fire all around, but he didn’t know. It burned him, but he didn’t take it to heart.”'),
  ('Isaiah', 43, 1, 'But now the LORD who created you, Jacob, and he who formed you, Israel, says: “Don’t be afraid, for I have redeemed you. I have called you by your name. You are mine.'),
  ('Isaiah', 43, 2, 'When you pass through the waters, I will be with you, and through the rivers, they will not overflow you. When you walk through the fire, you will not be burned, and flame will not scorch you.'),
  ('Isaiah', 43, 3, 'For I am the LORD your God, the Holy One of Israel, your Savior. I have given Egypt as your ransom, Ethiopia and Seba in your place.'),
  ('Isaiah', 43, 4, 'Since you have been precious and honored in my sight, and I have loved you, therefore I will give people in your place, and nations instead of your life.'),
  ('Isaiah', 43, 5, 'Don’t be afraid, for I am with you. I will bring your offspring from the east, and gather you from the west.'),
  ('Isaiah', 43, 6, 'I will tell the north, ‘Give them up!’ and tell the south, ‘Don’t hold them back! Bring my sons from far away, and my daughters from the ends of the earth—'),
  ('Isaiah', 43, 7, 'everyone who is called by my name, and whom I have created for my glory, whom I have formed, yes, whom I have made.’”'),
  ('Isaiah', 43, 8, 'Bring out the blind people who have eyes, and the deaf who have ears.'),
  ('Isaiah', 43, 9, 'Let all the nations be gathered together, and let the peoples be assembled. Who among them can declare this, and show us former things? Let them bring their witnesses, that they may be justified, or let them hear, and say, “That is true.”'),
  ('Isaiah', 43, 10, '“You are my witnesses,” says the LORD, “With my servant whom I have chosen; that you may know and believe me, and understand that I am he. Before me there was no God formed, neither will there be after me.'),
  ('Isaiah', 43, 11, 'I myself am the LORD. Besides me, there is no savior.'),
  ('Isaiah', 43, 12, 'I have declared, I have saved, and I have shown, and there was no strange god among you. Therefore you are my witnesses”, says the LORD, “and I am God.'),
  ('Isaiah', 43, 13, 'Yes, since the day was, I am he. There is no one who can deliver out of my hand. I will work, and who can hinder it?”'),
  ('Isaiah', 43, 14, 'The LORD, your Redeemer, the Holy One of Israel says: “For your sake, I have sent to Babylon, and I will bring all of them down as fugitives, even the Chaldeans, in the ships of their rejoicing.'),
  ('Isaiah', 43, 15, 'I am the LORD, your Holy One, the Creator of Israel, your King.”'),
  ('Isaiah', 43, 16, 'The LORD, who makes a way in the sea, and a path in the mighty waters,'),
  ('Isaiah', 43, 17, 'who brings out the chariot and horse, the army and the mighty man (they lie down together, they shall not rise; they are extinct, they are quenched like a wick) says:'),
  ('Isaiah', 43, 18, '“Don’t remember the former things, and don’t consider the things of old.'),
  ('Isaiah', 43, 19, 'Behold, I will do a new thing. It springs out now. Don’t you know it? I will even make a way in the wilderness, and rivers in the desert.'),
  ('Isaiah', 43, 20, 'The animals of the field, the jackals and the ostriches, shall honor me, because I give water in the wilderness and rivers in the desert, to give drink to my people, my chosen,'),
  ('Isaiah', 43, 21, 'the people which I formed for myself, that they might declare my praise.'),
  ('Isaiah', 43, 22, 'Yet you have not called on me, Jacob; but you have been weary of me, Israel.'),
  ('Isaiah', 43, 23, 'You have not brought me any of your sheep for burnt offerings, neither have you honored me with your sacrifices. I have not burdened you with offerings, nor wearied you with frankincense.'),
  ('Isaiah', 43, 24, 'You have bought me no sweet cane with money, nor have you filled me with the fat of your sacrifices, but you have burdened me with your sins. You have wearied me with your iniquities.'),
  ('Isaiah', 43, 25, 'I, even I, am he who blots out your transgressions for my own sake; and I will not remember your sins.'),
  ('Isaiah', 43, 26, 'Put me in remembrance. Let us plead together. Declare your case, that you may be justified.'),
  ('Isaiah', 43, 27, 'Your first father sinned, and your teachers have transgressed against me.'),
  ('Isaiah', 43, 28, 'Therefore I will profane the princes of the sanctuary; and I will make Jacob a curse, and Israel an insult.”'),
  ('Isaiah', 44, 1, 'Yet listen now, Jacob my servant, and Israel, whom I have chosen.'),
  ('Isaiah', 44, 2, 'This is what the LORD who made you, and formed you from the womb, who will help you says: “Don’t be afraid, Jacob my servant; and you, Jeshurun, whom I have chosen.'),
  ('Isaiah', 44, 3, 'For I will pour water on him who is thirsty, and streams on the dry ground. I will pour my Spirit on your descendants, and my blessing on your offspring;'),
  ('Isaiah', 44, 4, 'and they will spring up among the grass, as willows by the watercourses.'),
  ('Isaiah', 44, 5, 'One will say, ‘I am the LORD’s.’ Another will be called by the name of Jacob; and another will write with his hand ‘to the LORD,’ and honor the name of Israel.”'),
  ('Isaiah', 44, 6, 'This is what the LORD, the King of Israel, and his Redeemer, the LORD of Armies, says: “I am the first, and I am the last; and besides me there is no God.'),
  ('Isaiah', 44, 7, 'Who is like me? Who will call, and will declare it, and set it in order for me, since I established the ancient people? Let them declare the things that are coming, and that will happen.'),
  ('Isaiah', 44, 8, 'Don’t fear, neither be afraid. Haven’t I declared it to you long ago, and shown it? You are my witnesses. Is there a God besides me? Indeed, there is not. I don’t know any other Rock.”'),
  ('Isaiah', 44, 9, 'Everyone who makes a carved image is vain. The things that they delight in will not profit. Their own witnesses don’t see, nor know, that they may be disappointed.'),
  ('Isaiah', 44, 10, 'Who has fashioned a god, or molds an image that is profitable for nothing?'),
  ('Isaiah', 44, 11, 'Behold, all his fellows will be disappointed; and the workmen are mere men. Let them all be gathered together. Let them stand up. They will fear. They will be put to shame together.'),
  ('Isaiah', 44, 12, 'The blacksmith takes an ax, works in the coals, fashions it with hammers, and works it with his strong arm. He is hungry, and his strength fails; he drinks no water, and is faint.'),
  ('Isaiah', 44, 13, 'The carpenter stretches out a line. He marks it out with a pencil. He shapes it with planes. He marks it out with compasses, and shapes it like the figure of a man, with the beauty of a man, to reside in a house.'),
  ('Isaiah', 44, 14, 'He cuts down cedars for himself, and takes the cypress and the oak, and strengthens for himself one among the trees of the forest. He plants a cypress tree, and the rain nourishes it.'),
  ('Isaiah', 44, 15, 'Then it will be for a man to burn; and he takes some of it and warms himself. Yes, he burns it and bakes bread. Yes, he makes a god and worships it; he makes it a carved image, and falls down to it.'),
  ('Isaiah', 44, 16, 'He burns part of it in the fire. With part of it, he eats meat. He roasts a roast and is satisfied. Yes, he warms himself and says, “Aha! I am warm. I have seen the fire.”'),
  ('Isaiah', 44, 17, 'The rest of it he makes into a god, even his engraved image. He bows down to it and worships, and prays to it, and says, “Deliver me, for you are my god!”'),
  ('Isaiah', 44, 18, 'They don’t know, neither do they consider, for he has shut their eyes, that they can’t see, and their hearts, that they can’t understand.'),
  ('Isaiah', 44, 19, 'No one thinks, neither is there knowledge nor understanding to say, “I have burned part of it in the fire. Yes, I have also baked bread on its coals. I have roasted meat and eaten it. Shall I make the rest of it into an abomination? Shall I bow down to a tree trunk?”'),
  ('Isaiah', 44, 20, 'He feeds on ashes. A deceived heart has turned him aside; and he can’t deliver his soul, nor say, “Isn’t there a lie in my right hand?”'),
  ('Isaiah', 44, 21, 'Remember these things, Jacob and Israel, for you are my servant. I have formed you. You are my servant. Israel, you will not be forgotten by me.'),
  ('Isaiah', 44, 22, 'I have blotted out, as a thick cloud, your transgressions, and, as a cloud, your sins. Return to me, for I have redeemed you.'),
  ('Isaiah', 44, 23, 'Sing, you heavens, for the LORD has done it! Shout, you lower parts of the earth! Break out into singing, you mountains, O forest, all of your trees, for the LORD has redeemed Jacob, and will glorify himself in Israel.'),
  ('Isaiah', 44, 24, 'The LORD, your Redeemer, and he who formed you from the womb says: “I am the LORD, who makes all things; who alone stretches out the heavens; who spreads out the earth by myself;'),
  ('Isaiah', 44, 25, 'who frustrates the signs of the liars, and makes diviners mad; who turns wise men backward, and makes their knowledge foolish;'),
  ('Isaiah', 44, 26, 'who confirms the word of his servant, and performs the counsel of his messengers; who says of Jerusalem, ‘She will be inhabited;’ and of the cities of Judah, ‘They will be built,’ and ‘I will raise up its waste places;’'),
  ('Isaiah', 44, 27, 'who says to the deep, ‘Be dry,’ and ‘I will dry up your rivers,’'),
  ('Isaiah', 44, 28, 'who says of Cyrus, ‘He is my shepherd, and shall perform all my pleasure,’ even saying of Jerusalem, ‘She will be built;’ and of the temple, ‘Your foundation will be laid.’”'),
  ('Isaiah', 45, 1, 'The LORD says to his anointed, to Cyrus, whose right hand I have held to subdue nations before him and strip kings of their armor, to open the doors before him, and the gates shall not be shut:'),
  ('Isaiah', 45, 2, '“I will go before you and make the rough places smooth. I will break the doors of bronze in pieces and cut apart the bars of iron.'),
  ('Isaiah', 45, 3, 'I will give you the treasures of darkness and hidden riches of secret places, that you may know that it is I, the LORD, who calls you by your name, even the God of Israel.'),
  ('Isaiah', 45, 4, 'For Jacob my servant’s sake, and Israel my chosen, I have called you by your name. I have given you a title, though you have not known me.'),
  ('Isaiah', 45, 5, 'I am the LORD, and there is no one else. Besides me, there is no God. I will strengthen you, though you have not known me,'),
  ('Isaiah', 45, 6, 'that they may know from the rising of the sun, and from the west, that there is no one besides me. I am the LORD, and there is no one else.'),
  ('Isaiah', 45, 7, 'I form the light and create darkness. I make peace and create calamity. I am the LORD, who does all these things.'),
  ('Isaiah', 45, 8, 'Rain, you heavens, from above, and let the skies pour down righteousness. Let the earth open, that it may produce salvation, and let it cause righteousness to spring up with it. I, the LORD, have created it.'),
  ('Isaiah', 45, 9, 'Woe to him who strives with his Maker— a clay pot among the clay pots of the earth! Shall the clay ask him who fashions it, ‘What are you making?’ or your work, ‘He has no hands’?'),
  ('Isaiah', 45, 10, 'Woe to him who says to a father, ‘What have you become the father of?’ or to a mother, ‘What have you given birth to?’”'),
  ('Isaiah', 45, 11, 'The LORD, the Holy One of Israel and his Maker says: “You ask me about the things that are to come, concerning my sons, and you command me concerning the work of my hands!'),
  ('Isaiah', 45, 12, 'I have made the earth, and created man on it. I, even my hands, have stretched out the heavens. I have commanded all their army.'),
  ('Isaiah', 45, 13, 'I have raised him up in righteousness, and I will make all his ways straight. He shall build my city, and he shall let my exiles go free, not for price nor reward,” says the LORD of Armies.'),
  ('Isaiah', 45, 14, 'The LORD says: “The labor of Egypt, and the merchandise of Ethiopia, and the Sabeans, men of stature, will come over to you, and they will be yours. They will go after you. They shall come over in chains. They will bow down to you. They will make supplication to you: ‘Surely God is in you; and there is no one else. There is no other god.'),
  ('Isaiah', 45, 15, 'Most certainly you are a God who has hidden yourself, God of Israel, the Savior.’”'),
  ('Isaiah', 45, 16, 'They will be disappointed, yes, confounded, all of them. Those who are makers of idols will go into confusion together.'),
  ('Isaiah', 45, 17, 'Israel will be saved by the LORD with an everlasting salvation. You will not be disappointed nor confounded to ages everlasting.'),
  ('Isaiah', 45, 18, 'For the LORD who created the heavens, the God who formed the earth and made it, who established it and didn’t create it a waste, who formed it to be inhabited says: “I am the LORD. There is no other.'),
  ('Isaiah', 45, 19, 'I have not spoken in secret, in a place of the land of darkness. I didn’t say to the offspring of Jacob, ‘Seek me in vain.’ I, the LORD, speak righteousness. I declare things that are right.'),
  ('Isaiah', 45, 20, '“Assemble yourselves and come. Draw near together, you who have escaped from the nations. Those have no knowledge who carry the wood of their engraved image, and pray to a god that can’t save.'),
  ('Isaiah', 45, 21, 'Declare and present it. Yes, let them take counsel together. Who has shown this from ancient time? Who has declared it of old? Haven’t I, the LORD? There is no other God besides me, a just God and a Savior. There is no one besides me.'),
  ('Isaiah', 45, 22, '“Look to me, and be saved, all the ends of the earth; for I am God, and there is no other.'),
  ('Isaiah', 45, 23, 'I have sworn by myself. The word has gone out of my mouth in righteousness, and will not be revoked, that to me every knee shall bow, every tongue shall take an oath.'),
  ('Isaiah', 45, 24, 'They will say of me, ‘There is righteousness and strength only in the LORD.’” Even to him will men come. All those who raged against him will be disappointed.'),
  ('Isaiah', 45, 25, 'All the offspring of Israel will be justified in the LORD, and will rejoice!'),
  ('Isaiah', 46, 1, 'Bel bows down. Nebo stoops. Their idols are carried by animals, and on the livestock. The things that you carried around are heavy loads, a burden for the weary.'),
  ('Isaiah', 46, 2, 'They stoop and they bow down together. They could not deliver the burden, but they have gone into captivity.'),
  ('Isaiah', 46, 3, '“Listen to me, house of Jacob, and all the remnant of the house of Israel, that have been carried from their birth, that have been carried from the womb.'),
  ('Isaiah', 46, 4, 'Even to old age I am he, and even to gray hairs I will carry you. I have made, and I will bear. Yes, I will carry, and will deliver.'),
  ('Isaiah', 46, 5, '“To whom will you compare me, and consider my equal, and compare me, as if we were the same?'),
  ('Isaiah', 46, 6, 'Some pour out gold from the bag, and weigh silver in the balance. They hire a goldsmith, and he makes it a god. They fall down— yes, they worship.'),
  ('Isaiah', 46, 7, 'They bear it on their shoulder. They carry it, and set it in its place, and it stands there. It cannot move from its place. Yes, one may cry to it, yet it can not answer. It cannot save him out of his trouble.'),
  ('Isaiah', 46, 8, '“Remember this, and show yourselves men. Bring it to mind again, you transgressors.'),
  ('Isaiah', 46, 9, 'Remember the former things of old; for I am God, and there is no other. I am God, and there is none like me.'),
  ('Isaiah', 46, 10, 'I declare the end from the beginning, and from ancient times things that are not yet done. I say: My counsel will stand, and I will do all that I please.'),
  ('Isaiah', 46, 11, 'I call a ravenous bird from the east, the man of my counsel from a far country. Yes, I have spoken. I will also bring it to pass. I have planned. I will also do it.'),
  ('Isaiah', 46, 12, 'Listen to me, you stubborn-hearted, who are far from righteousness!'),
  ('Isaiah', 46, 13, 'I bring my righteousness near. It is not far off, and my salvation will not wait. I will grant salvation to Zion, my glory to Israel.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 47, 1, '“Come down and sit in the dust, virgin daughter of Babylon. Sit on the ground without a throne, daughter of the Chaldeans. For you will no longer be called tender and delicate.'),
  ('Isaiah', 47, 2, 'Take the millstones and grind flour. Remove your veil, lift up your skirt, uncover your legs, and wade through the rivers.'),
  ('Isaiah', 47, 3, 'Your nakedness will be uncovered. Yes, your shame will be seen. I will take vengeance, and will spare no one.”'),
  ('Isaiah', 47, 4, 'Our Redeemer, the LORD of Armies is his name, is the Holy One of Israel.'),
  ('Isaiah', 47, 5, '“Sit in silence, and go into darkness, daughter of the Chaldeans. For you shall no longer be called the mistress of kingdoms.'),
  ('Isaiah', 47, 6, 'I was angry with my people. I profaned my inheritance and gave them into your hand. You showed them no mercy. You laid a very heavy yoke on the aged.'),
  ('Isaiah', 47, 7, 'You said, ‘I will be a princess forever,’ so that you didn’t lay these things to your heart, nor did you remember the results.'),
  ('Isaiah', 47, 8, '“Now therefore hear this, you who are given to pleasures, who sit securely, who say in your heart, ‘I am, and there is no one else besides me. I won’t sit as a widow, neither will I know the loss of children.’'),
  ('Isaiah', 47, 9, 'But these two things will come to you in a moment in one day: the loss of children and widowhood. They will come on you in their full measure, in the multitude of your sorceries, and the great abundance of your enchantments.'),
  ('Isaiah', 47, 10, 'For you have trusted in your wickedness. You have said, ‘No one sees me.’ Your wisdom and your knowledge has perverted you. You have said in your heart, ‘I am, and there is no one else besides me.’'),
  ('Isaiah', 47, 11, 'Therefore disaster will come on you. You won’t know when it dawns. Mischief will fall on you. You won’t be able to put it away. Desolation will come on you suddenly, which you don’t understand.'),
  ('Isaiah', 47, 12, '“Stand now with your enchantments and with the multitude of your sorceries, in which you have labored from your youth, as if you might profit, as if you might prevail.'),
  ('Isaiah', 47, 13, 'You are wearied in the multitude of your counsels. Now let the astrologers, the stargazers, and the monthly prognosticators stand up and save you from the things that will happen to you.'),
  ('Isaiah', 47, 14, 'Behold, they are like stubble. The fire will burn them. They won’t deliver themselves from the power of the flame. It won’t be a coal to warm at or a fire to sit by.'),
  ('Isaiah', 47, 15, 'The things that you labored in will be like this: those who have trafficked with you from your youth will each wander in his own way. There will be no one to save you.'),
  ('Isaiah', 48, 1, '“Hear this, house of Jacob, you who are called by the name of Israel, and have come out of the waters of Judah. You swear by the LORD’s name, and make mention of the God of Israel, but not in truth, nor in righteousness—'),
  ('Isaiah', 48, 2, 'for they call themselves citizens of the holy city, and rely on the God of Israel; the LORD of Armies is his name.'),
  ('Isaiah', 48, 3, 'I have declared the former things from of old. Yes, they went out of my mouth, and I revealed them. I did them suddenly, and they happened.'),
  ('Isaiah', 48, 4, 'Because I knew that you are obstinate, and your neck is an iron sinew, and your brow bronze;'),
  ('Isaiah', 48, 5, 'therefore I have declared it to you from of old; before it came to pass I showed it to you; lest you should say, ‘My idol has done them. My engraved image and my molten image has commanded them.’'),
  ('Isaiah', 48, 6, 'You have heard it. Now see all this. And you, won’t you declare it? “I have shown you new things from this time, even hidden things, which you have not known.'),
  ('Isaiah', 48, 7, 'They are created now, and not from of old. Before today, you didn’t hear them, lest you should say, ‘Behold, I knew them.’'),
  ('Isaiah', 48, 8, 'Yes, you didn’t hear. Yes, you didn’t know. Yes, from of old your ear was not opened, for I knew that you dealt very treacherously, and were called a transgressor from the womb.'),
  ('Isaiah', 48, 9, 'For my name’s sake, I will defer my anger, and for my praise, I hold it back for you so that I don’t cut you off.'),
  ('Isaiah', 48, 10, 'Behold, I have refined you, but not as silver. I have chosen you in the furnace of affliction.'),
  ('Isaiah', 48, 11, 'For my own sake, for my own sake, I will do it; for how would my name be profaned? I will not give my glory to another.'),
  ('Isaiah', 48, 12, '“Listen to me, O Jacob, and Israel my called: I am he. I am the first. I am also the last.'),
  ('Isaiah', 48, 13, 'Yes, my hand has laid the foundation of the earth, and my right hand has spread out the heavens. when I call to them, they stand up together.'),
  ('Isaiah', 48, 14, '“Assemble yourselves, all of you, and hear! Who among them has declared these things? He whom the LORD loves will do what he likes to Babylon, and his arm will be against the Chaldeans.'),
  ('Isaiah', 48, 15, 'I, even I, have spoken. Yes, I have called him. I have brought him and he shall make his way prosperous.'),
  ('Isaiah', 48, 16, '“Come near to me and hear this: “From the beginning I have not spoken in secret; from the time that it happened, I was there.” Now the Lord GOD has sent me with his Spirit.'),
  ('Isaiah', 48, 17, 'The LORD, your Redeemer, the Holy One of Israel, says: “I am the LORD your God, who teaches you to profit, who leads you by the way that you should go.'),
  ('Isaiah', 48, 18, 'Oh that you had listened to my commandments! Then your peace would have been like a river and your righteousness like the waves of the sea.'),
  ('Isaiah', 48, 19, 'Your offspring also would have been as the sand and the descendants of your body like its grains. His name would not be cut off nor destroyed from before me.”'),
  ('Isaiah', 48, 20, 'Leave Babylon! Flee from the Chaldeans! With the sound of joyful shouting announce this, tell it even to the end of the earth; say, “The LORD has redeemed his servant Jacob!”'),
  ('Isaiah', 48, 21, 'They didn’t thirst when he led them through the deserts. He caused the waters to flow out of the rock for them. He also split the rock and the waters gushed out.'),
  ('Isaiah', 48, 22, '“There is no peace”, says the LORD, “for the wicked.”'),
  ('Isaiah', 49, 1, 'Listen, islands, to me. Listen, you peoples, from afar: the LORD has called me from the womb; from the inside of my mother, he has mentioned my name.'),
  ('Isaiah', 49, 2, 'He has made my mouth like a sharp sword. He has hidden me in the shadow of his hand. He has made me a polished shaft. He has kept me close in his quiver.'),
  ('Isaiah', 49, 3, 'He said to me, “You are my servant, Israel, in whom I will be glorified.”'),
  ('Isaiah', 49, 4, 'But I said, “I have labored in vain. I have spent my strength in vain for nothing; yet surely the justice due to me is with the LORD, and my reward with my God.”'),
  ('Isaiah', 49, 5, 'Now the LORD, he who formed me from the womb to be his servant, says to bring Jacob again to him, and to gather Israel to him, for I am honorable in the LORD’s eyes, and my God has become my strength.'),
  ('Isaiah', 49, 6, 'Indeed, he says, “It is too light a thing that you should be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel. I will also give you as a light to the nations, that you may be my salvation to the end of the earth.”'),
  ('Isaiah', 49, 7, 'The LORD, the Redeemer of Israel, and his Holy One, says to him whom man despises, to him whom the nation abhors, to a servant of rulers: “Kings shall see and rise up, princes, and they shall worship, because of the LORD who is faithful, even the Holy One of Israel, who has chosen you.”'),
  ('Isaiah', 49, 8, 'The LORD says, “I have answered you in an acceptable time. I have helped you in a day of salvation. I will preserve you and give you for a covenant of the people, to raise up the land, to make them inherit the desolate heritage,'),
  ('Isaiah', 49, 9, 'saying to those who are bound, ‘Come out!’; to those who are in darkness, ‘Show yourselves!’ “They shall feed along the paths, and their pasture shall be on all treeless heights.'),
  ('Isaiah', 49, 10, 'They shall not hunger nor thirst; neither shall the heat nor sun strike them, for he who has mercy on them will lead them. He will guide them by springs of water.'),
  ('Isaiah', 49, 11, 'I will make all my mountains a road, and my highways shall be exalted.'),
  ('Isaiah', 49, 12, 'Behold, these shall come from afar, and behold, these from the north and from the west, and these from the land of Sinim.”'),
  ('Isaiah', 49, 13, 'Sing, heavens, and be joyful, earth! Break out into singing, mountains! For the LORD has comforted his people, and will have compassion on his afflicted.'),
  ('Isaiah', 49, 14, 'But Zion said, “The LORD has forsaken me, and the Lord has forgotten me.”'),
  ('Isaiah', 49, 15, '“Can a woman forget her nursing child, that she should not have compassion on the son of her womb? Yes, these may forget, yet I will not forget you!'),
  ('Isaiah', 49, 16, 'Behold, I have engraved you on the palms of my hands. Your walls are continually before me.'),
  ('Isaiah', 49, 17, 'Your children hurry. Your destroyers and those who devastated you will leave you.'),
  ('Isaiah', 49, 18, 'Lift up your eyes all around, and see: all these gather themselves together, and come to you. As I live,” says the LORD, “you shall surely clothe yourself with them all as with an ornament, and dress yourself with them, like a bride.'),
  ('Isaiah', 49, 19, '“For, as for your waste and your desolate places, and your land that has been destroyed, surely now that land will be too small for the inhabitants, and those who swallowed you up will be far away.'),
  ('Isaiah', 49, 20, 'The children of your bereavement will say in your ears, ‘This place is too small for me. Give me a place to live in.’'),
  ('Isaiah', 49, 21, 'Then you will say in your heart, ‘Who has conceived these for me, since I have been bereaved of my children and am alone, an exile, and wandering back and forth? Who has brought these up? Behold, I was left alone. Where were these?’”'),
  ('Isaiah', 49, 22, 'The Lord GOD says, “Behold, I will lift up my hand to the nations, and lift up my banner to the peoples. They shall bring your sons in their bosom, and your daughters shall be carried on their shoulders.'),
  ('Isaiah', 49, 23, 'Kings shall be your foster fathers, and their queens your nursing mothers. They will bow down to you with their faces to the earth, and lick the dust of your feet. Then you will know that I am the LORD; and those who wait for me won’t be disappointed.”'),
  ('Isaiah', 49, 24, 'Shall the plunder be taken from the mighty, or the lawful captives be delivered?'),
  ('Isaiah', 49, 25, 'But the LORD says, “Even the captives of the mighty shall be taken away, and the plunder retrieved from the fierce, for I will contend with him who contends with you and I will save your children.'),
  ('Isaiah', 49, 26, 'I will feed those who oppress you with their own flesh; and they will be drunk on their own blood, as with sweet wine. Then all flesh shall know that I, the LORD, am your Savior and your Redeemer, the Mighty One of Jacob.”'),
  ('Isaiah', 50, 1, 'The LORD says, “Where is the bill of your mother’s divorce, with which I have put her away? Or to which of my creditors have I sold you? Behold, you were sold for your iniquities, and your mother was put away for your transgressions.'),
  ('Isaiah', 50, 2, 'Why, when I came, was there no one? When I called, why was there no one to answer? Is my hand shortened at all, that it can’t redeem? Or have I no power to deliver? Behold, at my rebuke I dry up the sea. I make the rivers a wilderness. Their fish stink because there is no water, and die of thirst.'),
  ('Isaiah', 50, 3, 'I clothe the heavens with blackness. I make sackcloth their covering.”'),
  ('Isaiah', 50, 4, 'The Lord GOD has given me the tongue of those who are taught, that I may know how to sustain with words him who is weary. He awakens morning by morning, he awakens my ear to hear as those who are taught.'),
  ('Isaiah', 50, 5, 'The Lord GOD has opened my ear. I was not rebellious. I have not turned back.'),
  ('Isaiah', 50, 6, 'I gave my back to those who beat me, and my cheeks to those who plucked off the hair. I didn’t hide my face from shame and spitting.'),
  ('Isaiah', 50, 7, 'For the Lord GOD will help me. Therefore I have not been confounded. Therefore I have set my face like a flint, and I know that I won’t be disappointed.'),
  ('Isaiah', 50, 8, 'He who justifies me is near. Who will bring charges against me? Let us stand up together. Who is my adversary? Let him come near to me.'),
  ('Isaiah', 50, 9, 'Behold, the Lord GOD will help me! Who is he who will condemn me? Behold, they will all grow old like a garment. The moths will eat them up.'),
  ('Isaiah', 50, 10, 'Who among you fears the LORD and obeys the voice of his servant? He who walks in darkness and has no light, let him trust in the LORD’s name, and rely on his God.'),
  ('Isaiah', 50, 11, 'Behold, all you who kindle a fire, who adorn yourselves with torches around yourselves, walk in the flame of your fire, and among the torches that you have kindled. You will have this from my hand: you will lie down in sorrow.'),
  ('Isaiah', 51, 1, '“Listen to me, you who follow after righteousness, you who seek the LORD. Look to the rock you were cut from, and to the quarry you were dug from.'),
  ('Isaiah', 51, 2, 'Look to Abraham your father, and to Sarah who bore you; for when he was but one I called him, I blessed him, and made him many.'),
  ('Isaiah', 51, 3, 'For the LORD has comforted Zion. He has comforted all her waste places, and has made her wilderness like Eden, and her desert like the garden of the LORD. Joy and gladness will be found in them, thanksgiving, and the voice of melody.'),
  ('Isaiah', 51, 4, '“Listen to me, my people; and hear me, my nation, for a law will go out from me, and I will establish my justice for a light to the peoples.'),
  ('Isaiah', 51, 5, 'My righteousness is near. My salvation has gone out, and my arms will judge the peoples. The islands will wait for me, and they will trust my arm.'),
  ('Isaiah', 51, 6, 'Lift up your eyes to the heavens, and look at the earth beneath; for the heavens will vanish away like smoke, and the earth will wear out like a garment. Its inhabitants will die in the same way, but my salvation will be forever, and my righteousness will not be abolished.'),
  ('Isaiah', 51, 7, '“Listen to me, you who know righteousness, the people in whose heart is my law. Don’t fear the reproach of men, and don’t be dismayed at their insults.'),
  ('Isaiah', 51, 8, 'For the moth will eat them up like a garment, and the worm will eat them like wool; but my righteousness will be forever, and my salvation to all generations.”'),
  ('Isaiah', 51, 9, 'Awake, awake, put on strength, arm of the LORD! Awake, as in the days of old, the generations of ancient times. Isn’t it you who cut Rahab in pieces, who pierced the monster?'),
  ('Isaiah', 51, 10, 'Isn’t it you who dried up the sea, the waters of the great deep; who made the depths of the sea a way for the redeemed to pass over?'),
  ('Isaiah', 51, 11, 'Those ransomed by the LORD will return, and come with singing to Zion. Everlasting joy shall be on their heads. They will obtain gladness and joy. Sorrow and sighing shall flee away.'),
  ('Isaiah', 51, 12, '“I, even I, am he who comforts you. Who are you, that you are afraid of man who shall die, and of the son of man who will be made as grass?'),
  ('Isaiah', 51, 13, 'Have you forgotten the LORD your Maker, who stretched out the heavens, and laid the foundations of the earth? Do you live in fear continually all day because of the fury of the oppressor, when he prepares to destroy? Where is the fury of the oppressor?'),
  ('Isaiah', 51, 14, 'The captive exile will speedily be freed. He will not die and go down into the pit. His bread won’t fail.'),
  ('Isaiah', 51, 15, 'For I am the LORD your God, who stirs up the sea so that its waves roar. the LORD of Armies is his name.'),
  ('Isaiah', 51, 16, 'I have put my words in your mouth and have covered you in the shadow of my hand, that I may plant the heavens, and lay the foundations of the earth, and tell Zion, ‘You are my people.’”'),
  ('Isaiah', 51, 17, 'Awake, awake! Stand up, Jerusalem, you who have drunk from the LORD’s hand the cup of his wrath. You have drunken the bowl of the cup of staggering, and drained it.'),
  ('Isaiah', 51, 18, 'There is no one to guide her among all the sons to whom she has given birth; and there is no one who takes her by the hand among all the sons whom she has brought up.'),
  ('Isaiah', 51, 19, 'These two things have happened to you— who will grieve with you?— desolation and destruction, and famine and the sword. How can I comfort you?'),
  ('Isaiah', 51, 20, 'Your sons have fainted. They lie at the head of all the streets, like an antelope in a net. They are full of the LORD’s wrath, the rebuke of your God.'),
  ('Isaiah', 51, 21, 'Therefore now hear this, you afflicted, and drunken, but not with wine:'),
  ('Isaiah', 51, 22, 'Your Lord GOD, your God who pleads the cause of his people, says, “Behold, I have taken out of your hand the cup of staggering, even the bowl of the cup of my wrath. You will not drink it any more.'),
  ('Isaiah', 51, 23, 'I will put it into the hand of those who afflict you, who have said to your soul, ‘Bow down, that we may walk over you;’ and you have laid your back as the ground, like a street to those who walk over.”'),
  ('Isaiah', 52, 1, 'Awake, awake! Put on your strength, Zion. Put on your beautiful garments, Jerusalem, the holy city, for from now on the uncircumcised and the unclean will no more come into you.'),
  ('Isaiah', 52, 2, 'Shake yourself from the dust! Arise, sit up, Jerusalem! Release yourself from the bonds of your neck, captive daughter of Zion!'),
  ('Isaiah', 52, 3, 'For the LORD says, “You were sold for nothing; and you will be redeemed without money.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 52, 4, 'For the Lord GOD says: “My people went down at the first into Egypt to live there; and the Assyrian has oppressed them without cause.'),
  ('Isaiah', 52, 5, '“Now therefore, what do I do here,” says the LORD, “seeing that my people are taken away for nothing? Those who rule over them mock,” says the LORD, “and my name is blasphemed continually all day long.'),
  ('Isaiah', 52, 6, 'Therefore my people shall know my name. Therefore they shall know in that day that I am he who speaks. Behold, it is I.”'),
  ('Isaiah', 52, 7, 'How beautiful on the mountains are the feet of him who brings good news, who publishes peace, who brings good news, who proclaims salvation, who says to Zion, “Your God reigns!”'),
  ('Isaiah', 52, 8, 'Your watchmen lift up their voice. Together they sing; for they shall see eye to eye when the LORD returns to Zion.'),
  ('Isaiah', 52, 9, 'Break out into joy! Sing together, you waste places of Jerusalem; for the LORD has comforted his people. He has redeemed Jerusalem.'),
  ('Isaiah', 52, 10, 'The LORD has made his holy arm bare in the eyes of all the nations. All the ends of the earth have seen the salvation of our God.'),
  ('Isaiah', 52, 11, 'Depart! Depart! Go out from there! Touch no unclean thing! Go out from among her! Cleanse yourselves, you who carry the LORD’s vessels.'),
  ('Isaiah', 52, 12, 'For you shall not go out in haste, neither shall you go by flight; for the LORD will go before you, and the God of Israel will be your rear guard.'),
  ('Isaiah', 52, 13, 'Behold, my servant will deal wisely. He will be exalted and lifted up, and will be very high.'),
  ('Isaiah', 52, 14, 'Just as many were astonished at you— his appearance was marred more than any man, and his form more than the sons of men—'),
  ('Isaiah', 52, 15, 'so he will cleanse many nations. Kings will shut their mouths at him; for they will see that which had not been told them, and they will understand that which they had not heard.'),
  ('Isaiah', 53, 1, 'Who has believed our message? To whom has the LORD’s arm been revealed?'),
  ('Isaiah', 53, 2, 'For he grew up before him as a tender plant, and as a root out of dry ground. He has no good looks or majesty. When we see him, there is no beauty that we should desire him.'),
  ('Isaiah', 53, 3, 'He was despised and rejected by men, a man of suffering and acquainted with disease. He was despised as one from whom men hide their face; and we didn’t respect him.'),
  ('Isaiah', 53, 4, 'Surely he has borne our sickness and carried our suffering; yet we considered him plagued, struck by God, and afflicted.'),
  ('Isaiah', 53, 5, 'But he was pierced for our transgressions. He was crushed for our iniquities. The punishment that brought our peace was on him; and by his wounds we are healed.'),
  ('Isaiah', 53, 6, 'All we like sheep have gone astray. Everyone has turned to his own way; and the LORD has laid on him the iniquity of us all.'),
  ('Isaiah', 53, 7, 'He was oppressed, yet when he was afflicted he didn’t open his mouth. As a lamb that is led to the slaughter, and as a sheep that before its shearers is silent, so he didn’t open his mouth.'),
  ('Isaiah', 53, 8, 'He was taken away by oppression and judgment. As for his generation, who considered that he was cut off out of the land of the living and stricken for the disobedience of my people?'),
  ('Isaiah', 53, 9, 'They made his grave with the wicked, and with a rich man in his death, although he had done no violence, nor was any deceit in his mouth.'),
  ('Isaiah', 53, 10, 'Yet it pleased the LORD to bruise him. He has caused him to suffer. When you make his soul an offering for sin, he will see his offspring. He will prolong his days and the LORD’s pleasure will prosper in his hand.'),
  ('Isaiah', 53, 11, 'After the suffering of his soul, he will see the light and be satisfied. My righteous servant will justify many by the knowledge of himself; and he will bear their iniquities.'),
  ('Isaiah', 53, 12, 'Therefore I will give him a portion with the great. He will divide the plunder with the strong, because he poured out his soul to death and was counted with the transgressors; yet he bore the sins of many and made intercession for the transgressors.'),
  ('Isaiah', 54, 1, '“Sing, barren, you who didn’t give birth! Break out into singing, and cry aloud, you who didn’t travail with child! For more are the children of the desolate than the children of the married wife,” says the LORD.'),
  ('Isaiah', 54, 2, '“Enlarge the place of your tent, and let them stretch out the curtains of your habitations; don’t spare; lengthen your cords, and strengthen your stakes.'),
  ('Isaiah', 54, 3, 'For you will spread out on the right hand and on the left; and your offspring will possess the nations and settle in desolate cities.'),
  ('Isaiah', 54, 4, '“Don’t be afraid, for you will not be ashamed. Don’t be confounded, for you will not be disappointed. For you will forget the shame of your youth. You will remember the reproach of your widowhood no more.'),
  ('Isaiah', 54, 5, 'For your Maker is your husband; the LORD of Armies is his name. The Holy One of Israel is your Redeemer. He will be called the God of the whole earth.'),
  ('Isaiah', 54, 6, 'For the LORD has called you as a wife forsaken and grieved in spirit, even a wife of youth, when she is cast off,” says your God.'),
  ('Isaiah', 54, 7, '“For a small moment I have forsaken you, but I will gather you with great mercies.'),
  ('Isaiah', 54, 8, 'In overflowing wrath I hid my face from you for a moment, but with everlasting loving kindness I will have mercy on you,” says the LORD your Redeemer.'),
  ('Isaiah', 54, 9, '“For this is like the waters of Noah to me; for as I have sworn that the waters of Noah will no more go over the earth, so I have sworn that I will not be angry with you, nor rebuke you.'),
  ('Isaiah', 54, 10, 'For the mountains may depart, and the hills be removed, but my loving kindness will not depart from you, and my covenant of peace will not be removed,” says the LORD who has mercy on you.'),
  ('Isaiah', 54, 11, '“You afflicted, tossed with storms, and not comforted, behold, I will set your stones in beautiful colors, and lay your foundations with sapphires.'),
  ('Isaiah', 54, 12, 'I will make your pinnacles of rubies, your gates of sparkling jewels, and all your walls of precious stones.'),
  ('Isaiah', 54, 13, 'All your children will be taught by the LORD, and your children’s peace will be great.'),
  ('Isaiah', 54, 14, 'You will be established in righteousness. You will be far from oppression, for you will not be afraid, and far from terror, for it shall not come near you.'),
  ('Isaiah', 54, 15, 'Behold, they may gather together, but not by me. Whoever gathers together against you will fall because of you.'),
  ('Isaiah', 54, 16, '“Behold, I have created the blacksmith who fans the coals into flame, and forges a weapon for his work; and I have created the destroyer to destroy.'),
  ('Isaiah', 54, 17, 'No weapon that is formed against you will prevail; and you will condemn every tongue that rises against you in judgment. This is the heritage of the LORD’s servants, and their righteousness is of me,” says the LORD.'),
  ('Isaiah', 55, 1, '“Hey! Come, everyone who thirsts, to the waters! Come, he who has no money, buy, and eat! Yes, come, buy wine and milk without money and without price.'),
  ('Isaiah', 55, 2, 'Why do you spend money for that which is not bread, and your labor for that which doesn’t satisfy? Listen diligently to me, and eat that which is good, and let your soul delight itself in richness.'),
  ('Isaiah', 55, 3, 'Turn your ear, and come to me. Hear, and your soul will live. I will make an everlasting covenant with you, even the sure mercies of David.'),
  ('Isaiah', 55, 4, 'Behold, I have given him for a witness to the peoples, a leader and commander to the peoples.'),
  ('Isaiah', 55, 5, 'Behold, you shall call a nation that you don’t know; and a nation that didn’t know you shall run to you, because of the LORD your God, and for the Holy One of Israel; for he has glorified you.”'),
  ('Isaiah', 55, 6, 'Seek the LORD while he may be found. Call on him while he is near.'),
  ('Isaiah', 55, 7, 'Let the wicked forsake his way, and the unrighteous man his thoughts. Let him return to the LORD, and he will have mercy on him, to our God, for he will freely pardon.'),
  ('Isaiah', 55, 8, '“For my thoughts are not your thoughts, and your ways are not my ways,” says the LORD.'),
  ('Isaiah', 55, 9, '“For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.'),
  ('Isaiah', 55, 10, 'For as the rain comes down and the snow from the sky, and doesn’t return there, but waters the earth, and makes it grow and bud, and gives seed to the sower and bread to the eater;'),
  ('Isaiah', 55, 11, 'so is my word that goes out of my mouth: it will not return to me void, but it will accomplish that which I please, and it will prosper in the thing I sent it to do.'),
  ('Isaiah', 55, 12, 'For you shall go out with joy, and be led out with peace. The mountains and the hills will break out before you into singing; and all the trees of the fields will clap their hands.'),
  ('Isaiah', 55, 13, 'Instead of the thorn the cypress tree will come up; and instead of the brier the myrtle tree will come up. It will make a name for the LORD, for an everlasting sign that will not be cut off.”'),
  ('Isaiah', 56, 1, 'The LORD says: “Maintain justice and do what is right, for my salvation is near and my righteousness will soon be revealed.'),
  ('Isaiah', 56, 2, 'Blessed is the man who does this, and the son of man who holds it fast; who keeps the Sabbath without profaning it and keeps his hand from doing any evil.”'),
  ('Isaiah', 56, 3, 'Let no foreigner who has joined himself to the LORD speak, saying, “The LORD will surely separate me from his people.” Do not let the eunuch say, “Behold, I am a dry tree.”'),
  ('Isaiah', 56, 4, 'For the LORD says, “To the eunuchs who keep my Sabbaths, choose the things that please me, and hold fast to my covenant,'),
  ('Isaiah', 56, 5, 'I will give them in my house and within my walls a memorial and a name better than of sons and of daughters. I will give them an everlasting name that will not be cut off.'),
  ('Isaiah', 56, 6, 'Also the foreigners who join themselves to the LORD to serve him, and to love the LORD’s name, to be his servants, everyone who keeps the Sabbath from profaning it, and holds fast my covenant,'),
  ('Isaiah', 56, 7, 'I will bring these to my holy mountain, and make them joyful in my house of prayer. Their burnt offerings and their sacrifices will be accepted on my altar; for my house will be called a house of prayer for all peoples.”'),
  ('Isaiah', 56, 8, 'The Lord GOD, who gathers the outcasts of Israel, says, “I will yet gather others to him, in addition to his own who are gathered.”'),
  ('Isaiah', 56, 9, 'All you animals of the field, come to devour, all you animals in the forest.'),
  ('Isaiah', 56, 10, 'His watchmen are blind. They are all without knowledge. They are all mute dogs. They can’t bark— dreaming, lying down, loving to slumber.'),
  ('Isaiah', 56, 11, 'Yes, the dogs are greedy. They can never have enough. They are shepherds who can’t understand. They have all turned to their own way, each one to his gain, from every quarter.'),
  ('Isaiah', 56, 12, '“Come,” they say, “I will get wine, and we will fill ourselves with strong drink; and tomorrow will be as today, great beyond measure.”'),
  ('Isaiah', 57, 1, 'The righteous perish, and no one lays it to heart. Merciful men are taken away, and no one considers that the righteous is taken away from the evil.'),
  ('Isaiah', 57, 2, 'He enters into peace. They rest in their beds, each one who walks in his uprightness.'),
  ('Isaiah', 57, 3, '“But draw near here, you sons of a sorceress, you offspring of adulterers and prostitutes.'),
  ('Isaiah', 57, 4, 'Whom do you mock? Against whom do you make a wide mouth and stick out your tongue? Aren’t you children of disobedience and offspring of falsehood,'),
  ('Isaiah', 57, 5, 'you who inflame yourselves among the oaks, under every green tree; who kill the children in the valleys, under the clefts of the rocks?'),
  ('Isaiah', 57, 6, 'Among the smooth stones of the valley is your portion. They, they are your lot. You have even poured a drink offering to them. You have offered an offering. Shall I be appeased for these things?'),
  ('Isaiah', 57, 7, 'On a high and lofty mountain you have set your bed. You also went up there to offer sacrifice.'),
  ('Isaiah', 57, 8, 'You have set up your memorial behind the doors and the posts, for you have exposed yourself to someone besides me, and have gone up. You have enlarged your bed and made a covenant for yourself with them. You loved what you saw on their bed.'),
  ('Isaiah', 57, 9, 'You went to the king with oil, increased your perfumes, sent your ambassadors far off, and degraded yourself even to Sheol.'),
  ('Isaiah', 57, 10, 'You were wearied with the length of your ways; yet you didn’t say, ‘It is in vain.’ You found a reviving of your strength; therefore you weren’t faint.'),
  ('Isaiah', 57, 11, '“Whom have you dreaded and feared, so that you lie, and have not remembered me, nor laid it to your heart? Haven’t I held my peace for a long time, and you don’t fear me?'),
  ('Isaiah', 57, 12, 'I will declare your righteousness; and as for your works, they will not benefit you.'),
  ('Isaiah', 57, 13, 'When you cry, let those whom you have gathered deliver you, but the wind will take them. A breath will carry them all away, but he who takes refuge in me will possess the land, and will inherit my holy mountain.”'),
  ('Isaiah', 57, 14, 'He will say, “Build up, build up, prepare the way! Remove the stumbling-block out of the way of my people.”'),
  ('Isaiah', 57, 15, 'For the high and lofty One who inhabits eternity, whose name is Holy, says: “I dwell in the high and holy place, with him also who is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite.'),
  ('Isaiah', 57, 16, 'For I will not contend forever, neither will I always be angry; for the spirit would faint before me, and the souls whom I have made.'),
  ('Isaiah', 57, 17, 'I was angry because of the iniquity of his covetousness and struck him. I hid myself and was angry; and he went on backsliding in the way of his heart.'),
  ('Isaiah', 57, 18, 'I have seen his ways, and will heal him. I will lead him also, and restore comforts to him and to his mourners.'),
  ('Isaiah', 57, 19, 'I create the fruit of the lips: Peace, peace, to him who is far off and to him who is near,” says the LORD; “and I will heal them.”'),
  ('Isaiah', 57, 20, 'But the wicked are like the troubled sea; for it can’t rest and its waters cast up mire and mud.'),
  ('Isaiah', 57, 21, '“There is no peace”, says my God, “for the wicked.”'),
  ('Isaiah', 58, 1, '“Cry aloud! Don’t spare! Lift up your voice like a trumpet! Declare to my people their disobedience, and to the house of Jacob their sins.'),
  ('Isaiah', 58, 2, 'Yet they seek me daily, and delight to know my ways. As a nation that did righteousness, and didn’t forsake the ordinance of their God, they ask of me righteous judgments. They delight to draw near to God.'),
  ('Isaiah', 58, 3, '‘Why have we fasted,’ they say, ‘and you don’t see? Why have we afflicted our soul, and you don’t notice?’ “Behold, in the day of your fast you find pleasure, and oppress all your laborers.'),
  ('Isaiah', 58, 4, 'Behold, you fast for strife and contention, and to strike with the fist of wickedness. You don’t fast today so as to make your voice to be heard on high.'),
  ('Isaiah', 58, 5, 'Is this the fast that I have chosen? A day for a man to humble his soul? Is it to bow down his head like a reed, and to spread sackcloth and ashes under himself? Will you call this a fast, and an acceptable day to the LORD?'),
  ('Isaiah', 58, 6, '“Isn’t this the fast that I have chosen: to release the bonds of wickedness, to undo the straps of the yoke, to let the oppressed go free, and that you break every yoke?'),
  ('Isaiah', 58, 7, 'Isn’t it to distribute your bread to the hungry, and that you bring the poor who are cast out to your house? When you see the naked, that you cover him; and that you not hide yourself from your own flesh?'),
  ('Isaiah', 58, 8, 'Then your light will break out as the morning, and your healing will appear quickly; then your righteousness shall go before you, and the LORD’s glory will be your rear guard.'),
  ('Isaiah', 58, 9, 'Then you will call, and the LORD will answer. You will cry for help, and he will say, ‘Here I am.’ “If you take away from among you the yoke, finger pointing, and speaking wickedly;'),
  ('Isaiah', 58, 10, 'and if you pour out your soul to the hungry, and satisfy the afflicted soul, then your light will rise in darkness, and your obscurity will be as the noonday;'),
  ('Isaiah', 58, 11, 'and the LORD will guide you continually, satisfy your soul in dry places, and make your bones strong. You will be like a watered garden, and like a spring of water whose waters don’t fail.'),
  ('Isaiah', 58, 12, 'Those who will be of you will build the old waste places. You will raise up the foundations of many generations. You will be called Repairer of the Breach, Restorer of Paths with Dwellings.'),
  ('Isaiah', 58, 13, '“If you turn away your foot from the Sabbath, from doing your pleasure on my holy day, and call the Sabbath a delight, and the holy of the LORD honorable, and honor it, not doing your own ways, nor finding your own pleasure, nor speaking your own words,');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 58, 14, 'then you will delight yourself in the LORD, and I will make you to ride on the high places of the earth, and I will feed you with the heritage of Jacob your father;” for the LORD’s mouth has spoken it.'),
  ('Isaiah', 59, 1, 'Behold, the LORD’s hand is not shortened, that it can’t save; nor his ear dull, that it can’t hear.'),
  ('Isaiah', 59, 2, 'But your iniquities have separated you and your God, and your sins have hidden his face from you, so that he will not hear.'),
  ('Isaiah', 59, 3, 'For your hands are defiled with blood, and your fingers with iniquity. Your lips have spoken lies. Your tongue mutters wickedness.'),
  ('Isaiah', 59, 4, 'No one sues in righteousness, and no one pleads in truth. They trust in vanity and speak lies. They conceive mischief and give birth to iniquity.'),
  ('Isaiah', 59, 5, 'They hatch adders’ eggs and weave the spider’s web. He who eats of their eggs dies; and that which is crushed breaks out into a viper.'),
  ('Isaiah', 59, 6, 'Their webs won’t become garments. They won’t cover themselves with their works. Their works are works of iniquity, and acts of violence are in their hands.'),
  ('Isaiah', 59, 7, 'Their feet run to evil, and they hurry to shed innocent blood. Their thoughts are thoughts of iniquity. Desolation and destruction are in their paths.'),
  ('Isaiah', 59, 8, 'They don’t know the way of peace; and there is no justice in their ways. They have made crooked paths for themselves; whoever goes in them doesn’t know peace.'),
  ('Isaiah', 59, 9, 'Therefore justice is far from us, and righteousness doesn’t overtake us. We look for light, but see darkness; for brightness, but we walk in obscurity.'),
  ('Isaiah', 59, 10, 'We grope for the wall like the blind. Yes, we grope as those who have no eyes. We stumble at noon as if it were twilight. Among those who are strong, we are like dead men.'),
  ('Isaiah', 59, 11, 'We all roar like bears and moan sadly like doves. We look for justice, but there is none, for salvation, but it is far off from us.'),
  ('Isaiah', 59, 12, 'For our transgressions are multiplied before you, and our sins testify against us; for our transgressions are with us, and as for our iniquities, we know them:'),
  ('Isaiah', 59, 13, 'transgressing and denying the LORD, and turning away from following our God, speaking oppression and revolt, conceiving and uttering from the heart words of falsehood.'),
  ('Isaiah', 59, 14, 'Justice is turned away backward, and righteousness stands far away; for truth has fallen in the street, and uprightness can’t enter.'),
  ('Isaiah', 59, 15, 'Yes, truth is lacking; and he who departs from evil makes himself a prey. The LORD saw it, and it displeased him that there was no justice.'),
  ('Isaiah', 59, 16, 'He saw that there was no man, and wondered that there was no intercessor. Therefore his own arm brought salvation to him; and his righteousness sustained him.'),
  ('Isaiah', 59, 17, 'He put on righteousness as a breastplate, and a helmet of salvation on his head. He put on garments of vengeance for clothing, and was clad with zeal as a mantle.'),
  ('Isaiah', 59, 18, 'According to their deeds, he will repay as appropriate: wrath to his adversaries, recompense to his enemies. He will repay the islands their due.'),
  ('Isaiah', 59, 19, 'So they will fear the LORD’s name from the west, and his glory from the rising of the sun; for he will come as a rushing stream, which the LORD’s breath drives.'),
  ('Isaiah', 59, 20, '“A Redeemer will come to Zion, and to those who turn from disobedience in Jacob,” says the LORD.'),
  ('Isaiah', 59, 21, '“As for me, this is my covenant with them,” says the LORD. “My Spirit who is on you, and my words which I have put in your mouth shall not depart out of your mouth, nor out of the mouth of your offspring, nor out of the mouth of your offspring’s offspring,” says the LORD, “from now on and forever.”'),
  ('Isaiah', 60, 1, '“Arise, shine; for your light has come, and the LORD’s glory has risen on you!'),
  ('Isaiah', 60, 2, 'For behold, darkness will cover the earth, and thick darkness the peoples; but the LORD will arise on you, and his glory shall be seen on you.'),
  ('Isaiah', 60, 3, 'Nations will come to your light, and kings to the brightness of your rising.'),
  ('Isaiah', 60, 4, '“Lift up your eyes all around, and see: they all gather themselves together. They come to you. Your sons will come from far away, and your daughters will be carried in arms.'),
  ('Isaiah', 60, 5, 'Then you shall see and be radiant, and your heart will thrill and be enlarged; because the abundance of the sea will be turned to you. The wealth of the nations will come to you.'),
  ('Isaiah', 60, 6, 'A multitude of camels will cover you, the dromedaries of Midian and Ephah. All from Sheba will come. They will bring gold and frankincense, and will proclaim the praises of the LORD.'),
  ('Isaiah', 60, 7, 'All the flocks of Kedar will be gathered together to you. The rams of Nebaioth will serve you. They will be accepted as offerings on my altar; and I will beautify my glorious house.'),
  ('Isaiah', 60, 8, '“Who are these who fly as a cloud, and as the doves to their windows?'),
  ('Isaiah', 60, 9, 'Surely the islands will wait for me, and the ships of Tarshish first, to bring your sons from far away, their silver and their gold with them, for the name of the LORD your God, and for the Holy One of Israel, because he has glorified you.'),
  ('Isaiah', 60, 10, '“Foreigners will build up your walls, and their kings will serve you; for in my wrath I struck you, but in my favor I have had mercy on you.'),
  ('Isaiah', 60, 11, 'Your gates also shall be open continually; they shall not be shut day nor night, that men may bring to you the wealth of the nations, and their kings led captive.'),
  ('Isaiah', 60, 12, 'For that nation and kingdom that will not serve you shall perish; yes, those nations shall be utterly wasted.'),
  ('Isaiah', 60, 13, '“The glory of Lebanon shall come to you, the cypress tree, the pine, and the box tree together, to beautify the place of my sanctuary; and I will make the place of my feet glorious.'),
  ('Isaiah', 60, 14, 'The sons of those who afflicted you will come bowing to you; and all those who despised you will bow themselves down at the soles of your feet. They will call you the LORD’s City, the Zion of the Holy One of Israel.'),
  ('Isaiah', 60, 15, '“Whereas you have been forsaken and hated, so that no one passed through you, I will make you an eternal excellency, a joy of many generations.'),
  ('Isaiah', 60, 16, 'You will also drink the milk of the nations, and will nurse from royal breasts. Then you will know that I, the LORD, am your Savior, your Redeemer, the Mighty One of Jacob.'),
  ('Isaiah', 60, 17, 'For bronze I will bring gold; for iron I will bring silver; for wood, bronze, and for stones, iron. I will also make peace your governor, and righteousness your ruler.'),
  ('Isaiah', 60, 18, 'Violence shall no more be heard in your land, nor desolation or destruction within your borders; but you will call your walls Salvation, and your gates Praise.'),
  ('Isaiah', 60, 19, 'The sun will be no more your light by day, nor will the brightness of the moon give light to you, but the LORD will be your everlasting light, and your God will be your glory.'),
  ('Isaiah', 60, 20, 'Your sun will not go down any more, nor will your moon withdraw itself; for the LORD will be your everlasting light, and the days of your mourning will end.'),
  ('Isaiah', 60, 21, 'Then your people will all be righteous. They will inherit the land forever, the branch of my planting, the work of my hands, that I may be glorified.'),
  ('Isaiah', 60, 22, 'The little one will become a thousand, and the small one a strong nation. I, the LORD, will do this quickly in its time.”'),
  ('Isaiah', 61, 1, 'The Lord GOD’s Spirit is on me, because the LORD has anointed me to preach good news to the humble. He has sent me to bind up the broken hearted, to proclaim liberty to the captives and release to those who are bound,'),
  ('Isaiah', 61, 2, 'to proclaim the year of the LORD’s favor and the day of vengeance of our God, to comfort all who mourn,'),
  ('Isaiah', 61, 3, 'to provide for those who mourn in Zion, to give to them a garland for ashes, the oil of joy for mourning, the garment of praise for the spirit of heaviness, that they may be called trees of righteousness, the planting of the LORD, that he may be glorified.'),
  ('Isaiah', 61, 4, 'They will rebuild the old ruins. They will raise up the former devastated places. They will repair the ruined cities that have been devastated for many generations.'),
  ('Isaiah', 61, 5, 'Strangers will stand and feed your flocks. Foreigners will work your fields and your vineyards.'),
  ('Isaiah', 61, 6, 'But you will be called the LORD’s priests. Men will call you the servants of our God. You will eat the wealth of the nations. You will boast in their glory.'),
  ('Isaiah', 61, 7, 'Instead of your shame you will have double. Instead of dishonor, they will rejoice in their portion. Therefore in their land they will possess double. Everlasting joy will be to them.'),
  ('Isaiah', 61, 8, '“For I, the LORD, love justice. I hate robbery and iniquity. I will give them their reward in truth and I will make an everlasting covenant with them.'),
  ('Isaiah', 61, 9, 'Their offspring will be known among the nations, and their offspring among the peoples. All who see them will acknowledge them, that they are the offspring which the LORD has blessed.”'),
  ('Isaiah', 61, 10, 'I will greatly rejoice in the LORD! My soul will be joyful in my God, for he has clothed me with the garments of salvation. He has covered me with the robe of righteousness, as a bridegroom decks himself with a garland and as a bride adorns herself with her jewels.'),
  ('Isaiah', 61, 11, 'For as the earth produces its bud, and as the garden causes the things that are sown in it to spring up, so the Lord GOD will cause righteousness and praise to spring up before all the nations.'),
  ('Isaiah', 62, 1, 'For Zion’s sake I will not hold my peace, and for Jerusalem’s sake I will not rest, until her righteousness shines out like the dawn, and her salvation like a burning lamp.'),
  ('Isaiah', 62, 2, 'The nations will see your righteousness, and all kings your glory. You will be called by a new name, which the LORD’s mouth will name.'),
  ('Isaiah', 62, 3, 'You will also be a crown of beauty in the LORD’s hand, and a royal diadem in your God’s hand.'),
  ('Isaiah', 62, 4, 'You will not be called Forsaken any more, nor will your land be called Desolate any more; but you will be called Hephzibah, and your land Beulah; for the LORD delights in you, and your land will be married.'),
  ('Isaiah', 62, 5, 'For as a young man marries a virgin, so your sons will marry you. As a bridegroom rejoices over his bride, so your God will rejoice over you.'),
  ('Isaiah', 62, 6, 'I have set watchmen on your walls, Jerusalem. They will never be silent day nor night. You who call on the LORD, take no rest,'),
  ('Isaiah', 62, 7, 'and give him no rest until he establishes, and until he makes Jerusalem a praise in the earth.'),
  ('Isaiah', 62, 8, 'The LORD has sworn by his right hand, and by the arm of his strength, “Surely I will no more give your grain to be food for your enemies, and foreigners will not drink your new wine, for which you have labored,'),
  ('Isaiah', 62, 9, 'but those who have harvested it will eat it, and praise the LORD. Those who have gathered it will drink it in the courts of my sanctuary.”'),
  ('Isaiah', 62, 10, 'Go through, go through the gates! Prepare the way of the people! Build up, build up the highway! Gather out the stones! Lift up a banner for the peoples.'),
  ('Isaiah', 62, 11, 'Behold, the LORD has proclaimed to the end of the earth: “Say to the daughter of Zion, ‘Behold, your salvation comes! Behold, his reward is with him, and his recompense before him!’”'),
  ('Isaiah', 62, 12, 'They will call them “The Holy People, The LORD’s Redeemed”. You will be called “Sought Out, A City Not Forsaken”.'),
  ('Isaiah', 63, 1, 'Who is this who comes from Edom, with dyed garments from Bozrah? Who is this who is glorious in his clothing, marching in the greatness of his strength? “It is I who speak in righteousness, mighty to save.”'),
  ('Isaiah', 63, 2, 'Why is your clothing red, and your garments like him who treads in the wine vat?'),
  ('Isaiah', 63, 3, '“I have trodden the wine press alone. Of the peoples, no one was with me. Yes, I trod them in my anger and trampled them in my wrath. Their lifeblood is sprinkled on my garments, and I have stained all my clothing.'),
  ('Isaiah', 63, 4, 'For the day of vengeance was in my heart, and the year of my redeemed has come.'),
  ('Isaiah', 63, 5, 'I looked, and there was no one to help; and I wondered that there was no one to uphold. Therefore my own arm brought salvation to me. My own wrath upheld me.'),
  ('Isaiah', 63, 6, 'I trod down the peoples in my anger and made them drunk in my wrath. I poured their lifeblood out on the earth.”'),
  ('Isaiah', 63, 7, 'I will tell of the loving kindnesses of the LORD and the praises of the LORD, according to all that the LORD has given to us, and the great goodness toward the house of Israel, which he has given to them according to his mercies, and according to the multitude of his loving kindnesses.'),
  ('Isaiah', 63, 8, 'For he said, “Surely, they are my people, children who will not deal falsely;” so he became their Savior.'),
  ('Isaiah', 63, 9, 'In all their affliction he was afflicted, and the angel of his presence saved them. In his love and in his pity he redeemed them. He bore them, and carried them all the days of old.'),
  ('Isaiah', 63, 10, 'But they rebelled and grieved his Holy Spirit. Therefore he turned and became their enemy, and he himself fought against them.'),
  ('Isaiah', 63, 11, 'Then he remembered the days of old, Moses and his people, saying, “Where is he who brought them up out of the sea with the shepherds of his flock? Where is he who put his Holy Spirit among them?”'),
  ('Isaiah', 63, 12, 'Who caused his glorious arm to be at Moses’ right hand? Who divided the waters before them, to make himself an everlasting name?'),
  ('Isaiah', 63, 13, 'Who led them through the depths, like a horse in the wilderness, so that they didn’t stumble?'),
  ('Isaiah', 63, 14, 'As the livestock that go down into the valley, the LORD’s Spirit caused them to rest. So you led your people to make yourself a glorious name.'),
  ('Isaiah', 63, 15, 'Look down from heaven, and see from the habitation of your holiness and of your glory. Where are your zeal and your mighty acts? The yearning of your heart and your compassion is restrained toward me.'),
  ('Isaiah', 63, 16, 'For you are our Father, though Abraham doesn’t know us, and Israel does not acknowledge us. You, LORD, are our Father. Our Redeemer from everlasting is your name.'),
  ('Isaiah', 63, 17, 'O LORD, why do you make us wander from your ways, and harden our heart from your fear? Return for your servants’ sake, the tribes of your inheritance.'),
  ('Isaiah', 63, 18, 'Your holy people possessed it but a little while. Our adversaries have trodden down your sanctuary.'),
  ('Isaiah', 63, 19, 'We have become like those over whom you never ruled, like those who were not called by your name.'),
  ('Isaiah', 64, 1, 'Oh that you would tear the heavens, that you would come down, that the mountains might quake at your presence—'),
  ('Isaiah', 64, 2, 'as when fire kindles the brushwood, and the fire causes the water to boil. Make your name known to your adversaries, that the nations may tremble at your presence!'),
  ('Isaiah', 64, 3, 'When you did awesome things which we didn’t look for, you came down, and the mountains quaked at your presence.'),
  ('Isaiah', 64, 4, 'For from of old men have not heard, nor perceived by the ear, nor has the eye seen a God besides you, who works for him who waits for him.'),
  ('Isaiah', 64, 5, 'You meet him who rejoices and does righteousness, those who remember you in your ways. Behold, you were angry, and we sinned. We have been in sin for a long time. Shall we be saved?'),
  ('Isaiah', 64, 6, 'For we have all become like one who is unclean, and all our righteousness is like a polluted garment. We all fade like a leaf; and our iniquities, like the wind, take us away.'),
  ('Isaiah', 64, 7, 'There is no one who calls on your name, who stirs himself up to take hold of you; for you have hidden your face from us, and have consumed us by means of our iniquities.'),
  ('Isaiah', 64, 8, 'But now, LORD, you are our Father. We are the clay and you our potter. We all are the work of your hand.'),
  ('Isaiah', 64, 9, 'Don’t be furious, LORD. Don’t remember iniquity forever. Look and see, we beg you, we are all your people.'),
  ('Isaiah', 64, 10, 'Your holy cities have become a wilderness. Zion has become a wilderness, Jerusalem a desolation.'),
  ('Isaiah', 64, 11, 'Our holy and our beautiful house where our fathers praised you is burned with fire. All our pleasant places are laid waste.'),
  ('Isaiah', 64, 12, 'Will you hold yourself back for these things, LORD? Will you keep silent and punish us very severely?'),
  ('Isaiah', 65, 1, '“I am inquired of by those who didn’t ask. I am found by those who didn’t seek me. I said, ‘See me, see me,’ to a nation that was not called by my name.'),
  ('Isaiah', 65, 2, 'I have spread out my hands all day to a rebellious people, who walk in a way that is not good, after their own thoughts;');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Isaiah', 65, 3, 'a people who provoke me to my face continually, sacrificing in gardens, and burning incense on bricks;'),
  ('Isaiah', 65, 4, 'who sit among the graves, and spend nights in secret places; who eat pig’s meat, and broth of abominable things is in their vessels;'),
  ('Isaiah', 65, 5, 'who say, ‘Stay by yourself, don’t come near to me, for I am holier than you.’ These are smoke in my nose, a fire that burns all day.'),
  ('Isaiah', 65, 6, '“Behold, it is written before me: I will not keep silence, but will repay, yes, I will repay into their bosom'),
  ('Isaiah', 65, 7, 'your own iniquities and the iniquities of your fathers together”, says the LORD, “who have burned incense on the mountains, and blasphemed me on the hills. Therefore I will first measure their work into their bosom.”'),
  ('Isaiah', 65, 8, 'The LORD says, “As the new wine is found in the cluster, and one says, ‘Don’t destroy it, for a blessing is in it:’ so I will do for my servants’ sake, that I may not destroy them all.'),
  ('Isaiah', 65, 9, 'I will bring offspring out of Jacob, and out of Judah an inheritor of my mountains. My chosen will inherit it, and my servants will dwell there.'),
  ('Isaiah', 65, 10, 'Sharon will be a fold of flocks, and the valley of Achor a place for herds to lie down in, for my people who have sought me.'),
  ('Isaiah', 65, 11, '“But you who forsake the LORD, who forget my holy mountain, who prepare a table for Fortune, and who fill up mixed wine to Destiny;'),
  ('Isaiah', 65, 12, 'I will destine you to the sword, and you will all bow down to the slaughter; because when I called, you didn’t answer. When I spoke, you didn’t listen; but you did that which was evil in my eyes, and chose that in which I didn’t delight.”'),
  ('Isaiah', 65, 13, 'Therefore the Lord GOD says, “Behold, my servants will eat, but you will be hungry; behold, my servants will drink, but you will be thirsty. Behold, my servants will rejoice, but you will be disappointed.'),
  ('Isaiah', 65, 14, 'Behold, my servants will sing for joy of heart, but you will cry for sorrow of heart, and will wail for anguish of spirit.'),
  ('Isaiah', 65, 15, 'You will leave your name for a curse to my chosen, and the Lord GOD will kill you. He will call his servants by another name,'),
  ('Isaiah', 65, 16, 'so that he who blesses himself in the earth will bless himself in the God of truth; and he who swears in the earth will swear by the God of truth; because the former troubles are forgotten, and because they are hidden from my eyes.'),
  ('Isaiah', 65, 17, '“For, behold, I create new heavens and a new earth; and the former things will not be remembered, nor come into mind.'),
  ('Isaiah', 65, 18, 'But be glad and rejoice forever in that which I create; for, behold, I create Jerusalem to be a delight, and her people a joy.'),
  ('Isaiah', 65, 19, 'I will rejoice in Jerusalem, and delight in my people; and the voice of weeping and the voice of crying will be heard in her no more.'),
  ('Isaiah', 65, 20, '“No more will there be an infant who only lives a few days, nor an old man who has not filled his days; for the child will die one hundred years old, and the sinner being one hundred years old will be accursed.'),
  ('Isaiah', 65, 21, 'They will build houses and inhabit them. They will plant vineyards and eat their fruit.'),
  ('Isaiah', 65, 22, 'They will not build and another inhabit. They will not plant and another eat; for the days of my people will be like the days of a tree, and my chosen will long enjoy the work of their hands.'),
  ('Isaiah', 65, 23, 'They will not labor in vain nor give birth for calamity; for they are the offspring of the LORD’s blessed and their descendants with them.'),
  ('Isaiah', 65, 24, 'It will happen that before they call, I will answer; and while they are yet speaking, I will hear.'),
  ('Isaiah', 65, 25, 'The wolf and the lamb will feed together. The lion will eat straw like the ox. Dust will be the serpent’s food. They will not hurt nor destroy in all my holy mountain,” says the LORD.'),
  ('Isaiah', 66, 1, 'The LORD says: “Heaven is my throne, and the earth is my footstool. What kind of house will you build to me? Where will I rest?'),
  ('Isaiah', 66, 2, 'For my hand has made all these things, and so all these things came to be,” says the LORD: “but I will look to this man, even to he who is poor and of a contrite spirit, and who trembles at my word.'),
  ('Isaiah', 66, 3, 'He who kills an ox is as he who kills a man; he who sacrifices a lamb, as he who breaks a dog’s neck; he who offers an offering, as he who offers pig’s blood; he who burns frankincense, as he who blesses an idol. Yes, they have chosen their own ways, and their soul delights in their abominations.'),
  ('Isaiah', 66, 4, 'I also will choose their delusions, and will bring their fears on them, because when I called, no one answered; when I spoke, they didn’t listen, but they did that which was evil in my eyes, and chose that in which I didn’t delight.”'),
  ('Isaiah', 66, 5, 'Hear the LORD’s word, you who tremble at his word: “Your brothers who hate you, who cast you out for my name’s sake, have said, ‘Let the LORD be glorified, that we may see your joy;’ but it is those who shall be disappointed.'),
  ('Isaiah', 66, 6, 'A voice of tumult from the city, a voice from the temple, a voice of the LORD that repays his enemies what they deserve.'),
  ('Isaiah', 66, 7, '“Before she travailed, she gave birth. Before her pain came, she delivered a son.'),
  ('Isaiah', 66, 8, 'Who has heard of such a thing? Who has seen such things? Shall a land be born in one day? Shall a nation be born at once? For as soon as Zion travailed, she gave birth to her children.'),
  ('Isaiah', 66, 9, 'Shall I bring to the birth, and not cause to be delivered?” says the LORD. “Shall I who cause to give birth shut the womb?” says your God.'),
  ('Isaiah', 66, 10, '“Rejoice with Jerusalem, and be glad for her, all you who love her. Rejoice for joy with her, all you who mourn over her;'),
  ('Isaiah', 66, 11, 'that you may nurse and be satisfied at the comforting breasts; that you may drink deeply, and be delighted with the abundance of her glory.”'),
  ('Isaiah', 66, 12, 'For the LORD says, “Behold, I will extend peace to her like a river, and the glory of the nations like an overflowing stream, and you will nurse. You will be carried on her side, and will be dandled on her knees.'),
  ('Isaiah', 66, 13, 'As one whom his mother comforts, so I will comfort you. You will be comforted in Jerusalem.”'),
  ('Isaiah', 66, 14, 'You will see it, and your heart shall rejoice, and your bones will flourish like the tender grass. The LORD’s hand will be known among his servants; and he will have indignation against his enemies.'),
  ('Isaiah', 66, 15, 'For, behold, the LORD will come with fire, and his chariots will be like the whirlwind; to give his anger with fierceness, and his rebuke with flames of fire.'),
  ('Isaiah', 66, 16, 'For the LORD will execute judgment by fire and by his sword on all flesh; and those slain by the LORD will be many.'),
  ('Isaiah', 66, 17, '“Those who sanctify themselves and purify themselves to go to the gardens, following one in the middle, eating pig’s meat, abominable things, and the mouse, they shall come to an end together,” says the LORD.'),
  ('Isaiah', 66, 18, '“For I know their works and their thoughts. The time comes that I will gather all nations and languages, and they will come, and will see my glory.'),
  ('Isaiah', 66, 19, '“I will set a sign among them, and I will send those who escape of them to the nations, to Tarshish, Pul, and Lud, who draw the bow, to Tubal and Javan, to far-away islands, who have not heard my fame, nor have seen my glory; and they shall declare my glory among the nations.'),
  ('Isaiah', 66, 20, 'They shall bring all your brothers out of all the nations for an offering to the LORD, on horses, in chariots, in litters, on mules, and on camels, to my holy mountain Jerusalem, says the LORD, as the children of Israel bring their offering in a clean vessel into the LORD’s house.'),
  ('Isaiah', 66, 21, 'Of them I will also select priests and Levites,” says the LORD.'),
  ('Isaiah', 66, 22, '“For as the new heavens and the new earth, which I will make, shall remain before me,” says the LORD, “so your offspring and your name shall remain.'),
  ('Isaiah', 66, 23, 'It shall happen that from one new moon to another, and from one Sabbath to another, all flesh will come to worship before me,” says the LORD.'),
  ('Isaiah', 66, 24, '“They will go out, and look at the dead bodies of the men who have transgressed against me; for their worm will not die, nor will their fire be quenched, and they will be loathsome to all mankind.”'),
  ('Jeremiah', 1, 1, 'The words of Jeremiah the son of Hilkiah, one of the priests who were in Anathoth in the land of Benjamin.'),
  ('Jeremiah', 1, 2, 'The LORD’s word came to him in the days of Josiah the son of Amon, king of Judah, in the thirteenth year of his reign.'),
  ('Jeremiah', 1, 3, 'It came also in the days of Jehoiakim the son of Josiah, king of Judah, to the end of the eleventh year of Zedekiah, the son of Josiah, king of Judah, to the carrying away of Jerusalem captive in the fifth month.'),
  ('Jeremiah', 1, 4, 'Now the LORD’s word came to me, saying,'),
  ('Jeremiah', 1, 5, '“Before I formed you in the womb, I knew you. Before you were born, I sanctified you. I have appointed you a prophet to the nations.”'),
  ('Jeremiah', 1, 6, 'Then I said, “Ah, Lord GOD! Behold, I don’t know how to speak; for I am a child.”'),
  ('Jeremiah', 1, 7, 'But the LORD said to me, “Don’t say, ‘I am a child;’ for you must go to whomever I send you, and you must say whatever I command you.'),
  ('Jeremiah', 1, 8, 'Don’t be afraid because of them, for I am with you to rescue you,” says the LORD.'),
  ('Jeremiah', 1, 9, 'Then the LORD stretched out his hand and touched my mouth. Then the LORD said to me, “Behold, I have put my words in your mouth.'),
  ('Jeremiah', 1, 10, 'Behold, I have today set you over the nations and over the kingdoms, to uproot and to tear down, to destroy and to overthrow, to build and to plant.”'),
  ('Jeremiah', 1, 11, 'Moreover the LORD’s word came to me, saying, “Jeremiah, what do you see?” I said, “I see a branch of an almond tree.”'),
  ('Jeremiah', 1, 12, 'Then the LORD said to me, “You have seen well; for I watch over my word to perform it.”'),
  ('Jeremiah', 1, 13, 'The LORD’s word came to me the second time, saying, “What do you see?” I said, “I see a boiling cauldron; and it is tipping away from the north.”'),
  ('Jeremiah', 1, 14, 'Then the LORD said to me, “Out of the north, evil will break out on all the inhabitants of the land.'),
  ('Jeremiah', 1, 15, 'For behold, I will call all the families of the kingdoms of the north,” says the LORD. “They will come, and they will each set his throne at the entrance of the gates of Jerusalem, and against all its walls all around, and against all the cities of Judah.'),
  ('Jeremiah', 1, 16, 'I will utter my judgments against them concerning all their wickedness, in that they have forsaken me, and have burned incense to other gods, and worshiped the works of their own hands.'),
  ('Jeremiah', 1, 17, '“You therefore put your belt on your waist, arise, and say to them all that I command you. Don’t be dismayed at them, lest I dismay you before them.'),
  ('Jeremiah', 1, 18, 'For behold, I have made you today a fortified city, an iron pillar, and bronze walls against the whole land—against the kings of Judah, against its princes, against its priests, and against the people of the land.'),
  ('Jeremiah', 1, 19, 'They will fight against you, but they will not prevail against you; for I am with you”, says the LORD, “to rescue you.”'),
  ('Jeremiah', 2, 1, 'The LORD’s word came to me, saying,'),
  ('Jeremiah', 2, 2, '“Go and proclaim in the ears of Jerusalem, saying, ‘The LORD says, “I remember for you the kindness of your youth, your love as a bride, how you went after me in the wilderness, in a land that was not sown.'),
  ('Jeremiah', 2, 3, 'Israel was holiness to the LORD, the first fruits of his increase. All who devour him will be held guilty. Evil will come on them,”’ says the LORD.”'),
  ('Jeremiah', 2, 4, 'Hear the LORD’s word, O house of Jacob, and all the families of the house of Israel!'),
  ('Jeremiah', 2, 5, 'The LORD says, “What unrighteousness have your fathers found in me, that they have gone far from me, and have walked after worthless vanity, and have become worthless?'),
  ('Jeremiah', 2, 6, 'They didn’t say, ‘Where is the LORD who brought us up out of the land of Egypt, who led us through the wilderness, through a land of deserts and of pits, through a land of drought and of the shadow of death, through a land that no one passed through, and where no man lived?’'),
  ('Jeremiah', 2, 7, 'I brought you into a plentiful land to eat its fruit and its goodness; but when you entered, you defiled my land, and made my heritage an abomination.'),
  ('Jeremiah', 2, 8, 'The priests didn’t say, ‘Where is the LORD?’ and those who handle the law didn’t know me. The rulers also transgressed against me, and the prophets prophesied by Baal and followed things that do not profit.'),
  ('Jeremiah', 2, 9, '“Therefore I will yet contend with you,” says the LORD, “and I will contend with your children’s children.'),
  ('Jeremiah', 2, 10, 'For pass over to the islands of Kittim, and see. Send to Kedar, and consider diligently, and see if there has been such a thing.'),
  ('Jeremiah', 2, 11, 'Has a nation changed its gods, which really are no gods? But my people have changed their glory for that which doesn’t profit.'),
  ('Jeremiah', 2, 12, '“Be astonished, you heavens, at this and be horribly afraid. Be very desolate,” says the LORD.'),
  ('Jeremiah', 2, 13, '“For my people have committed two evils: they have forsaken me, the spring of living waters, and cut out cisterns for themselves: broken cisterns that can’t hold water.'),
  ('Jeremiah', 2, 14, 'Is Israel a slave? Is he born into slavery? Why has he become a captive?'),
  ('Jeremiah', 2, 15, 'The young lions have roared at him and raised their voices. They have made his land waste. His cities are burned up, without inhabitant.'),
  ('Jeremiah', 2, 16, 'The children also of Memphis and Tahpanhes have broken the crown of your head.'),
  ('Jeremiah', 2, 17, '“Haven’t you brought this on yourself, in that you have forsaken the LORD your God, when he led you by the way?'),
  ('Jeremiah', 2, 18, 'Now what do you gain by going to Egypt, to drink the waters of the Shihor? Or why do you go on the way to Assyria, to drink the waters of the River?'),
  ('Jeremiah', 2, 19, '“Your own wickedness will correct you, and your backsliding will rebuke you. Know therefore and see that it is an evil and bitter thing, that you have forsaken the LORD your God, and that my fear is not in you,” says the Lord, GOD of Armies.'),
  ('Jeremiah', 2, 20, '“For long ago I broke off your yoke, and burst your bonds. You said, ‘I will not serve;’ for on every high hill and under every green tree you bowed yourself, playing the prostitute.'),
  ('Jeremiah', 2, 21, 'Yet I had planted you a noble vine, a pure and faithful seed. How then have you turned into the degenerate branches of a foreign vine to me?'),
  ('Jeremiah', 2, 22, 'For though you wash yourself with lye, and use much soap, yet your iniquity is marked before me,” says the Lord GOD.'),
  ('Jeremiah', 2, 23, '“How can you say, ‘I am not defiled. I have not gone after the Baals’? See your way in the valley. Know what you have done. You are a swift dromedary traversing her ways,'),
  ('Jeremiah', 2, 24, 'a wild donkey used to the wilderness, that sniffs the wind in her craving. When she is in heat, who can turn her away? All those who seek her will not weary themselves. In her month, they will find her.'),
  ('Jeremiah', 2, 25, '“Keep your feet from being bare, and your throat from thirst. But you said, ‘It is in vain. No, for I have loved strangers, and I will go after them.’'),
  ('Jeremiah', 2, 26, 'As the thief is ashamed when he is found, so the house of Israel is ashamed— they, their kings, their princes, their priests, and their prophets,'),
  ('Jeremiah', 2, 27, 'who tell wood, ‘You are my father,’ and a stone, ‘You have given birth to me,’ for they have turned their back to me, and not their face, but in the time of their trouble they will say, ‘Arise, and save us!’'),
  ('Jeremiah', 2, 28, '“But where are your gods that you have made for yourselves? Let them arise, if they can save you in the time of your trouble, for you have as many gods as you have towns, O Judah.'),
  ('Jeremiah', 2, 29, '“Why will you contend with me? You all have transgressed against me,” says the LORD.'),
  ('Jeremiah', 2, 30, '“I have struck your children in vain. They received no correction. Your own sword has devoured your prophets, like a destroying lion.'),
  ('Jeremiah', 2, 31, 'Generation, consider the LORD’s word. Have I been a wilderness to Israel? Or a land of thick darkness? Why do my people say, ‘We have broken loose. We will come to you no more’?'),
  ('Jeremiah', 2, 32, '“Can a virgin forget her ornaments, or a bride her attire? Yet my people have forgotten me for days without number.'),
  ('Jeremiah', 2, 33, 'How well you prepare your way to seek love! Therefore you have even taught the wicked women your ways.'),
  ('Jeremiah', 2, 34, 'Also the blood of the souls of the innocent poor is found in your skirts. You didn’t find them breaking in, but it is because of all these things.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 2, 35, '“Yet you said, ‘I am innocent. Surely his anger has turned away from me.’ “Behold, I will judge you, because you say, ‘I have not sinned.’'),
  ('Jeremiah', 2, 36, 'Why do you go about so much to change your ways? You will be ashamed of Egypt also, as you were ashamed of Assyria.'),
  ('Jeremiah', 2, 37, 'You will also leave that place with your hands on your head; for the LORD has rejected those in whom you trust, and you won’t prosper with them.'),
  ('Jeremiah', 3, 1, '“They say, ‘If a man puts away his wife, and she goes from him, and becomes another man’s, should he return to her again?’ Wouldn’t that land be greatly polluted? But you have played the prostitute with many lovers; yet return again to me,” says the LORD.'),
  ('Jeremiah', 3, 2, '“Lift up your eyes to the bare heights, and see! Where have you not been lain with? You have sat waiting for them by the road, as an Arabian in the wilderness. You have polluted the land with your prostitution and with your wickedness.'),
  ('Jeremiah', 3, 3, 'Therefore the showers have been withheld and there has been no latter rain; yet you have had a prostitute’s forehead and you refused to be ashamed.'),
  ('Jeremiah', 3, 4, 'Will you not from this time cry to me, ‘My Father, you are the guide of my youth!’?'),
  ('Jeremiah', 3, 5, '“‘Will he retain his anger forever? Will he keep it to the end?’ Behold, you have spoken and have done evil things, and have had your way.”'),
  ('Jeremiah', 3, 6, 'Moreover, the LORD said to me in the days of Josiah the king, “Have you seen that which backsliding Israel has done? She has gone up on every high mountain and under every green tree, and has played the prostitute there.'),
  ('Jeremiah', 3, 7, 'I said after she had done all these things, ‘She will return to me;’ but she didn’t return, and her treacherous sister Judah saw it.'),
  ('Jeremiah', 3, 8, 'I saw when, for this very cause, that backsliding Israel had committed adultery, I had put her away and given her a certificate of divorce, yet treacherous Judah, her sister, had no fear, but she also went and played the prostitute.'),
  ('Jeremiah', 3, 9, 'Because she took her prostitution lightly, the land was polluted, and she committed adultery with stones and with wood.'),
  ('Jeremiah', 3, 10, 'Yet for all this her treacherous sister, Judah, has not returned to me with her whole heart, but only in pretense,” says the LORD.'),
  ('Jeremiah', 3, 11, 'The LORD said to me, “Backsliding Israel has shown herself more righteous than treacherous Judah.'),
  ('Jeremiah', 3, 12, 'Go, and proclaim these words toward the north, and say, ‘Return, you backsliding Israel,’ says the LORD; ‘I will not look in anger on you, for I am merciful,’ says the LORD. ‘I will not keep anger forever.'),
  ('Jeremiah', 3, 13, 'Only acknowledge your iniquity, that you have transgressed against the LORD your God, and have scattered your ways to the strangers under every green tree, and you have not obeyed my voice,’” says the LORD.'),
  ('Jeremiah', 3, 14, '“Return, backsliding children,” says the LORD, “for I am a husband to you. I will take one of you from a city, and two from a family, and I will bring you to Zion.'),
  ('Jeremiah', 3, 15, 'I will give you shepherds according to my heart, who will feed you with knowledge and understanding.'),
  ('Jeremiah', 3, 16, 'It will come to pass, when you are multiplied and increased in the land in those days,” says the LORD, “they will no longer say, ‘the ark of the LORD’s covenant!’ It will not come to mind. They won’t remember it. They won’t miss it, nor will another be made.'),
  ('Jeremiah', 3, 17, 'At that time they will call Jerusalem ‘The LORD’s Throne;’ and all the nations will be gathered to it, to the LORD’s name, to Jerusalem. They will no longer walk after the stubbornness of their evil heart.'),
  ('Jeremiah', 3, 18, 'In those days the house of Judah will walk with the house of Israel, and they will come together out of the land of the north to the land that I gave for an inheritance to your fathers.'),
  ('Jeremiah', 3, 19, '“But I said, ‘How I desire to put you among the children, and give you a pleasant land, a goodly heritage of the armies of the nations!’ and I said, ‘You shall call me “My Father”, and shall not turn away from following me.’'),
  ('Jeremiah', 3, 20, '“Surely as a wife treacherously departs from her husband, so you have dealt treacherously with me, house of Israel,” says the LORD.'),
  ('Jeremiah', 3, 21, 'A voice is heard on the bare heights, the weeping and the petitions of the children of Israel; because they have perverted their way, they have forgotten the LORD their God.'),
  ('Jeremiah', 3, 22, 'Return, you backsliding children, and I will heal your backsliding. “Behold, we have come to you; for you are the LORD our God.'),
  ('Jeremiah', 3, 23, 'Truly help from the hills, the tumult on the mountains, is in vain. Truly the salvation of Israel is in the LORD our God.'),
  ('Jeremiah', 3, 24, 'But the shameful thing has devoured the labor of our fathers from our youth, their flocks and their herds, their sons and their daughters.'),
  ('Jeremiah', 3, 25, 'Let us lie down in our shame, and let our confusion cover us; for we have sinned against the LORD our God, we and our fathers, from our youth even to this day. We have not obeyed the LORD our God’s voice.”'),
  ('Jeremiah', 4, 1, '“If you will return, Israel,” says the LORD, “if you will return to me, and if you will put away your abominations out of my sight; then you will not be removed;'),
  ('Jeremiah', 4, 2, 'and you will swear, ‘As the LORD lives,’ in truth, in justice, and in righteousness. The nations will bless themselves in him, and they will glory in him.”'),
  ('Jeremiah', 4, 3, 'For the LORD says to the men of Judah and to Jerusalem, “Break up your fallow ground, and don’t sow among thorns.'),
  ('Jeremiah', 4, 4, 'Circumcise yourselves to the LORD, and take away the foreskins of your heart, you men of Judah and inhabitants of Jerusalem; lest my wrath go out like fire, and burn so that no one can quench it, because of the evil of your doings.'),
  ('Jeremiah', 4, 5, 'Declare in Judah, and publish in Jerusalem; and say, ‘Blow the trumpet in the land!’ Cry aloud and say, ‘Assemble yourselves! Let’s go into the fortified cities!’'),
  ('Jeremiah', 4, 6, 'Set up a standard toward Zion. Flee for safety! Don’t wait; for I will bring evil from the north, and a great destruction.”'),
  ('Jeremiah', 4, 7, 'A lion has gone up from his thicket, and a destroyer of nations. He is on his way. He has gone out from his place, to make your land desolate, that your cities be laid waste, without inhabitant.'),
  ('Jeremiah', 4, 8, 'For this, clothe yourself with sackcloth, lament and wail; for the fierce anger of the LORD hasn’t turned back from us.'),
  ('Jeremiah', 4, 9, '“It will happen at that day,” says the LORD, “that the heart of the king will perish, along with the heart of the princes. The priests will be astonished, and the prophets will wonder.”'),
  ('Jeremiah', 4, 10, 'Then I said, “Ah, Lord GOD! Surely you have greatly deceived this people and Jerusalem, saying, ‘You will have peace;’ whereas the sword reaches to the heart.”'),
  ('Jeremiah', 4, 11, 'At that time it will be said to this people and to Jerusalem, “A hot wind blows from the bare heights in the wilderness toward the daughter of my people, not to winnow, nor to cleanse.'),
  ('Jeremiah', 4, 12, 'A full wind from these will come for me. Now I will also utter judgments against them.”'),
  ('Jeremiah', 4, 13, 'Behold, he will come up as clouds, and his chariots will be as the whirlwind. His horses are swifter than eagles. Woe to us! For we are ruined.'),
  ('Jeremiah', 4, 14, 'Jerusalem, wash your heart from wickedness, that you may be saved. How long will your evil thoughts lodge within you?'),
  ('Jeremiah', 4, 15, 'For a voice declares from Dan, and publishes evil from the hills of Ephraim:'),
  ('Jeremiah', 4, 16, '“Tell the nations, behold, publish against Jerusalem, ‘Watchers come from a far country, and raise their voice against the cities of Judah.'),
  ('Jeremiah', 4, 17, 'As keepers of a field, they are against her all around, because she has been rebellious against me,’” says the LORD.'),
  ('Jeremiah', 4, 18, '“Your way and your doings have brought these things to you. This is your wickedness, for it is bitter, for it reaches to your heart.”'),
  ('Jeremiah', 4, 19, 'My anguish, my anguish! I am pained at my very heart! My heart trembles within me. I can’t hold my peace, because you have heard, O my soul, the sound of the trumpet, the alarm of war.'),
  ('Jeremiah', 4, 20, 'Destruction on destruction is decreed, for the whole land is laid waste. Suddenly my tents are destroyed, and my curtains gone in a moment.'),
  ('Jeremiah', 4, 21, 'How long will I see the standard and hear the sound of the trumpet?'),
  ('Jeremiah', 4, 22, '“For my people are foolish. They don’t know me. They are foolish children, and they have no understanding. They are skillful in doing evil, but they don’t know how to do good.”'),
  ('Jeremiah', 4, 23, 'I saw the earth and, behold, it was waste and void, and the heavens, and they had no light.'),
  ('Jeremiah', 4, 24, 'I saw the mountains, and behold, they trembled, and all the hills moved back and forth.'),
  ('Jeremiah', 4, 25, 'I saw, and behold, there was no man, and all the birds of the sky had fled.'),
  ('Jeremiah', 4, 26, 'I saw, and behold, the fruitful field was a wilderness, and all its cities were broken down at the presence of the LORD, before his fierce anger.'),
  ('Jeremiah', 4, 27, 'For the LORD says, “The whole land will be a desolation; yet I will not make a full end.'),
  ('Jeremiah', 4, 28, 'For this the earth will mourn, and the heavens above be black, because I have spoken it. I have planned it, and I have not repented, neither will I turn back from it.”'),
  ('Jeremiah', 4, 29, 'Every city flees for the noise of the horsemen and archers. They go into the thickets and climb up on the rocks. Every city is forsaken, and not a man dwells therein.'),
  ('Jeremiah', 4, 30, 'You, when you are made desolate, what will you do? Though you clothe yourself with scarlet, though you deck yourself with ornaments of gold, though you enlarge your eyes with makeup, you make yourself beautiful in vain. Your lovers despise you. They seek your life.'),
  ('Jeremiah', 4, 31, 'For I have heard a voice as of a woman in travail, the anguish as of her who gives birth to her first child, the voice of the daughter of Zion, who gasps for breath, who spreads her hands, saying, “Woe is me now! For my soul faints before the murderers.”'),
  ('Jeremiah', 5, 1, '“Run back and forth through the streets of Jerusalem, and see now, and know, and seek in its wide places, if you can find a man, if there is anyone who does justly, who seeks truth, then I will pardon her.'),
  ('Jeremiah', 5, 2, 'Though they say, ‘As the LORD lives,’ surely they swear falsely.”'),
  ('Jeremiah', 5, 3, 'O LORD, don’t your eyes look on truth? You have stricken them, but they were not grieved. You have consumed them, but they have refused to receive correction. They have made their faces harder than a rock. They have refused to return.'),
  ('Jeremiah', 5, 4, 'Then I said, “Surely these are poor. They are foolish; for they don’t know the LORD’s way, nor the law of their God.'),
  ('Jeremiah', 5, 5, 'I will go to the great men and will speak to them, for they know the way of the LORD, and the law of their God.” But these with one accord have broken the yoke, and burst the bonds.'),
  ('Jeremiah', 5, 6, 'Therefore a lion out of the forest will kill them. A wolf of the evenings will destroy them. A leopard will watch against their cities. Everyone who goes out there will be torn in pieces, because their transgressions are many and their backsliding has increased.'),
  ('Jeremiah', 5, 7, '“How can I pardon you? Your children have forsaken me, and sworn by what are no gods. When I had fed them to the full, they committed adultery, and assembled themselves in troops at the prostitutes’ houses.'),
  ('Jeremiah', 5, 8, 'They were as fed horses roaming at large. Everyone neighed after his neighbor’s wife.'),
  ('Jeremiah', 5, 9, 'Shouldn’t I punish them for these things?” says the LORD. “Shouldn’t my soul be avenged on such a nation as this?'),
  ('Jeremiah', 5, 10, '“Go up on her walls, and destroy, but don’t make a full end. Take away her branches, for they are not the LORD’s.'),
  ('Jeremiah', 5, 11, 'For the house of Israel and the house of Judah have dealt very treacherously against me,” says the LORD.'),
  ('Jeremiah', 5, 12, 'They have denied the LORD, and said, “It is not he. Evil won’t come on us. We won’t see sword or famine.'),
  ('Jeremiah', 5, 13, 'The prophets will become wind, and the word is not in them. Thus it will be done to them.”'),
  ('Jeremiah', 5, 14, 'Therefore the LORD, the God of Armies says, “Because you speak this word, behold, I will make my words in your mouth fire, and this people wood, and it will devour them.'),
  ('Jeremiah', 5, 15, 'Behold, I will bring a nation on you from far away, house of Israel,” says the LORD. “It is a mighty nation. It is an ancient nation, a nation whose language you don’t know and don’t understand what they say.'),
  ('Jeremiah', 5, 16, 'Their quiver is an open tomb. They are all mighty men.'),
  ('Jeremiah', 5, 17, 'They will eat up your harvest and your bread, which your sons and your daughters should eat. They will eat up your flocks and your herds. They will eat up your vines and your fig trees. They will beat down your fortified cities in which you trust with the sword.'),
  ('Jeremiah', 5, 18, '“But even in those days,” says the LORD, “I will not make a full end of you.'),
  ('Jeremiah', 5, 19, 'It will happen when you say, ‘Why has the LORD our God done all these things to us?’ Then you shall say to them, ‘Just as you have forsaken me and served foreign gods in your land, so you will serve strangers in a land that is not yours.’'),
  ('Jeremiah', 5, 20, '“Declare this in the house of Jacob, and publish it in Judah, saying,'),
  ('Jeremiah', 5, 21, '‘Hear this now, foolish people without understanding, who have eyes, and don’t see, who have ears, and don’t hear:'),
  ('Jeremiah', 5, 22, 'Don’t you fear me?’ says the LORD; ‘Won’t you tremble at my presence, who have placed the sand for the bound of the sea by a perpetual decree, that it can’t pass it? Though its waves toss themselves, yet they can’t prevail. Though they roar, they still can’t pass over it.’'),
  ('Jeremiah', 5, 23, '“But this people has a revolting and a rebellious heart. They have revolted and gone.'),
  ('Jeremiah', 5, 24, 'They don’t say in their heart, ‘Let’s now fear the LORD our God, who gives rain, both the former and the latter, in its season, who preserves to us the appointed weeks of the harvest.’'),
  ('Jeremiah', 5, 25, '“Your iniquities have turned away these things, and your sins have withheld good from you.'),
  ('Jeremiah', 5, 26, 'For wicked men are found among my people. They watch, as fowlers lie in wait. They set a trap. They catch men.'),
  ('Jeremiah', 5, 27, 'As a cage is full of birds, so are their houses full of deceit. Therefore they have become great, and grew rich.'),
  ('Jeremiah', 5, 28, 'They have grown fat. They shine; yes, they excel in deeds of wickedness. They don’t plead the cause, the cause of the fatherless, that they may prosper; and they don’t defend the rights of the needy.'),
  ('Jeremiah', 5, 29, '“Shouldn’t I punish for these things?” says the LORD. “Shouldn’t my soul be avenged on such a nation as this?'),
  ('Jeremiah', 5, 30, '“An astonishing and horrible thing has happened in the land.'),
  ('Jeremiah', 5, 31, 'The prophets prophesy falsely, and the priests rule by their own authority; and my people love to have it so. What will you do in the end of it?'),
  ('Jeremiah', 6, 1, '“Flee for safety, you children of Benjamin, out of the middle of Jerusalem! Blow the trumpet in Tekoa and raise up a signal on Beth Haccherem, for evil looks out from the north with a great destruction.'),
  ('Jeremiah', 6, 2, 'I will cut off the beautiful and delicate one, the daughter of Zion.'),
  ('Jeremiah', 6, 3, 'Shepherds with their flocks will come to her. They will pitch their tents against her all around. They will feed everyone in his place.”'),
  ('Jeremiah', 6, 4, '“Prepare war against her! Arise! Let’s go up at noon. Woe to us! For the day declines, for the shadows of the evening are stretched out.'),
  ('Jeremiah', 6, 5, 'Arise! Let’s go up by night, and let’s destroy her palaces.”'),
  ('Jeremiah', 6, 6, 'For the LORD of Armies said, “Cut down trees, and cast up a mound against Jerusalem. This is the city to be visited. She is filled with oppression within herself.'),
  ('Jeremiah', 6, 7, 'As a well produces its waters, so she produces her wickedness. Violence and destruction is heard in her. Sickness and wounds are continually before me.'),
  ('Jeremiah', 6, 8, 'Be instructed, Jerusalem, lest my soul be alienated from you, lest I make you a desolation, an uninhabited land.”'),
  ('Jeremiah', 6, 9, 'The LORD of Armies says, “They will thoroughly glean the remnant of Israel like a vine. Turn again your hand as a grape gatherer into the baskets.”'),
  ('Jeremiah', 6, 10, 'To whom should I speak and testify, that they may hear? Behold, their ear is uncircumcised, and they can’t listen. Behold, the LORD’s word has become a reproach to them. They have no delight in it.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 6, 11, 'Therefore I am full of the LORD’s wrath. I am weary with holding it in. “Pour it out on the children in the street, and on the assembly of young men together; for even the husband with the wife will be taken, the aged with him who is full of days.'),
  ('Jeremiah', 6, 12, 'Their houses will be turned to others, their fields and their wives together; for I will stretch out my hand on the inhabitants of the land, says the LORD.”'),
  ('Jeremiah', 6, 13, '“For from their least even to their greatest, everyone is given to covetousness. From the prophet even to the priest, everyone deals falsely.'),
  ('Jeremiah', 6, 14, 'They have healed also the hurt of my people superficially, saying, ‘Peace, peace!’ when there is no peace.'),
  ('Jeremiah', 6, 15, 'Were they ashamed when they had committed abomination? No, they were not at all ashamed, neither could they blush. Therefore they will fall among those who fall. When I visit them, they will be cast down,” says the LORD.'),
  ('Jeremiah', 6, 16, 'The LORD says, “Stand in the ways and see, and ask for the old paths, ‘Where is the good way?’ and walk in it, and you will find rest for your souls. But they said, ‘We will not walk in it.’'),
  ('Jeremiah', 6, 17, 'I set watchmen over you, saying, ‘Listen to the sound of the trumpet!’ But they said, ‘We will not listen!’'),
  ('Jeremiah', 6, 18, 'Therefore hear, you nations, and know, congregation, what is among them.'),
  ('Jeremiah', 6, 19, 'Hear, earth! Behold, I will bring evil on this people, even the fruit of their thoughts, because they have not listened to my words; and as for my law, they have rejected it.'),
  ('Jeremiah', 6, 20, 'To what purpose does frankincense from Sheba come to me, and the sweet cane from a far country? Your burnt offerings are not acceptable, and your sacrifices are not pleasing to me.”'),
  ('Jeremiah', 6, 21, 'Therefore the LORD says, “Behold, I will lay stumbling blocks before this people. The fathers and the sons together will stumble against them. The neighbor and his friend will perish.”'),
  ('Jeremiah', 6, 22, 'The LORD says, “Behold, a people comes from the north country. A great nation will be stirred up from the uttermost parts of the earth.'),
  ('Jeremiah', 6, 23, 'They take hold of bow and spear. They are cruel, and have no mercy. Their voice roars like the sea, and they ride on horses, everyone set in array, as a man to the battle, against you, daughter of Zion.”'),
  ('Jeremiah', 6, 24, 'We have heard its report. Our hands become feeble. Anguish has taken hold of us, and pains as of a woman in labor.'),
  ('Jeremiah', 6, 25, 'Don’t go out into the field or walk by the way; for the sword of the enemy and terror are on every side.'),
  ('Jeremiah', 6, 26, 'Daughter of my people, clothe yourself with sackcloth, and wallow in ashes! Mourn, as for an only son, most bitter lamentation, for the destroyer will suddenly come on us.'),
  ('Jeremiah', 6, 27, '“I have made you a tester of metals and a fortress among my people, that you may know and try their way.'),
  ('Jeremiah', 6, 28, 'They are all grievous rebels, going around to slander. They are bronze and iron. All of them deal corruptly.'),
  ('Jeremiah', 6, 29, 'The bellows blow fiercely. The lead is consumed in the fire. In vain they go on refining, for the wicked are not plucked away.'),
  ('Jeremiah', 6, 30, 'Men will call them rejected silver, because the LORD has rejected them.”'),
  ('Jeremiah', 7, 1, 'The word that came to Jeremiah from the LORD, saying,'),
  ('Jeremiah', 7, 2, '“Stand in the gate of the LORD’s house, and proclaim this word there, and say, ‘Hear the LORD’s word, all you of Judah, who enter in at these gates to worship the LORD.’”'),
  ('Jeremiah', 7, 3, 'The LORD of Armies, the God of Israel says, “Amend your ways and your doings, and I will cause you to dwell in this place.'),
  ('Jeremiah', 7, 4, 'Don’t trust in lying words, saying, ‘The LORD’s temple, the LORD’s temple, the LORD’s temple, are these.’'),
  ('Jeremiah', 7, 5, 'For if you thoroughly amend your ways and your doings, if you thoroughly execute justice between a man and his neighbor;'),
  ('Jeremiah', 7, 6, 'if you don’t oppress the foreigner, the fatherless, and the widow, and don’t shed innocent blood in this place, and don’t walk after other gods to your own hurt,'),
  ('Jeremiah', 7, 7, 'then I will cause you to dwell in this place, in the land that I gave to your fathers, from of old even forever more.'),
  ('Jeremiah', 7, 8, 'Behold, you trust in lying words that can’t profit.'),
  ('Jeremiah', 7, 9, 'Will you steal, murder, commit adultery, swear falsely, burn incense to Baal, and walk after other gods that you have not known,'),
  ('Jeremiah', 7, 10, 'then come and stand before me in this house, which is called by my name, and say, ‘We are delivered,’ that you may do all these abominations?'),
  ('Jeremiah', 7, 11, 'Has this house, which is called by my name, become a den of robbers in your eyes? Behold, I myself have seen it,” says the LORD.'),
  ('Jeremiah', 7, 12, '“But go now to my place which was in Shiloh, where I caused my name to dwell at the first, and see what I did to it for the wickedness of my people Israel.'),
  ('Jeremiah', 7, 13, 'Now, because you have done all these works,” says the LORD, “and I spoke to you, rising up early and speaking, but you didn’t hear; and I called you, but you didn’t answer;'),
  ('Jeremiah', 7, 14, 'therefore I will do to the house which is called by my name, in which you trust, and to the place which I gave to you and to your fathers, as I did to Shiloh.'),
  ('Jeremiah', 7, 15, 'I will cast you out of my sight, as I have cast out all your brothers, even the whole offspring of Ephraim.'),
  ('Jeremiah', 7, 16, '“Therefore don’t pray for this people. Don’t lift up a cry or prayer for them or make intercession to me; for I will not hear you.'),
  ('Jeremiah', 7, 17, 'Don’t you see what they do in the cities of Judah and in the streets of Jerusalem?'),
  ('Jeremiah', 7, 18, 'The children gather wood, and the fathers kindle the fire, and the women knead the dough, to make cakes to the queen of the sky, and to pour out drink offerings to other gods, that they may provoke me to anger.'),
  ('Jeremiah', 7, 19, 'Do they provoke me to anger?” says the LORD. “Don’t they provoke themselves, to the confusion of their own faces?”'),
  ('Jeremiah', 7, 20, 'Therefore the Lord GOD says: “Behold, my anger and my wrath will be poured out on this place, on man, on animal, on the trees of the field, and on the fruit of the ground; and it will burn and will not be quenched.”'),
  ('Jeremiah', 7, 21, 'The LORD of Armies, the God of Israel says: “Add your burnt offerings to your sacrifices and eat meat.'),
  ('Jeremiah', 7, 22, 'For I didn’t speak to your fathers or command them in the day that I brought them out of the land of Egypt concerning burnt offerings or sacrifices;'),
  ('Jeremiah', 7, 23, 'but this thing I commanded them, saying, ‘Listen to my voice, and I will be your God, and you shall be my people. Walk in all the way that I command you, that it may be well with you.’'),
  ('Jeremiah', 7, 24, 'But they didn’t listen or turn their ear, but walked in their own counsels and in the stubbornness of their evil heart, and went backward, and not forward.'),
  ('Jeremiah', 7, 25, 'Since the day that your fathers came out of the land of Egypt to this day, I have sent to you all my servants the prophets, daily rising up early and sending them.'),
  ('Jeremiah', 7, 26, 'Yet they didn’t listen to me or incline their ear, but made their neck stiff. They did worse than their fathers.'),
  ('Jeremiah', 7, 27, '“You shall speak all these words to them, but they will not listen to you. You shall also call to them, but they will not answer you.'),
  ('Jeremiah', 7, 28, 'You shall tell them, ‘This is the nation that has not listened to the LORD their God’s voice, nor received instruction. Truth has perished, and is cut off from their mouth.’'),
  ('Jeremiah', 7, 29, 'Cut off your hair, and throw it away, and take up a lamentation on the bare heights; for the LORD has rejected and forsaken the generation of his wrath.'),
  ('Jeremiah', 7, 30, '“For the children of Judah have done that which is evil in my sight,” says the LORD. “They have set their abominations in the house which is called by my name, to defile it.'),
  ('Jeremiah', 7, 31, 'They have built the high places of Topheth, which is in the valley of the son of Hinnom, to burn their sons and their daughters in the fire, which I didn’t command, nor did it come into my mind.'),
  ('Jeremiah', 7, 32, 'Therefore behold, the days come”, says the LORD, “that it will no more be called ‘Topheth’ or ‘The valley of the son of Hinnom’, but ‘The valley of Slaughter’; for they will bury in Topheth until there is no place to bury.'),
  ('Jeremiah', 7, 33, 'The dead bodies of this people will be food for the birds of the sky, and for the animals of the earth. No one will frighten them away.'),
  ('Jeremiah', 7, 34, 'Then I will cause to cease from the cities of Judah and from the streets of Jerusalem the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride; for the land will become a waste.”'),
  ('Jeremiah', 8, 1, '“At that time,” says the LORD, “they will bring the bones of the kings of Judah, the bones of his princes, the bones of the priests, the bones of the prophets, and the bones of the inhabitants of Jerusalem, out of their graves.'),
  ('Jeremiah', 8, 2, 'They will spread them before the sun, the moon, and all the army of the sky, which they have loved, which they have served, after which they have walked, which they have sought, and which they have worshiped. They will not be gathered or be buried. They will be like dung on the surface of the earth.'),
  ('Jeremiah', 8, 3, 'Death will be chosen rather than life by all the residue that remain of this evil family, that remain in all the places where I have driven them,” says the LORD of Armies.'),
  ('Jeremiah', 8, 4, '“Moreover you shall tell them, ‘The LORD says: “‘Do men fall, and not rise up again? Does one turn away, and not return?'),
  ('Jeremiah', 8, 5, 'Why then have the people of Jerusalem fallen back by a perpetual backsliding? They cling to deceit. They refuse to return.'),
  ('Jeremiah', 8, 6, 'I listened and heard, but they didn’t say what is right. No one repents of his wickedness, saying, “What have I done?” Everyone turns to his course, as a horse that rushes headlong in the battle.'),
  ('Jeremiah', 8, 7, 'Yes, the stork in the sky knows her appointed times. The turtledove, the swallow, and the crane observe the time of their coming; but my people don’t know the LORD’s law.'),
  ('Jeremiah', 8, 8, '“‘How do you say, “We are wise, and the LORD’s law is with us”? But, behold, the false pen of the scribes has made that a lie.'),
  ('Jeremiah', 8, 9, 'The wise men are disappointed. They are dismayed and trapped. Behold, they have rejected the LORD’s word. What kind of wisdom is in them?'),
  ('Jeremiah', 8, 10, 'Therefore I will give their wives to others and their fields to those who will possess them. For everyone from the least even to the greatest is given to covetousness; from the prophet even to the priest everyone deals falsely.'),
  ('Jeremiah', 8, 11, 'They have healed the hurt of the daughter of my people slightly, saying, “Peace, peace,” when there is no peace.'),
  ('Jeremiah', 8, 12, 'Were they ashamed when they had committed abomination? No, they were not at all ashamed. They couldn’t blush. Therefore they will fall among those who fall. In the time of their visitation they will be cast down, says the LORD.'),
  ('Jeremiah', 8, 13, '“‘I will utterly consume them, says the LORD. No grapes will be on the vine, no figs on the fig tree, and the leaf will fade. The things that I have given them will pass away from them.’”'),
  ('Jeremiah', 8, 14, '“Why do we sit still? Assemble yourselves! Let’s enter into the fortified cities, and let’s be silent there; for the LORD our God has put us to silence, and given us poisoned water to drink, because we have sinned against the LORD.'),
  ('Jeremiah', 8, 15, 'We looked for peace, but no good came; and for a time of healing, and behold, dismay!'),
  ('Jeremiah', 8, 16, 'The snorting of his horses is heard from Dan. The whole land trembles at the sound of the neighing of his strong ones; for they have come, and have devoured the land and all that is in it, the city and those who dwell therein.”'),
  ('Jeremiah', 8, 17, '“For, behold, I will send serpents, adders among you, which will not be charmed; and they will bite you,” says the LORD.'),
  ('Jeremiah', 8, 18, 'Oh that I could comfort myself against sorrow! My heart is faint within me.'),
  ('Jeremiah', 8, 19, 'Behold, the voice of the cry of the daughter of my people from a land that is very far off: “Isn’t the LORD in Zion? Isn’t her King in her?” “Why have they provoked me to anger with their engraved images, and with foreign idols?”'),
  ('Jeremiah', 8, 20, '“The harvest is past. The summer has ended, and we are not saved.”'),
  ('Jeremiah', 8, 21, 'For the hurt of the daughter of my people, I am hurt. I mourn. Dismay has taken hold of me.'),
  ('Jeremiah', 8, 22, 'Is there no balm in Gilead? Is there no physician there? Why then isn’t the health of the daughter of my people recovered?'),
  ('Jeremiah', 9, 1, 'Oh that my head were waters, and my eyes a spring of tears, that I might weep day and night for the slain of the daughter of my people!'),
  ('Jeremiah', 9, 2, 'Oh that I had in the wilderness a lodging place of wayfaring men, that I might leave my people and go from them! For they are all adulterers, an assembly of treacherous men.'),
  ('Jeremiah', 9, 3, '“They bend their tongue, as their bow, for falsehood. They have grown strong in the land, but not for truth; for they proceed from evil to evil, and they don’t know me,” says the LORD.'),
  ('Jeremiah', 9, 4, '“Everyone beware of his neighbor, and don’t trust in any brother; for every brother will utterly supplant, and every neighbor will go around like a slanderer.'),
  ('Jeremiah', 9, 5, 'Friends deceive each other, and will not speak the truth. They have taught their tongue to speak lies. They weary themselves committing iniquity.'),
  ('Jeremiah', 9, 6, 'Your habitation is in the middle of deceit. Through deceit, they refuse to know me,” says the LORD.'),
  ('Jeremiah', 9, 7, 'Therefore the LORD of Armies says, “Behold, I will melt them and test them; for how should I deal with the daughter of my people?'),
  ('Jeremiah', 9, 8, 'Their tongue is a deadly arrow. It speaks deceit. One speaks peaceably to his neighbor with his mouth, but in his heart, he waits to ambush him.'),
  ('Jeremiah', 9, 9, 'Shouldn’t I punish them for these things?” says the LORD. “Shouldn’t my soul be avenged on a nation such as this?'),
  ('Jeremiah', 9, 10, 'I will weep and wail for the mountains, and lament for the pastures of the wilderness, because they are burned up, so that no one passes through; Men can’t hear the voice of the livestock. Both the birds of the sky and the animals have fled. They are gone.'),
  ('Jeremiah', 9, 11, '“I will make Jerusalem heaps, a dwelling place of jackals. I will make the cities of Judah a desolation, without inhabitant.”'),
  ('Jeremiah', 9, 12, 'Who is wise enough to understand this? Who is he to whom the mouth of the LORD has spoken, that he may declare it? Why has the land perished and burned up like a wilderness, so that no one passes through?'),
  ('Jeremiah', 9, 13, 'The LORD says, “Because they have forsaken my law which I set before them, and have not obeyed my voice or walked in my ways,'),
  ('Jeremiah', 9, 14, 'but have walked after the stubbornness of their own heart and after the Baals, which their fathers taught them.”'),
  ('Jeremiah', 9, 15, 'Therefore the LORD of Armies, the God of Israel, says, “Behold, I will feed them, even this people, with wormwood and give them poisoned water to drink.'),
  ('Jeremiah', 9, 16, 'I will scatter them also among the nations, whom neither they nor their fathers have known. I will send the sword after them, until I have consumed them.”'),
  ('Jeremiah', 9, 17, 'The LORD of Armies says, “Consider, and call for the mourning women, that they may come. Send for the skillful women, that they may come.'),
  ('Jeremiah', 9, 18, 'Let them make haste and take up a wailing for us, that our eyes may run down with tears and our eyelids gush out with waters.'),
  ('Jeremiah', 9, 19, 'For a voice of wailing is heard out of Zion, ‘How we are ruined! We are greatly confounded because we have forsaken the land, because they have cast down our dwellings.’”'),
  ('Jeremiah', 9, 20, 'Yet hear the LORD’s word, you women. Let your ear receive the word of his mouth. Teach your daughters wailing. Everyone teach her neighbor a lamentation.'),
  ('Jeremiah', 9, 21, 'For death has come up into our windows. It has entered into our palaces to cut off the children from outside, and the young men from the streets.'),
  ('Jeremiah', 9, 22, 'Speak, “The LORD says, “‘The dead bodies of men will fall as dung on the open field, and as the handful after the harvester. No one will gather them.’”'),
  ('Jeremiah', 9, 23, 'The LORD says, “Don’t let the wise man glory in his wisdom. Don’t let the mighty man glory in his might. Don’t let the rich man glory in his riches.'),
  ('Jeremiah', 9, 24, 'But let him who glories glory in this, that he has understanding, and knows me, that I am the LORD who exercises loving kindness, justice, and righteousness in the earth, for I delight in these things,” says the LORD.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 9, 25, '“Behold, the days come,” says the LORD, “that I will punish all those who are circumcised only in their flesh:'),
  ('Jeremiah', 9, 26, 'Egypt, Judah, Edom, the children of Ammon, Moab, and all who have the corners of their hair cut off, who dwell in the wilderness, for all the nations are uncircumcised, and all the house of Israel are uncircumcised in heart.”'),
  ('Jeremiah', 10, 1, 'Hear the word which the LORD speaks to you, house of Israel!'),
  ('Jeremiah', 10, 2, 'The LORD says, “Don’t learn the way of the nations, and don’t be dismayed at the signs of the sky; for the nations are dismayed at them.'),
  ('Jeremiah', 10, 3, 'For the customs of the peoples are vanity; for one cuts a tree out of the forest, the work of the hands of the workman with the ax.'),
  ('Jeremiah', 10, 4, 'They deck it with silver and with gold. They fasten it with nails and with hammers, so that it can’t move.'),
  ('Jeremiah', 10, 5, 'They are like a palm tree, of turned work, and don’t speak. They must be carried, because they can’t move. Don’t be afraid of them; for they can’t do evil, neither is it in them to do good.”'),
  ('Jeremiah', 10, 6, 'There is no one like you, LORD. You are great, and your name is great in might.'),
  ('Jeremiah', 10, 7, 'Who shouldn’t fear you, King of the nations? For it belongs to you. Because among all the wise men of the nations, and in all their royal estate, there is no one like you.'),
  ('Jeremiah', 10, 8, 'But they are together brutish and foolish, instructed by idols! It is just wood.'),
  ('Jeremiah', 10, 9, 'There is silver beaten into plates, which is brought from Tarshish, and gold from Uphaz, the work of the engraver and of the hands of the goldsmith. Their clothing is blue and purple. They are all the work of skillful men.'),
  ('Jeremiah', 10, 10, 'But the LORD is the true God. He is the living God, and an everlasting King. At his wrath, the earth trembles. The nations aren’t able to withstand his indignation.'),
  ('Jeremiah', 10, 11, '“You shall say this to them: ‘The gods that have not made the heavens and the earth will perish from the earth, and from under the heavens.’”'),
  ('Jeremiah', 10, 12, 'God has made the earth by his power. He has established the world by his wisdom, and by his understanding has he stretched out the heavens.'),
  ('Jeremiah', 10, 13, 'When he utters his voice, the waters in the heavens roar, and he causes the vapors to ascend from the ends of the earth. He makes lightnings for the rain, and brings the wind out of his treasuries.'),
  ('Jeremiah', 10, 14, 'Every man has become brutish and without knowledge. Every goldsmith is disappointed by his engraved image; for his molten image is falsehood, and there is no breath in them.'),
  ('Jeremiah', 10, 15, 'They are vanity, a work of delusion. In the time of their visitation they will perish.'),
  ('Jeremiah', 10, 16, 'The portion of Jacob is not like these; for he is the maker of all things; and Israel is the tribe of his inheritance. The LORD of Armies is his name.'),
  ('Jeremiah', 10, 17, 'Gather up your wares out of the land, you who live under siege.'),
  ('Jeremiah', 10, 18, 'For the LORD says, “Behold, I will sling out the inhabitants of the land at this time, and will distress them, that they may feel it.”'),
  ('Jeremiah', 10, 19, 'Woe is me because of my injury! My wound is serious; but I said, “Truly this is my grief, and I must bear it.”'),
  ('Jeremiah', 10, 20, 'My tent has been destroyed, and all my cords are broken. My children have gone away from me, and they are no more. There is no one to spread my tent any more, to set up my curtains.'),
  ('Jeremiah', 10, 21, 'For the shepherds have become brutish, and have not inquired of the LORD. Therefore they have not prospered, and all their flocks have scattered.'),
  ('Jeremiah', 10, 22, 'The voice of news, behold, it comes, and a great commotion out of the north country, to make the cities of Judah a desolation, a dwelling place of jackals.'),
  ('Jeremiah', 10, 23, 'LORD, I know that the way of man is not in himself. It is not in man who walks to direct his steps.'),
  ('Jeremiah', 10, 24, 'LORD, correct me, but gently; not in your anger, lest you reduce me to nothing.'),
  ('Jeremiah', 10, 25, 'Pour out your wrath on the nations that don’t know you, and on the families that don’t call on your name; for they have devoured Jacob. Yes, they have devoured him, consumed him, and have laid waste his habitation.'),
  ('Jeremiah', 11, 1, 'The word that came to Jeremiah from the LORD, saying,'),
  ('Jeremiah', 11, 2, '“Hear the words of this covenant, and speak to the men of Judah, and to the inhabitants of Jerusalem;'),
  ('Jeremiah', 11, 3, 'and say to them, the LORD, the God of Israel says: ‘Cursed is the man who doesn’t hear the words of this covenant,'),
  ('Jeremiah', 11, 4, 'which I commanded your fathers in the day that I brought them out of the land of Egypt, out of the iron furnace,’ saying, ‘Obey my voice and do them, according to all which I command you; so you shall be my people, and I will be your God;'),
  ('Jeremiah', 11, 5, 'that I may establish the oath which I swore to your fathers, to give them a land flowing with milk and honey,’ as it is today.” Then I answered, and said, “Amen, LORD.”'),
  ('Jeremiah', 11, 6, 'The LORD said to me, “Proclaim all these words in the cities of Judah, and in the streets of Jerusalem, saying, ‘Hear the words of this covenant, and do them.'),
  ('Jeremiah', 11, 7, 'For I earnestly protested to your fathers in the day that I brought them up out of the land of Egypt, even to this day, rising early and protesting, saying, “Obey my voice.”'),
  ('Jeremiah', 11, 8, 'Yet they didn’t obey, nor turn their ear, but everyone walked in the stubbornness of their evil heart. Therefore I brought on them all the words of this covenant, which I commanded them to do, but they didn’t do them.’”'),
  ('Jeremiah', 11, 9, 'The LORD said to me, “A conspiracy is found among the men of Judah, and among the inhabitants of Jerusalem.'),
  ('Jeremiah', 11, 10, 'They have turned back to the iniquities of their forefathers, who refused to hear my words. They have gone after other gods to serve them. The house of Israel and the house of Judah have broken my covenant which I made with their fathers.'),
  ('Jeremiah', 11, 11, 'Therefore the LORD says, ‘Behold, I will bring evil on them which they will not be able to escape; and they will cry to me, but I will not listen to them.'),
  ('Jeremiah', 11, 12, 'Then the cities of Judah and the inhabitants of Jerusalem will go and cry to the gods to which they offer incense, but they will not save them at all in the time of their trouble.'),
  ('Jeremiah', 11, 13, 'For according to the number of your cities are your gods, Judah; and according to the number of the streets of Jerusalem you have set up altars to the shameful thing, even altars to burn incense to Baal.’'),
  ('Jeremiah', 11, 14, '“Therefore don’t pray for this people. Don’t lift up cry or prayer for them; for I will not hear them in the time that they cry to me because of their trouble.'),
  ('Jeremiah', 11, 15, 'What has my beloved to do in my house, since she has behaved lewdly with many, and the holy flesh has passed from you? When you do evil, then you rejoice.”'),
  ('Jeremiah', 11, 16, 'The LORD called your name, “A green olive tree, beautiful with goodly fruit.” With the noise of a great roar he has kindled fire on it, and its branches are broken.'),
  ('Jeremiah', 11, 17, 'For the LORD of Armies, who planted you, has pronounced evil against you, because of the evil of the house of Israel and of the house of Judah, which they have done to themselves in provoking me to anger by offering incense to Baal.'),
  ('Jeremiah', 11, 18, 'The LORD gave me knowledge of it, and I knew it. Then you showed me their doings.'),
  ('Jeremiah', 11, 19, 'But I was like a gentle lamb that is led to the slaughter. I didn’t know that they had devised plans against me, saying, “Let’s destroy the tree with its fruit, and let’s cut him off from the land of the living, that his name may be no more remembered.”'),
  ('Jeremiah', 11, 20, 'But, LORD of Armies, who judges righteously, who tests the heart and the mind, I will see your vengeance on them; for to you I have revealed my cause.'),
  ('Jeremiah', 11, 21, '“Therefore the LORD says concerning the men of Anathoth, who seek your life, saying, ‘You shall not prophesy in the LORD’s name, that you not die by our hand’—'),
  ('Jeremiah', 11, 22, 'therefore the LORD of Armies says, ‘Behold, I will punish them. The young men will die by the sword. Their sons and their daughters will die by famine.'),
  ('Jeremiah', 11, 23, 'There will be no remnant to them, for I will bring evil on the men of Anathoth, even the year of their visitation.’”'),
  ('Jeremiah', 12, 1, 'You are righteous, LORD, when I contend with you; yet I would like to plead a case with you. Why does the way of the wicked prosper? Why are they all at ease who deal very treacherously?'),
  ('Jeremiah', 12, 2, 'You have planted them. Yes, they have taken root. They grow. Yes, they produce fruit. You are near in their mouth, and far from their heart.'),
  ('Jeremiah', 12, 3, 'But you, LORD, know me. You see me, and test my heart toward you. Pull them out like sheep for the slaughter, and prepare them for the day of slaughter.'),
  ('Jeremiah', 12, 4, 'How long will the land mourn, and the herbs of the whole country wither? Because of the wickedness of those who dwell therein, the animals and birds are consumed; because they said, “He won’t see our latter end.”'),
  ('Jeremiah', 12, 5, '“If you have run with the footmen, and they have wearied you, then how can you contend with horses? Though in a land of peace you are secure, yet how will you do in the pride of the Jordan?'),
  ('Jeremiah', 12, 6, 'For even your brothers, and the house of your father, even they have dealt treacherously with you! Even they have cried aloud after you! Don’t believe them, though they speak beautiful words to you.'),
  ('Jeremiah', 12, 7, '“I have forsaken my house. I have cast off my heritage. I have given the dearly beloved of my soul into the hand of her enemies.'),
  ('Jeremiah', 12, 8, 'My heritage has become to me as a lion in the forest. She has uttered her voice against me. Therefore I have hated her.'),
  ('Jeremiah', 12, 9, 'Is my heritage to me as a speckled bird of prey? Are the birds of prey against her all around? Go, assemble all the animals of the field. Bring them to devour.'),
  ('Jeremiah', 12, 10, 'Many shepherds have destroyed my vineyard. They have trodden my portion under foot. They have made my pleasant portion a desolate wilderness.'),
  ('Jeremiah', 12, 11, 'They have made it a desolation. It mourns to me, being desolate. The whole land is made desolate, because no one cares.'),
  ('Jeremiah', 12, 12, 'Destroyers have come on all the bare heights in the wilderness; for the sword of the LORD devours from the one end of the land even to the other end of the land. No flesh has peace.'),
  ('Jeremiah', 12, 13, 'They have sown wheat, and have reaped thorns. They have exhausted themselves, and profit nothing. You will be ashamed of your fruits, because of the LORD’s fierce anger.”'),
  ('Jeremiah', 12, 14, 'The LORD says, “Concerning all my evil neighbors, who touch the inheritance which I have caused my people Israel to inherit: Behold, I will pluck them up from off their land, and will pluck up the house of Judah from among them.'),
  ('Jeremiah', 12, 15, 'It will happen that after I have plucked them up, I will return and have compassion on them. I will bring them again, every man to his heritage, and every man to his land.'),
  ('Jeremiah', 12, 16, 'It will happen, if they will diligently learn the ways of my people, to swear by my name, ‘As the LORD lives;’ even as they taught my people to swear by Baal, then they will be built up in the middle of my people.'),
  ('Jeremiah', 12, 17, 'But if they will not hear, then I will pluck up that nation, plucking up and destroying it,” says the LORD.'),
  ('Jeremiah', 13, 1, 'The LORD said to me, “Go, and buy yourself a linen belt, and put it on your waist, and don’t put it in water.”'),
  ('Jeremiah', 13, 2, 'So I bought a belt according to the LORD’s word, and put it on my waist.'),
  ('Jeremiah', 13, 3, 'The LORD’s word came to me the second time, saying,'),
  ('Jeremiah', 13, 4, '“Take the belt that you have bought, which is on your waist, and arise, go to the Euphrates, and hide it there in a cleft of the rock.”'),
  ('Jeremiah', 13, 5, 'So I went and hid it by the Euphrates, as the LORD commanded me.'),
  ('Jeremiah', 13, 6, 'After many days, the LORD said to me, “Arise, go to the Euphrates, and take the belt from there, which I commanded you to hide there.”'),
  ('Jeremiah', 13, 7, 'Then I went to the Euphrates, and dug, and took the belt from the place where I had hidden it; and behold, the belt was ruined. It was profitable for nothing.'),
  ('Jeremiah', 13, 8, 'Then the LORD’s word came to me, saying,'),
  ('Jeremiah', 13, 9, '“The LORD says, ‘In this way I will ruin the pride of Judah, and the great pride of Jerusalem.'),
  ('Jeremiah', 13, 10, 'This evil people, who refuse to hear my words, who walk in the stubbornness of their heart, and have gone after other gods to serve them and to worship them, will even be as this belt, which is profitable for nothing.'),
  ('Jeremiah', 13, 11, 'For as the belt clings to the waist of a man, so I have caused the whole house of Israel and the whole house of Judah to cling to me,’ says the LORD; ‘that they may be to me for a people, for a name, for praise, and for glory; but they would not hear.’'),
  ('Jeremiah', 13, 12, '“Therefore you shall speak to them this word: ‘The LORD, the God of Israel says, “Every container should be filled with wine.”’ They will tell you, ‘Do we not certainly know that every container should be filled with wine?’'),
  ('Jeremiah', 13, 13, 'Then tell them, ‘The LORD says, “Behold, I will fill all the inhabitants of this land, even the kings who sit on David’s throne, the priests, the prophets, and all the inhabitants of Jerusalem, with drunkenness.'),
  ('Jeremiah', 13, 14, 'I will dash them one against another, even the fathers and the sons together,” says the LORD: “I will not pity, spare, or have compassion, that I should not destroy them.”’”'),
  ('Jeremiah', 13, 15, 'Hear, and give ear. Don’t be proud, for the LORD has spoken.'),
  ('Jeremiah', 13, 16, 'Give glory to the LORD your God, before he causes darkness, and before your feet stumble on the dark mountains, and while you look for light, he turns it into the shadow of death, and makes it deep darkness.'),
  ('Jeremiah', 13, 17, 'But if you will not hear it, my soul will weep in secret for your pride. My eye will weep bitterly, and run down with tears, because the LORD’s flock has been taken captive.'),
  ('Jeremiah', 13, 18, 'Say to the king and to the queen mother, “Humble yourselves. Sit down, for your crowns have come down, even the crown of your glory.'),
  ('Jeremiah', 13, 19, 'The cities of the South are shut up, and there is no one to open them. Judah is carried away captive: all of them. They are wholly carried away captive.'),
  ('Jeremiah', 13, 20, 'Lift up your eyes, and see those who come from the north. Where is the flock that was given to you, your beautiful flock?'),
  ('Jeremiah', 13, 21, 'What will you say when he sets over you as head those whom you have yourself taught to be friends to you? Won’t sorrows take hold of you, as of a woman in travail?'),
  ('Jeremiah', 13, 22, 'If you say in your heart, “Why have these things come on me?” Your skirts are uncovered because of the greatness of your iniquity, and your heels suffer violence.'),
  ('Jeremiah', 13, 23, 'Can the Ethiopian change his skin, or the leopard his spots? Then may you also do good, who are accustomed to do evil.'),
  ('Jeremiah', 13, 24, '“Therefore I will scatter them as the stubble that passes away by the wind of the wilderness.'),
  ('Jeremiah', 13, 25, 'This is your lot, the portion measured to you from me,” says the LORD, “because you have forgotten me, and trusted in falsehood.”'),
  ('Jeremiah', 13, 26, 'Therefore I will also uncover your skirts on your face, and your shame will appear.'),
  ('Jeremiah', 13, 27, 'I have seen your abominations, even your adulteries and your neighing, the lewdness of your prostitution, on the hills in the field. Woe to you, Jerusalem! You will not be made clean. How long will it yet be?”'),
  ('Jeremiah', 14, 1, 'This is the LORD’s word that came to Jeremiah concerning the drought:'),
  ('Jeremiah', 14, 2, '“Judah mourns, and its gates languish. They sit in black on the ground. The cry of Jerusalem goes up.'),
  ('Jeremiah', 14, 3, 'Their nobles send their little ones to the waters. They come to the cisterns, and find no water. They return with their vessels empty. They are disappointed and confounded, and cover their heads.'),
  ('Jeremiah', 14, 4, 'Because of the ground which is cracked, because no rain has been in the land, the plowmen are disappointed. They cover their heads.'),
  ('Jeremiah', 14, 5, 'Yes, the doe in the field also calves and forsakes her young, because there is no grass.'),
  ('Jeremiah', 14, 6, 'The wild donkeys stand on the bare heights. They pant for air like jackals. Their eyes fail, because there is no vegetation.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 14, 7, 'Though our iniquities testify against us, work for your name’s sake, LORD; for our rebellions are many. We have sinned against you.'),
  ('Jeremiah', 14, 8, 'You hope of Israel, its Savior in the time of trouble, why should you be as a foreigner in the land, and as a wayfaring man who turns aside to stay for a night?'),
  ('Jeremiah', 14, 9, 'Why should you be like a scared man, as a mighty man who can’t save? Yet you, LORD, are in the middle of us, and we are called by your name. Don’t leave us.'),
  ('Jeremiah', 14, 10, 'The LORD says to this people: “Even so they have loved to wander. They have not restrained their feet. Therefore the LORD does not accept them. Now he will remember their iniquity, and punish them for their sins.”'),
  ('Jeremiah', 14, 11, 'The LORD said to me, “Don’t pray for this people for their good.'),
  ('Jeremiah', 14, 12, 'When they fast, I will not hear their cry; and when they offer burnt offering and meal offering, I will not accept them; but I will consume them by the sword, by famine, and by pestilence.”'),
  ('Jeremiah', 14, 13, 'Then I said, “Ah, Lord GOD! Behold, the prophets tell them, ‘You will not see the sword, neither will you have famine; but I will give you assured peace in this place.’”'),
  ('Jeremiah', 14, 14, 'Then the LORD said to me, “The prophets prophesy lies in my name. I didn’t send them. I didn’t command them. I didn’t speak to them. They prophesy to you a lying vision, divination, and a thing of nothing, and the deceit of their own heart.'),
  ('Jeremiah', 14, 15, 'Therefore the LORD says concerning the prophets who prophesy in my name, but I didn’t send them, yet they say, ‘Sword and famine will not be in this land.’ Those prophets will be consumed by sword and famine.'),
  ('Jeremiah', 14, 16, 'The people to whom they prophesy will be cast out in the streets of Jerusalem because of the famine and the sword. They will have no one to bury them—them, their wives, their sons, or their daughters, for I will pour their wickedness on them.'),
  ('Jeremiah', 14, 17, '“You shall say this word to them: “‘Let my eyes run down with tears night and day, and let them not cease; for the virgin daughter of my people is broken with a great breach, with a very grievous wound.'),
  ('Jeremiah', 14, 18, 'If I go out into the field, then behold, the slain with the sword! If I enter into the city, then behold, those who are sick with famine! For both the prophet and the priest go about in the land, and have no knowledge.’”'),
  ('Jeremiah', 14, 19, 'Have you utterly rejected Judah? Has your soul loathed Zion? Why have you struck us, and there is no healing for us? We looked for peace, but no good came; and for a time of healing, and behold, dismay!'),
  ('Jeremiah', 14, 20, 'We acknowledge, LORD, our wickedness, and the iniquity of our fathers; for we have sinned against you.'),
  ('Jeremiah', 14, 21, 'Do not abhor us, for your name’s sake. Do not disgrace the throne of your glory. Remember, and don’t break your covenant with us.'),
  ('Jeremiah', 14, 22, 'Are there any among the vanities of the nations that can cause rain? Or can the sky give showers? Aren’t you he, the LORD our God? Therefore we will wait for you; for you have made all these things.'),
  ('Jeremiah', 15, 1, 'Then the LORD said to me, “Though Moses and Samuel stood before me, yet my mind would not turn toward this people. Cast them out of my sight, and let them go out!'),
  ('Jeremiah', 15, 2, 'It will happen when they ask you, ‘Where shall we go out?’ then you shall tell them, ‘The LORD says: “Such as are for death, to death; such as are for the sword, to the sword; such as are for the famine, to the famine; and such as are for captivity, to captivity.”’'),
  ('Jeremiah', 15, 3, '“I will appoint over them four kinds,” says the LORD: “the sword to kill, the dogs to tear, the birds of the sky, and the animals of the earth, to devour and to destroy.'),
  ('Jeremiah', 15, 4, 'I will cause them to be tossed back and forth among all the kingdoms of the earth, because of Manasseh, the son of Hezekiah, king of Judah, for that which he did in Jerusalem.'),
  ('Jeremiah', 15, 5, 'For who will have pity on you, Jerusalem? Who will mourn you? Who will come to ask of your welfare?'),
  ('Jeremiah', 15, 6, 'You have rejected me,” says the LORD. “You have gone backward. Therefore I have stretched out my hand against you and destroyed you. I am weary of showing compassion.'),
  ('Jeremiah', 15, 7, 'I have winnowed them with a fan in the gates of the land. I have bereaved them of children. I have destroyed my people. They didn’t return from their ways.'),
  ('Jeremiah', 15, 8, 'Their widows are increased more than the sand of the seas. I have brought on them against the mother of the young men a destroyer at noonday. I have caused anguish and terrors to fall on her suddenly.'),
  ('Jeremiah', 15, 9, 'She who has borne seven languishes. She has given up the spirit. Her sun has gone down while it was yet day. She has been disappointed and confounded. I will deliver their residue to the sword before their enemies,” says the LORD.'),
  ('Jeremiah', 15, 10, 'Woe is me, my mother, that you have borne me, a man of strife, and a man of contention to the whole earth! I have not lent, neither have men lent to me; yet every one of them curses me.'),
  ('Jeremiah', 15, 11, 'The LORD said, “Most certainly I will strengthen you for good. Most certainly I will cause the enemy to make supplication to you in the time of evil and in the time of affliction.'),
  ('Jeremiah', 15, 12, 'Can one break iron, even iron from the north, and bronze?'),
  ('Jeremiah', 15, 13, 'I will give your substance and your treasures for a plunder without price, and that for all your sins, even in all your borders.'),
  ('Jeremiah', 15, 14, 'I will make them to pass with your enemies into a land which you don’t know; for a fire is kindled in my anger, which will burn on you.”'),
  ('Jeremiah', 15, 15, 'LORD, you know. Remember me, visit me, and avenge me of my persecutors. You are patient, so don’t take me away. Know that for your sake I have suffered reproach.'),
  ('Jeremiah', 15, 16, 'Your words were found, and I ate them. Your words were to me a joy and the rejoicing of my heart, for I am called by your name, LORD, God of Armies.'),
  ('Jeremiah', 15, 17, 'I didn’t sit in the assembly of those who make merry and rejoice. I sat alone because of your hand, for you have filled me with indignation.'),
  ('Jeremiah', 15, 18, 'Why is my pain perpetual, and my wound incurable, which refuses to be healed? Will you indeed be to me as a deceitful brook, like waters that fail?'),
  ('Jeremiah', 15, 19, 'Therefore the LORD says, “If you return, then I will bring you again, that you may stand before me; and if you take out the precious from the vile, you will be as my mouth. They will return to you, but you will not return to them.'),
  ('Jeremiah', 15, 20, 'I will make you to this people a fortified bronze wall. They will fight against you, but they will not prevail against you; for I am with you to save you and to deliver you,” says the LORD.'),
  ('Jeremiah', 15, 21, '“I will deliver you out of the hand of the wicked, and I will redeem you out of the hand of the terrible.”'),
  ('Jeremiah', 16, 1, 'Then the LORD’s word came to me, saying,'),
  ('Jeremiah', 16, 2, '“You shall not take a wife, neither shall you have sons or daughters, in this place.”'),
  ('Jeremiah', 16, 3, 'For the LORD says concerning the sons and concerning the daughters who are born in this place, and concerning their mothers who bore them, and concerning their fathers who became their father in this land:'),
  ('Jeremiah', 16, 4, '“They will die grievous deaths. They will not be lamented, neither will they be buried. They will be as dung on the surface of the ground. They will be consumed by the sword and by famine. Their dead bodies will be food for the birds of the sky and for the animals of the earth.”'),
  ('Jeremiah', 16, 5, 'For the LORD says, “Don’t enter into the house of mourning. Don’t go to lament. Don’t bemoan them, for I have taken away my peace from this people,” says the LORD, “even loving kindness and tender mercies.'),
  ('Jeremiah', 16, 6, 'Both great and small will die in this land. They will not be buried. Men won’t lament for them, cut themselves, or make themselves bald for them.'),
  ('Jeremiah', 16, 7, 'Men won’t break bread for them in mourning, to comfort them for the dead. Men won’t give them the cup of consolation to drink for their father or for their mother.'),
  ('Jeremiah', 16, 8, '“You shall not go into the house of feasting to sit with them, to eat and to drink.”'),
  ('Jeremiah', 16, 9, 'For the LORD of Armies, the God of Israel says: “Behold, I will cause to cease out of this place, before your eyes and in your days, the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride.'),
  ('Jeremiah', 16, 10, 'It will happen, when you tell this people all these words, and they ask you, ‘Why has the LORD pronounced all this great evil against us?’ or ‘What is our iniquity?’ or ‘What is our sin that we have committed against the LORD our God?’'),
  ('Jeremiah', 16, 11, 'then you shall tell them, ‘Because your fathers have forsaken me,’ says the LORD, ‘and have walked after other gods, have served them, have worshiped them, have forsaken me, and have not kept my law.'),
  ('Jeremiah', 16, 12, 'You have done evil more than your fathers, for behold, you each walk after the stubbornness of his evil heart, so that you don’t listen to me.'),
  ('Jeremiah', 16, 13, 'Therefore I will cast you out of this land into the land that you have not known, neither you nor your fathers. There you will serve other gods day and night, for I will show you no favor.’'),
  ('Jeremiah', 16, 14, '“Therefore behold, the days come,” says the LORD, “that it will no more be said, ‘As the LORD lives, who brought up the children of Israel out of the land of Egypt;’'),
  ('Jeremiah', 16, 15, 'but, ‘As the LORD lives, who brought up the children of Israel from the land of the north, and from all the countries where he had driven them.’ I will bring them again into their land that I gave to their fathers.'),
  ('Jeremiah', 16, 16, '“Behold, I will send for many fishermen,” says the LORD, “and they will fish them up. Afterward I will send for many hunters, and they will hunt them from every mountain, from every hill, and out of the clefts of the rocks.'),
  ('Jeremiah', 16, 17, 'For my eyes are on all their ways. They are not hidden from my face. Their iniquity isn’t concealed from my eyes.'),
  ('Jeremiah', 16, 18, 'First I will recompense their iniquity and their sin double, because they have polluted my land with the carcasses of their detestable things, and have filled my inheritance with their abominations.”'),
  ('Jeremiah', 16, 19, 'LORD, my strength, my stronghold, and my refuge in the day of affliction, the nations will come to you from the ends of the earth, and will say, “Our fathers have inherited nothing but lies, vanity and things in which there is no profit.'),
  ('Jeremiah', 16, 20, 'Should a man make to himself gods which yet are no gods?”'),
  ('Jeremiah', 16, 21, '“Therefore behold, I will cause them to know, this once I will cause them to know my hand and my might. Then they will know that my name is the LORD.”'),
  ('Jeremiah', 17, 1, '“The sin of Judah is written with a pen of iron, and with the point of a diamond. It is engraved on the tablet of their heart, and on the horns of your altars.'),
  ('Jeremiah', 17, 2, 'Even their children remember their altars and their Asherah poles by the green trees on the high hills.'),
  ('Jeremiah', 17, 3, 'My mountain in the field, I will give your substance and all your treasures for a plunder, and your high places, because of sin, throughout all your borders.'),
  ('Jeremiah', 17, 4, 'You, even of yourself, will discontinue from your heritage that I gave you. I will cause you to serve your enemies in the land which you don’t know, for you have kindled a fire in my anger which will burn forever.”'),
  ('Jeremiah', 17, 5, 'The LORD says: “Cursed is the man who trusts in man, relies on strength of flesh, and whose heart departs from the LORD.'),
  ('Jeremiah', 17, 6, 'For he will be like a bush in the desert, and will not see when good comes, but will inhabit the parched places in the wilderness, an uninhabited salt land.'),
  ('Jeremiah', 17, 7, '“Blessed is the man who trusts in the LORD, and whose confidence is in the LORD.'),
  ('Jeremiah', 17, 8, 'For he will be as a tree planted by the waters, who spreads out its roots by the river, and will not fear when heat comes, but its leaf will be green, and will not be concerned in the year of drought. It won’t cease from yielding fruit.'),
  ('Jeremiah', 17, 9, 'The heart is deceitful above all things and it is exceedingly corrupt. Who can know it?'),
  ('Jeremiah', 17, 10, '“I, the LORD, search the mind. I try the heart, even to give every man according to his ways, according to the fruit of his doings.”'),
  ('Jeremiah', 17, 11, 'As the partridge that sits on eggs which she has not laid, so is he who gets riches, and not by right. In the middle of his days, they will leave him. At his end, he will be a fool.'),
  ('Jeremiah', 17, 12, 'A glorious throne, set on high from the beginning, is the place of our sanctuary.'),
  ('Jeremiah', 17, 13, 'LORD, the hope of Israel, all who forsake you will be disappointed. Those who depart from me will be written in the earth, because they have forsaken the LORD, the spring of living waters.'),
  ('Jeremiah', 17, 14, 'Heal me, O LORD, and I will be healed. Save me, and I will be saved; for you are my praise.'),
  ('Jeremiah', 17, 15, 'Behold, they ask me, “Where is the LORD’s word? Let it be fulfilled now.”'),
  ('Jeremiah', 17, 16, 'As for me, I have not hurried from being a shepherd after you. I haven’t desired the woeful day. You know. That which came out of my lips was before your face.'),
  ('Jeremiah', 17, 17, 'Don’t be a terror to me. You are my refuge in the day of evil.'),
  ('Jeremiah', 17, 18, 'Let them be disappointed who persecute me, but don’t let me be disappointed. Let them be dismayed, but don’t let me be dismayed. Bring on them the day of evil, and destroy them with double destruction.'),
  ('Jeremiah', 17, 19, 'The LORD said this to me: “Go and stand in the gate of the children of the people, through which the kings of Judah come in and by which they go out, and in all the gates of Jerusalem.'),
  ('Jeremiah', 17, 20, 'Tell them, ‘Hear the LORD’s word, you kings of Judah, all Judah, and all the inhabitants of Jerusalem, that enter in by these gates:'),
  ('Jeremiah', 17, 21, 'The LORD says, “Be careful, and bear no burden on the Sabbath day, nor bring it in by the gates of Jerusalem.'),
  ('Jeremiah', 17, 22, 'Don’t carry a burden out of your houses on the Sabbath day. Don’t do any work, but make the Sabbath day holy, as I commanded your fathers.'),
  ('Jeremiah', 17, 23, 'But they didn’t listen. They didn’t turn their ear, but made their neck stiff, that they might not hear, and might not receive instruction.'),
  ('Jeremiah', 17, 24, 'It will happen, if you diligently listen to me,” says the LORD, “to bring in no burden through the gates of this city on the Sabbath day, but to make the Sabbath day holy, to do no work therein;'),
  ('Jeremiah', 17, 25, 'then there will enter in by the gates of this city kings and princes sitting on David’s throne, riding in chariots and on horses, they and their princes, the men of Judah and the inhabitants of Jerusalem; and this city will remain forever.'),
  ('Jeremiah', 17, 26, 'They will come from the cities of Judah, and from the places around Jerusalem, from the land of Benjamin, from the lowland, from the hill country, and from the South, bringing burnt offerings, sacrifices, meal offerings, and frankincense, and bringing sacrifices of thanksgiving to the LORD’s house.'),
  ('Jeremiah', 17, 27, 'But if you will not listen to me to make the Sabbath day holy, and not to bear a burden and enter in at the gates of Jerusalem on the Sabbath day, then I will kindle a fire in its gates, and it will devour the palaces of Jerusalem. It will not be quenched.”’”'),
  ('Jeremiah', 18, 1, 'The word which came to Jeremiah from the LORD, saying,'),
  ('Jeremiah', 18, 2, '“Arise, and go down to the potter’s house, and there I will cause you to hear my words.”'),
  ('Jeremiah', 18, 3, 'Then I went down to the potter’s house, and behold, he was making something on the wheels.'),
  ('Jeremiah', 18, 4, 'When the vessel that he made of the clay was marred in the hand of the potter, he made it again another vessel, as seemed good to the potter to make it.'),
  ('Jeremiah', 18, 5, 'Then the LORD’s word came to me, saying,'),
  ('Jeremiah', 18, 6, '“House of Israel, can’t I do with you as this potter?” says the LORD. “Behold, as the clay in the potter’s hand, so are you in my hand, house of Israel.'),
  ('Jeremiah', 18, 7, 'At the instant I speak concerning a nation, and concerning a kingdom, to pluck up and to break down and to destroy it,'),
  ('Jeremiah', 18, 8, 'if that nation, concerning which I have spoken, turns from their evil, I will repent of the evil that I thought to do to them.'),
  ('Jeremiah', 18, 9, 'At the instant I speak concerning a nation, and concerning a kingdom, to build and to plant it,'),
  ('Jeremiah', 18, 10, 'if they do that which is evil in my sight, that they don’t obey my voice, then I will repent of the good with which I said I would benefit them.'),
  ('Jeremiah', 18, 11, '“Now therefore, speak to the men of Judah, and to the inhabitants of Jerusalem, saying, ‘The LORD says: “Behold, I frame evil against you, and devise a plan against you. Everyone return from his evil way now, and amend your ways and your doings.”’'),
  ('Jeremiah', 18, 12, 'But they say, ‘It is in vain; for we will walk after our own plans, and we will each follow the stubbornness of his evil heart.’”'),
  ('Jeremiah', 18, 13, 'Therefore the LORD says: “Ask now among the nations, ‘Who has heard such things?’ The virgin of Israel has done a very horrible thing.'),
  ('Jeremiah', 18, 14, 'Will the snow of Lebanon fail from the rock of the field? Will the cold waters that flow down from afar be dried up?'),
  ('Jeremiah', 18, 15, 'For my people have forgotten me. They have burned incense to false gods. They have been made to stumble in their ways in the ancient paths, to walk in byways, in a way not built up,');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 18, 16, 'to make their land an astonishment, and a perpetual hissing. Everyone who passes by it will be astonished, and shake his head.'),
  ('Jeremiah', 18, 17, 'I will scatter them as with an east wind before the enemy. I will show them the back, and not the face, in the day of their calamity.'),
  ('Jeremiah', 18, 18, 'Then they said, “Come! Let’s devise plans against Jeremiah; for the law won’t perish from the priest, nor counsel from the wise, nor the word from the prophet. Come, and let’s strike him with the tongue, and let’s not give heed to any of his words.”'),
  ('Jeremiah', 18, 19, 'Give heed to me, LORD, and listen to the voice of those who contend with me.'),
  ('Jeremiah', 18, 20, 'Should evil be recompensed for good? For they have dug a pit for my soul. Remember how I stood before you to speak good for them, to turn away your wrath from them.'),
  ('Jeremiah', 18, 21, 'Therefore deliver up their children to the famine, and give them over to the power of the sword. Let their wives become childless and widows. Let their men be killed and their young men struck by the sword in battle.'),
  ('Jeremiah', 18, 22, 'Let a cry be heard from their houses when you bring a troop suddenly on them; for they have dug a pit to take me and hidden snares for my feet.'),
  ('Jeremiah', 18, 23, 'Yet, LORD, you know all their counsel against me to kill me. Don’t forgive their iniquity. Don’t blot out their sin from your sight, Let them be overthrown before you. Deal with them in the time of your anger.'),
  ('Jeremiah', 19, 1, 'Thus said the LORD, “Go, and buy a potter’s earthen container, and take some of the elders of the people and of the elders of the priests;'),
  ('Jeremiah', 19, 2, 'and go out to the valley of the son of Hinnom, which is by the entry of the gate Harsith, and proclaim there the words that I will tell you.'),
  ('Jeremiah', 19, 3, 'Say, ‘Hear the LORD’s word, kings of Judah and inhabitants of Jerusalem: The LORD of Armies, the God of Israel says, “Behold, I will bring evil on this place, which whoever hears, his ears will tingle.'),
  ('Jeremiah', 19, 4, 'Because they have forsaken me, and have defiled this place, and have burned incense in it to other gods that they didn’t know—they, their fathers, and the kings of Judah—and have filled this place with the blood of innocents,'),
  ('Jeremiah', 19, 5, 'and have built the high places of Baal to burn their children in the fire for burnt offerings to Baal, which I didn’t command, nor speak, which didn’t even enter into my mind.'),
  ('Jeremiah', 19, 6, 'Therefore, behold, the days come,” says the LORD, “that this place will no more be called ‘Topheth’, nor ‘The Valley of the son of Hinnom’, but ‘The valley of Slaughter’.'),
  ('Jeremiah', 19, 7, '“‘“I will make the counsel of Judah and Jerusalem void in this place. I will cause them to fall by the sword before their enemies, and by the hand of those who seek their life. I will give their dead bodies to be food for the birds of the sky and for the animals of the earth.'),
  ('Jeremiah', 19, 8, 'I will make this city an astonishment and a hissing. Everyone who passes by it will be astonished and hiss because of all its plagues.'),
  ('Jeremiah', 19, 9, 'I will cause them to eat the flesh of their sons and the flesh of their daughters. They will each eat the flesh of his friend in the siege and in the distress with which their enemies, and those who seek their life, will distress them.”’'),
  ('Jeremiah', 19, 10, '“Then you shall break the container in the sight of the men who go with you,'),
  ('Jeremiah', 19, 11, 'and shall tell them, ‘The LORD of Armies says: “Even so I will break this people and this city as one breaks a potter’s vessel, that can’t be made whole again. They will bury in Topheth until there is no place to bury.'),
  ('Jeremiah', 19, 12, 'This is what I will do to this place,” says the LORD, “and to its inhabitants, even making this city as Topheth.'),
  ('Jeremiah', 19, 13, 'The houses of Jerusalem and the houses of the kings of Judah, which are defiled, will be as the place of Topheth, even all the houses on whose roofs they have burned incense to all the army of the sky and have poured out drink offerings to other gods.”’”'),
  ('Jeremiah', 19, 14, 'Then Jeremiah came from Topheth, where the LORD had sent him to prophesy, and he stood in the court of the LORD’s house, and said to all the people:'),
  ('Jeremiah', 19, 15, '“The LORD of Armies, the God of Israel says, ‘Behold, I will bring on this city and on all its towns all the evil that I have pronounced against it, because they have made their neck stiff, that they may not hear my words.’”'),
  ('Jeremiah', 20, 1, 'Now Pashhur, the son of Immer the priest, who was chief officer in the LORD’s house, heard Jeremiah prophesying these things.'),
  ('Jeremiah', 20, 2, 'Then Pashhur struck Jeremiah the prophet and put him in the stocks that were in the upper gate of Benjamin, which was in the LORD’s house.'),
  ('Jeremiah', 20, 3, 'On the next day, Pashhur released Jeremiah out of the stocks. Then Jeremiah said to him, “The LORD has not called your name Pashhur, but Magormissabib.'),
  ('Jeremiah', 20, 4, 'For the LORD says, ‘Behold, I will make you a terror to yourself and to all your friends. They will fall by the sword of their enemies, and your eyes will see it. I will give all Judah into the hand of the king of Babylon, and he will carry them captive to Babylon, and will kill them with the sword.'),
  ('Jeremiah', 20, 5, 'Moreover I will give all the riches of this city, and all its gains, and all its precious things, yes, I will give all the treasures of the kings of Judah into the hand of their enemies. They will make them captives, take them, and carry them to Babylon.'),
  ('Jeremiah', 20, 6, 'You, Pashhur, and all who dwell in your house will go into captivity. You will come to Babylon, and there you will die, and there you will be buried, you, and all your friends, to whom you have prophesied falsely.’”'),
  ('Jeremiah', 20, 7, 'LORD, you have persuaded me, and I was persuaded. You are stronger than I, and have prevailed. I have become a laughingstock all day. Everyone mocks me.'),
  ('Jeremiah', 20, 8, 'For as often as I speak, I cry out; I cry, “Violence and destruction!” because the LORD’s word has been made a reproach to me, and a derision, all day.'),
  ('Jeremiah', 20, 9, 'If I say that I will not make mention of him, or speak any more in his name, then there is in my heart as it were a burning fire shut up in my bones. I am weary with holding it in. I can’t.'),
  ('Jeremiah', 20, 10, 'For I have heard the defaming of many: “Terror on every side! Denounce, and we will denounce him!” say all my familiar friends, those who watch for my fall. “Perhaps he will be persuaded, and we will prevail against him, and we will take our revenge on him.”'),
  ('Jeremiah', 20, 11, 'But the LORD is with me as an awesome mighty one. Therefore my persecutors will stumble, and they won’t prevail. They will be utterly disappointed because they have not dealt wisely, even with an everlasting dishonor which will never be forgotten.'),
  ('Jeremiah', 20, 12, 'But the LORD of Armies, who tests the righteous, who sees the heart and the mind, let me see your vengeance on them, for I have revealed my cause to you.'),
  ('Jeremiah', 20, 13, 'Sing to the LORD! Praise the LORD, for he has delivered the soul of the needy from the hand of evildoers.'),
  ('Jeremiah', 20, 14, 'Cursed is the day in which I was born. Don’t let the day in which my mother bore me be blessed.'),
  ('Jeremiah', 20, 15, 'Cursed is the man who brought news to my father, saying, “A boy is born to you,” making him very glad.'),
  ('Jeremiah', 20, 16, 'Let that man be as the cities which the LORD overthrew, and didn’t repent. Let him hear a cry in the morning, and shouting at noontime,'),
  ('Jeremiah', 20, 17, 'because he didn’t kill me from the womb. So my mother would have been my grave, and her womb always great.'),
  ('Jeremiah', 20, 18, 'Why did I come out of the womb to see labor and sorrow, that my days should be consumed with shame?'),
  ('Jeremiah', 21, 1, 'The word which came to Jeremiah from the LORD, when King Zedekiah sent to him Pashhur the son of Malchijah, and Zephaniah the son of Maaseiah, the priest, saying,'),
  ('Jeremiah', 21, 2, '“Please inquire of the LORD for us; for Nebuchadnezzar king of Babylon makes war against us. Perhaps the LORD will deal with us according to all his wondrous works, that he may withdraw from us.”'),
  ('Jeremiah', 21, 3, 'Then Jeremiah said to them, “Tell Zedekiah:'),
  ('Jeremiah', 21, 4, '‘The LORD, the God of Israel says, “Behold, I will turn back the weapons of war that are in your hands, with which you fight against the king of Babylon, and against the Chaldeans who besiege you outside the walls; and I will gather them into the middle of this city.'),
  ('Jeremiah', 21, 5, 'I myself will fight against you with an outstretched hand and with a strong arm, even in anger, in wrath, and in great indignation.'),
  ('Jeremiah', 21, 6, 'I will strike the inhabitants of this city, both man and animal. They will die of a great pestilence.'),
  ('Jeremiah', 21, 7, 'Afterward,” says the LORD, “I will deliver Zedekiah king of Judah, his servants, and the people, even those who are left in this city from the pestilence, from the sword, and from the famine, into the hand of Nebuchadnezzar king of Babylon, and into the hand of their enemies, and into the hand of those who seek their life. He will strike them with the edge of the sword. He will not spare them, have pity, or have mercy.”’'),
  ('Jeremiah', 21, 8, '“You shall say to this people, ‘The LORD says: “Behold, I set before you the way of life and the way of death.'),
  ('Jeremiah', 21, 9, 'He who remains in this city will die by the sword, by the famine, and by the pestilence, but he who goes out and passes over to the Chaldeans who besiege you, he will live, and he will escape with his life.'),
  ('Jeremiah', 21, 10, 'For I have set my face on this city for evil, and not for good,” says the LORD. “It will be given into the hand of the king of Babylon, and he will burn it with fire.”’'),
  ('Jeremiah', 21, 11, '“Concerning the house of the king of Judah, hear the LORD’s word:'),
  ('Jeremiah', 21, 12, 'House of David, the LORD says, ‘Execute justice in the morning, and deliver him who is robbed out of the hand of the oppressor, lest my wrath go out like fire, and burn so that no one can quench it, because of the evil of your doings.'),
  ('Jeremiah', 21, 13, 'Behold, I am against you, O inhabitant of the valley, and of the rock of the plain,’ says the LORD. ‘You that say, “Who would come down against us?” or, “Who would enter into our homes?”'),
  ('Jeremiah', 21, 14, 'I will punish you according to the fruit of your doings,’ says the LORD; ‘and I will kindle a fire in her forest, and it will devour all that is around her.’”'),
  ('Jeremiah', 22, 1, 'The LORD said, “Go down to the house of the king of Judah, and speak this word there:'),
  ('Jeremiah', 22, 2, '‘Hear the LORD’s word, king of Judah, who sits on David’s throne—you, your servants, and your people who enter in by these gates.'),
  ('Jeremiah', 22, 3, 'The LORD says: “Execute justice and righteousness, and deliver him who is robbed out of the hand of the oppressor. Do no wrong. Do no violence to the foreigner, the fatherless, or the widow. Don’t shed innocent blood in this place.'),
  ('Jeremiah', 22, 4, 'For if you do this thing indeed, then kings sitting on David’s throne will enter in by the gates of this house, riding in chariots and on horses—they, their servants, and their people.'),
  ('Jeremiah', 22, 5, 'But if you will not hear these words, I swear by myself,” says the LORD, “that this house will become a desolation.”’”'),
  ('Jeremiah', 22, 6, 'For the LORD says concerning the house of the king of Judah: “You are Gilead to me, the head of Lebanon. Yet surely I will make you a wilderness, cities which are not inhabited.'),
  ('Jeremiah', 22, 7, 'I will prepare destroyers against you, everyone with his weapons, and they will cut down your choice cedars, and cast them into the fire.'),
  ('Jeremiah', 22, 8, '“Many nations will pass by this city, and they will each ask his neighbor, ‘Why has the LORD done this to this great city?’'),
  ('Jeremiah', 22, 9, 'Then they will answer, ‘Because they abandoned the covenant of the LORD their God, worshiped other gods, and served them.’”'),
  ('Jeremiah', 22, 10, 'Don’t weep for the dead. Don’t bemoan him; but weep bitterly for him who goes away, for he will return no more, and not see his native country.'),
  ('Jeremiah', 22, 11, 'For the LORD says touching Shallum the son of Josiah, king of Judah, who reigned instead of Josiah his father, and who went out of this place: “He won’t return there any more.'),
  ('Jeremiah', 22, 12, 'But he will die in the place where they have led him captive. He will see this land no more.”'),
  ('Jeremiah', 22, 13, '“Woe to him who builds his house by unrighteousness, and his rooms by injustice; who uses his neighbor’s service without wages, and doesn’t give him his hire;'),
  ('Jeremiah', 22, 14, 'who says, ‘I will build myself a wide house and spacious rooms,’ and cuts out windows for himself, with a cedar ceiling, and painted with red.'),
  ('Jeremiah', 22, 15, '“Should you reign because you strive to excel in cedar? Didn’t your father eat and drink, and do justice and righteousness? Then it was well with him.'),
  ('Jeremiah', 22, 16, 'He judged the cause of the poor and needy; so then it was well. Wasn’t this to know me?” says the LORD.'),
  ('Jeremiah', 22, 17, 'But your eyes and your heart are only for your covetousness, for shedding innocent blood, for oppression, and for doing violence.”'),
  ('Jeremiah', 22, 18, 'Therefore the LORD says concerning Jehoiakim the son of Josiah, king of Judah: “They won’t lament for him, saying, ‘Ah my brother!’ or, ‘Ah sister!’ They won’t lament for him, saying ‘Ah lord!’ or, ‘Ah his glory!’'),
  ('Jeremiah', 22, 19, 'He will be buried with the burial of a donkey, drawn and cast out beyond the gates of Jerusalem.”'),
  ('Jeremiah', 22, 20, '“Go up to Lebanon, and cry out. Lift up your voice in Bashan, and cry from Abarim; for all your lovers have been destroyed.'),
  ('Jeremiah', 22, 21, 'I spoke to you in your prosperity, but you said, ‘I will not listen.’ This has been your way from your youth, that you didn’t obey my voice.'),
  ('Jeremiah', 22, 22, 'The wind will feed all your shepherds, and your lovers will go into captivity. Surely then you will be ashamed and confounded for all your wickedness.'),
  ('Jeremiah', 22, 23, 'Inhabitant of Lebanon, who makes your nest in the cedars, how greatly to be pitied you will be when pangs come on you, the pain as of a woman in travail!'),
  ('Jeremiah', 22, 24, '“As I live,” says the LORD, “though Coniah the son of Jehoiakim king of Judah were the signet on my right hand, I would still pluck you from there.'),
  ('Jeremiah', 22, 25, 'I would give you into the hand of those who seek your life, and into the hand of them of whom you are afraid, even into the hand of Nebuchadnezzar king of Babylon, and into the hand of the Chaldeans.'),
  ('Jeremiah', 22, 26, 'I will cast you out with your mother who bore you into another country, where you were not born; and there you will die.'),
  ('Jeremiah', 22, 27, 'But to the land to which their soul longs to return, there they will not return.”'),
  ('Jeremiah', 22, 28, 'Is this man Coniah a despised broken vessel? Is he a vessel in which no one delights? Why are they cast out, he and his offspring, and cast into a land which they don’t know?'),
  ('Jeremiah', 22, 29, 'O earth, earth, earth, hear the LORD’s word!'),
  ('Jeremiah', 22, 30, 'The LORD says, “Record this man as childless, a man who will not prosper in his days; for no more will a man of his offspring prosper, sitting on David’s throne and ruling in Judah.”'),
  ('Jeremiah', 23, 1, '“Woe to the shepherds who destroy and scatter the sheep of my pasture!” says the LORD.'),
  ('Jeremiah', 23, 2, 'Therefore the LORD, the God of Israel, says against the shepherds who feed my people: “You have scattered my flock, driven them away, and have not visited them. Behold, I will visit on you the evil of your doings,” says the LORD.'),
  ('Jeremiah', 23, 3, '“I will gather the remnant of my flock out of all the countries where I have driven them, and will bring them again to their folds; and they will be fruitful and multiply.'),
  ('Jeremiah', 23, 4, 'I will set up shepherds over them who will feed them. They will no longer be afraid or dismayed, neither will any be lacking,” says the LORD.'),
  ('Jeremiah', 23, 5, '“Behold, the days come,” says the LORD, “that I will raise to David a righteous Branch; and he will reign as king and deal wisely, and will execute justice and righteousness in the land.'),
  ('Jeremiah', 23, 6, 'In his days Judah will be saved, and Israel will dwell safely. This is his name by which he will be called: The LORD our righteousness.'),
  ('Jeremiah', 23, 7, '“Therefore, behold, the days come,” says the LORD, “that they will no more say, ‘As the LORD lives, who brought up the children of Israel out of the land of Egypt;’'),
  ('Jeremiah', 23, 8, 'but, ‘As the LORD lives, who brought up and who led the offspring of the house of Israel out of the north country, and from all the countries where I had driven them.’ Then they will dwell in their own land.”'),
  ('Jeremiah', 23, 9, 'Concerning the prophets: My heart within me is broken. All my bones shake. I am like a drunken man, and like a man whom wine has overcome, because of the LORD, and because of his holy words.'),
  ('Jeremiah', 23, 10, '“For the land is full of adulterers; for because of the curse the land mourns. The pastures of the wilderness have dried up. Their course is evil, and their might is not right;'),
  ('Jeremiah', 23, 11, 'for both prophet and priest are profane. Yes, in my house I have found their wickedness,” says the LORD.'),
  ('Jeremiah', 23, 12, 'Therefore their way will be to them as slippery places in the darkness. They will be driven on, and fall therein; for I will bring evil on them, even the year of their visitation,” says the LORD.'),
  ('Jeremiah', 23, 13, '“I have seen folly in the prophets of Samaria. They prophesied by Baal, and caused my people Israel to err.'),
  ('Jeremiah', 23, 14, 'In the prophets of Jerusalem I have also seen a horrible thing: they commit adultery and walk in lies. They strengthen the hands of evildoers, so that no one returns from his wickedness. They have all become to me as Sodom, and its inhabitants as Gomorrah.”'),
  ('Jeremiah', 23, 15, 'Therefore the LORD of Armies says concerning the prophets: “Behold, I will feed them with wormwood, and make them drink poisoned water; for from the prophets of Jerusalem ungodliness has gone out into all the land.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 23, 16, 'The LORD of Armies says, “Don’t listen to the words of the prophets who prophesy to you. They teach you vanity. They speak a vision of their own heart, and not out of the mouth of the LORD.'),
  ('Jeremiah', 23, 17, 'They say continually to those who despise me, ‘The LORD has said, “You will have peace;”’ and to everyone who walks in the stubbornness of his own heart they say, ‘No evil will come on you.’'),
  ('Jeremiah', 23, 18, 'For who has stood in the council of the LORD, that he should perceive and hear his word? Who has listened to my word, and heard it?'),
  ('Jeremiah', 23, 19, 'Behold, the LORD’s storm, his wrath, has gone out. Yes, a whirling storm! It will burst on the head of the wicked.'),
  ('Jeremiah', 23, 20, 'The LORD’s anger will not return until he has executed and performed the intents of his heart. In the latter days, you will understand it perfectly.'),
  ('Jeremiah', 23, 21, 'I didn’t send these prophets, yet they ran. I didn’t speak to them, yet they prophesied.'),
  ('Jeremiah', 23, 22, 'But if they had stood in my council, then they would have caused my people to hear my words, and would have turned them from their evil way, and from the evil of their doings.'),
  ('Jeremiah', 23, 23, '“Am I a God at hand,” says the LORD, “and not a God afar off?'),
  ('Jeremiah', 23, 24, 'Can anyone hide himself in secret places so that I can’t see him?” says the LORD. “Don’t I fill heaven and earth?” says the LORD.'),
  ('Jeremiah', 23, 25, '“I have heard what the prophets have said, who prophesy lies in my name, saying, ‘I had a dream! I had a dream!’'),
  ('Jeremiah', 23, 26, 'How long will this be in the heart of the prophets who prophesy lies, even the prophets of the deceit of their own heart?'),
  ('Jeremiah', 23, 27, 'They intend to cause my people to forget my name by their dreams which they each tell his neighbor, as their fathers forgot my name because of Baal.'),
  ('Jeremiah', 23, 28, 'The prophet who has a dream, let him tell a dream; and he who has my word, let him speak my word faithfully. What is the straw to the wheat?” says the LORD.'),
  ('Jeremiah', 23, 29, '“Isn’t my word like fire?” says the LORD; “and like a hammer that breaks the rock in pieces?'),
  ('Jeremiah', 23, 30, '“Therefore behold, I am against the prophets,” says the LORD, “who each steal my words from his neighbor.'),
  ('Jeremiah', 23, 31, 'Behold, I am against the prophets,” says the LORD, “who use their tongues, and say, ‘He says.’'),
  ('Jeremiah', 23, 32, 'Behold, I am against those who prophesy lying dreams,” says the LORD, “who tell them, and cause my people to err by their lies, and by their vain boasting; yet I didn’t send them or command them. They don’t profit this people at all,” says the LORD.'),
  ('Jeremiah', 23, 33, '“When this people, or the prophet, or a priest, asks you, saying, ‘What is the message from the LORD?’ Then you shall tell them, ‘“What message? I will cast you off,” says the LORD.’'),
  ('Jeremiah', 23, 34, 'As for the prophet, the priest, and the people, who say, ‘The message from the LORD,’ I will even punish that man and his household.'),
  ('Jeremiah', 23, 35, 'You will say everyone to his neighbor, and everyone to his brother, ‘What has the LORD answered?’ and, ‘What has the LORD said?’'),
  ('Jeremiah', 23, 36, 'You will mention the message from the LORD no more, for every man’s own word has become his message; for you have perverted the words of the living God, of the LORD of Armies, our God.'),
  ('Jeremiah', 23, 37, 'You will say to the prophet, ‘What has the LORD answered you?’ and, ‘What has the LORD spoken?’'),
  ('Jeremiah', 23, 38, 'Although you say, ‘The message from the LORD,’ therefore the LORD says: ‘Because you say this word, “The message from the LORD,” and I have sent to you, telling you not to say, “The message from the LORD,”'),
  ('Jeremiah', 23, 39, 'therefore behold, I will utterly forget you, and I will cast you off with the city that I gave to you and to your fathers, away from my presence.'),
  ('Jeremiah', 23, 40, 'I will bring an everlasting reproach on you, and a perpetual shame, which will not be forgotten.’”'),
  ('Jeremiah', 24, 1, 'The LORD showed me, and behold, two baskets of figs were set before the LORD’s temple, after Nebuchadnezzar king of Babylon had carried away captive Jeconiah the son of Jehoiakim, king of Judah, and the princes of Judah, with the craftsmen and smiths, from Jerusalem, and had brought them to Babylon.'),
  ('Jeremiah', 24, 2, 'One basket had very good figs, like the figs that are first-ripe; and the other basket had very bad figs, which could not be eaten, they were so bad.'),
  ('Jeremiah', 24, 3, 'Then the LORD asked me, “What do you see, Jeremiah?” I said, “Figs. The good figs are very good, and the bad are very bad, so bad that they can’t be eaten.”'),
  ('Jeremiah', 24, 4, 'The LORD’s word came to me, saying,'),
  ('Jeremiah', 24, 5, '“The LORD, the God of Israel says: ‘Like these good figs, so I will regard the captives of Judah, whom I have sent out of this place into the land of the Chaldeans, as good.'),
  ('Jeremiah', 24, 6, 'For I will set my eyes on them for good, and I will bring them again to this land. I will build them, and not pull them down. I will plant them, and not pluck them up.'),
  ('Jeremiah', 24, 7, 'I will give them a heart to know me, that I am the LORD. They will be my people, and I will be their God; for they will return to me with their whole heart.'),
  ('Jeremiah', 24, 8, '“‘As the bad figs, which can’t be eaten, they are so bad,’ surely the LORD says, ‘So I will give up Zedekiah the king of Judah, and his princes, and the remnant of Jerusalem who remain in this land, and those who dwell in the land of Egypt.'),
  ('Jeremiah', 24, 9, 'I will even give them up to be tossed back and forth among all the kingdoms of the earth for evil, to be a reproach and a proverb, a taunt and a curse, in all places where I will drive them.'),
  ('Jeremiah', 24, 10, 'I will send the sword, the famine, and the pestilence among them, until they are consumed from off the land that I gave to them and to their fathers.’”'),
  ('Jeremiah', 25, 1, 'The word that came to Jeremiah concerning all the people of Judah, in the fourth year of Jehoiakim the son of Josiah, king of Judah (this was the first year of Nebuchadnezzar king of Babylon),'),
  ('Jeremiah', 25, 2, 'which Jeremiah the prophet spoke to all the people of Judah, and to all the inhabitants of Jerusalem:'),
  ('Jeremiah', 25, 3, 'From the thirteenth year of Josiah the son of Amon, king of Judah, even to this day, these twenty-three years, the LORD’s word has come to me, and I have spoken to you, rising up early and speaking; but you have not listened.'),
  ('Jeremiah', 25, 4, 'The LORD has sent to you all his servants the prophets, rising up early and sending them (but you have not listened or inclined your ear to hear),'),
  ('Jeremiah', 25, 5, 'saying, “Return now everyone from his evil way, and from the evil of your doings, and dwell in the land that the LORD has given to you and to your fathers, from of old and even forever more.'),
  ('Jeremiah', 25, 6, 'Don’t go after other gods to serve them or worship them, and don’t provoke me to anger with the work of your hands; then I will do you no harm.”'),
  ('Jeremiah', 25, 7, '“Yet you have not listened to me,” says the LORD, “that you may provoke me to anger with the work of your hands to your own hurt.”'),
  ('Jeremiah', 25, 8, 'Therefore the LORD of Armies says: “Because you have not heard my words,'),
  ('Jeremiah', 25, 9, 'behold, I will send and take all the families of the north,” says the LORD, “and I will send to Nebuchadnezzar the king of Babylon, my servant, and will bring them against this land, and against its inhabitants, and against all these nations around. I will utterly destroy them, and make them an astonishment, and a hissing, and perpetual desolations.'),
  ('Jeremiah', 25, 10, 'Moreover I will take from them the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride, the sound of the millstones, and the light of the lamp.'),
  ('Jeremiah', 25, 11, 'This whole land will be a desolation, and an astonishment; and these nations will serve the king of Babylon seventy years.'),
  ('Jeremiah', 25, 12, '“It will happen, when seventy years are accomplished, that I will punish the king of Babylon and that nation,” says the LORD, “for their iniquity. I will make the land of the Chaldeans desolate forever.'),
  ('Jeremiah', 25, 13, 'I will bring on that land all my words which I have pronounced against it, even all that is written in this book, which Jeremiah has prophesied against all the nations.'),
  ('Jeremiah', 25, 14, 'For many nations and great kings will make bondservants of them, even of them. I will recompense them according to their deeds, and according to the work of their hands.”'),
  ('Jeremiah', 25, 15, 'For the LORD, the God of Israel, says to me: “Take this cup of the wine of wrath from my hand, and cause all the nations to whom I send you to drink it.'),
  ('Jeremiah', 25, 16, 'They will drink, and reel back and forth, and be insane, because of the sword that I will send among them.”'),
  ('Jeremiah', 25, 17, 'Then I took the cup at the LORD’s hand, and made all the nations to drink, to whom the LORD had sent me:'),
  ('Jeremiah', 25, 18, 'Jerusalem, and the cities of Judah, with its kings and its princes, to make them a desolation, an astonishment, a hissing, and a curse, as it is today;'),
  ('Jeremiah', 25, 19, 'Pharaoh king of Egypt, with his servants, his princes, and all his people;'),
  ('Jeremiah', 25, 20, 'and all the mixed people, and all the kings of the land of Uz, all the kings of the Philistines, Ashkelon, Gaza, Ekron, and the remnant of Ashdod;'),
  ('Jeremiah', 25, 21, 'Edom, Moab, and the children of Ammon;'),
  ('Jeremiah', 25, 22, 'and all the kings of Tyre, all the kings of Sidon, and the kings of the isle which is beyond the sea;'),
  ('Jeremiah', 25, 23, 'Dedan, Tema, Buz, and all who have the corners of their beard cut off;'),
  ('Jeremiah', 25, 24, 'and all the kings of Arabia, all the kings of the mixed people who dwell in the wilderness;'),
  ('Jeremiah', 25, 25, 'and all the kings of Zimri, all the kings of Elam, and all the kings of the Medes;'),
  ('Jeremiah', 25, 26, 'and all the kings of the north, far and near, one with another; and all the kingdoms of the world, which are on the surface of the earth. The king of Sheshach will drink after them.'),
  ('Jeremiah', 25, 27, '“You shall tell them, ‘The LORD of Armies, the God of Israel says: “Drink, and be drunk, vomit, fall, and rise no more, because of the sword which I will send among you.”’'),
  ('Jeremiah', 25, 28, 'It shall be, if they refuse to take the cup at your hand to drink, then you shall tell them, ‘The LORD of Armies says: “You shall surely drink.'),
  ('Jeremiah', 25, 29, 'For, behold, I begin to work evil at the city which is called by my name; and should you be utterly unpunished? You will not be unpunished; for I will call for a sword on all the inhabitants of the earth, says the LORD of Armies.”’'),
  ('Jeremiah', 25, 30, '“Therefore prophesy against them all these words, and tell them, “‘The LORD will roar from on high, and utter his voice from his holy habitation. He will mightily roar against his fold. He will give a shout, as those who tread grapes, against all the inhabitants of the earth.'),
  ('Jeremiah', 25, 31, 'A noise will come even to the end of the earth; for the LORD has a controversy with the nations. He will enter into judgment with all flesh. As for the wicked, he will give them to the sword,”’ says the LORD.”'),
  ('Jeremiah', 25, 32, 'The LORD of Armies says, “Behold, evil will go out from nation to nation, and a great storm will be raised up from the uttermost parts of the earth.”'),
  ('Jeremiah', 25, 33, 'The slain of the LORD will be at that day from one end of the earth even to the other end of the earth. They won’t be lamented. They won’t be gathered or buried. They will be dung on the surface of the ground.'),
  ('Jeremiah', 25, 34, 'Wail, you shepherds, and cry. Wallow in dust, you leader of the flock; for the days of your slaughter and of your dispersions have fully come, and you will fall like fine pottery.'),
  ('Jeremiah', 25, 35, 'The shepherds will have no way to flee. The leader of the flock will have no escape.'),
  ('Jeremiah', 25, 36, 'A voice of the cry of the shepherds, and the wailing of the leader of the flock, for the LORD destroys their pasture.'),
  ('Jeremiah', 25, 37, 'The peaceful folds are brought to silence because of the fierce anger of the LORD.'),
  ('Jeremiah', 25, 38, 'He has left his covert, as the lion; for their land has become an astonishment because of the fierceness of the oppression, and because of his fierce anger.'),
  ('Jeremiah', 26, 1, 'In the beginning of the reign of Jehoiakim the son of Josiah, king of Judah, this word came from the LORD:'),
  ('Jeremiah', 26, 2, '“The LORD says: ‘Stand in the court of the LORD’s house, and speak to all the cities of Judah which come to worship in the LORD’s house, all the words that I command you to speak to them. Don’t omit a word.'),
  ('Jeremiah', 26, 3, 'It may be they will listen, and every man turn from his evil way, that I may relent from the evil which I intend to do to them because of the evil of their doings.’”'),
  ('Jeremiah', 26, 4, 'You shall tell them, “The LORD says: ‘If you will not listen to me, to walk in my law which I have set before you,'),
  ('Jeremiah', 26, 5, 'to listen to the words of my servants the prophets whom I send to you, even rising up early and sending them—but you have not listened—'),
  ('Jeremiah', 26, 6, 'then I will make this house like Shiloh, and will make this city a curse to all the nations of the earth.’”'),
  ('Jeremiah', 26, 7, 'The priests and the prophets and all the people heard Jeremiah speaking these words in the LORD’s house.'),
  ('Jeremiah', 26, 8, 'When Jeremiah had finished speaking all that the LORD had commanded him to speak to all the people, the priests and the prophets and all the people seized him, saying, “You shall surely die!'),
  ('Jeremiah', 26, 9, 'Why have you prophesied in the LORD’s name, saying, ‘This house will be like Shiloh, and this city will be desolate, without inhabitant’?” All the people were crowded around Jeremiah in the LORD’s house.'),
  ('Jeremiah', 26, 10, 'When the princes of Judah heard these things, they came up from the king’s house to the LORD’s house; and they sat in the entry of the new gate of the LORD’s house.'),
  ('Jeremiah', 26, 11, 'Then the priests and the prophets spoke to the princes and to all the people, saying, “This man is worthy of death, for he has prophesied against this city, as you have heard with your ears.”'),
  ('Jeremiah', 26, 12, 'Then Jeremiah spoke to all the princes and to all the people, saying, “The LORD sent me to prophesy against this house and against this city all the words that you have heard.'),
  ('Jeremiah', 26, 13, 'Now therefore amend your ways and your doings, and obey the LORD your God’s voice; then the LORD will relent from the evil that he has pronounced against you.'),
  ('Jeremiah', 26, 14, 'But as for me, behold, I am in your hand. Do with me what is good and right in your eyes.'),
  ('Jeremiah', 26, 15, 'Only know for certain that if you put me to death, you will bring innocent blood on yourselves, on this city, and on its inhabitants; for in truth the LORD has sent me to you to speak all these words in your ears.”'),
  ('Jeremiah', 26, 16, 'Then the princes and all the people said to the priests and to the prophets: “This man is not worthy of death; for he has spoken to us in the name of the LORD our God.”'),
  ('Jeremiah', 26, 17, 'Then certain of the elders of the land rose up, and spoke to all the assembly of the people, saying,'),
  ('Jeremiah', 26, 18, '“Micah the Morashtite prophesied in the days of Hezekiah king of Judah; and he spoke to all the people of Judah, saying, ‘The LORD of Armies says: “‘Zion will be plowed as a field, and Jerusalem will become heaps, and the mountain of the house as the high places of a forest.’'),
  ('Jeremiah', 26, 19, 'Did Hezekiah king of Judah and all Judah put him to death? Didn’t he fear the LORD, and entreat the favor of the LORD, and the LORD relented of the disaster which he had pronounced against them? We would commit great evil against our own souls that way!”'),
  ('Jeremiah', 26, 20, 'There was also a man who prophesied in the LORD’s name, Uriah the son of Shemaiah of Kiriath Jearim; and he prophesied against this city and against this land according to all the words of Jeremiah.'),
  ('Jeremiah', 26, 21, 'When Jehoiakim the king, with all his mighty men and all the princes heard his words, the king sought to put him to death; but when Uriah heard it, he was afraid, and fled, and went into Egypt.'),
  ('Jeremiah', 26, 22, 'Then Jehoiakim the king sent Elnathan the son of Achbor and certain men with him into Egypt.'),
  ('Jeremiah', 26, 23, 'They fetched Uriah out of Egypt and brought him to Jehoiakim the king, who killed him with the sword and cast his dead body into the graves of the common people.'),
  ('Jeremiah', 26, 24, 'But the hand of Ahikam the son of Shaphan was with Jeremiah, so that they didn’t give him into the hand of the people to put him to death.'),
  ('Jeremiah', 27, 1, 'In the beginning of the reign of Jehoiakim the son of Josiah, king of Judah, this word came to Jeremiah from the LORD, saying,'),
  ('Jeremiah', 27, 2, 'the LORD says to me: “Make bonds and bars, and put them on your neck.'),
  ('Jeremiah', 27, 3, 'Then send them to the king of Edom, to the king of Moab, to the king of the children of Ammon, to the king of Tyre, and to the king of Sidon, by the hand of the messengers who come to Jerusalem to Zedekiah king of Judah.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 27, 4, 'Give them a command to their masters, saying, ‘The LORD of Armies, the God of Israel says, “You shall tell your masters:'),
  ('Jeremiah', 27, 5, '‘I have made the earth, the men, and the animals that are on the surface of the earth by my great power and by my outstretched arm. I give it to whom it seems right to me.'),
  ('Jeremiah', 27, 6, 'Now I have given all these lands into the hand of Nebuchadnezzar the king of Babylon, my servant. I have also given the animals of the field to him to serve him.'),
  ('Jeremiah', 27, 7, 'All the nations will serve him, his son, and his son’s son, until the time of his own land comes. Then many nations and great kings will make him their bondservant.'),
  ('Jeremiah', 27, 8, '“‘“‘It will happen that I will punish the nation and the kingdom which will not serve the same Nebuchadnezzar king of Babylon, and that will not put their neck under the yoke of the king of Babylon,’ says the LORD, ‘with the sword, with famine, and with pestilence, until I have consumed them by his hand.'),
  ('Jeremiah', 27, 9, 'But as for you, don’t listen to your prophets, to your diviners, to your dreams, to your soothsayers, or to your sorcerers, who speak to you, saying, “You shall not serve the king of Babylon;”'),
  ('Jeremiah', 27, 10, 'for they prophesy a lie to you, to remove you far from your land, so that I would drive you out, and you would perish.'),
  ('Jeremiah', 27, 11, 'But the nation that brings their neck under the yoke of the king of Babylon and serves him, that nation I will let remain in their own land,’ says the LORD; ‘and they will till it and dwell in it.’”’”'),
  ('Jeremiah', 27, 12, 'I spoke to Zedekiah king of Judah according to all these words, saying, “Bring your necks under the yoke of the king of Babylon, and serve him and his people, and live.'),
  ('Jeremiah', 27, 13, 'Why will you die, you and your people, by the sword, by the famine, and by the pestilence, as the LORD has spoken concerning the nation that will not serve the king of Babylon?'),
  ('Jeremiah', 27, 14, 'Don’t listen to the words of the prophets who speak to you, saying, ‘You shall not serve the king of Babylon;’ for they prophesy a lie to you.'),
  ('Jeremiah', 27, 15, 'For I have not sent them,” says the LORD, “but they prophesy falsely in my name; that I may drive you out, and that you may perish, you, and the prophets who prophesy to you.”'),
  ('Jeremiah', 27, 16, 'Also I spoke to the priests and to all this people, saying, the LORD says, “Don’t listen to the words of your prophets who prophesy to you, saying, ‘Behold, the vessels of the LORD’s house will now shortly be brought again from Babylon;’ for they prophesy a lie to you.'),
  ('Jeremiah', 27, 17, 'Don’t listen to them. Serve the king of Babylon, and live. Why should this city become a desolation?'),
  ('Jeremiah', 27, 18, 'But if they are prophets, and if the LORD’s word is with them, let them now make intercession to the LORD of Armies, that the vessels which are left in the LORD’s house, in the house of the king of Judah, and at Jerusalem, don’t go to Babylon.'),
  ('Jeremiah', 27, 19, 'For the LORD of Armies says concerning the pillars, concerning the sea, concerning the bases, and concerning the rest of the vessels that are left in this city,'),
  ('Jeremiah', 27, 20, 'which Nebuchadnezzar king of Babylon didn’t take when he carried away captive Jeconiah the son of Jehoiakim, king of Judah, from Jerusalem to Babylon, and all the nobles of Judah and Jerusalem—'),
  ('Jeremiah', 27, 21, 'yes, the LORD of Armies, the God of Israel, says concerning the vessels that are left in the LORD’s house, and in the house of the king of Judah, and at Jerusalem:'),
  ('Jeremiah', 27, 22, '‘They will be carried to Babylon, and there they will be, until the day that I visit them,’ says the LORD; ‘then I will bring them up, and restore them to this place.’”'),
  ('Jeremiah', 28, 1, 'That same year, in the beginning of the reign of Zedekiah king of Judah, in the fourth year, in the fifth month, Hananiah the son of Azzur, the prophet, who was of Gibeon, spoke to me in the LORD’s house, in the presence of the priests and of all the people, saying,'),
  ('Jeremiah', 28, 2, '“The LORD of Armies, the God of Israel, says, ‘I have broken the yoke of the king of Babylon.'),
  ('Jeremiah', 28, 3, 'Within two full years I will bring again into this place all the vessels of the LORD’s house that Nebuchadnezzar king of Babylon took away from this place and carried to Babylon.'),
  ('Jeremiah', 28, 4, 'I will bring again to this place Jeconiah the son of Jehoiakim, king of Judah, with all the captives of Judah, who went to Babylon,’ says the LORD; ‘for I will break the yoke of the king of Babylon.’”'),
  ('Jeremiah', 28, 5, 'Then the prophet Jeremiah said to the prophet Hananiah in the presence of the priests, and in the presence of all the people who stood in the LORD’s house,'),
  ('Jeremiah', 28, 6, 'even the prophet Jeremiah said, “Amen! May the LORD do so. May the LORD perform your words which you have prophesied, to bring again the vessels of the LORD’s house, and all those who are captives, from Babylon to this place.'),
  ('Jeremiah', 28, 7, 'Nevertheless listen now to this word that I speak in your ears, and in the ears of all the people:'),
  ('Jeremiah', 28, 8, 'The prophets who have been before me and before you of old prophesied against many countries, and against great kingdoms, of war, of evil, and of pestilence.'),
  ('Jeremiah', 28, 9, 'As for the prophet who prophesies of peace, when the word of the prophet happens, then the prophet will be known, that the LORD has truly sent him.”'),
  ('Jeremiah', 28, 10, 'Then Hananiah the prophet took the bar from off the prophet Jeremiah’s neck, and broke it.'),
  ('Jeremiah', 28, 11, 'Hananiah spoke in the presence of all the people, saying, “The LORD says: ‘Even so I will break the yoke of Nebuchadnezzar king of Babylon from off the neck of all the nations within two full years.’” Then the prophet Jeremiah went his way.'),
  ('Jeremiah', 28, 12, 'Then the LORD’s word came to Jeremiah, after Hananiah the prophet had broken the bar from off the neck of the prophet Jeremiah, saying,'),
  ('Jeremiah', 28, 13, '“Go, and tell Hananiah, saying, ‘The LORD says, “You have broken the bars of wood, but you have made in their place bars of iron.”'),
  ('Jeremiah', 28, 14, 'For the LORD of Armies, the God of Israel says, “I have put a yoke of iron on the neck of all these nations, that they may serve Nebuchadnezzar king of Babylon; and they will serve him. I have also given him the animals of the field.”’”'),
  ('Jeremiah', 28, 15, 'Then the prophet Jeremiah said to Hananiah the prophet, “Listen, Hananiah! The LORD has not sent you, but you make this people trust in a lie.'),
  ('Jeremiah', 28, 16, 'Therefore the LORD says, ‘Behold, I will send you away from off the surface of the earth. This year you will die, because you have spoken rebellion against the LORD.’”'),
  ('Jeremiah', 28, 17, 'So Hananiah the prophet died the same year in the seventh month.'),
  ('Jeremiah', 29, 1, 'Now these are the words of the letter that Jeremiah the prophet sent from Jerusalem to the residue of the elders of the captivity, and to the priests, to the prophets, and to all the people whom Nebuchadnezzar had carried away captive from Jerusalem to Babylon,'),
  ('Jeremiah', 29, 2, '(after Jeconiah the king, the queen mother, the eunuchs, the princes of Judah and Jerusalem, the craftsmen, and the smiths had departed from Jerusalem),'),
  ('Jeremiah', 29, 3, 'by the hand of Elasah the son of Shaphan and Gemariah the son of Hilkiah, (whom Zedekiah king of Judah sent to Babylon to Nebuchadnezzar king of Babylon). It said:'),
  ('Jeremiah', 29, 4, 'The LORD of Armies, the God of Israel, says to all the captives whom I have caused to be carried away captive from Jerusalem to Babylon:'),
  ('Jeremiah', 29, 5, '“Build houses and dwell in them. Plant gardens and eat their fruit.'),
  ('Jeremiah', 29, 6, 'Take wives and father sons and daughters. Take wives for your sons, and give your daughters to husbands, that they may bear sons and daughters. Multiply there, and don’t be diminished.'),
  ('Jeremiah', 29, 7, 'Seek the peace of the city where I have caused you to be carried away captive, and pray to the LORD for it; for in its peace you will have peace.”'),
  ('Jeremiah', 29, 8, 'For the LORD of Armies, the God of Israel says: “Don’t let your prophets who are among you and your diviners deceive you. Don’t listen to your dreams which you cause to be dreamed.'),
  ('Jeremiah', 29, 9, 'For they prophesy falsely to you in my name. I have not sent them,” says the LORD.'),
  ('Jeremiah', 29, 10, 'For the LORD says, “After seventy years are accomplished for Babylon, I will visit you and perform my good word toward you, in causing you to return to this place.'),
  ('Jeremiah', 29, 11, 'For I know the thoughts that I think toward you,” says the LORD, “thoughts of peace, and not of evil, to give you hope and a future.'),
  ('Jeremiah', 29, 12, 'You shall call on me, and you shall go and pray to me, and I will listen to you.'),
  ('Jeremiah', 29, 13, 'You shall seek me and find me, when you search for me with all your heart.'),
  ('Jeremiah', 29, 14, 'I will be found by you,” says the LORD, “and I will turn again your captivity, and I will gather you from all the nations, and from all the places where I have driven you,” says the LORD. “I will bring you again to the place from where I caused you to be carried away captive.”'),
  ('Jeremiah', 29, 15, 'Because you have said, “The LORD has raised us up prophets in Babylon,”'),
  ('Jeremiah', 29, 16, 'the LORD says concerning the king who sits on David’s throne, and concerning all the people who dwell in this city, your brothers who haven’t gone with you into captivity,'),
  ('Jeremiah', 29, 17, 'the LORD of Armies says: “Behold, I will send on them the sword, the famine, and the pestilence, and will make them like rotten figs that can’t be eaten, they are so bad.'),
  ('Jeremiah', 29, 18, 'I will pursue after them with the sword, with the famine, and with the pestilence, and will deliver them to be tossed back and forth among all the kingdoms of the earth, to be an object of horror, an astonishment, a hissing, and a reproach among all the nations where I have driven them,'),
  ('Jeremiah', 29, 19, 'because they have not listened to my words,” says the LORD, “with which I sent to them my servants the prophets, rising up early and sending them; but you would not hear,” says the LORD.'),
  ('Jeremiah', 29, 20, 'Hear therefore the LORD’s word, all you captives whom I have sent away from Jerusalem to Babylon.'),
  ('Jeremiah', 29, 21, 'The LORD of Armies, the God of Israel, says concerning Ahab the son of Kolaiah, and concerning Zedekiah the son of Maaseiah, who prophesy a lie to you in my name: “Behold, I will deliver them into the hand of Nebuchadnezzar king of Babylon; and he will kill them before your eyes.'),
  ('Jeremiah', 29, 22, 'A curse will be taken up about them by all the captives of Judah who are in Babylon, saying, ‘The LORD make you like Zedekiah and like Ahab, whom the king of Babylon roasted in the fire;’'),
  ('Jeremiah', 29, 23, 'because they have done foolish things in Israel, and have committed adultery with their neighbors’ wives, and have spoken words in my name falsely, which I didn’t command them. I am he who knows, and am witness,” says the LORD.'),
  ('Jeremiah', 29, 24, 'Concerning Shemaiah the Nehelamite you shall speak, saying,'),
  ('Jeremiah', 29, 25, '“The LORD of Armies, the God of Israel, says, ‘Because you have sent letters in your own name to all the people who are at Jerusalem, and to Zephaniah the son of Maaseiah, the priest, and to all the priests, saying,'),
  ('Jeremiah', 29, 26, '“The LORD has made you priest in the place of Jehoiada the priest, that there may be officers in the LORD’s house, for every man who is crazy and makes himself a prophet, that you should put him in the stocks and in shackles.'),
  ('Jeremiah', 29, 27, 'Now therefore, why have you not rebuked Jeremiah of Anathoth, who makes himself a prophet to you,'),
  ('Jeremiah', 29, 28, 'because he has sent to us in Babylon, saying, The captivity is long. Build houses, and dwell in them. Plant gardens, and eat their fruit?”’”'),
  ('Jeremiah', 29, 29, 'Zephaniah the priest read this letter in the hearing of Jeremiah the prophet.'),
  ('Jeremiah', 29, 30, 'Then the LORD’s word came to Jeremiah, saying,'),
  ('Jeremiah', 29, 31, '“Send to all of the captives, saying, ‘The LORD says concerning Shemaiah the Nehelamite: “Because Shemaiah has prophesied to you, and I didn’t send him, and he has caused you to trust in a lie,”'),
  ('Jeremiah', 29, 32, 'therefore the LORD says, “Behold, I will punish Shemaiah the Nehelamite and his offspring. He will not have a man to dwell among this people. He won’t see the good that I will do to my people,” says the LORD, “because he has spoken rebellion against the LORD.”’”'),
  ('Jeremiah', 30, 1, 'The word that came to Jeremiah from the LORD, saying,'),
  ('Jeremiah', 30, 2, '“The LORD, the God of Israel, says, ‘Write all the words that I have spoken to you in a book.'),
  ('Jeremiah', 30, 3, 'For, behold, the days come,’ says the LORD, ‘that I will reverse the captivity of my people Israel and Judah,’ says the LORD. ‘I will cause them to return to the land that I gave to their fathers, and they will possess it.’”'),
  ('Jeremiah', 30, 4, 'These are the words that the LORD spoke concerning Israel and concerning Judah.'),
  ('Jeremiah', 30, 5, 'For the LORD says: “We have heard a voice of trembling; a voice of fear, and not of peace.'),
  ('Jeremiah', 30, 6, 'Ask now, and see whether a man travails with child. Why do I see every man with his hands on his waist, as a woman in travail, and all faces are turned pale?'),
  ('Jeremiah', 30, 7, 'Alas, for that day is great, so that none is like it! It is even the time of Jacob’s trouble; but he will be saved out of it.'),
  ('Jeremiah', 30, 8, 'It will come to pass in that day, says the LORD of Armies, that I will break his yoke from off your neck, and will burst your bonds. Strangers will no more make them their bondservants;'),
  ('Jeremiah', 30, 9, 'but they will serve the LORD their God, and David their king, whom I will raise up to them.'),
  ('Jeremiah', 30, 10, 'Therefore don’t be afraid, O Jacob my servant, says the LORD. Don’t be dismayed, Israel. For, behold, I will save you from afar, and save your offspring from the land of their captivity. Jacob will return, and will be quiet and at ease. No one will make him afraid.'),
  ('Jeremiah', 30, 11, 'For I am with you, says the LORD, to save you; for I will make a full end of all the nations where I have scattered you, but I will not make a full end of you; but I will correct you in measure, and will in no way leave you unpunished.”'),
  ('Jeremiah', 30, 12, 'For the LORD says, “Your hurt is incurable. Your wound is grievous.'),
  ('Jeremiah', 30, 13, 'There is no one to plead your cause, that you may be bound up. You have no healing medicines.'),
  ('Jeremiah', 30, 14, 'All your lovers have forgotten you. They don’t seek you. For I have wounded you with the wound of an enemy, with the chastisement of a cruel one, for the greatness of your iniquity, because your sins were increased.'),
  ('Jeremiah', 30, 15, 'Why do you cry over your injury? Your pain is incurable. For the greatness of your iniquity, because your sins have increased, I have done these things to you.'),
  ('Jeremiah', 30, 16, 'Therefore all those who devour you will be devoured. All your adversaries, everyone of them, will go into captivity. Those who plunder you will be plunder. I will make all who prey on you become prey.'),
  ('Jeremiah', 30, 17, 'For I will restore health to you, and I will heal you of your wounds,” says the LORD, “because they have called you an outcast, saying, ‘It is Zion, whom no man seeks after.’”'),
  ('Jeremiah', 30, 18, 'The LORD says: “Behold, I will reverse the captivity of Jacob’s tents, and have compassion on his dwelling places. The city will be built on its own hill, and the palace will be inhabited in its own place.'),
  ('Jeremiah', 30, 19, 'Thanksgiving will proceed out of them with the voice of those who make merry. I will multiply them, and they will not be few; I will also glorify them, and they will not be small.'),
  ('Jeremiah', 30, 20, 'Their children also will be as before, and their congregation will be established before me. I will punish all who oppress them.'),
  ('Jeremiah', 30, 21, 'Their prince will be one of them, and their ruler will proceed from among them. I will cause him to draw near, and he will approach me; for who is he who has had boldness to approach me?” says the LORD.'),
  ('Jeremiah', 30, 22, '“You shall be my people, and I will be your God.'),
  ('Jeremiah', 30, 23, 'Behold, the LORD’s storm, his wrath, has gone out, a sweeping storm; it will burst on the head of the wicked.'),
  ('Jeremiah', 30, 24, 'The fierce anger of the LORD will not return until he has accomplished, and until he has performed the intentions of his heart. In the latter days you will understand it.”'),
  ('Jeremiah', 31, 1, '“At that time,” says the LORD, “I will be the God of all the families of Israel, and they will be my people.”'),
  ('Jeremiah', 31, 2, 'The LORD says, “The people who survive the sword found favor in the wilderness; even Israel, when I went to cause him to rest.”'),
  ('Jeremiah', 31, 3, 'The LORD appeared of old to me, saying, “Yes, I have loved you with an everlasting love. Therefore I have drawn you with loving kindness.'),
  ('Jeremiah', 31, 4, 'I will build you again, and you will be built, O virgin of Israel. You will again be adorned with your tambourines, and will go out in the dances of those who make merry.'),
  ('Jeremiah', 31, 5, 'Again you will plant vineyards on the mountains of Samaria. The planters will plant, and will enjoy its fruit.'),
  ('Jeremiah', 31, 6, 'For there will be a day that the watchmen on the hills of Ephraim cry, ‘Arise! Let’s go up to Zion to the LORD our God.’”'),
  ('Jeremiah', 31, 7, 'For the LORD says, “Sing with gladness for Jacob, and shout for the chief of the nations. Publish, praise, and say, ‘LORD, save your people, the remnant of Israel!’'),
  ('Jeremiah', 31, 8, 'Behold, I will bring them from the north country, and gather them from the uttermost parts of the earth, along with the blind and the lame, the woman with child and her who travails with child together. They will return as a great company.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 31, 9, 'They will come with weeping. I will lead them with petitions. I will cause them to walk by rivers of waters, in a straight way in which they won’t stumble; for I am a father to Israel. Ephraim is my firstborn.'),
  ('Jeremiah', 31, 10, '“Hear the LORD’s word, you nations, and declare it in the distant islands. Say, ‘He who scattered Israel will gather him, and keep him, as a shepherd does his flock.’'),
  ('Jeremiah', 31, 11, 'For the LORD has ransomed Jacob, and redeemed him from the hand of him who was stronger than he.'),
  ('Jeremiah', 31, 12, 'They will come and sing in the height of Zion, and will flow to the goodness of the LORD, to the grain, to the new wine, to the oil, and to the young of the flock and of the herd. Their soul will be as a watered garden. They will not sorrow any more at all.'),
  ('Jeremiah', 31, 13, 'Then the virgin will rejoice in the dance, the young men and the old together; for I will turn their mourning into joy, and will comfort them, and make them rejoice from their sorrow.'),
  ('Jeremiah', 31, 14, 'I will satiate the soul of the priests with fatness, and my people will be satisfied with my goodness,” says the LORD.'),
  ('Jeremiah', 31, 15, 'The LORD says: “A voice is heard in Ramah, lamentation and bitter weeping, Rachel weeping for her children. She refuses to be comforted for her children, because they are no more.”'),
  ('Jeremiah', 31, 16, 'The LORD says: “Refrain your voice from weeping, and your eyes from tears, for your work will be rewarded,” says the LORD. “They will come again from the land of the enemy.'),
  ('Jeremiah', 31, 17, 'There is hope for your latter end,” says the LORD. “Your children will come again to their own territory.'),
  ('Jeremiah', 31, 18, '“I have surely heard Ephraim grieving thus, ‘You have chastised me, and I was chastised, as an untrained calf. Turn me, and I will be turned, for you are the LORD my God.'),
  ('Jeremiah', 31, 19, 'Surely after that I was turned. I repented. After that I was instructed. I struck my thigh. I was ashamed, yes, even confounded, because I bore the reproach of my youth.’'),
  ('Jeremiah', 31, 20, 'Is Ephraim my dear son? Is he a darling child? For as often as I speak against him, I still earnestly remember him. Therefore my heart yearns for him. I will surely have mercy on him,” says the LORD.'),
  ('Jeremiah', 31, 21, '“Set up road signs. Make guideposts. Set your heart toward the highway, even the way by which you went. Turn again, virgin of Israel. Turn again to these your cities.'),
  ('Jeremiah', 31, 22, 'How long will you go here and there, you backsliding daughter? For the LORD has created a new thing in the earth: a woman will encompass a man.”'),
  ('Jeremiah', 31, 23, 'The LORD of Armies, the God of Israel, says: “Yet again they will use this speech in the land of Judah and in its cities, when I reverse their captivity: ‘The LORD bless you, habitation of righteousness, mountain of holiness.’'),
  ('Jeremiah', 31, 24, 'Judah and all its cities will dwell therein together, the farmers, and those who go about with flocks.'),
  ('Jeremiah', 31, 25, 'For I have satiated the weary soul, and I have replenished every sorrowful soul.”'),
  ('Jeremiah', 31, 26, 'On this I awakened, and saw; and my sleep was sweet to me.'),
  ('Jeremiah', 31, 27, '“Behold, the days come,” says the LORD, “that I will sow the house of Israel and the house of Judah with the seed of man and with the seed of animal.'),
  ('Jeremiah', 31, 28, 'It will happen that, like as I have watched over them to pluck up and to break down and to overthrow and to destroy and to afflict, so I will watch over them to build and to plant,” says the LORD.'),
  ('Jeremiah', 31, 29, '“In those days they will say no more, “‘The fathers have eaten sour grapes, and the children’s teeth are set on edge.’'),
  ('Jeremiah', 31, 30, 'But everyone will die for his own iniquity. Every man who eats the sour grapes, his teeth will be set on edge.'),
  ('Jeremiah', 31, 31, '“Behold, the days come,” says the LORD, “that I will make a new covenant with the house of Israel, and with the house of Judah,'),
  ('Jeremiah', 31, 32, 'not according to the covenant that I made with their fathers in the day that I took them by the hand to bring them out of the land of Egypt, which covenant of mine they broke, although I was a husband to them,” says the LORD.'),
  ('Jeremiah', 31, 33, '“But this is the covenant that I will make with the house of Israel after those days,” says the LORD: “I will put my law in their inward parts, and I will write it in their heart. I will be their God, and they shall be my people.'),
  ('Jeremiah', 31, 34, 'They will no longer each teach his neighbor, and every man teach his brother, saying, ‘Know the LORD;’ for they will all know me, from their least to their greatest,” says the LORD, “for I will forgive their iniquity, and I will remember their sin no more.”'),
  ('Jeremiah', 31, 35, 'The LORD, who gives the sun for a light by day, and the ordinances of the moon and of the stars for a light by night, who stirs up the sea, so that its waves roar— the LORD of Armies is his name, says:'),
  ('Jeremiah', 31, 36, '“If these ordinances depart from before me,” says the LORD, “then the offspring of Israel also will cease from being a nation before me forever.”'),
  ('Jeremiah', 31, 37, 'The LORD says: “If heaven above can be measured, and the foundations of the earth searched out beneath, then I will also cast off all the offspring of Israel for all that they have done,” says the LORD.'),
  ('Jeremiah', 31, 38, '“Behold, the days come,” says the LORD, “that the city will be built to the LORD from the tower of Hananel to the gate of the corner.'),
  ('Jeremiah', 31, 39, 'The measuring line will go out further straight onward to the hill Gareb, and will turn toward Goah.'),
  ('Jeremiah', 31, 40, 'The whole valley of the dead bodies and of the ashes, and all the fields to the brook Kidron, to the corner of the horse gate toward the east, will be holy to the LORD. It will not be plucked up or thrown down any more forever.”'),
  ('Jeremiah', 32, 1, 'This is the word that came to Jeremiah from the LORD in the tenth year of Zedekiah king of Judah, which was the eighteenth year of Nebuchadnezzar.'),
  ('Jeremiah', 32, 2, 'Now at that time the king of Babylon’s army was besieging Jerusalem. Jeremiah the prophet was shut up in the court of the guard, which was in the king of Judah’s house.'),
  ('Jeremiah', 32, 3, 'For Zedekiah king of Judah had shut him up, saying, “Why do you prophesy, and say, ‘The LORD says, “Behold, I will give this city into the hand of the king of Babylon, and he will take it;'),
  ('Jeremiah', 32, 4, 'and Zedekiah king of Judah won’t escape out of the hand of the Chaldeans, but will surely be delivered into the hand of the king of Babylon, and will speak with him mouth to mouth, and his eyes will see his eyes;'),
  ('Jeremiah', 32, 5, 'and he will bring Zedekiah to Babylon, and he will be there until I visit him,” says the LORD, “though you fight with the Chaldeans, you will not prosper”’?”'),
  ('Jeremiah', 32, 6, 'Jeremiah said, “The LORD’s word came to me, saying,'),
  ('Jeremiah', 32, 7, '‘Behold, Hanamel the son of Shallum your uncle will come to you, saying, “Buy my field that is in Anathoth; for the right of redemption is yours to buy it.”’”'),
  ('Jeremiah', 32, 8, '“So Hanamel my uncle’s son came to me in the court of the guard according to the LORD’s word, and said to me, ‘Please buy my field that is in Anathoth, which is in the land of Benjamin; for the right of inheritance is yours, and the redemption is yours. Buy it for yourself.’ “Then I knew that this was the LORD’s word.'),
  ('Jeremiah', 32, 9, 'I bought the field that was in Anathoth of Hanamel my uncle’s son, and weighed him the money, even seventeen shekels of silver.'),
  ('Jeremiah', 32, 10, 'I signed the deed, sealed it, called witnesses, and weighed the money in the balances to him.'),
  ('Jeremiah', 32, 11, 'So I took the deed of the purchase, both that which was sealed, containing the terms and conditions, and that which was open;'),
  ('Jeremiah', 32, 12, 'and I delivered the deed of the purchase to Baruch the son of Neriah, the son of Mahseiah, in the presence of Hanamel my uncle’s son, and in the presence of the witnesses who signed the deed of the purchase, before all the Jews who sat in the court of the guard.'),
  ('Jeremiah', 32, 13, '“I commanded Baruch before them, saying,'),
  ('Jeremiah', 32, 14, 'the LORD of Armies, the God of Israel, says: ‘Take these deeds, this deed of the purchase which is sealed, and this deed which is open, and put them in an earthen vessel, that they may last many days.’'),
  ('Jeremiah', 32, 15, 'For the LORD of Armies, the God of Israel says: ‘Houses and fields and vineyards will yet again be bought in this land.’'),
  ('Jeremiah', 32, 16, 'Now after I had delivered the deed of the purchase to Baruch the son of Neriah, I prayed to the LORD, saying,'),
  ('Jeremiah', 32, 17, '“Ah Lord GOD! Behold, you have made the heavens and the earth by your great power and by your outstretched arm. There is nothing too hard for you.'),
  ('Jeremiah', 32, 18, 'You show loving kindness to thousands, and repay the iniquity of the fathers into the bosom of their children after them. The great, the mighty God, the LORD of Armies is your name:'),
  ('Jeremiah', 32, 19, 'great in counsel, and mighty in work; whose eyes are open to all the ways of the children of men, to give everyone according to his ways, and according to the fruit of his doings;'),
  ('Jeremiah', 32, 20, 'who performed signs and wonders in the land of Egypt, even to this day, both in Israel and among other men; and made yourself a name, as it is today;'),
  ('Jeremiah', 32, 21, 'and brought your people Israel out of the land of Egypt with signs, with wonders, with a strong hand, with an outstretched arm, and with great terror;'),
  ('Jeremiah', 32, 22, 'and gave them this land, which you swore to their fathers to give them, a land flowing with milk and honey.'),
  ('Jeremiah', 32, 23, 'They came in and possessed it, but they didn’t obey your voice and didn’t walk in your law. They have done nothing of all that you commanded them to do. Therefore you have caused all this evil to come upon them.'),
  ('Jeremiah', 32, 24, '“Behold, siege ramps have been built against the city to take it. The city is given into the hand of the Chaldeans who fight against it, because of the sword, of the famine, and of the pestilence. What you have spoken has happened. Behold, you see it.'),
  ('Jeremiah', 32, 25, 'You have said to me, Lord GOD, ‘Buy the field for money, and call witnesses;’ whereas the city is given into the hand of the Chaldeans.”'),
  ('Jeremiah', 32, 26, 'Then the LORD’s word came to Jeremiah, saying,'),
  ('Jeremiah', 32, 27, '“Behold, I am the LORD, the God of all flesh. Is there anything too hard for me?'),
  ('Jeremiah', 32, 28, 'Therefore the LORD says: Behold, I will give this city into the hand of the Chaldeans, and into the hand of Nebuchadnezzar king of Babylon, and he will take it.'),
  ('Jeremiah', 32, 29, 'The Chaldeans, who fight against this city, will come and set this city on fire, and burn it with the houses on whose roofs they have offered incense to Baal, and poured out drink offerings to other gods, to provoke me to anger.'),
  ('Jeremiah', 32, 30, '“For the children of Israel and the children of Judah have done only that which was evil in my sight from their youth; for the children of Israel have only provoked me to anger with the work of their hands, says the LORD.'),
  ('Jeremiah', 32, 31, 'For this city has been to me a provocation of my anger and of my wrath from the day that they built it even to this day, so that I should remove it from before my face,'),
  ('Jeremiah', 32, 32, 'because of all the evil of the children of Israel and of the children of Judah, which they have done to provoke me to anger—they, their kings, their princes, their priests, their prophets, the men of Judah, and the inhabitants of Jerusalem.'),
  ('Jeremiah', 32, 33, 'They have turned their backs to me, and not their faces. Although I taught them, rising up early and teaching them, yet they have not listened to receive instruction.'),
  ('Jeremiah', 32, 34, 'But they set their abominations in the house which is called by my name, to defile it.'),
  ('Jeremiah', 32, 35, 'They built the high places of Baal, which are in the valley of the son of Hinnom, to cause their sons and their daughters to pass through fire to Molech, which I didn’t command them. It didn’t even come into my mind, that they should do this abomination, to cause Judah to sin.”'),
  ('Jeremiah', 32, 36, 'Now therefore the LORD, the God of Israel, says concerning this city, about which you say, “It is given into the hand of the king of Babylon by the sword, by the famine, and by the pestilence:”'),
  ('Jeremiah', 32, 37, '“Behold, I will gather them out of all the countries where I have driven them in my anger, and in my wrath, and in great indignation; and I will bring them again to this place. I will cause them to dwell safely.'),
  ('Jeremiah', 32, 38, 'Then they will be my people, and I will be their God.'),
  ('Jeremiah', 32, 39, 'I will give them one heart and one way, that they may fear me forever, for their good and the good of their children after them.'),
  ('Jeremiah', 32, 40, 'I will make an everlasting covenant with them, that I will not turn away from following them, to do them good. I will put my fear in their hearts, that they may not depart from me.'),
  ('Jeremiah', 32, 41, 'Yes, I will rejoice over them to do them good, and I will plant them in this land assuredly with my whole heart and with my whole soul.”'),
  ('Jeremiah', 32, 42, 'For the LORD says: “Just as I have brought all this great evil on this people, so I will bring on them all the good that I have promised them.'),
  ('Jeremiah', 32, 43, 'Fields will be bought in this land, about which you say, ‘It is desolate, without man or animal. It is given into the hand of the Chaldeans.’'),
  ('Jeremiah', 32, 44, 'Men will buy fields for money, sign the deeds, seal them, and call witnesses, in the land of Benjamin, and in the places around Jerusalem, in the cities of Judah, in the cities of the hill country, in the cities of the lowland, and in the cities of the South; for I will cause their captivity to be reversed,” says the LORD.'),
  ('Jeremiah', 33, 1, 'Moreover the LORD’s word came to Jeremiah the second time, while he was still locked up in the court of the guard, saying,'),
  ('Jeremiah', 33, 2, '“The LORD who does it, the LORD who forms it to establish it—the LORD is his name, says:'),
  ('Jeremiah', 33, 3, '‘Call to me, and I will answer you, and will show you great and difficult things, which you don’t know.’'),
  ('Jeremiah', 33, 4, 'For the LORD, the God of Israel, says concerning the houses of this city and concerning the houses of the kings of Judah, which are broken down to make a defense against the mounds and against the sword:'),
  ('Jeremiah', 33, 5, '‘While men come to fight with the Chaldeans, and to fill them with the dead bodies of men, whom I have killed in my anger and in my wrath, and for all whose wickedness I have hidden my face from this city,'),
  ('Jeremiah', 33, 6, 'behold, I will bring it health and healing, and I will cure them; and I will reveal to them abundance of peace and truth.'),
  ('Jeremiah', 33, 7, 'I will restore the fortunes of Judah and Israel, and will build them as at the first.'),
  ('Jeremiah', 33, 8, 'I will cleanse them from all their iniquity by which they have sinned against me. I will pardon all their iniquities by which they have sinned against me and by which they have transgressed against me.'),
  ('Jeremiah', 33, 9, 'This city will be to me for a name of joy, for praise, and for glory, before all the nations of the earth, which will hear all the good that I do to them, and will fear and tremble for all the good and for all the peace that I provide to it.’”'),
  ('Jeremiah', 33, 10, 'The LORD says: “Yet again there will be heard in this place, about which you say, ‘It is waste, without man and without animal, even in the cities of Judah, and in the streets of Jerusalem, that are desolate, without man and without inhabitant and without animal,’'),
  ('Jeremiah', 33, 11, 'the voice of joy and the voice of gladness, the voice of the bridegroom and the voice of the bride, the voice of those who say, ‘Give thanks to the LORD of Armies, for the LORD is good, for his loving kindness endures forever;’ who bring thanksgiving into the LORD’s house. For I will cause the captivity of the land to be reversed as at the first,” says the LORD.'),
  ('Jeremiah', 33, 12, 'The LORD of Armies says: “Yet again there will be in this place, which is waste, without man and without animal, and in all its cities, a habitation of shepherds causing their flocks to lie down.'),
  ('Jeremiah', 33, 13, 'In the cities of the hill country, in the cities of the lowland, in the cities of the South, in the land of Benjamin, in the places around Jerusalem, and in the cities of Judah, the flocks will again pass under the hands of him who counts them,” says the LORD.'),
  ('Jeremiah', 33, 14, '“Behold, the days come,” says the LORD, “that I will perform that good word which I have spoken concerning the house of Israel and concerning the house of Judah.'),
  ('Jeremiah', 33, 15, '“In those days and at that time, I will cause a Branch of righteousness to grow up to David. He will execute justice and righteousness in the land.'),
  ('Jeremiah', 33, 16, 'In those days Judah will be saved, and Jerusalem will dwell safely. This is the name by which she will be called: The LORD our righteousness.”'),
  ('Jeremiah', 33, 17, 'For the LORD says: “David will never lack a man to sit on the throne of the house of Israel.'),
  ('Jeremiah', 33, 18, 'The Levitical priests won’t lack a man before me to offer burnt offerings, to burn meal offerings, and to do sacrifice continually.”'),
  ('Jeremiah', 33, 19, 'The LORD’s word came to Jeremiah, saying,'),
  ('Jeremiah', 33, 20, '“The LORD says: ‘If you can break my covenant of the day and my covenant of the night, so that there will not be day and night in their time,'),
  ('Jeremiah', 33, 21, 'then my covenant could also be broken with David my servant, that he won’t have a son to reign on his throne; and with the Levitical priests, my ministers.'),
  ('Jeremiah', 33, 22, 'As the army of the sky can’t be counted, and the sand of the sea can’t be measured, so I will multiply the offspring of David my servant and the Levites who minister to me.’”'),
  ('Jeremiah', 33, 23, 'The LORD’s word came to Jeremiah, saying,'),
  ('Jeremiah', 33, 24, '“Don’t consider what this people has spoken, saying, ‘Has the LORD cast off the two families which he chose?’ Thus they despise my people, that they should be no more a nation before them.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 33, 25, 'The LORD says: “If my covenant of day and night fails, if I have not appointed the ordinances of heaven and earth,'),
  ('Jeremiah', 33, 26, 'then I will also cast away the offspring of Jacob, and of David my servant, so that I will not take of his offspring to be rulers over the offspring of Abraham, Isaac, and Jacob; for I will cause their captivity to be reversed and will have mercy on them.”'),
  ('Jeremiah', 34, 1, 'The word which came to Jeremiah from the LORD, when Nebuchadnezzar king of Babylon, with all his army, all the kingdoms of the earth that were under his dominion, and all the peoples, were fighting against Jerusalem and against all its cities, saying:'),
  ('Jeremiah', 34, 2, '“The LORD, the God of Israel, says, ‘Go, and speak to Zedekiah king of Judah, and tell him, the LORD says, “Behold, I will give this city into the hand of the king of Babylon and he will burn it with fire.'),
  ('Jeremiah', 34, 3, 'You won’t escape out of his hand, but will surely be taken and delivered into his hand. Your eyes will see the eyes of the king of Babylon, and he will speak with you mouth to mouth. You will go to Babylon.”’'),
  ('Jeremiah', 34, 4, '“Yet hear the LORD’s word, O Zedekiah king of Judah. The LORD says concerning you, ‘You won’t die by the sword.'),
  ('Jeremiah', 34, 5, 'You will die in peace; and with the burnings of your fathers, the former kings who were before you, so they will make a burning for you. They will lament you, saying, “Ah Lord!” for I have spoken the word,’ says the LORD.”'),
  ('Jeremiah', 34, 6, 'Then Jeremiah the prophet spoke all these words to Zedekiah king of Judah in Jerusalem,'),
  ('Jeremiah', 34, 7, 'when the king of Babylon’s army was fighting against Jerusalem and against all the cities of Judah that were left, against Lachish and against Azekah; for these alone remained of the cities of Judah as fortified cities.'),
  ('Jeremiah', 34, 8, 'The word came to Jeremiah from the LORD, after King Zedekiah had made a covenant with all the people who were at Jerusalem, to proclaim liberty to them,'),
  ('Jeremiah', 34, 9, 'that every man should let his male servant, and every man his female servant, who is a Hebrew or a Hebrewess, go free, that no one should make bondservants of them, of a Jew his brother.'),
  ('Jeremiah', 34, 10, 'All the princes and all the people obeyed who had entered into the covenant, that everyone should let his male servant and everyone his female servant go free, that no one should make bondservants of them any more. They obeyed and let them go,'),
  ('Jeremiah', 34, 11, 'but afterwards they turned, and caused the servants and the handmaids whom they had let go free to return, and brought them into subjection for servants and for handmaids.'),
  ('Jeremiah', 34, 12, 'Therefore the LORD’s word came to Jeremiah from the LORD, saying,'),
  ('Jeremiah', 34, 13, '“The LORD, the God of Israel, says: ‘I made a covenant with your fathers in the day that I brought them out of the land of Egypt, out of the house of bondage, saying:'),
  ('Jeremiah', 34, 14, 'At the end of seven years, every man of you shall release his brother who is a Hebrew, who has been sold to you, and has served you six years. You shall let him go free from you. But your fathers didn’t listen to me, and didn’t incline their ear.'),
  ('Jeremiah', 34, 15, 'You had now turned, and had done that which is right in my eyes, in every man proclaiming liberty to his neighbor. You had made a covenant before me in the house which is called by my name;'),
  ('Jeremiah', 34, 16, 'but you turned and profaned my name, and every man caused his servant and every man his handmaid, whom you had let go free at their pleasure, to return. You brought them into subjection, to be to you for servants and for handmaids.’”'),
  ('Jeremiah', 34, 17, 'Therefore the LORD says: “You have not listened to me, to proclaim liberty, every man to his brother, and every man to his neighbor. Behold, I proclaim to you a liberty,” says the LORD, “to the sword, to the pestilence, and to the famine. I will make you be tossed back and forth among all the kingdoms of the earth.'),
  ('Jeremiah', 34, 18, 'I will give the men who have transgressed my covenant, who have not performed the words of the covenant which they made before me when they cut the calf in two and passed between its parts:'),
  ('Jeremiah', 34, 19, 'the princes of Judah, the princes of Jerusalem, the eunuchs, the priests, and all the people of the land, who passed between the parts of the calf.'),
  ('Jeremiah', 34, 20, 'I will even give them into the hand of their enemies and into the hand of those who seek their life. Their dead bodies will be food for the birds of the sky and for the animals of the earth.'),
  ('Jeremiah', 34, 21, '“I will give Zedekiah king of Judah and his princes into the hands of their enemies, into the hands of those who seek their life and into the hands of the king of Babylon’s army, who has gone away from you.'),
  ('Jeremiah', 34, 22, 'Behold, I will command,” says the LORD, “and cause them to return to this city. They will fight against it, take it, and burn it with fire. I will make the cities of Judah a desolation, without inhabitant.”'),
  ('Jeremiah', 35, 1, 'The word which came to Jeremiah from the LORD in the days of Jehoiakim the son of Josiah, king of Judah, saying,'),
  ('Jeremiah', 35, 2, '“Go to the house of the Rechabites, and speak to them, and bring them into the LORD’s house, into one of the rooms, and give them wine to drink.”'),
  ('Jeremiah', 35, 3, 'Then I took Jaazaniah the son of Jeremiah, the son of Habazziniah, with his brothers, all his sons, and the whole house of the Rechabites;'),
  ('Jeremiah', 35, 4, 'and I brought them into the LORD’s house, into the room of the sons of Hanan the son of Igdaliah, the man of God, which was by the room of the princes, which was above the room of Maaseiah the son of Shallum, the keeper of the threshold.'),
  ('Jeremiah', 35, 5, 'I set before the sons of the house of the Rechabites bowls full of wine, and cups; and I said to them, “Drink wine!”'),
  ('Jeremiah', 35, 6, 'But they said, “We will drink no wine; for Jonadab the son of Rechab, our father, commanded us, saying, ‘You shall drink no wine, neither you nor your children, forever.'),
  ('Jeremiah', 35, 7, 'You shall not build a house, sow seed, plant a vineyard, or have any; but all your days you shall dwell in tents, that you may live many days in the land in which you live as nomads.’'),
  ('Jeremiah', 35, 8, 'We have obeyed the voice of Jonadab the son of Rechab, our father, in all that he commanded us, to drink no wine all our days, we, our wives, our sons, or our daughters;'),
  ('Jeremiah', 35, 9, 'and not to build houses for ourselves to dwell in. We have no vineyard, field, or seed;'),
  ('Jeremiah', 35, 10, 'but we have lived in tents, and have obeyed, and done according to all that Jonadab our father commanded us.'),
  ('Jeremiah', 35, 11, 'But when Nebuchadnezzar king of Babylon came up into the land, we said, ‘Come! Let’s go to Jerusalem for fear of the army of the Chaldeans, and for fear of the army of the Syrians; so we will dwell at Jerusalem.’”'),
  ('Jeremiah', 35, 12, 'Then the LORD’s word came to Jeremiah, saying,'),
  ('Jeremiah', 35, 13, '“The LORD of Armies, the God of Israel, says: ‘Go and tell the men of Judah and the inhabitants of Jerusalem, “Will you not receive instruction to listen to my words?” says the LORD.'),
  ('Jeremiah', 35, 14, '“The words of Jonadab the son of Rechab that he commanded his sons, not to drink wine, are performed; and to this day they drink none, for they obey their father’s commandment; but I have spoken to you, rising up early and speaking, and you have not listened to me.'),
  ('Jeremiah', 35, 15, 'I have sent also to you all my servants the prophets, rising up early and sending them, saying, ‘Every one of you must return now from his evil way, amend your doings, and don’t go after other gods to serve them. Then you will dwell in the land which I have given to you and to your fathers;’ but you have not inclined your ear, nor listened to me.'),
  ('Jeremiah', 35, 16, 'The sons of Jonadab the son of Rechab have performed the commandment of their father which he commanded them, but this people has not listened to me.”’'),
  ('Jeremiah', 35, 17, '“Therefore the LORD, the God of Armies, the God of Israel, says: ‘Behold, I will bring on Judah and on all the inhabitants of Jerusalem all the evil that I have pronounced against them, because I have spoken to them, but they have not heard; and I have called to them, but they have not answered.’”'),
  ('Jeremiah', 35, 18, 'Jeremiah said to the house of the Rechabites, “The LORD of Armies, the God of Israel, says: ‘Because you have obeyed the commandment of Jonadab your father, and kept all his precepts, and done according to all that he commanded you,’'),
  ('Jeremiah', 35, 19, 'therefore the LORD of Armies, the God of Israel, says: ‘Jonadab the son of Rechab will not lack a man to stand before me forever.’”'),
  ('Jeremiah', 36, 1, 'In the fourth year of Jehoiakim the son of Josiah, king of Judah, this word came to Jeremiah from the LORD, saying,'),
  ('Jeremiah', 36, 2, '“Take a scroll of a book, and write in it all the words that I have spoken to you against Israel, against Judah, and against all the nations, from the day I spoke to you, from the days of Josiah even to this day.'),
  ('Jeremiah', 36, 3, 'It may be that the house of Judah will hear all the evil which I intend to do to them, that they may each return from his evil way; that I may forgive their iniquity and their sin.”'),
  ('Jeremiah', 36, 4, 'Then Jeremiah called Baruch the son of Neriah; and Baruch wrote from the mouth of Jeremiah all the LORD’s words, which he had spoken to him, on a scroll of a book.'),
  ('Jeremiah', 36, 5, 'Jeremiah commanded Baruch, saying, “I am restricted. I can’t go into the LORD’s house.'),
  ('Jeremiah', 36, 6, 'Therefore you go, and read from the scroll which you have written from my mouth, the LORD’s words, in the ears of the people in the LORD’s house on the fast day. Also you shall read them in the ears of all Judah who come out of their cities.'),
  ('Jeremiah', 36, 7, 'It may be they will present their supplication before the LORD, and will each return from his evil way; for the LORD has pronounced great anger and wrath against this people.”'),
  ('Jeremiah', 36, 8, 'Baruch the son of Neriah did according to all that Jeremiah the prophet commanded him, reading in the book the LORD’s words in the LORD’s house.'),
  ('Jeremiah', 36, 9, 'Now in the fifth year of Jehoiakim the son of Josiah, king of Judah, in the ninth month, all the people in Jerusalem and all the people who came from the cities of Judah to Jerusalem, proclaimed a fast before the LORD.'),
  ('Jeremiah', 36, 10, 'Then Baruch read the words of Jeremiah from the book in the LORD’s house, in the room of Gemariah the son of Shaphan the scribe, in the upper court, at the entry of the new gate of the LORD’s house, in the ears of all the people.'),
  ('Jeremiah', 36, 11, 'When Micaiah the son of Gemariah, the son of Shaphan, had heard out of the book all the LORD’s words,'),
  ('Jeremiah', 36, 12, 'he went down into the king’s house, into the scribe’s room; and behold, all the princes were sitting there, Elishama the scribe, Delaiah the son of Shemaiah, Elnathan the son of Achbor, Gemariah the son of Shaphan, Zedekiah the son of Hananiah, and all the princes.'),
  ('Jeremiah', 36, 13, 'Then Micaiah declared to them all the words that he had heard, when Baruch read the book in the ears of the people.'),
  ('Jeremiah', 36, 14, 'Therefore all the princes sent Jehudi the son of Nethaniah, the son of Shelemiah, the son of Cushi, to Baruch, saying, “Take in your hand the scroll in which you have read in the ears of the people, and come.” So Baruch the son of Neriah took the scroll in his hand, and came to them.'),
  ('Jeremiah', 36, 15, 'They said to him, “Sit down now, and read it in our hearing.” So Baruch read it in their hearing.'),
  ('Jeremiah', 36, 16, 'Now when they had heard all the words, they turned in fear one toward another, and said to Baruch, “We will surely tell the king of all these words.”'),
  ('Jeremiah', 36, 17, 'They asked Baruch, saying, “Tell us now, how did you write all these words at his mouth?”'),
  ('Jeremiah', 36, 18, 'Then Baruch answered them, “He dictated all these words to me with his mouth, and I wrote them with ink in the book.”'),
  ('Jeremiah', 36, 19, 'Then the princes said to Baruch, “You and Jeremiah go hide. Don’t let anyone know where you are.”'),
  ('Jeremiah', 36, 20, 'They went in to the king into the court, but they had laid up the scroll in the room of Elishama the scribe. Then they told all the words in the hearing of the king.'),
  ('Jeremiah', 36, 21, 'So the king sent Jehudi to get the scroll, and he took it out of the room of Elishama the scribe. Jehudi read it in the hearing of the king, and in the hearing of all the princes who stood beside the king.'),
  ('Jeremiah', 36, 22, 'Now the king was sitting in the winter house in the ninth month, and there was a fire in the brazier burning before him.'),
  ('Jeremiah', 36, 23, 'When Jehudi had read three or four columns, the king cut it with the penknife, and cast it into the fire that was in the brazier, until all the scroll was consumed in the fire that was in the brazier.'),
  ('Jeremiah', 36, 24, 'The king and his servants who heard all these words were not afraid, and didn’t tear their garments.'),
  ('Jeremiah', 36, 25, 'Moreover Elnathan and Delaiah and Gemariah had made intercession to the king that he would not burn the scroll; but he would not listen to them.'),
  ('Jeremiah', 36, 26, 'The king commanded Jerahmeel the king’s son, and Seraiah the son of Azriel, and Shelemiah the son of Abdeel, to arrest Baruch the scribe and Jeremiah the prophet; but the LORD hid them.'),
  ('Jeremiah', 36, 27, 'Then the LORD’s word came to Jeremiah, after the king had burned the scroll, and the words which Baruch wrote at the mouth of Jeremiah, saying,'),
  ('Jeremiah', 36, 28, '“Take again another scroll, and write in it all the former words that were in the first scroll, which Jehoiakim the king of Judah has burned.'),
  ('Jeremiah', 36, 29, 'Concerning Jehoiakim king of Judah you shall say, ‘The LORD says: “You have burned this scroll, saying, ‘Why have you written therein, saying, “The king of Babylon will certainly come and destroy this land, and will cause to cease from there man and animal”?’”'),
  ('Jeremiah', 36, 30, 'Therefore the LORD says concerning Jehoiakim king of Judah: “He will have no one to sit on David’s throne. His dead body will be cast out in the day to the heat, and in the night to the frost.'),
  ('Jeremiah', 36, 31, 'I will punish him, his offspring, and his servants for their iniquity. I will bring on them, on the inhabitants of Jerusalem, and on the men of Judah, all the evil that I have pronounced against them, but they didn’t listen.”’”'),
  ('Jeremiah', 36, 32, 'Then Jeremiah took another scroll, and gave it to Baruch the scribe, the son of Neriah, who wrote therein from the mouth of Jeremiah all the words of the book which Jehoiakim king of Judah had burned in the fire; and many similar words were added to them.'),
  ('Jeremiah', 37, 1, 'Zedekiah the son of Josiah reigned as king instead of Coniah the son of Jehoiakim, whom Nebuchadnezzar king of Babylon made king in the land of Judah.'),
  ('Jeremiah', 37, 2, 'But neither he, nor his servants, nor the people of the land, listened to the LORD’s words, which he spoke by the prophet Jeremiah.'),
  ('Jeremiah', 37, 3, 'Zedekiah the king sent Jehucal the son of Shelemiah and Zephaniah the son of Maaseiah, the priest, to the prophet Jeremiah, saying, “Pray now to the LORD our God for us.”'),
  ('Jeremiah', 37, 4, 'Now Jeremiah came in and went out among the people, for they had not put him into prison.'),
  ('Jeremiah', 37, 5, 'Pharaoh’s army had come out of Egypt; and when the Chaldeans who were besieging Jerusalem heard news of them, they withdrew from Jerusalem.'),
  ('Jeremiah', 37, 6, 'Then the LORD’s word came to the prophet Jeremiah, saying,'),
  ('Jeremiah', 37, 7, '“The LORD, the God of Israel, says, ‘You shall tell the king of Judah, who sent you to me to inquire of me: “Behold, Pharaoh’s army, which has come out to help you, will return to Egypt into their own land.'),
  ('Jeremiah', 37, 8, 'The Chaldeans will come again, and fight against this city. They will take it and burn it with fire.”’'),
  ('Jeremiah', 37, 9, '“The LORD says, ‘Don’t deceive yourselves, saying, “The Chaldeans will surely depart from us;” for they will not depart.'),
  ('Jeremiah', 37, 10, 'For though you had struck the whole army of the Chaldeans who fight against you, and only wounded men remained among them, they would each rise up in his tent and burn this city with fire.’”'),
  ('Jeremiah', 37, 11, 'When the army of the Chaldeans had withdrawn from Jerusalem for fear of Pharaoh’s army,'),
  ('Jeremiah', 37, 12, 'then Jeremiah went out of Jerusalem to go into the land of Benjamin, to receive his portion there, in the middle of the people.'),
  ('Jeremiah', 37, 13, 'When he was in Benjamin’s gate, a captain of the guard was there, whose name was Irijah, the son of Shelemiah, the son of Hananiah; and he seized Jeremiah the prophet, saying, “You are defecting to the Chaldeans!”'),
  ('Jeremiah', 37, 14, 'Then Jeremiah said, “That is false! I am not defecting to the Chaldeans.” But he didn’t listen to him; so Irijah seized Jeremiah, and brought him to the princes.'),
  ('Jeremiah', 37, 15, 'The princes were angry with Jeremiah, and struck him, and put him in prison in the house of Jonathan the scribe; for they had made that the prison.'),
  ('Jeremiah', 37, 16, 'When Jeremiah had come into the dungeon house and into the cells, and Jeremiah had remained there many days,'),
  ('Jeremiah', 37, 17, 'then Zedekiah the king sent and had him brought out. The king asked him secretly in his house, “Is there any word from the LORD?” Jeremiah said, “There is.” He also said, “You will be delivered into the hand of the king of Babylon.”'),
  ('Jeremiah', 37, 18, 'Moreover Jeremiah said to King Zedekiah, “How have I sinned against you, against your servants, or against this people, that you have put me in prison?'),
  ('Jeremiah', 37, 19, 'Now where are your prophets who prophesied to you, saying, ‘The king of Babylon will not come against you, nor against this land’?'),
  ('Jeremiah', 37, 20, 'Now please hear, my lord the king: please let my supplication be presented before you, that you not cause me to return to the house of Jonathan the scribe, lest I die there.”'),
  ('Jeremiah', 37, 21, 'Then Zedekiah the king commanded, and they committed Jeremiah into the court of the guard. They gave him daily a loaf of bread out of the bakers’ street, until all the bread in the city was gone. Thus Jeremiah remained in the court of the guard.'),
  ('Jeremiah', 38, 1, 'Shephatiah the son of Mattan, Gedaliah the son of Pashhur, Jucal the son of Shelemiah, and Pashhur the son of Malchijah heard the words that Jeremiah spoke to all the people, saying,'),
  ('Jeremiah', 38, 2, '“The LORD says, ‘He who remains in this city will die by the sword, by the famine, and by the pestilence, but he who goes out to the Chaldeans will live. He will escape with his life and he will live.’'),
  ('Jeremiah', 38, 3, 'The LORD says, ‘This city will surely be given into the hand of the army of the king of Babylon, and he will take it.’”'),
  ('Jeremiah', 38, 4, 'Then the princes said to the king, “Please let this man be put to death, because he weakens the hands of the men of war who remain in this city, and the hands of all the people, in speaking such words to them; for this man doesn’t seek the welfare of this people, but harm.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Jeremiah', 38, 5, 'Zedekiah the king said, “Behold, he is in your hand; for the king can’t do anything to oppose you.”'),
  ('Jeremiah', 38, 6, 'Then they took Jeremiah and threw him into the dungeon of Malchijah the king’s son, that was in the court of the guard. They let down Jeremiah with cords. In the dungeon there was no water, but mire; and Jeremiah sank in the mire.'),
  ('Jeremiah', 38, 7, 'Now when Ebedmelech the Ethiopian, a eunuch, who was in the king’s house, heard that they had put Jeremiah in the dungeon (the king was then sitting in Benjamin’s gate),'),
  ('Jeremiah', 38, 8, 'Ebedmelech went out of the king’s house, and spoke to the king, saying,'),
  ('Jeremiah', 38, 9, '“My lord the king, these men have done evil in all that they have done to Jeremiah the prophet, whom they have cast into the dungeon. He is likely to die in the place where he is, because of the famine; for there is no more bread in the city.”'),
  ('Jeremiah', 38, 10, 'Then the king commanded Ebedmelech the Ethiopian, saying, “Take from here thirty men with you, and take up Jeremiah the prophet out of the dungeon, before he dies.”'),
  ('Jeremiah', 38, 11, 'So Ebedmelech took the men with him, and went into the house of the king under the treasury, and took from there rags and worn-out garments, and let them down by cords into the dungeon to Jeremiah.'),
  ('Jeremiah', 38, 12, 'Ebedmelech the Ethiopian said to Jeremiah, “Now put these rags and worn-out garments under your armpits under the cords.” Jeremiah did so.'),
  ('Jeremiah', 38, 13, 'So they lifted Jeremiah up with the cords, and took him up out of the dungeon; and Jeremiah remained in the court of the guard.'),
  ('Jeremiah', 38, 14, 'Then Zedekiah the king sent and took Jeremiah the prophet to himself into the third entry that is in the LORD’s house. Then the king said to Jeremiah, “I will ask you something. Hide nothing from me.”'),
  ('Jeremiah', 38, 15, 'Then Jeremiah said to Zedekiah, “If I declare it to you, will you not surely put me to death? If I give you counsel, you will not listen to me.”'),
  ('Jeremiah', 38, 16, 'So Zedekiah the king swore secretly to Jeremiah, saying, “As the LORD lives, who made our souls, I will not put you to death, neither will I give you into the hand of these men who seek your life.”'),
  ('Jeremiah', 38, 17, 'Then Jeremiah said to Zedekiah, “The LORD, the God of Armies, the God of Israel, says: ‘If you will go out to the king of Babylon’s princes, then your soul will live, and this city will not be burned with fire. You will live, along with your house.'),
  ('Jeremiah', 38, 18, 'But if you will not go out to the king of Babylon’s princes, then this city will be given into the hand of the Chaldeans, and they will burn it with fire, and you won’t escape out of their hand.’”'),
  ('Jeremiah', 38, 19, 'Zedekiah the king said to Jeremiah, “I am afraid of the Jews who have defected to the Chaldeans, lest they deliver me into their hand, and they mock me.”'),
  ('Jeremiah', 38, 20, 'But Jeremiah said, “They won’t deliver you. Obey, I beg you, the LORD’s voice, in that which I speak to you; so it will be well with you, and your soul will live.'),
  ('Jeremiah', 38, 21, 'But if you refuse to go out, this is the word that the LORD has shown me:'),
  ('Jeremiah', 38, 22, '‘Behold, all the women who are left in the king of Judah’s house will be brought out to the king of Babylon’s princes, and those women will say, “Your familiar friends have turned on you, and have prevailed over you. Your feet are sunk in the mire, they have turned away from you.”'),
  ('Jeremiah', 38, 23, 'They will bring out all your wives and your children to the Chaldeans. You won’t escape out of their hand, but will be taken by the hand of the king of Babylon. You will cause this city to be burned with fire.’”'),
  ('Jeremiah', 38, 24, 'Then Zedekiah said to Jeremiah, “Let no man know of these words, and you won’t die.'),
  ('Jeremiah', 38, 25, 'But if the princes hear that I have talked with you, and they come to you, and tell you, ‘Declare to us now what you have said to the king; don’t hide it from us, and we will not put you to death; also tell us what the king said to you;’'),
  ('Jeremiah', 38, 26, 'then you shall tell them, ‘I presented my supplication before the king, that he would not cause me to return to Jonathan’s house, to die there.’”'),
  ('Jeremiah', 38, 27, 'Then all the princes came to Jeremiah, and asked him; and he told them according to all these words that the king had commanded. So they stopped speaking with him, for the matter was not perceived.'),
  ('Jeremiah', 38, 28, 'So Jeremiah stayed in the court of the guard until the day that Jerusalem was taken.'),
  ('Jeremiah', 39, 1, 'In the ninth year of Zedekiah king of Judah, in the tenth month, Nebuchadnezzar king of Babylon and all his army came against Jerusalem, and besieged it.'),
  ('Jeremiah', 39, 2, 'In the eleventh year of Zedekiah, in the fourth month, the ninth day of the month, a breach was made in the city.'),
  ('Jeremiah', 39, 3, 'All the princes of the king of Babylon came in, and sat in the middle gate: Nergal Sharezer, Samgarnebo, Sarsechim the Rabsaris, Nergal Sharezer the Rabmag, with all the rest of the princes of the king of Babylon.'),
  ('Jeremiah', 39, 4, 'When Zedekiah the king of Judah and all the men of war saw them, then they fled and went out of the city by night, by the way of the king’s garden, through the gate between the two walls; and he went out toward the Arabah.'),
  ('Jeremiah', 39, 5, 'But the army of the Chaldeans pursued them, and overtook Zedekiah in the plains of Jericho. When they had taken him, they brought him up to Nebuchadnezzar king of Babylon to Riblah in the land of Hamath; and he pronounced judgment on him.'),
  ('Jeremiah', 39, 6, 'Then the king of Babylon killed Zedekiah’s sons in Riblah before his eyes. The king of Babylon also killed all the nobles of Judah.'),
  ('Jeremiah', 39, 7, 'Moreover he put out Zedekiah’s eyes and bound him in fetters, to carry him to Babylon.'),
  ('Jeremiah', 39, 8, 'The Chaldeans burned the king’s house and the people’s houses with fire and broke down the walls of Jerusalem.'),
  ('Jeremiah', 39, 9, 'Then Nebuzaradan the captain of the guard carried away captive into Babylon the rest of the people who remained in the city, the deserters also who fell away to him, and the rest of the people who remained.'),
  ('Jeremiah', 39, 10, 'But Nebuzaradan the captain of the guard left of the poor of the people, who had nothing, in the land of Judah, and gave them vineyards and fields at the same time.'),
  ('Jeremiah', 39, 11, 'Now Nebuchadnezzar king of Babylon commanded Nebuzaradan the captain of the guard concerning Jeremiah, saying,'),
  ('Jeremiah', 39, 12, '“Take him and take care of him. Do him no harm; but do to him even as he tells you.”'),
  ('Jeremiah', 39, 13, 'So Nebuzaradan the captain of the guard, Nebushazban, Rabsaris, and Nergal Sharezer, Rabmag, and all the chief officers of the king of Babylon'),
  ('Jeremiah', 39, 14, 'sent and took Jeremiah out of the court of the guard, and committed him to Gedaliah the son of Ahikam, the son of Shaphan, that he should bring him home. So he lived among the people.'),
  ('Jeremiah', 39, 15, 'Now the LORD’s word came to Jeremiah while he was shut up in the court of the guard, saying,'),
  ('Jeremiah', 39, 16, '“Go, and speak to Ebedmelech the Ethiopian, saying, ‘The LORD of Armies, the God of Israel, says: “Behold, I will bring my words on this city for evil, and not for good; and they will be accomplished before you in that day.'),
  ('Jeremiah', 39, 17, 'But I will deliver you in that day,” says the LORD; “and you will not be given into the hand of the men of whom you are afraid.'),
  ('Jeremiah', 39, 18, 'For I will surely save you. You won’t fall by the sword, but you will escape with your life, because you have put your trust in me,” says the LORD.’”'),
  ('Jeremiah', 40, 1, 'The word which came to Jeremiah from the LORD, after Nebuzaradan the captain of the guard had let him go from Ramah, when he had taken him being bound in chains among all the captives of Jerusalem and Judah who were carried away captive to Babylon.'),
  ('Jeremiah', 40, 2, 'The captain of the guard took Jeremiah and said to him, “The LORD your God pronounced this evil on this place;'),
  ('Jeremiah', 40, 3, 'and the LORD has brought it, and done according as he spoke. Because you have sinned against the LORD, and have not obeyed his voice, therefore this thing has come on you.'),
  ('Jeremiah', 40, 4, 'Now, behold, I release you today from the chains which are on your hand. If it seems good to you to come with me into Babylon, come, and I will take care of you; but if it seems bad to you to come with me into Babylon, don’t. Behold, all the land is before you. Where it seems good and right to you to go, go there.”'),
  ('Jeremiah', 40, 5, 'Now while he had not yet gone back, “Go back then,” he said, “to Gedaliah the son of Ahikam, the son of Shaphan, whom the king of Babylon has made governor over the cities of Judah, and dwell with him among the people; or go wherever it seems right to you to go.” So the captain of the guard gave him food and a present, and let him go.'),
  ('Jeremiah', 40, 6, 'Then Jeremiah went to Gedaliah the son of Ahikam to Mizpah, and lived with him among the people who were left in the land.'),
  ('Jeremiah', 40, 7, 'Now when all the captains of the forces who were in the fields, even they and their men, heard that the king of Babylon had made Gedaliah the son of Ahikam governor in the land, and had committed to him men, women, children, and of the poorest of the land, of those who were not carried away captive to Babylon,'),
  ('Jeremiah', 40, 8, 'then Ishmael the son of Nethaniah, and Johanan and Jonathan the sons of Kareah, and Seraiah the son of Tanhumeth, and the sons of Ephai the Netophathite, and Jezaniah the son of the Maacathite, they and their men came to Gedaliah to Mizpah.'),
  ('Jeremiah', 40, 9, 'Gedaliah the son of Ahikam the son of Shaphan swore to them and to their men, saying, “Don’t be afraid to serve the Chaldeans. Dwell in the land, and serve the king of Babylon, and it will be well with you.'),
  ('Jeremiah', 40, 10, 'As for me, behold, I will dwell at Mizpah, to stand before the Chaldeans who will come to us; but you, gather wine and summer fruits and oil, and put them in your vessels, and dwell in your cities that you have taken.”'),
  ('Jeremiah', 40, 11, 'Likewise when all the Jews who were in Moab, and among the children of Ammon, and in Edom, and who were in all the countries, heard that the king of Babylon had left a remnant of Judah, and that he had set over them Gedaliah the son of Ahikam, the son of Shaphan,'),
  ('Jeremiah', 40, 12, 'then all the Jews returned out of all places where they were driven, and came to the land of Judah, to Gedaliah, to Mizpah, and gathered very much wine and summer fruits.'),
  ('Jeremiah', 40, 13, 'Moreover Johanan the son of Kareah, and all the captains of the forces who were in the fields, came to Gedaliah to Mizpah,'),
  ('Jeremiah', 40, 14, 'and said to him, “Do you know that Baalis the king of the children of Ammon has sent Ishmael the son of Nethaniah to take your life?” But Gedaliah the son of Ahikam didn’t believe them.'),
  ('Jeremiah', 40, 15, 'Then Johanan the son of Kareah spoke to Gedaliah in Mizpah secretly, saying, “Please let me go, and I will kill Ishmael the son of Nethaniah, and no man will know it. Why should he take your life, that all the Jews who are gathered to you should be scattered, and the remnant of Judah perish?”'),
  ('Jeremiah', 40, 16, 'But Gedaliah the son of Ahikam said to Johanan the son of Kareah, “You shall not do this thing, for you speak falsely of Ishmael.”'),
  ('Jeremiah', 41, 1, 'Now in the seventh month, Ishmael the son of Nethaniah, the son of Elishama, of the royal offspring and one of the chief officers of the king, and ten men with him, came to Gedaliah the son of Ahikam to Mizpah; and there they ate bread together in Mizpah.'),
  ('Jeremiah', 41, 2, 'Then Ishmael the son of Nethaniah arose, and the ten men who were with him, and struck Gedaliah the son of Ahikam the son of Shaphan with the sword and killed him, whom the king of Babylon had made governor over the land.'),
  ('Jeremiah', 41, 3, 'Ishmael also killed all the Jews who were with Gedaliah at Mizpah, and the Chaldean men of war who were found there.'),
  ('Jeremiah', 41, 4, 'The second day after he had killed Gedaliah, and no man knew it,'),
  ('Jeremiah', 41, 5, 'men came from Shechem, from Shiloh, and from Samaria, even eighty men, having their beards shaved and their clothes torn, and having cut themselves, with meal offerings and frankincense in their hand, to bring them to the LORD’s house.'),
  ('Jeremiah', 41, 6, 'Ishmael the son of Nethaniah went out from Mizpah to meet them, weeping all along as he went, and as he met them, he said to them, “Come to Gedaliah the son of Ahikam.”'),
  ('Jeremiah', 41, 7, 'It was so, when they came into the middle of the city, that Ishmael the son of Nethaniah killed them, and cast them into the middle of the pit, he, and the men who were with him.'),
  ('Jeremiah', 41, 8, 'But ten men were found among those who said to Ishmael, “Don’t kill us; for we have stores hidden in the field, of wheat, and of barley, and of oil, and of honey.” So he stopped, and didn’t kill them among their brothers.'),
  ('Jeremiah', 41, 9, 'Now the pit in which Ishmael cast all the dead bodies of the men whom he had killed, by the side of Gedaliah (this was that which Asa the king had made for fear of Baasha king of Israel), Ishmael the son of Nethaniah filled it with those who were killed.'),
  ('Jeremiah', 41, 10, 'Then Ishmael carried away captive all of the people who were left in Mizpah, even the king’s daughters, and all the people who remained in Mizpah, whom Nebuzaradan the captain of the guard had committed to Gedaliah the son of Ahikam. Ishmael the son of Nethaniah carried them away captive, and departed to go over to the children of Ammon.'),
  ('Jeremiah', 41, 11, 'But when Johanan the son of Kareah, and all the captains of the forces who were with him, heard of all the evil that Ishmael the son of Nethaniah had done,'),
  ('Jeremiah', 41, 12, 'then they took all the men, and went to fight with Ishmael the son of Nethaniah, and found him by the great waters that are in Gibeon.'),
  ('Jeremiah', 41, 13, 'Now when all the people who were with Ishmael saw Johanan the son of Kareah, and all the captains of the forces who were with him, then they were glad.'),
  ('Jeremiah', 41, 14, 'So all the people who Ishmael had carried away captive from Mizpah turned about and came back, and went to Johanan the son of Kareah.'),
  ('Jeremiah', 41, 15, 'But Ishmael the son of Nethaniah escaped from Johanan with eight men, and went to the children of Ammon.'),
  ('Jeremiah', 41, 16, 'Then Johanan the son of Kareah and all the captains of the forces who were with him took all the remnant of the people whom he had recovered from Ishmael the son of Nethaniah, from Mizpah, after he had killed Gedaliah the son of Ahikam—the men of war, with the women, the children, and the eunuchs, whom he had brought back from Gibeon.'),
  ('Jeremiah', 41, 17, 'They departed and lived in Geruth Chimham, which is by Bethlehem, to go to enter into Egypt'),
  ('Jeremiah', 41, 18, 'because of the Chaldeans; for they were afraid of them, because Ishmael the son of Nethaniah had killed Gedaliah the son of Ahikam, whom the king of Babylon made governor over the land.'),
  ('Jeremiah', 42, 1, 'Then all the captains of the forces, and Johanan the son of Kareah, and Jezaniah the son of Hoshaiah, and all the people from the least even to the greatest, came near,'),
  ('Jeremiah', 42, 2, 'and said to Jeremiah the prophet, “Please let our supplication be presented before you, and pray for us to the LORD your God, even for all this remnant, for we are left but a few of many, as your eyes see us,'),
  ('Jeremiah', 42, 3, 'that the LORD your God may show us the way in which we should walk, and the things that we should do.”'),
  ('Jeremiah', 42, 4, 'Then Jeremiah the prophet said to them, “I have heard you. Behold, I will pray to the LORD your God according to your words; and it will happen that whatever thing the LORD answers you, I will declare it to you. I will keep nothing back from you.”'),
  ('Jeremiah', 42, 5, 'Then they said to Jeremiah, “May the LORD be a true and faithful witness among us, if we don’t do according to all the word with which the LORD your God sends you to tell us.'),
  ('Jeremiah', 42, 6, 'Whether it is good, or whether it is bad, we will obey the voice of the LORD our God, to whom we send you; that it may be well with us, when we obey the voice of the LORD our God.”'),
  ('Jeremiah', 42, 7, 'After ten days, the LORD’s word came to Jeremiah.'),
  ('Jeremiah', 42, 8, 'Then he called Johanan the son of Kareah, and all the captains of the forces who were with him, and all the people from the least even to the greatest,'),
  ('Jeremiah', 42, 9, 'and said to them, “The LORD, the God of Israel, to whom you sent me to present your supplication before him, says:'),
  ('Jeremiah', 42, 10, '‘If you will still live in this land, then I will build you, and not pull you down, and I will plant you, and not pluck you up; for I grieve over the distress that I have brought on you.'),
  ('Jeremiah', 42, 11, 'Don’t be afraid of the king of Babylon, of whom you are afraid. Don’t be afraid of him,’ says the LORD, ‘for I am with you to save you, and to deliver you from his hand.'),
  ('Jeremiah', 42, 12, 'I will grant you mercy, that he may have mercy on you, and cause you to return to your own land.'),
  ('Jeremiah', 42, 13, '“‘But if you say, “We will not dwell in this land,” so that you don’t obey the LORD your God’s voice,'),
  ('Jeremiah', 42, 14, 'saying, “No, but we will go into the land of Egypt, where we will see no war, nor hear the sound of the trumpet, nor have hunger of bread; and there we will dwell;”’'),
  ('Jeremiah', 42, 15, 'now therefore hear the LORD’s word, O remnant of Judah! The LORD of Armies, the God of Israel, says, ‘If you indeed set your faces to enter into Egypt, and go to live there,'),
  ('Jeremiah', 42, 16, 'then it will happen that the sword, which you fear, will overtake you there in the land of Egypt; and the famine, about which you are afraid, will follow close behind you there in Egypt; and you will die there.'),
  ('Jeremiah', 42, 17, 'So will it be with all the men who set their faces to go into Egypt to live there. They will die by the sword, by the famine, and by the pestilence. None of them will remain or escape from the evil that I will bring on them.’'),
  ('Jeremiah', 42, 18, 'For the LORD of Armies, the God of Israel, says: ‘As my anger and my wrath has been poured out on the inhabitants of Jerusalem, so my wrath will be poured out on you, when you enter into Egypt; and you will be an object of horror, an astonishment, a curse, and a reproach; and you will see this place no more.’'),
  ('Jeremiah', 42, 19, '“The LORD has spoken concerning you, remnant of Judah, ‘Don’t go into Egypt!’ Know certainly that I have testified to you today.'),
  ('Jeremiah', 42, 20, 'For you have dealt deceitfully against your own souls; for you sent me to the LORD your God, saying, ‘Pray for us to the LORD our God; and according to all that the LORD our God says, so declare to us, and we will do it.’'),
  ('Jeremiah', 42, 21, 'I have declared it to you today; but you have not obeyed the LORD your God’s voice in anything for which he has sent me to you.'),
  ('Jeremiah', 42, 22, 'Now therefore know certainly that you will die by the sword, by the famine, and by the pestilence in the place where you desire to go to live.”'),
  ('Jeremiah', 43, 1, 'When Jeremiah had finished speaking to all the people all the words of the LORD their God, with which the LORD their God had sent him to them, even all these words,'),
  ('Jeremiah', 43, 2, 'then Azariah the son of Hoshaiah, Johanan the son of Kareah, and all the proud men spoke, saying to Jeremiah, “You speak falsely. The LORD our God has not sent you to say, ‘You shall not go into Egypt to live there;’');
